  // Changes for user with readonly permission - this should be the topmost code dont write anything above this
  $(document).ready(function () {
    // Check if quoteIsReadOnly is defined and true
    if (typeof quoteIsReadOnly !== "undefined" && quoteIsReadOnly === true) {
      // Hide the buttons on viewquote page when readonly
      $('a[href^="/Public/ViewEditQuote?"]').hide();
      $(".block-renewals").hide();
      $(".btnCopyReQuote").hide();
      $(".btnUploadDocuments").hide();
      $('[title="Notes"]').hide();

      // Disabling multi item buttons in readonly
      $(".instanda-multi-item-add").attr("disabled", "disabled");
      $(".instanda-multi-item-remove").attr("disabled", "disabled");

      // Disable API trigger buttons
      $(".AddressValidBtn").attr("disabled", "disabled");
      $(".GeocodeBtn").attr("disabled", "disabled");
      $(".BancreateBtn").attr("disabled", "disabled");

      // Hide notes button on question pages for readonly
      $(".instanda-notes-button").hide();

      // Add body class for readonly mode
      $("body").addClass("readonlymode");

      // Only run this logic if neither forbidden class exists
      if (
        !$(".page-agentretrievequotecrosspackage").length > 0 &&
        !$(".page-agentretrievequotebypackage").length > 0
      ) {
        // Make all input, textarea fields readonly, and apply strong styles (except hidden fields)
        $(
          'input.form-control:not([type="hidden"]), textarea.form-control'
        ).each(function () {
          if (
            $(this).is(
              'input[type="text"], input[type="number"], input[type="date"], textarea'
            )
          ) {
            $(this)
              .attr("readonly", "readonly")[0]
              .style.setProperty("background-color", "#eee", "important");
            this.style.setProperty("color", "#888", "important");
            this.style.setProperty("cursor", "not-allowed", "important");
            this.style.setProperty("pointer-events", "none", "important");
          }
        });

        // Style disabled selects with .form-control, using setProperty for !important
        $("select.form-control:disabled").each(function () {
          this.style.setProperty("background-color", "#eee", "important");
          this.style.setProperty("color", "#888", "important");
          this.style.setProperty("cursor", "not-allowed", "important");
          this.style.setProperty("pointer-events", "none", "important");
        });
      }
    }
  });

