  function vinRulesAuto(mod_vin, mod_year) {
    const customWarnings = document.querySelectorAll("#custom-warn-response");
    customWarnings.forEach((warnings) => {
      warnings.remove();
    });

    if (mod_year >= 1965 && mod_year <= 1969) {
      //The VIN for model years 1965 to 1969 must be at least 9 digits long.
      if (mod_vin.length < 9)
        displayApiWarningMessage(
          "The VIN for model years 1965 to 1969 must be at least 9 digits long."
        );
    }

    if (mod_year >= 1970 && mod_year <= 1980) {
      //The VIN for model years 1970 to 1980 must be at least 10 digits long.
      if (mod_vin.length < 10)
        displayApiWarningMessage(
          "The VIN for model years 1970 to 1980 must be at least 10 digits long."
        );
    }

    if (mod_year >= 1981 && mod_year <= 2009) {
      //The 4th and 5th digits of the VIN must be alphabetic.
      if (!(/^[a-zA-Z]$/.test(mod_vin[3]) && /^[a-zA-Z]$/.test(mod_vin[4]))) {
        displayApiWarningMessage(
          "The 4th and 5th digits of the VIN must be alphabetic."
        );
      }

      //The 6th and 7th digits of the VIN must be numeric.
      if (!(/^\d$/.test(mod_vin[5]) && /^\d$/.test(mod_vin[6]))) {
        displayApiWarningMessage(
          "The 6th and 7th digits of the VIN must be numeric."
        );
      }
    }

    if (mod_year >= 1981) {
      //The VIN for model years 1981 to current must be 17 digits long.
      if (mod_vin.length < 17)
        displayApiWarningMessage(
          "The VIN for model years 1981 to current must be 17 digits long."
        );
      //The VIN must not include letters  'I', 'O' and 'Q'.
      if (/[ioq]/i.test(mod_vin))
        displayApiWarningMessage(
          "The VIN must not include letters  'I', 'O' and 'Q'."
        );

      //The last 4 digits of the VIN must be numeric.
      if (!/\d{4}$/.test(mod_vin))
        displayApiWarningMessage(
          "The last 4 digits of the VIN must be numeric."
        );

      //The 10th digit of the VIN must be [code for the year]. The 10th digit of the VIN cannot be letters I, O, Q, U, Z or the digit 0.
      if (mod_vin.length >= 10 && /[ioquz0]/i.test(mod_vin[9]))
        displayApiWarningMessage(
          "The 10th digit of the VIN must be [code for the year]. The 10th digit of the VIN cannot be letters I, O, Q, U, Z or the digit 0."
        );

      //The 9th digit of the VIN must be numeric or the letter 'X'.
      if (!/^[0-9x]+$/i.test(mod_vin[8]))
        displayApiWarningMessage(
          "The 9th digit of the VIN must be numeric or the letter 'X'."
        );

      //The VIN must not include special characters and spaces.
      if (/[^a-zA-Z0-9\s]/.test(mod_vin) || /\s/.test(mod_vin))
        displayApiWarningMessage(
          "The VIN must not include special characters and spaces."
        );
    }

    //The 7th digit of the VIN must be alphabetic.z
    if (mod_year >= 2010) {
      if (!/^[a-zA-Z]$/.test(mod_vin[6])) {
        displayApiWarningMessage(
          "The 7th digit of the VIN must be alphabetic."
        );
      }
    }
  }
  //VIN Warnings code ends here

  //User Roles
  $(document).ready(function () {
    function applyRoleClass() {
      // 1. Try referral level from DOM
      let referrallevelRaw = document
        .getElementById("LoggedInUserReferralLevel")
        ?.textContent.trim();
      let referrallevel =
        referrallevelRaw && !isNaN(Number(referrallevelRaw)) ?
          Number(referrallevelRaw) :
          null;

      // 2. If not available, use salespersonref from variables
      let salespersonref =
        referrallevel !== null && !isNaN(referrallevel) ?
          referrallevel :
          typeof Instanda?.Variables?.SalespersonReferralLevel !==
            "undefined" &&
            !isNaN(Number(Instanda.Variables.SalespersonReferralLevel)) ?
            Number(Instanda.Variables.SalespersonReferralLevel) :
            Number(Instanda?.Variables?.PCSReferralLevel) || 0;

      // Your role classes
      const roleClasses = {
        0: "logged-in-external",
        1: "logged-in-internal",
        2: "logged-in-broker",
        3: "logged-in-broker",
        4: "logged-in-ops",
        5: "logged-in-opsmanager",
        6: "logged-in-uwtech",
        7: "logged-in-uw",
        8: "logged-in-senioruw",
        9: "logged-in-uwmanager",
        10: "logged-in-superuser",
      };

      // Remove previously added role classes
      $("body").removeClass(Object.values(roleClasses).join(" "));

      // Assign class based on found referral/salespersonref
      const roleClass = roleClasses[salespersonref] || "logged-in-external";
      if (roleClass) {
        $("body").addClass(roleClass);
      }
    }

    // Call on initial page load
    applyRoleClass();
  });

