  //Auto
  function hideUploadedDocs() {
    const params = new URLSearchParams(window.location.search);
    const quoteRef = params.get("quoteRef");
    const allDownloadDocLinks = document.querySelectorAll(
      'a[href*="/DownloadDocument"]'
    );

    function getUploadedDocs(quoteRef, transaction) {
      const prevTransDownloadDocLinks = Array.from(allDownloadDocLinks);
      if (transaction != "current") {
        return prevTransDownloadDocLinks.filter((link) => {
          return !link.href.includes(`quoteRef=${quoteRef}`);
        });
      }
      return prevTransDownloadDocLinks.filter((link) => {
        return link.href.includes(`quoteRef=${quoteRef}`);
      });
    }

    //Initializing hash-map
    const hashMap = new Map();

    //Putting all previous trans docs and storing in hash-map with 0 value
    getUploadedDocs(quoteRef, "old").forEach((links) => {
      if (!hashMap.has(links.innerText)) {
        hashMap.set(links.innerText, 1);
      } else {
        hashMap.set(links.innerText, hashMap.get(links.innerText) + 1);
      }
    });

    var currentTrans = getUploadedDocs(quoteRef, "current");

    console.log(currentTrans);

    for (let i = currentTrans.length - 1; i >= 0; i--) {
      if (
        hashMap.has(currentTrans[i].innerText) &&
        hashMap.get(currentTrans[i].innerText) > 0
      ) {
        console.log(`${currentTrans[i].innerText} should be hidden.`);
        currentTrans[i].parentElement.style.display = "none";
        hashMap.set(
          currentTrans[i].innerText,
          hashMap.get(currentTrans[i].innerText) - 1
        );
      }
    }
  }

