  // To make fields always editable with class alwayseditable

  function restoreAlwaysEditable() {
    const productcode = Instanda.Variables.ProductCode_CHOICE;

    if (productcode === "Admitted") {
      $(".alwayseditable").each(function () {
        this.style.setProperty("pointer-events", "auto", "important");
        this.style.setProperty("background-color", "", "important");
        this.style.setProperty("opacity", "1", "important");
        this.style.setProperty("cursor", "", "important");

        $(this)
          .find('input[type="radio"],input[type="text"]')
          .each(function () {
            this.style.setProperty("pointer-events", "auto", "important");
            this.style.setProperty("opacity", "1", "important");
            $(this).prop("readonly", false);
            if (this.type === "radio") {
              $(this).prop("disabled", false);
            }
            $(this).removeAttr("tabindex");
          });

        $(this)
          .find("label.radio-inline")
          .each(function () {
            this.style.setProperty("pointer-events", "auto", "important");
            this.style.setProperty("color", "", "important");
            this.style.setProperty("cursor", "pointer", "important");
          });

        $(this)
          .find("label.instanda-unselected,label.instanda-selected")
          .removeClass("instanda-unselected instanda-selected");
      });
    } else if (productcode === "Non-Admitted") {
      $("#SupressPrint_YNYes").prop("checked", true).trigger("click");
      $("#SubSuppressPrint_YNYes").prop("checked", true).trigger("click");
      $("#CancelWaiveDocs_YNYes").prop("checked", true).trigger("click");

      $(".alwayseditable").each(function () {
        this.style.setProperty("pointer-events", "none", "important");
        this.style.setProperty("background-color", "#f0f0f0", "important");
        this.style.setProperty("opacity", "0.6", "important");
        this.style.setProperty("cursor", "not-allowed", "important");

        // Only set readonly (not disabled)
        $(this)
          .find('input[type="radio"],input[type="text"]')
          .each(function () {
            this.style.setProperty("pointer-events", "none", "important");
            this.style.setProperty("opacity", "0.6", "important");
            $(this).prop("readonly", true); // Only readonly, not disabled
            if (this.type === "radio") {
              $(this).prop("disabled", false); // Ensure radios are NOT disabled
            }
            $(this).attr("tabindex", -1);
          });

        $(this)
          .find("label.radio-inline")
          .each(function () {
            this.style.setProperty("pointer-events", "none", "important");
            this.style.setProperty("color", "#aaa", "important");
            this.style.setProperty("cursor", "not-allowed", "important");
          });

        $(this)
          .find("label.instanda-unselected,label.instanda-selected")
          .removeClass("instanda-unselected instanda-selected");
      });
    }
  }

  function conversionAlwaysEditable() {
    const ConvPolicy =
      Instanda.Variables.ConvertedPolicy_YN ||
      Instanda.Variables.ConvertedPolicy_YNP;

    if (ConvPolicy === "Yes") {
      $(".conversionEditable, .conversion-editable").each(function () {
        this.style.setProperty("pointer-events", "auto", "important");
        //    this.style.setProperty("background-color", "white", "important");
        this.style.setProperty("opacity", "1", "important");
        this.style.setProperty("cursor", "auto", "important");

        // Remove "disabled" and related classes from the main element
        $(this).removeClass("disabled readonly");

        $(this)
          .find('input[type="radio"], input[type="text"]')
          .each(function () {
            this.style.setProperty("pointer-events", "auto", "important");
            this.style.setProperty("opacity", "1", "important");
            //   this.style.setProperty("background-color", "white", "important");
            this.style.setProperty("cursor", "auto", "important");
            $(this).prop("readonly", false);
            $(this).prop("disabled", false);
            $(this).removeAttr("tabindex");
            $(this).removeClass("disabled readonly");

            // Remove inherited or framework-added classes
            this.classList.remove("disabled", "readonly");
          });

        $(this)
          .find("label.radio-inline")
          .each(function () {
            this.style.setProperty("pointer-events", "auto", "important");
            this.style.setProperty("color", "", "important");
            this.style.setProperty("cursor", "pointer", "important");
            this.classList.remove("disabled", "readonly");
          });
      });
    }
  }

