  // // Forbidding brokers from performing OOS transactions

  async function startMTA(
    changeEffectiveDate = Instanda.Variables.EffectiveChangeDate
  ) {
    const link = window.location.href;
    const quote = new URLSearchParams(link.split("?")[1]).get("quoteRef");
    changeEffectiveDate = changeEffectiveDate.replaceAll("/", "%2F");
    const apiEndpointMTA = `https://${link.split("?")[0].split("/")[2]
      }/Public/InitializeMTALatestConfig`;
    const params = `quoteRef=${quote}&EffectiveChangeDate=${changeEffectiveDate}`;
    fetch(apiEndpointMTA, {
      method: "POST",
      headers: {
        Accept: "application/json, text/javascript, */*; q=0.01",
        "Accept-Language": "en-US,en;q=0.9",
        "Cache-Control": "no-cache",
        Connection: "keep-alive",
        "Content-Type": "application/x-www-form-urlencoded; charset=UTF-8",
        Origin: `https://${link.split("?")[0].split("/")[2]}`,
        Pragma: "no-cache",
        Referer: link,
        "X-Requested-With": "XMLHttpRequest",
        // Cookies must be sent automatically (see note below)
      },
      body: params,
      credentials: "include", // Send cookies with the request
    })
      .then((response) => response.json())
      .then((data) =>
        window.open(
          `https://${link.split("?")[0].split("/")[2]}${data.redirectUrl}`,
          "_self"
        )
      )
      .catch((error) => console.error("Error:", error));
  }

  async function continueOOS() {
    var referrallevel = parseInt(
      document
        .getElementById("LoggedInUserReferralLevel")
        ?.textContent.trim() || "0",
      10
    );
    if (
      $(".page-viewquoteorpolicy").length > 0 &&
      $(".sale-stage-salecomplete").length > 0
    ) {
      const changeEffectiveDate = document.querySelector(
        "#Effective-Change-Date"
      );
      if (changeEffectiveDate.value != "") {
        if (
          Date.parse(changeEffectiveDate.value) <
          Date.parse(Instanda.Variables.EffectiveDate_DATE.split(" ")[0]) ||
          Date.parse(changeEffectiveDate.value) >
          Date.parse(Instanda.Variables.ExpirationDate_DATE.split(" ")[0])
        ) {
          alert(
            `The effective change date must fall on or after the policy start date and on or before policy expiration date.`
          );
        } else {
          if (
            Date.parse(changeEffectiveDate.value) <
            Date.parse(Instanda.Variables.EffectiveChangeDate.split(" ")[0])
          ) {
            if (referrallevel < 4)
              alert(
                "This is ‘Out of Sequence’ change, please contact endorsements@privateclientselect.com for processing of the transaction."
              );
            else if (
              confirm(
                "This is ‘Out of Sequence’ change, would you like to continue?"
              )
            )
              await startMTA(changeEffectiveDate.value);
          } else {
            await startMTA(changeEffectiveDate.value);
          }
        }
      }
    }
  }

