  function waitForAnchorWithText(text = "View", callback) {
    // Check if anchor is already present
    const match = Array.from(document.querySelectorAll("a")).find(
      (a) => a.textContent.trim() === text
    );
    if (match) {
      callback(match);
      return;
    }

    // Set up observer for future additions
    const observer = new MutationObserver(() => {
      const match = Array.from(document.querySelectorAll("a")).find(
        (a) => a.textContent.trim() === text
      );
      if (match) {
        observer.disconnect();
        callback(match);
      }
    });

    observer.observe(document.body, {
      childList: true,
      subtree: true,
    });
  }

