  //Auto Update button quick quote//

  function maybeAutoContinue() {
    if (sessionStorage.getItem("autoContinueAfterUpdate") === "true") {
      let elapsed = 0;
      const interval = setInterval(() => {
        $(".spinner").hide();
        // Fastest: look for id first
        let continueBtn =
          document.getElementById("continueButton") ||
          document.querySelector('button[name="continueButton"]');
        if (continueBtn) {
          // *** Make visible before clicking! ***
          //continueBtn.style.display = "";
          continueBtn.disabled = false;

          // Simulate real user event (robust for more UIs)
          continueBtn.dispatchEvent(
            new MouseEvent("mouseover", {
              bubbles: true,
            })
          );
          continueBtn.dispatchEvent(
            new MouseEvent("mousedown", {
              bubbles: true,
            })
          );
          continueBtn.dispatchEvent(
            new MouseEvent("mouseup", {
              bubbles: true,
            })
          );
          continueBtn.dispatchEvent(
            new MouseEvent("click", {
              bubbles: true,
            })
          );

          clearInterval(interval);
          sessionStorage.removeItem("autoContinueAfterUpdate");
          console.log("Auto-clicked Continue button!");
        } else if ((elapsed += 500) > 10000) {
          clearInterval(interval);
          sessionStorage.removeItem("autoContinueAfterUpdate");
          console.warn(
            "Continue button not found for auto-click. Check selector and page HTML."
          );
        }
      }, 500);
    }
  }

  $(document).ready(function () {
    if ($(".page-quickquote.package-24338").length > 0) {
      // Hide the continue button on load
      const continueBtn =
        document.getElementById("continueButton") ||
        document.querySelector('button[name="continueButton"]');
      if (continueBtn) {
        continueBtn.style.display = "none";
        console.log("Continue button hidden on page load.");
      }

      const updBtn = document.querySelector('button[name="updateButton"]');

      // Create 'Premiums' button if not present, insert before update button
      if (updBtn && !document.getElementById("premiumsButton")) {
        // Clone the visual style from the existing continue button if present
        let btnClasses =
          "instanda-button instanda-quote-continue-button btn btn-primary";
        let btnHTML = "Premiums";

        if (continueBtn) {
          btnClasses = continueBtn.getAttribute("class") || btnClasses;
          // Optional: replicate button inner HTML for consistency (icon, etc.)
        }

        const premiumsBtn = document.createElement("button");
        premiumsBtn.type = "button";
        premiumsBtn.style.display = "none"; // default hidden, like continue button
        premiumsBtn.id = "Premium";
        premiumsBtn.name = "Premium";
        premiumsBtn.className = btnClasses;
        premiumsBtn.innerHTML = 'Premiums <i class="fa fa-caret-right"></i>';

        // Insert before "update" button
        updBtn.parentNode.insertBefore(premiumsBtn, updBtn);
        console.log(
          "'Premiums' button created and inserted before update button."
        );
      }

      if (updBtn) {
        updBtn.textContent = "Continue";
        // Prevent duplicate attachments
        if (!updBtn.dataset.HandlerAttached) {
          updBtn.dataset.HandlerAttached = "true";
          let isProcessing = false;

          updBtn.addEventListener("click", async function (e) {
            if (isProcessing) {
              e.preventDefault();
              return;
            }
            isProcessing = true;
            e.preventDefault();

            // Spinner/UI logic
            if ($(".spinner").length > 0) {
              if (typeof showSpinner === "function") showSpinner();
              $(".spinner").hide();
            } else {
              if (typeof hideSpinner === "function") hideSpinner();
            }

            // Read-only shortcut: skip premium integration
            if (isReadOnlyView()) {
              const continueBtn =
                document.getElementById("continueButton") ||
                document.querySelector('button[name="continueButton"]');
              if (continueBtn) {
                continueBtn.click();
                console.log("Continue button auto-clicked (readonly mode).");
              } else {
                console.warn(
                  "Continue button not found for auto-clicking (readonly)."
                );
              }
              isProcessing = false;
              return; // Exit early so premium integration is not called!
            }

            // Not read-only: run premium integration as usual
            let integcallsapi;
            try {
              integcallsapi = await coherentpremiumevents(e);
              if (!integcallsapi)
                throw new Error("Premium event integration failed");
            } catch (error) {
              console.error("Premium event error:", error);
              isProcessing = false;
              // Do NOT auto-click continue button if premium call fails
              return;
            }

            // Only after success: set flag and click continue
            sessionStorage.setItem("autoContinueAfterUpdate", "true");
            const continueBtn =
              document.getElementById("continueButton") ||
              document.querySelector('button[name="continueButton"]');
            if (continueBtn) {
              continueBtn.click();
              console.log("Continue button auto-clicked.");
            } else {
              console.warn("Continue button not found for auto-clicking.");
            }

            isProcessing = false;
          });
        }
      }
    }
  });

  async function clickAndWaitForUpdate() {
    const updBtn = document.querySelector('button[name="updateButton"]');
    if (!updBtn) return;
    // Spinner logic
    if ($(".spinner").length > 0) {
      if (typeof showSpinner === "function") showSpinner();
      $(".spinner").hide();
    } else {
      if (typeof hideSpinner === "function") hideSpinner();
    }
    updBtn.textContent = "Continue";
    sessionStorage.setItem("autoContinueAfterUpdate", "true");
    updBtn.click();
    if (isReadOnlyView()) {
      const continueBtn =
        document.getElementById("continueButton") ||
        document.querySelector('button[name="continueButton"]');
      if (continueBtn) {
        continueBtn.click();
        console.log("Continue button auto-clicked.");
      } else {
        console.warn("Continue button not found for auto-clicking.");
      }
    }
    // Trigger the premiums process
    document.getElementById("Premium").click();
  }

