  /*
   * BH-20956
   * As part of this we're caching the requests related to reports in IndexedDB
   * And also in Instanda and preventing Duplicate Api Calls
   */
  //Home
  class ManageApiCache {
    static dbName = "ApiReportsCacheDB";
    static storeName = "ApiReportsCacheStore";
    static inputName = "ReportsApiCacheJSON_TXT";
    static reqInQueue = 0;
    static currentValue = {};

    static getLocalKey() {
      return `${Instanda.Variables.QuoteRef}`;
    }
    /**
     * Opens the IndexedDB database and returns a promise resolving with the IDBDatabase instance.
     * @returns {Promise<IDBDatabase>}
     *
     */
    static openDb() {
      return new Promise((resolve, reject) => {
        const request = indexedDB.open(this.dbName, 1);
        request.onupgradeneeded = (event) => {
          const db = event.target.result;
          if (!db.objectStoreNames.contains(this.storeName)) {
            db.createObjectStore(this.storeName, {
              keyPath: "key",
            });
          }
        };
        request.onsuccess = (event) => resolve(event.target.result);
        request.onerror = (event) => reject(event.target.error);
      });
    }

    // Get from IndexedDB
    static async getCache() {
      const db = await this.openDb();
      let dbValue = await new Promise((resolve, reject) => {
        const tx = db.transaction(this.storeName, "readonly");
        const store = tx.objectStore(this.storeName);
        const req = store.get(this.getLocalKey());
        req.onsuccess = (event) => {
          const cacheObj = event.target.result ? event.target.result.value : "";
          resolve(cacheObj);
        };
        req.onerror = (event) => reject(event.target.error);
      });

      const inputEl = document.getElementById(this.inputName);
      let inputValue = "";
      if (inputEl) {
        inputValue = inputEl.value;
      } else {
        inputValue = Instanda.Variables.ReportsApiCacheJSON_TXT;
      }
      const currentTimestamp = new Date().getTime();

      let dbTimestamp = currentTimestamp;
      let localTimestamp = currentTimestamp;
      if (!dbValue && !inputValue) return {};
      if (!dbValue && inputValue) return JSON.parse(inputValue);
      if (dbValue && !inputValue) return dbValue;
      try {
        dbValue = dbValue;
        dbTimestamp = dbValue["timestamp"];
        inputValue = JSON.parse(inputValue);
        localTimestamp = inputValue["timestamp"];
      } catch (error) {
        console.log("Invalid timestamps", error);
      }

      if (dbTimestamp == localTimestamp) {
        return dbValue;
      } else if (dbTimestamp >= localTimestamp) return dbValue;
      return inputValue;
    }

    // Set to IndexedDB
    static async setCache(endpoint, payload, response = null) {
      const output = {
        payload: payload,
        response: response,
      };
      if (this.reqInQueue > 0) {
        this.currentValue[endpoint] = output;
        return;
      } else {
        this.currentValue[endpoint] = output;
      }
      let currentCache = this.currentValue;
      currentCache["timestamp"] = new Date().getTime();

      const db = await this.openDb();
      return new Promise((resolve, reject) => {
        const tx = db.transaction(this.storeName, "readwrite");
        const store = tx.objectStore(this.storeName);
        store.put({
          key: this.getLocalKey(),
          value: currentCache,
        });
        tx.oncomplete = () => resolve();
        tx.onerror = (event) => reject(event.target.error);
      });
    }

    // Remove stale caches (older than 4 hours)
    static async removeStaleApiReportsCaches() {
      const TWELVE_HOURS_MS = 4 * 60 * 60 * 1000;
      const now = Date.now();
      const db = await this.openDb();

      return new Promise((resolve, reject) => {
        const tx = db.transaction(this.storeName, "readwrite");
        const store = tx.objectStore(this.storeName);
        const req = store.openCursor();
        req.onsuccess = function (event) {
          const cursor = event.target.result;

          if (cursor) {
            const cacheObj = cursor.value.value;
            const timestamp = cacheObj.timestamp;
            if (!timestamp || now - timestamp > TWELVE_HOURS_MS) {
              cursor.delete();
            }
            cursor.continue();
          } else {
            resolve();
          }
        };
        req.onerror = (event) => reject(event.target.error);
      });
    }

    // shouldCall logic
    static async shouldCall(endPoint, payload) {
      const cache = await this.getCache();
      if (
        !cache ||
        !cache[endPoint] ||
        cache[endPoint]?.payload != payload ||
        !cache[endPoint].response
      )
        return {
          status: true,
          res: null,
        };
      return {
        status: false,
        res: cache[endPoint].response,
      };
    }

    // Cached fetch logic with IndexedDB
    static async cachedFetch(input, options = {}) {
      let endpoint;
      let payload;
      if (typeof input === "string") {
        endpoint = input;
        payload = options.body || null;
      } else if (input instanceof Request) {
        endpoint = input.url;
        payload = input.body || null;
      } else {
        throw new Error("Invalid input for fetch: must be string or Request");
      }

      const shouldCallRes = await this.shouldCall(endpoint, payload);
      if (!shouldCallRes.status && shouldCallRes.res) {
        return Promise.resolve(
          new Response(shouldCallRes.res.text, {
            status: shouldCallRes.res.status || 200,
            statusText: shouldCallRes.res.statusText || "OK",
            headers: new Headers(),
            type: shouldCallRes.res.type,
          })
        );
      }

      if (this.reqInQueue == 0) {
        let currentCache = await this.getCache();
        if (!currentCache) {
          currentCache = {
            timestamp: new Date().getTime(),
          };
        } else {
          currentCache["timestamp"] = new Date().getTime();
        }
        this.currentValue = currentCache;
      }

      this.reqInQueue += 1;

      let output = {};

      return fetch(input, options)
        .then(async (response) => {
          output = {
            status: response.status,
            statusText: response.statusText,
            ok: response.ok,
            type: response.type,
            headers: {},
            text: await response.clone().text(),
          };
          return response;
        })
        .finally(() => {
          this.reqInQueue -= 1;
          if (output.ok) {
            this.setCache(endpoint, payload, output);
          }
        });
    }
  }
