  //Auto
  function setFaultCodeBasedOnAccidentDesc() {
    console.log("called setFaultCodeBasedOnAccidentDesc");

    const UNKNOWN_FAULT_VALUE = "Unknown/Un-determined";
    const accidentPrefix = "instanda-multi-item-Claim_MI";

    function selectElementValueFromOptions($select, valueToSelect) {
      const selectEl = $select && $select[0];
      if (!selectEl) return;

      const opt = Array.from(selectEl.options).find(
        (o) => o.value === valueToSelect
      );
      if (!opt) return;

      selectEl.value = opt.value;
      $select.trigger("change");
    }

    function inferSuffixFromAccidentValue(accidentDropdownValue) {
      const v = (accidentDropdownValue || "").toUpperCase().trim();

      if (v === "" || v.includes("UNKNOWN") || v.includes("UNDETERMIN"))
        return null;

      // 1) Prefer explicit suffix codes if present anywhere (use LAST one if multiple)
      // Examples matched: ".... - COMP", "AF", "LOSS (NAF)", "TEXT / AF / MORE"
      const codeMatches = Array.from(v.matchAll(/\b(NAF|AF|COMP)\b/g));
      if (codeMatches.length) return codeMatches[codeMatches.length - 1][1];

      // 2) Fall back to text inference
      // Allow hyphens/spaces/other separators so NOT-AT-FAULT doesn't fall through to AT-FAULT
      if (/NOT\W*AT\W*FAULT/.test(v)) return "NAF";
      if (/AT\W*FAULT/.test(v)) return "AF";
      if (/\bCOMPREHENSIVE\b/.test(v)) return "COMP";

      // Default per request
      return "NAF";
    }

    function setLockState($el, locked) {
      $el.css(
        locked ? {
          "pointer-events": "none",
          cursor: "not-allowed",
          "background-color": "#eee",
          color: "#888",
        } : {
          "pointer-events": "auto",
          cursor: "pointer",
          "background-color": "",
          color: "",
        }
      );
    }

    function updateOne(parent) {
      const miNumber = extractMINumber(parent, accidentPrefix);
      if (!miNumber) return;

      const accidentValueEl = document.querySelector(
        `#Claim_MI${miNumber}_AccidentValues_TXT`
      );
      const $faultIndicator = $(
        `#Claim_MI${miNumber}_C_FaultIndicator_Auto_TXT`
      );
      const $source = $(`#Claim_MI${miNumber}_Claim_Source_CHOICEP`);

      if (!accidentValueEl || !$faultIndicator[0] || !$source[0]) return;

      if ($source.val() !== "Manual") {
        setLockState($faultIndicator, false);
        return;
      }

      const accidentDropdownValue = accidentValueEl.value || "";
      const suffix = inferSuffixFromAccidentValue(accidentDropdownValue);

      let faultDesc;
      if (suffix === "AF") {
        faultDesc = "At-Fault";
      } else if (suffix === "NAF") {
        faultDesc = "Not At-Fault";
      } else if (suffix === "COMP") {
        faultDesc = "Comprehensive";
      } else {
        faultDesc = UNKNOWN_FAULT_VALUE;
      }

      selectElementValueFromOptions($faultIndicator, faultDesc);
      setLockState($faultIndicator, !!suffix);
    }

    // Initial pass
    document
      .querySelectorAll(`[class*='${accidentPrefix}']`)
      .forEach((parent) => updateOne(parent));

    // Update on change (accident value OR source), including dynamically added MI rows
    $(document)
      .off(
        "change.setFault",
        `[id$="_AccidentValues_TXT"], [id$="_Claim_Source_CHOICEP"]`
      )
      .on(
        "change.setFault",
        `[id$="_AccidentValues_TXT"], [id$="_Claim_Source_CHOICEP"]`,
        function () {
          const parent = this.closest(`[class*='${accidentPrefix}']`);
          if (parent) updateOne(parent);
        }
      );
  }

