      function setDriverNameAutoInfraction() {
        const InfractionsPrefixValue = "instanda-multi-item-Infraction_MI";

        // Only run this code when such containers exist on the page
        const InfractionsContMI = document.querySelectorAll(
          "[class*='instanda-multi-item-Infraction_MI']"
        );

        if (InfractionsContMI.length > 0) {
          InfractionsContMI.forEach((parent) => {
            const miNumber = extractMINumber(parent, InfractionsPrefixValue);
            if (!miNumber) return;

            // Find the DriverFullName_TXT field within this container
            const driverField = parent.querySelector(
              `#Infraction_MI${miNumber}_Infraction_Driver_TXT`
            );
            if (!driverField) return;

            driverField.addEventListener("blur", function () {
              const selectedDriver = this.value.trim();

              // Remove prefix number + dot if present
              let cleanedDriver = selectedDriver.replace(/^\d+\.\s*/, "");

              // Split by spaces
              const parts = cleanedDriver.split(" ").filter(Boolean);

              // If name has middle part: ["ALLEN", "S", "BAKER", ...]
              // Get first and last from appropriate positions
              let firstName = "";
              let lastName = "";
              if (parts.length >= 3) {
                firstName = parts[0]; // "ALLEN"
                lastName = parts[parts.length > 4 ? 2 : 1]; // "BAKER" (with or without middle name)
              }

              // Concatenate: "ALLEN BAKER"
              const fullName = firstName + " " + lastName;

              // Set the Driver Name fields for this record
              $(`#Infraction_MI${miNumber}_Inf_DriverFLName_TXT`)
                .val(fullName)
                .trigger("change");
            });
          });
        }
      }

