  //Common
  function getEnvFromUrl(url) {
    if (url.includes("azuse2devapim01")) return "dev";
    if (url.includes("azapimqa")) return "QA";
    if (url.includes("azapimprod")) return "prod";
    return null;
  }
  //Common
  function getSubscriptionKey(env) {
    const keys = {
      dev: "b0244fffcfe54b21a847b4c47c3288f8",
      QA: "a681be3e3f2445be965346bd5baa71fc",
      prod: "2d6438fcc4964c8c84941246033498f1",
    };
    return keys[env];
  }
  //Common
  function attachReportPaneDownloadHandlers() {
    document.querySelectorAll(".report-pane a").forEach((link) => {
      link.addEventListener("click", async function (event) {
        event.preventDefault();

        const href = link.getAttribute("href");
        const env = getEnvFromUrl(href);
        const subscriptionKey = getSubscriptionKey(env);

        if (!env || !subscriptionKey) {
          alert("Unknown environment or missing subscription key.");
          return;
        }

        // Extract base URL and file ID from href
        const urlObj = new URL(href);
        const apiBaseUrl = `${urlObj.origin}${urlObj.pathname}`;
        const fileId = urlObj.searchParams.get("id");
        const fullUrl = `${apiBaseUrl}?id=${fileId}`;

        // Prepare headers
        const headers = {
          "pcsctx-appName": "Instanda",
          "pcsctx-traceId": crypto.randomUUID(),
          "pcsctx-sessionId": crypto.randomUUID(),
          "pcsctx-productType": "HO",
          "Content-Type": "application/json",
          "Ocp-Apim-Subscription-Key": subscriptionKey,
        };

        try {
          const response = await fetch(fullUrl, {
            method: "GET",
            headers: headers,
          });

          if (!response.ok) {
            throw new Error(`Download failed: ${response.status}`);
          }

          const blob = await response.blob();
          const downloadUrl = window.URL.createObjectURL(blob);

          // Use the original link's text or a default filename
          // const filename = link.textContent.trim() || "document.pdf";

          // Trigger download
          // const a = document.createElement("a");
          // a.href = downloadUrl;
          // a.download = filename;
          // document.body.appendChild(a);
          // a.click();
          // a.remove();

          // Commented above lines, because it was not working..

          // Adding below line to open the file in new tab..
          window.open(downloadUrl, "_blank");
          setTimeout(() => URL.revokeObjectURL(downloadUrl), 10000);
        } catch (error) {
          console.error("Error downloading document:", error);
          alert(error.message);
        }
      });
    });
  }

  //////////////////////Report Pane EL and Auto//////////////////////
  //Common
  if (
    Instanda.Variables["PackageId"] == 24338 ||
    Instanda.Variables["PackageId"] == 24428
  ) {
    const reportResults = [];
    // If PackageId is 24428, add HOME_CLUE report first
    if (Instanda.Variables["PackageId"] == 24428) {
      const homeClueUrl = Instanda.Variables.HCLUERepURL_TXT_1 ?
        Instanda.Variables.HCLUERepURL_TXT_1.trim() :
        "";
      if (homeClueUrl) {
        reportResults.push(["CLUE", "HOME_CLUE", homeClueUrl]);
      }
    }

    // Prepare arrays of URLs from Instanda.Variables
    const mvrUrls = [];
    const clueUrls = [];
    for (let i = 1; i <= 36; i++) {
      mvrUrls.push(
        Instanda.Variables[`MVRRepURL_TXT_${i}`] ?
          Instanda.Variables[`MVRRepURL_TXT_${i}`].trim() :
          ""
      );
      clueUrls.push(
        Instanda.Variables[`CLUERepURL_TXT_${i}`] ?
          Instanda.Variables[`CLUERepURL_TXT_${i}`].trim() :
          ""
      );
    }

    // Get driver names from StoreDrivers_TXT (newline-separated)
    let driversRaw =
      typeof Instanda !== "undefined" &&
        Instanda.Variables &&
        Instanda.Variables.StoreDrivers_TXT ?
        Instanda.Variables.StoreDrivers_TXT :
        $("#StoreDrivers_TXT").val() || "";

    let driverNames = driversRaw
      .split(/\r?\n/)
      .map((name) => name.trim())
      .filter((name) => name.length > 0);

    console.log(driverNames);

    // Build reportResults using driverNames
    driverNames.forEach((fullName, idx) => {
      const mvrUrl = mvrUrls[idx] || "";
      const clueUrl = clueUrls[idx] || "";

      // Replace spaces with underscores in driver name
      const nameWithUnderscores = fullName.replace(/\s+/g, "_");

      if (fullName && clueUrl) {
        reportResults.push(["CLUE", `${nameWithUnderscores}_CLUE`, clueUrl]);
      }
      if (fullName && mvrUrl) {
        reportResults.push(["MVR", `${nameWithUnderscores}_MVR`, mvrUrl]);
      }
    });

    // Group/order: CLUE first, then MVR
    reportResults.sort((a, b) => {
      if (a[0] === b[0]) return 0;
      return a[0] === "CLUE" ? -1 : 1;
    });

    console.log(reportResults);

    if (
      reportResults.length > 0 &&
      Instanda.Variables.PageNumber === 3 &&
      Instanda.Variables.PageName === "quickquotequestions"
    ) {
      $(".parent-section").append(`
        <div class="warningMessage alert container" id="custom-success-response">
            <img src="/ImageUpload/DownloadImageVersion?uploadedImageVersionId=YWtWd04zSkVRM05OYVhsb2IyaFVOM29zZVRKd1VWOWYsQUVTMjU2X0NCQ19TVEFOREFSRCxKYlJjUW1lQWVEa2lqUHdyLDEwMDAsQTczaGxudnh0YUU4OU9LOSxENWErYmpqSjh4V2tXaHBYNFMzTVUxOFFRS3FkU0s2QzArdTd3eEx1MG9mQjdWTm4zOGxrNkRzRkdVNzdRUENVOHkzeitUd1NVNXZaSjZBRWNYdFhlUT09" />
            <span>Reports are generated successfully and are available in Report Pane section!</span>
            <button type="button" class="close" data-dismiss="alert" aria-label="Close">
                <span aria-hidden="true">×</span>
            </button>
        </div>
    `);
    }

    // const limitedResults = reportResults.slice(0, 10);
    // Build HTML
    let html = "<ul>";
    reportResults.forEach((entry) => {
      html += `<li><a href="${entry[2]}" target="_blank">${entry[1]}</a></li>`;
    });
    html += "</ul>";

    // Display in .report-pane
    $(".report-pane").html(html);

    attachReportPaneDownloadHandlers();
  }
  //Common
  function addLinkToReportPane() {
    // Guard: Only run if there's at least one report and the link doesn't exist already
    const reportPane = document.querySelector(".report-pane");
    if (
      document.querySelector("#view-all-reports") ||
      !reportPane ||
      reportPane.querySelectorAll("ul li").length === 0
    )
      return;

    // Robust recordId getter with safe fallback
    const quoteIdInput = document.querySelector(
      'input[name="QuoteRecordID_TXT"]'
    );
    const recordId = quoteIdInput ?
      quoteIdInput.value :
      Instanda.Variables && Instanda.Variables.QuoteRecordID_TXT;

    // Environment Detection
    const currentUrl = window.location.href;
    let env = null;
    if (currentUrl.includes("https://design.instanda.us")) env = "dev";
    else if (
      currentUrl.includes("https://private-client-select-agent-uat.instanda.us")
    )
      env = "uat1";
    else if (
      currentUrl.includes(
        "https://private-client-select-agent-uat2.instanda.us"
      )
    )
      env = "uat2";
    else if (
      currentUrl.includes("https://private-client-select-agent.instanda.us") ||
      currentUrl.includes("https://pcsuw.com")
    )
      env = "prod";

    // All possible Internal and Broker URLs by env, fallback to base if no recordId
    const INTERNAL_USER_URLS = {
      dev: recordId ?
        `https://pcsmga--devph2.sandbox.lightning.force.com/lightning/r/Insurance_Quote__c/${recordId}/view` : "https://pcsmga--devph2.sandbox.lightning.force.com",
      uat2: recordId ?
        `https://pcsmgu--qapcs.sandbox.lightning.force.com/lightning/r/Insurance_Quote__c/${recordId}/view` : "https://pcsmgu--qapcs.sandbox.lightning.force.com",
      uat1: recordId ?
        `https://pcsmgu--uat.sandbox.lightning.force.com/lightning/r/Insurance_Quote__c/${recordId}/view` : "https://pcsmgu--uat.sandbox.lightning.force.com",
      prod: recordId ?
        `https://pcsmgu.lightning.force.com/lightning/r/Insurance_Quote__c/${recordId}/view` : "https://pcsmgu.lightning.force.com",
    };
    const BROKER_URLS = {
      dev: recordId ?
        `https://pcsmgu--qapcs.sandbox.my.site.com/brokerportalapp/insurance-quote/${recordId}` : "https://pcsmgu--qapcs.sandbox.my.site.com/brokerportalapp/",
      uat2: recordId ?
        `https://pcsmgu--qapcs.sandbox.my.site.com/brokerportalapp/insurance-quote/${recordId}` : "https://pcsmgu--qapcs.sandbox.my.site.com/brokerportalapp/",
      uat1: recordId ?
        `https://pcsmgu--uat.sandbox.my.site.com/brokerportalapp/insurance-quote/${recordId}` : "https://pcsmgu--uat.sandbox.my.site.com/brokerportalapp/",
      prod: recordId ?
        `https://broker.pcsuw.com/insurance-quote/${recordId}` : "https://broker.pcsuw.com/",
    };

    // Determine user type for URL selection (broker/external/internal)
    let url;
    if (
      document.querySelector(".logged-in-broker") ||
      document.querySelector(".logged-in-internal") ||
      document.querySelector(".logged-in-external")
    ) {
      url = env ? BROKER_URLS[env] : BROKER_URLS["prod"];
    } else {
      url = env ? INTERNAL_USER_URLS[env] : INTERNAL_USER_URLS["prod"];
    }

    // Calculate reports count
    const reportsCount = reportPane.querySelectorAll("a").length;
    const anchorTag = document.createElement("a");
    anchorTag.setAttribute("href", url);
    anchorTag.setAttribute("id", "view-all-reports");
    anchorTag.setAttribute("target", "_blank");
    anchorTag.textContent =
      reportsCount === 1 ? "View 1 report" : `View All ${reportsCount} Reports`;

    reportPane.prepend(anchorTag);
  }

