  //Common
  if (Instanda.Variables["PackageId"] == 24337) {
    function getVar(name) {
      if (Instanda.Variables[name]) return Instanda.Variables[name];
      const domVal = $(`#${name}`).val();
      return domVal ? domVal : "";
    }

    // Each entry: [Short Form, Report URL Variable Name]
    const varPairs = [
      ["WSRB PPC (WA)", "ReportUrlWSRB_TXT"],
      ["RedZone Wildfire", "ReportUrlRedzone_TXT"],
      ["LN Prefill", "ReportUrlLNPrefill_TXT"],
      ["ISO PPC", "ReportUrlISOPPC_TXT"],
      ["ISO BCEGS", "ReportUrlISOBCEGS_TXT"],
      ["ISO Wind", "ReportUrlISOWD_TXT"],
      ["LC360 UW", "ReportUnderwritingReportUrl_TXT"],
      ["LC360 Client", "ReportRMSClientReportUrl_TXT"],
      ["HOME CLUE", "HCLUERepURL_TXT_1"],
    ];

    function generateReportHtml() {
      // Build displayResults: [Short Form, URL]
      const displayResults = varPairs
        .map(([shortName, urlVar]) => {
          const url = getVar(urlVar);
          return url ? [shortName, url] : null;
        })
        .filter(Boolean);

      // Build HTML as a <ul>
      let html = "<ul>";
      displayResults.forEach((entry) => {
        html += `<li><a href="${entry[1]}" target="_blank">${entry[0]}</a></li>`;
      });
      html += "</ul>";

      $(".report-pane").html(html);
    }

    generateReportHtml();
    attachReportPaneDownloadHandlers();
  }

