  /////////////////////////Original Agreed Value///////////////////////////////
  //Auto
  // =====================================================
  //  AGREED VALUE → ORIGINAL AGREED VALUE SYNC
  // Only runs on Package 24338 (your auto package)
  // =====================================================

  if ($(".page-quickquotequestions.page-number-4.package-24338").length > 0) {
    const convertedpolicy = Instanda.Variables.ConvertedPolicy_YN || Instanda.Variables.ConvertedPolicy_YNP;
    const processed = new Set();
    const syncAgreedValue = (mi) => {
      const agreedId = `#Vehicle_MI${mi}_AgreedVal_NUM`;
      const originalId = `#Vehicle_MI${mi}_OriginalAgreedVal_NUM`;
      const $agreed = $(agreedId);
      const $original = $(originalId);

      if (convertedpolicy === "Yes" || convertedpolicy == "yes") return;
      if (!$agreed.length || !$original.length) return;
      if (processed.has(mi)) return;
      processed.add(mi);

      const vars =
        window.Instanda && Instanda.Variables ? Instanda.Variables : {};
      const isNewBusiness = vars.CreatedFrom === "NewBusiness";

      const bindSync = () => {
        $agreed
          .off(".syncAgreed" + mi)
          .on("input.syncAgreed" + mi + " change.syncAgreed" + mi, function () {
            const current =
              typeof cleanVal === "function" ?
                cleanVal(this.value) :
                this.value;
            $original.val(current || "");
          });
      };

      if (isNewBusiness) {
        const initial = $agreed.val();
        if (initial !== "") $original.val(initial);
        bindSync();
      } else {
        const initial = $agreed.val();
        const orgval = $original.val();
        if (initial !== "" && orgval !== "") $original.val(initial);
        bindSync();
      }

      // Unlock THIS MI's OriginalAgreedVal if referral level condition met
      const spLevel = Number(vars.SalespersonReferralLevel || 0);
      const pcsLevel = Number(vars.PCSReferralLevel || 0);

      if (spLevel > 3 || pcsLevel > 3) {
        $original.prop("readonly", false).removeAttr("readonly");
        $original.prop("disabled", false).removeAttr("disabled"); // in case it's disabled

        // Remove readonly styling/lock from closest question wrapper (if present)
        $original.closest(".instanda-question-item").removeClass("readonly");
      }
    };

    const processAll = () => {
      document
        .querySelectorAll('[class*="instanda-multi-item-Vehicle_MI"]')
        .forEach((container) => {
          const match = container.className.match(
            /instanda-multi-item-Vehicle_MI(\d+)/
          );
          if (match) syncAgreedValue(parseInt(match[1], 10));
        });
    };

    $(document).ready(processAll);

    $(document).on("click", "#Vehicle_MIaddButton", () =>
      setTimeout(processAll, 250)
    );

    $(document).on(
      "change",
      'label:has([id$="_NewlyAddedToPolicy_YNYes"]), label:has([id$="_NewlyAddedToPolicy_YNNo"])',
      () => setTimeout(processAll, 150)
    );

    new MutationObserver((mutations) => {
      if (
        mutations.some((m) => [...m.addedNodes].some(
          (n) =>
            n.nodeType === 1 &&
            n.matches?.('[class*="instanda-multi-item-Vehicle_MI"]')
        ))
      ) {
        processed.clear();
        setTimeout(processAll, 200);
      }
    }).observe(document.body, {
      childList: true,
      subtree: true,
    });

    processAll();
  }

