  // Function for HO prefill in Earthquake
  //Integ
  async function queryODS(query) {
    if (isReadOnlyView()) {
      return Promise.resolve(Readonly);
    }

    return new Promise((resolve, reject) => {
      if (!query || typeof query !== "string") {
        reject(new Error("A valid SQL query string is required."));
        return;
      }

      const requestPayload = {
        query,
      };
      const {
        apiBaseUrl,
        subscriptionKey
      } = getApiEndpoint("phase2");
      const apiEndpoint = `${apiBaseUrl}/instanda/v1/queryODS`;
      const headers = generateHeaders(subscriptionKey);

      fetch(apiEndpoint, {
        method: "POST",
        headers: headers,
        body: JSON.stringify(requestPayload),
        redirect: "follow",
      })
        .then((response) => response.json())
        .then((data) => {
          // Accept both array and wrapped response
          if (Array.isArray(data)) {
            resolve(data);
          } else if (
            data &&
            data.targetResponse &&
            data.targetResponse.response
          ) {
            resolve(data.targetResponse.response);
          } else {
            reject(new Error("Malformed quote data response"));
          }
        })
        .catch((error) => {
          console.error("Error:", error);
          reject(error);
        });
    });
  }

