  // Get Policy Data by PolicyNumber or QuoteRef
  //Integ
  async function getPolicyData(ref) {
    return new Promise((resolve, reject) => {
      const quoteRef = typeof ref === "string" ? ref : ref.QuoteRef;
      if (!quoteRef) {
        reject(new Error("No valid quoteRef or PolicyNumber provided"));
        return;
      }

      const requestPayload = {
        method: "GET",
        query: {
          quoteRef: quoteRef,
        },
      };

      const {
        apiBaseUrl,
        subscriptionKey
      } = getApiEndpoint("phase2");
      const apiEndpoint = `${apiBaseUrl}/instanda/v1/manageQuotePolicy?resource=GetQuoteData&recordId=${quoteRef}`;

      // Use fixed headers since we have to get data from HO
      const headers = {
        "pcsctx-appName": "Instanda",
        "pcsctx-traceId": generateUUID(),
        "pcsctx-sessionId": generateUUID(),
        "pcsctx-productType": "HO",
        "Content-Type": "application/json",
        "Ocp-Apim-Subscription-Key": subscriptionKey,
      };

      fetch(apiEndpoint, {
        method: "POST",
        headers: headers,
        body: JSON.stringify(requestPayload),
        redirect: "follow",
      })
        .then((response) => response.json())
        .then((data) => {
          if (data && data.targetResponse && data.targetResponse.response) {
            resolve(data.targetResponse.response);
          } else {
            reject(new Error("Malformed quote data response"));
          }
        })
        .catch((error) => {
          console.error("Error:", error);
          reject(error);
        });
    });
  }

