      RiskStateRO_TXT: policyData.RiskStateRO_TXT,
      RiskPostCodeRO_TXT: policyData.RiskPostCodeRO_TXT,
      RiskCountryRO_TXT: policyData.RiskCountryRO_TXT,
      RiskAddress_Unit_TXT: policyData.RiskAddress_Unit_TXT,
      Segment__c: policyData.Segment__c,
      OriginalFirmDate_NUM: getYearFromDate(policyData.OriginalFirmDate_TXT),

      // Mailing Address Data
      MA_AddressLine1_TXT: policyData.MA_AddressLine1_TXT,
      MA_AddressLine2_TXT: policyData.MA_AddressLine2_TXT,
