      Guaranty_Zip_NUM: policyData.Guaranty_Zip_NUM,
      Guaranty_Country_CHOICE: policyData.Guaranty_Country_CHOICE,
      ProducingAgent_TXT: policyData.Guaranty_ProducingAgt_TXT,

      // NJ SLA License
      NJ_SLALicense_TXT: policyData.NJ_SLALicense_TXT,

      // Broker Address Data
      BrokerContact_Name_TXT: policyData.BrokerContact_Name_TXT,
      BrokerContactEmail_EMAIL: policyData.BrokerContactEmail_EMAIL,
      BrokerContact_Phone__PHONE: policyData.BrokerContact_Phone__PHONE,
      Broker_AddressLine1_TXT: policyData.Broker_AddressLine1_TXT,
      Broker_AddressLine2_TXT: policyData.Broker_AddressLine2_TXT,
      Broker_City_TXT: policyData.Broker_City_TXT,
      Broker_State_CHOICE: policyData.Broker_State_CHOICE,
      Broker_Zip_NUM: policyData.Broker_Zip_NUM,
      Broker_Country_CHOICE: policyData.Broker_Country_CHOICE,
      BrokerCode_CHOICE: policyData.BrokerCode_CHOICE,

      // Insured details
      FirstName_TXT: policyData.FirstName_TXT,
      MiddleName_TXT: policyData.MiddleName_TXT,
      LastName_TXT: policyData.LastName_TXT,
      ProducerName_TXT: policyData.ProducerName_TXT,
      BookTransfer_YN: policyData.BookTransfer_YN,
      Name_Type_CHOICEP: policyData.Name_Type_CHOICEP,
      ProductCode_CHOICE: policyData.ProductCode_CHOICE,
