      //EffectiveDate_DATE: addOneDay(policyData.EffectiveDate_DATE),
      ExpirationDate_DATE: addOneDayUTC(policyData.ExpirationDate_DATE),
      EntityName_TXT: policyData.EntityName_TXT,
      PrimaryInsuredBusiness_YN: policyData.PrimaryInsuredBusiness_YN,

      SameAddress_YNP: policyData.SameAddress_YNP,
      CoverageDeclined3Years_YN: policyData.CoverageDeclined3Years_YN,

      SurplusFilling_CHOICEP: policyData.SurplusFilling_CHOICEP,
      SurplusLicense_TXT: policyData.SurplusLicense_TXT,
      BrokerLicenseNumber_TXT: policyData.BrokerLicenseNumber_TXT,
