      ElevationVariance_NUM: policyData.ElevationVariance_NUM,
      Foundation_TXT: policyData.Foundation_CHOICE,

      //corelogic floodAPI- Sumiran
      RiskScore_NUM: parseNumberOrZero(policyData.RiskScoreEF_TXT),
