      PropertyElevation_NUM: parseNumberOrZero(
        policyData.PropertyElevationEF_TXT
      ),
      WaterSurfaceElevation_NUM: parseNumberOrZero(
        policyData.WaterSurfaceElevEF_TXT
      ),
      Distance100Year_NUM: parseNumberOrZero(
        policyData.DistOneKYearFloodEF_TXT
      ),
      Distance500YrFlood_NUM: parseNumberOrZero(
        policyData.DistFiveKYearFloodEF_TXT
      ),
