  $(document).ready(function () {
    if ($(".package-24518").length || $(".package-24588").length) {
      function makeReadOnly(el) {
        if (!el) return;
        if (el.tagName === "INPUT" || el.tagName === "TEXTAREA") {
          if (el.type === "radio" || el.type === "checkbox") {
            $('input[name="' + el.name + '"]').each(function () {
              $(this).attr("readonly", true).css({
                "pointer-events": "none",
                cursor: "not-allowed",
                background: "#f5f5f5",
              });
            });
          } else {
            $(el).prop("readonly", true).css({
              "pointer-events": "none",
              cursor: "not-allowed",
              background: "#f5f5f5",
            });
          }
        } else if (el.tagName === "SELECT") {
          $(el).css({
            "pointer-events": "none",
            cursor: "not-allowed",
            background: "#f5f5f5",
          });
        } else {
          $(el).css({
            "pointer-events": "none",
            cursor: "not-allowed",
            background: "#f5f5f5",
          });
        }
      }

      // Retrieve value from Instanda variable or hidden field, supporting both JSON array and pipe-delimited string
      let prefillArr = [];
      try {
        let prefillRaw = "";
        if (
          typeof Instanda !== "undefined" &&
          Instanda.Variables &&
          Instanda.Variables.UpdateBodyPrefill_TXT
        ) {
          prefillRaw = Instanda.Variables.UpdateBodyPrefill_TXT;
        } else {
          prefillRaw = $("#UpdateBodyPrefill_TXT").val() || "";
        }
        // Try JSON first, else treat as pipe-delimited
        if (prefillRaw.trim().startsWith("[")) {
          prefillArr = JSON.parse(prefillRaw);
        } else {
          prefillArr = prefillRaw
            .split("|")
            .map((str) => str.trim())
            .filter((str) => str.length > 0);
        }
      } catch (e) {
        prefillArr = [];
      }

      prefillArr.forEach(function (id) {
        var el = document.getElementById(id);
        if (
          el &&
          ((typeof el.value !== "undefined" &&
            el.value !== null &&
            el.value !== "") ||
            (typeof el.value === "undefined" &&
              el.textContent &&
              el.textContent.trim() !== ""))
        ) {
          makeReadOnly(el);
        }
      });

      // Optionally keep/re-run your multi-item readonly logic if needed
      ["AdditionalNameInsured", "AddClaim"].forEach(function (blockType) {
        $("div.instanda-multi-item")
          .filter(function () {
            return Array.from(this.classList).some(function (cls) {
              return new RegExp(
                "^instanda-multi-item-" + blockType + "_MI\\d+$"
              ).test(cls);
            });
          })
          .each(function () {
            $(this)
              .find("input, select, textarea")
              .each(function () {
                var el = this;
                var valuePresent =
                  (typeof el.value !== "undefined" &&
                    el.value !== null &&
                    el.value !== "") ||
                  (typeof el.value === "undefined" &&
                    el.textContent &&
                    el.textContent.trim() !== "");
                if (valuePresent) makeReadOnly(el);
              });
            // Additionally: Yes/No radio groups visually lock
            $(this)
              .find('input[type="radio"]')
              .each(function () {
                var labelFor = this.id ?
                  $('label[for="' + this.id + '"]') :
                  $();
                if (
                  this.value === "Yes" ||
                  this.value === "No" ||
                  (labelFor.length &&
                    (labelFor.text().trim() === "Yes" ||
                      labelFor.text().trim() === "No"))
                ) {
                  $(this).attr("readonly", true).css({
                    "pointer-events": "none",
                    cursor: "not-allowed",
                    background: "#f5f5f5",
                  });
                  if (labelFor.length) {
                    labelFor.css({
                      "pointer-events": "none",
                      cursor: "not-allowed",
                    });
                  }
                }
              });
          });
      });
    }
  });

  // Main Trigger Function for Prefill
  //Integ
  async function showPoliciesForCustomerAndUpdate(event, updateBody = {}) {
    try {
      showSpinner();
      // Get Customer ID
      const customerid =
        $("#CustomerID_TXT").val() || Instanda.Variables.CustomerID_TXT;
      if (!customerid) {
        hideSpinner();
        $("#unified-spinner-overlay").hide();
        displayApiErrorMessage("Customer ID is required");
        return;
      }

      // Query ODS for all policies/quotes for this customer
      const query = `
            SELECT [PolicyNumber], [QuoteRef], [NamedInsured_TXT], [SaleStage], [RiskAddressLine1RO_TXT],[RiskCityRO_TXT],[RiskStateRO_TXT]
            FROM [dbint_344].[dbint_344_4044_HOPrefill]
            WHERE [CustomerID_TXT] = '${customerid.replace(/'/g, "''")}'
            AND [SaleStage] IN ('Referred', 'SaleComplete', 'Quote', 'AboutToPay', 'Binder', 'Approved')
            AND SiteEnvironment = '${getSiteEnv()}'
        `;

      let odsResult;
      try {
        odsResult = await queryODS(query);
      } catch (err) {
        displayApiErrorMessage("ODS API error: " + err.message);
        $("#unified-spinner-overlay").hide();
        hideSpinner();
        return;
      }

      // Flatten the response if needed
      const dataArr = Array.isArray(odsResult) ? odsResult : [odsResult];
      const flatArr = Array.isArray(dataArr[0]) ? dataArr[0] : dataArr;

      const hasValidPolicyOrQuote = flatArr.some(
        (item) => item && (item.PolicyNumber || item.QuoteRef)
      );

      if (!flatArr.length || !hasValidPolicyOrQuote) {
        displayApiErrorMessage(
          "No matching policy or quote found for this customer."
        );
        hideSpinner();
        return;
      }

      // Show modal with selectable rows
      showSelectableModal(flatArr, async (selectedRow) => {
        // Use PolicyNumber if present, else QuoteRef
        const ref = selectedRow.QuoteRef;
        if (!ref) {
          displayApiErrorMessage("No valid Quote reference found.");
          hideSpinner();
          return;
        }

        // Get policy data
        let policyData;
        try {
          policyData = await getPolicyData(ref);
        } catch (err) {
          displayApiErrorMessage("Error fetching policy data: " + err.message);
          hideSpinner();
          return;
        }

        // Determine which update function to use based on packages
        let updateBodyFromPolicy;
        let updateFunction;
        // Initiate call for EQ
        if ($(".package-24518").length > 0) {
          updateBodyFromPolicy = buildUpdateBodyFromPolicyDataEQ(policyData);
          updateFunction = updateQuoteorPolicydata;
        }
        // Initiate call for EQ
        else if ($(".package-24588").length > 0) {
          updateBodyFromPolicy = buildUpdateBodyFromPolicyDataEF(policyData);
          updateFunction = updateQuoteorPolicydata;
        }

        // Initiate call for CO
        else if ($(".package-23424").length > 0) {
          updateBodyFromPolicy = buildUpdateBodyFromPolicyDataCO(policyData);
          updateFunction = updateQuoteorPolicydata;
        }
        // To add other packages in conditions

        // Update quote or policy data
        try {
          const updateResult = await updateFunction(event, {
            UpdateBodyPrefill_TXT: $("#UpdateBodyPrefill_TXT").val() || "",
            ...updateBodyFromPolicy,
          });
          console.log(updateResult);
          // $("#PrefillFlag_YN").val("Yes").trigger("change");
          // sessionStorage.setItem("readonlyAfterPrefill", "true");
          // $('button[name="saveButton"]').trigger("click");
          // setTimeout(function () {
          window.location.reload();
          // }, 1000);
          displayApiSuccessMessage("Your Quote/Policy has been prefilled.");
          hideSpinner();
        } catch (err) {
          displayApiErrorMessage("Error updating quote/policy: " + err.message);
          hideSpinner();
        }
      });
    } catch (err) {
      console.error("Process failed:", err);
      hideSpinner();
    }
  }

