  // Global function - Call this function if we need to display index number without using MIIndex
  // Common //
  function autoNumbering(selector) {
    // Function to update numbers
    const updateNumbers = () => {
      let count = 1;
      $(selector).each(function () {
        // Check if this input is inside any ancestor with id containing 'sampleMultiItem'
        const isInsideSampleMultiItem =
          $(this).closest('[id*="sampleMultiItem"]').length > 0;
        if (!isInsideSampleMultiItem) {
          $(this).val(count++);
        }
      });
    };

    // Run once initially
    updateNumbers();

    // Watch for add/remove in DOM
    const observer = new MutationObserver(() => {
      updateNumbers();
    });

    // Attach observer (to body or narrow down if you have MI container)
    observer.observe(document.body, {
      childList: true,
      subtree: true,
    });
  }
  autoNumbering(".indexing-infractions input");

