  //Common//
  function quickquoteloadingBtnClick() {
    // Define the premium selectors up front
    const premiumSelectors = [
      ".page-quickquotequestions.page-number-6.package-24337",
      // ".page-prequotequestions.page-number-1.package-24338",
      ".page-quickquotequestions.page-number-5.package-24428",
      ".page-quickquotequestions.page-number-5.package-24518",
      ".page-quickquotequestions.page-number-6.package-24588",
    ];

    // Helper: is any premium page present right now?
    function isPremiumPage() {
      return premiumSelectors.some((sel) => $(sel).length > 0);
    }

    // Helper: are we in read-only mode?
    function isReadOnlyView() {
      return $(".readonlymode").length > 0;
    }

    // Handler for read-only: just submit form
    function readonlyContinueHandler(event) {
      event.preventDefault();
      if (event.currentTarget.form) {
        event.currentTarget.form.submit();
      }
    }

    // Handler for normal (non-readonly) case, includes spinner logic & API call
    async function handleContinue(event) {
      event.preventDefault();
      const continueButtons = document.querySelectorAll(
        'button[name="continueButton"]'
      );

      continueButtons.forEach((btn) => {
        btn.innerHTML =
          '<span class="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span><span class="visually-hidden">Loading</span>';
        btn.disabled = true;
      });

      try {
        let integcallsapi = true;

        // Safely check premium + not read-only before API call
        if (isPremiumPage() && !isReadOnlyView()) {
          integcallsapi = await coherentpremiumevents(event);
          if (!integcallsapi)
            throw new Error("Premium event integration failed");
        }

        let formAction = null;
        if ($(".page-quickquotequestions").length > 0) {
          formAction = "QuickQuoteQuestionsContinue";
        } else if ($(".page-prequotequestions").length > 0) {
          formAction = "PreQuoteQuestionsContinue";
        }

        continueButtons.forEach((btn) => {
          if (formAction && btn.form) {
            btn.form.action = formAction;
            btn.form.submit();
          }
        });
      } catch (error) {
        continueButtons.forEach((btn) => {
          btn.innerHTML = "Continue";
          btn.disabled = false;
        });
        if (typeof hideSpinner === "function") hideSpinner();
        console.error("Error:", error);
      }
    }

    // Attach event handlers to every relevant continueButton
    const continueButtons = document.querySelectorAll(
      'button[name="continueButton"]'
    );
    continueButtons.forEach((btn) => {
      btn.removeEventListener("click", handleContinue);
      btn.removeEventListener("click", readonlyContinueHandler);

      if (isReadOnlyView()) {
        //btn.addEventListener("click", readonlyContinueHandler);
      } else {
        btn.addEventListener("click", handleContinue);
      }
    });
  }

