  //Enhancement card BH-25679 to display "The number of fulltime inside employees" and "The number of fulltime outside employees" only if Worker's Compensation/Employer's Liability surcharge is selected as Yes
  function showHideFullTimeEmployees() {
    if ($(".page-quickquotequestions.page-number-6.package-24337").length > 0) {
      console.log("Inside if codition...");
      const $yesLabel = $(`label:has(#WCEmplLiabSurcharge_YNYes)`);
      const $noLabel = $(`label:has(#WCEmplLiabSurcharge_YNNo)`);

      const $insideNumField = $(`#NumFullTimeInsideEmployees_NUM`);
      const $outsideNumField = $(`#NumFullTimeOutsideEmployees_NUM`);
      const $questionEl1 = $insideNumField.closest(".instanda-question-item");
      const $questionEl2 = $outsideNumField.closest(".instanda-question-item");
      const yesSelected =
        $yesLabel.hasClass("instanda-selected") &&
        $noLabel.hasClass("instanda-unselected");
      //const noSelected = $yesLabel.hasClass("instanda-unselected") && $noLabel.hasClass("instanda-selected");

      if (yesSelected) {
        $questionEl1.show();
        $questionEl2.show();
        $insideNumField.prop("required", true);
        $outsideNumField.prop("required", true);
      } else {
        $insideNumField.val("0");
        $outsideNumField.val("0");
        $insideNumField.prop("required", false);
        $outsideNumField.prop("required", false);
        $questionEl1.hide();
        $questionEl2.hide();
      }
    }
  }

