  //Home
  if ($(".page-quickquotequestions.page-number-5.package-24337").length > 0) {
    function HandleClaimRequiredFields(container, miNumber) {
      const source = container.querySelector(
        `#AddClaim_MI${miNumber}_AddClaimSource_CHOICE`
      );
      const claimDetails = container.querySelector(
        `#AddClaim_MI${miNumber}_AddClaimClaimDetails_TXT`
      );
      const allFields = container.querySelectorAll(".claimsDetails");

      if (source && allFields.length > 0) {
        function claimLogic() {
          if (source.value === "Manual") {
            allFields.forEach((fieldContainer) => {
              if (fieldContainer !== claimDetails) {
                // Find all input, select, textarea inside this .claimsDetails container
                const inputs = fieldContainer.querySelectorAll(
                  "input, select, textarea"
                );
                inputs.forEach((input) => {
                  $(input).prop("required", true).attr("required", "required");
                });

                // Add red asterisk to the label if not present
                const mainLabel = fieldContainer.querySelector("label");
                if (
                  mainLabel &&
                  !mainLabel.querySelector(".required-asterisk")
                ) {
                  mainLabel.insertAdjacentHTML(
                    "beforeend",
                    '<span class="required-asterisk" style="color:red;font-size:16px;"> *</span>'
                  );
                }
              }
            });
          } else {
            allFields.forEach((fieldContainer) => {
              if (fieldContainer !== claimDetails) {
                // Remove required from all input, select, textarea inside this .claimsDetails container
                const inputs = fieldContainer.querySelectorAll(
                  "input, select, textarea"
                );
                inputs.forEach((input) => {
                  $(input).prop("required", false).removeAttr("required");
                });

                // Remove red asterisk from the label
                const mainLabel = fieldContainer.querySelector("label");
                if (mainLabel) {
                  const asterisk =
                    mainLabel.querySelector(".required-asterisk");
                  if (asterisk) asterisk.remove();
                }
              }
            });
          }
        }

        claimLogic();

        source.addEventListener("change", function () {
          claimLogic();
        });
      } else {
        console.log("source or allFields not found");
      }
    }
  }
