  // Fix for BH-26723
  $(document).ready(function () {
    if (isReadOnlyView()) return;
    if ($(".page-quickquotequestions.page-number-3.package-24588").length === 0)
      return;

    const toNum = (v) => {
      const s = (v ?? "")
        .toString()
        .replace(/[$,\s]/g, "")
        .trim();
      const n = parseFloat(s);
      return Number.isFinite(n) ? n : 0;
    };

    function recalc() {
      const policytype = (Instanda?.Variables?.PolicyType_CHOICE ?? "").trim();

      if (policytype === "Homeowners") {
        const dwellinglimit = toNum(
          $("#DwellingLimit_NUM").val() ??
          Instanda?.Variables?.DwellingLimit_NUM
        );
        const underBuild = toNum(
          $("#UnderFloodCoverBuildLimit_NUM").val() ??
          Instanda?.Variables?.UnderFloodCoverBuildLimit_NUM
        );
        const diff = Math.max(dwellinglimit - underBuild, 0);

        if (diff === 0) {
          $("#ExcessBuildLimitReq_NUM")
            .val("0")
            .trigger("input")
            .trigger("change");
        }
      }

      if (
        policytype === "Homeowners" ||
        policytype === "Condo/Cooperative" ||
        policytype === "Tenant"
      ) {
        const contents = toNum(
          $("#HomeContentsLimit_NUM").val() ??
          Instanda?.Variables?.HomeContentsLimit_NUM
        );
        const underContents = toNum(
          $("#UnderFloodCoverageContentLimit_NUM").val() ??
          Instanda?.Variables?.UnderFloodCoverageContentLimit_NUM
        );
        const diff2 = Math.max(contents - underContents, 0);

        if (diff2 === 0) {
          $("#ExcessContentsLimitReq_NUM")
            .val("0")
            .trigger("input")
            .trigger("change");
        }
      }
    }

    // Run once after initial paint, then on changes
    setTimeout(recalc, 0);
    $(document).on(
      "input change",
      "#DwellingLimit_NUM,#UnderFloodCoverBuildLimit_NUM,#HomeContentsLimit_NUM,#UnderFloodCoverageContentLimit_NUM",
      recalc
    );
  });

