  // Code for updating Driver for UW Rules //
  // Helper: Format date to M/D/YYYY (no leading zeros)
  //Common
  function formatDateToMDYYYY(dateInput) {
    if (!dateInput) return "";
    const date = new Date(dateInput);
    if (isNaN(date)) return "";
    const mm = date.getMonth() + 1;
    const dd = date.getDate();
    const yyyy = date.getFullYear();
    return `${mm}/${dd}/${yyyy}`;
  }

  // Helper: Check if date (in MM/DD/YYYY or ISO) is within N years from today
  ////Common
  function isWithinYears(dateStr, years) {
    if (!dateStr) return false;
    let date = new Date(dateStr);
    if (isNaN(date)) {
      // Try parsing MM/DD/YYYY or M/D/YYYY
      const parts = dateStr.split("/");
      if (parts.length === 3) {
        const [mm, dd, yyyy] = parts;
        date = new Date(
          `${yyyy}-${mm.padStart(2, "0")}-${dd.padStart(2, "0")}`
        );
      }
    }
    if (isNaN(date)) return false;
    const now = new Date();
    const yearsAgo = new Date(
      now.getFullYear() - years,
      now.getMonth(),
      now.getDate()
    );
    return date >= yearsAgo && date <= now;
  }

