  // Main function to update drivers for underwriting rules
  //Common
  function isSubset(small, large) {
    return Object.entries(small).every(([key, value]) => large[key] === value);
  }
  //EL
  async function driverupdateforuwrules(event) {
    showSpinner();
    try {
      if (isReadOnlyView && isReadOnlyView()) {
        hideSpinner();
        console.log("Read-only view");
        return false;
      }

      const infractionsDetails = document.querySelector(
        "input[id = 'InfractionsDetails_TXT']"
      );
      const triggerRulesYes = document.querySelector(
        "input[id = 'TriggerRules_YNYes']"
      );
      const triggerRulesNo = document.querySelector(
        "input[id = 'TriggerRules_YNNo']"
      );
      const renewalCount = Instanda.Variables.RENEWAL_COUNT;

      if (infractionsDetails.value === null || infractionsDetails.value === "")
        infractionsDetails.value = "JB";

      console.log("Running driverupdateforuwrules");
      const quoteData = await getQuoteData(event);
      const drivers = quoteData.Driver_MI || [];
      const infractions = quoteData.Infractions_MI || [];

      const updatedDrivers = drivers.map((driver) => {
        // Build driver key: FirstName + LastName + DOB in M/D/YYYY (no leading zeros)
        const driverKey = (
          (driver.D_FirstName_TXT || "").trim().toUpperCase() +
          (driver.D_LastName_TXT || "").trim().toUpperCase() +
          formatDateToMDYYYY(driver.D_DOB_DATE) +
          (driver.LicenseNo_TXT || "").trim()
        ).replace(/\s+/g, "");

        // Find infractions for this driver
        const driverInfractions = infractions.filter((infraction) => {
          const infractionKey = (infraction.DriverFullName_TXT || "")
            .replace(/\s+/g, "")
            .toUpperCase()
            .substring(2);
          infractionKey === driverKey ?
            console.log("Key match") :
            console.log("Key no match");
          return infractionKey === driverKey;
        });

        // Track latest date
        let latestDateObj = null;

        driver.ConvictionsNumber_NUM = 0;
        driver.AccidentsNumber_NUM = 0;
        driver.MovingViolationsInLast1year_NUM = 0;
        driver.MovingAccidentsInLast1year_NUM = 0;
        driver.MovingViolationsInLast3years_NUM = 0;
        driver.MovingAccidentsInLast3years_NUM = 0;
        driver.MovingViolationsInLast5years_NUM = 0;
        driver.MovingAccidentsInLast5years_NUM = 0;
        driver.AtFaultAccidents_NUM = 0;
        driver.AccidentsAFNAFin3years_NUM = 0;
        driver.AccidentExcludeCompLossIn3Years_NUM = 0;
        driver.ViolationsAccidentsExcludeCompLossin3Years_NUM = 0;
        driver.DWIInLastYear_NUM = 0;
        driver.DWIInLast3Years_NUM = 0;
        driver.Points_NUM = 0;

        driverInfractions.forEach((infraction) => {
          const type = infraction.Infraction_Type_CHOICEP;
          const infractionDateRaw =
            type === "Accident" ?
              infraction.Claim_ViolationAccident_DATE :
              infraction.Infraction_Conviction_DATE;
          let infractionDate = "";
          if (infractionDateRaw) {
            infractionDate = formatDateToMMDDYYYY(infractionDateRaw);
          }
          const points =
            Number(
              type === "Accident" ?
                infraction.AccidentPoints_TXT :
                infraction.ConvictionPoints
            ) || 0;
          const infractionValue = (
            (type === "Accident" ?
              infraction.AccidentValues_TXT :
              infraction.ConvictionValues_TXT) || ""
          ).toUpperCase();

          // Update latest date (as Date object)
          if (infractionDateRaw) {
            const dateObj = new Date(infractionDateRaw);
            if (!latestDateObj || dateObj > latestDateObj) {
              latestDateObj = dateObj;
            }
          }

          // Points
          driver.Points_NUM += points;

          // Update Accidents / Convictions

          type === "Accident" ?
            ++driver.AccidentsNumber_NUM :
            ++driver.ConvictionsNumber_NUM;

          // Fault indicator
          if (infraction.C_FaultIndicator_Auto_TXT === "At Fault") {
            driver.FaultIndicator_TXT = "At Fault";
            if (type === "Accident") driver.AtFaultAccidents_NUM++;
          }

          // Major DWI
          if (MAJOR_DWI_VALUES.includes(infractionValue)) {
            driver.MajorDWI_YN = "Yes";

            if (isWithinYears(infractionDate, 1) || points >= 3)
              driver.DWIInLastYear_NUM++;

            if (isWithinYears(infractionDate, 3)) driver.DWIInLast3Years_NUM++;
          }

          // Comp Loss
          if (COMP_LOSS_VALUES.includes(infractionValue)) {
            driver.CompLoss_YN = "Yes";
          }

          // Violation or Accident counts and flags
          if (type === "Conviction") {
            if (isWithinYears(infractionDate, 1)) {
              driver.Violinlast1Year_YN = "Yes";
              driver.MovingViolationsInLast1year_NUM++;
            }
            if (isWithinYears(infractionDate, 3)) {
              driver.ViolinLast3Year_YN = "Yes";
              driver.MovingViolationsInLast3years_NUM++;
            }
            if (isWithinYears(infractionDate, 5)) {
              driver.ViolinLast5year_YN = "Yes";
              driver.MovingViolationsInLast5years_NUM++;
            }
          }
          if (type === "Accident") {
            if (isWithinYears(infractionDate, 1)) {
              driver.AccinLast1Year_YN = "Yes";
              driver.MovingAccidentsInLast1year_NUM++;
            }
            if (isWithinYears(infractionDate, 3)) {
              driver.AccinLast3Years_YN = "Yes";
              driver.MovingAccidentsInLast3Years_NUM++;

              if (infraction.C_FaultIndicator_Auto_TXT)
                driver.AccidentsAFNAFin3years_NUM++;

              if (!COMP_LOSS_VALUES.includes(infractionValue))
                driver.AccidentExcludeCompLossIn3Years_NUM++;
            }
            if (isWithinYears(infractionDate, 5)) {
              driver.AccinLast5Years_YN = "Yes";
              driver.MovingAccidentsInLast5years_NUM++;
            }
          }

          if (
            isWithinYears(infractionDate, 3) &&
            !COMP_LOSS_VALUES.includes(infractionValue)
          ) {
            driver.ViolationsAccidentsExcludeCompLossin3Years_NUM++;
          }
        });
        console.log("Updated driver");

        return driver;
      });

      await updateQuoteorPolicydata(event, {
        Driver_MI: updatedDrivers,
      });
      console.log("Code ran successfully");

      //Setting flag whether rules should trigger or not

      if (renewalCount) {
        let infractionDetails = [];
        try {
          infractionDetails = Array.parse(infractionsDetails.value);
        } catch (error) {
          console.error(error);
        }

        if (infractionDetails.length === infractions.length) {
          let flag = 0;
          for (let i = 0; i < infractions.length; i++) {
            if (!isSubset(infractions.at(i), infractionDetails.at(i))) {
              flag++;
            }
          }

          if (flag) {
            triggerRulesYes.click();
            console.log("Rules will trigger");
          } else {
            triggerRulesNo.click();
            console.log("Rules will not trigger");
          }
        } else {
          triggerRulesYes.click();
          console.log("Rules will trigger");
        }
      }

      hideSpinner();
    } catch (error) {
      hideSpinner();
      console.error("Error in driverupdateforuwrules:", error);
    }
  }
