  //Integ
  // 2. Fetch All Policy Data in Parallel
  function flattenODSResult(result) {
    if (
      Array.isArray(result) &&
      result.length === 1 &&
      Array.isArray(result[0])
    ) {
      return result[0];
    }
    return result;
  }
  //Integ
  async function fetchAllPrefillData(customerid) {
    const queries = {
      yacht: `SELECT Y.PolicyNumber AS PolicyNumber, Y.SaleStage AS SaleStage, Y.QuoteRef AS QuoteRef, Y.CreatedFrom AS CreatedFrom, Y.CreatedOn AS CreatedOn, Y.NamedInsured_TXT AS NamedInsured_TXT, Y.MA_AddressLine1_TXT AS MA_AddressLine1_TXT, Y.MA_City_TXT AS MA_City_TXT, Y.MA_State_CHOICE AS MA_State_CHOICE, Y.MA_Zip_NUM AS MA_Zip_NUM, Y.MA_Country_CHOICE AS MA_Country_CHOICE, [Index], [WATERCRAFT_TYPE], [WATERCRAFT_HIN], [WATERCRAFT_MAKE_TX], [WATERCRAFT_MODEL_TX], [SOURCE_SYSTEM_NM], [YACHT_NO], [ENGINES_NO], [TOW_IN], [ENGINE_MANUFACTURER], [RISKITEM_OID], [WATERCRAFT_LENGTH], [WATERCRAFT_YEAR], [HORSEPOWER_NO], [WATERCRAFT_VALUE] FROM [dbint_344].[dbint_344_3543_YTYACHTWATERCRAFT] X INNER JOIN [dbint_344].[dbint_344_4098_YachtPrefill] Y ON X.QUOTEREF = Y.QUOTEREF WHERE Y.CustomerID_TXT = '${customerid.replace(
        /'/g,
        "''"
      )}' AND X.QuoteRef IS NOT NULL AND X.QuoteRef <> ''`,
      ho: `SELECT PolicyNumber,QuoteRef,CreatedFrom,SaleStage,NamedInsured_TXT,CreatedOn,RiskAddressLine1RO_TXT,RiskCityRO_TXT,RiskStateRO_TXT,OccupancyType_CHOICEP,CustomerID_TXT FROM [dbint_344].[dbint_344_4044_HOPrefill] WHERE  CustomerID_TXT = '${customerid.replace(
        /'/g,
        "''"
      )}'`,
      auto: `SELECT PolicyNumber, QuoteRef, CreatedFrom, SaleStage, NamedInsured_TXT, CreatedOn, RiskAddressLine1RO_TXT, RiskCityRO_TXT, RiskStateRO_TXT, CustomerID_TXT FROM [dbint_344].[dbint_344_4099_AutoPrefill] WHERE CustomerID_TXT = '${customerid.replace(
        /'/g,
        "''"
      )}'`,
    };

    const [yacht, ho, auto] = await Promise.all([
      queryODS(queries.yacht).catch(() => []),
      queryODS(queries.ho).catch(() => []),
      queryODS(queries.auto).catch(() => []),
    ]);

    return {
      yacht: flattenODSResult(yacht),
      ho: flattenODSResult(ho),
      auto: flattenODSResult(auto),
    };
  }

  // 3. Unified Modal with Tabs
  //Integ
  function showUnifiedELPrefillModal(event) {
    showSpinner();

    const customerid =
      $("#CustomerID_TXT").val() || Instanda.Variables.CustomerID_TXT;

    if (!customerid) {
      hideSpinner();
      $("#unified-spinner-overlay").hide();
      displayApiErrorMessage("Customer ID is required for data prefilling.");
      return;
    }

    fetchAllPrefillData(customerid)
      .then((data) => {
        buildUnifiedModalUI(data, event);
      })
      .catch((err) => {
        hideSpinner();
        $("#unified-spinner-overlay").hide();
        displayApiErrorMessage("Error fetching prefill data: " + err.message);
      });
  }

  // 4. Modal UI Builder
  //Integ
  function buildUnifiedModalUI(data, event) {
    hideSpinner();
    // Remove existing modal
    $("#ELPrefill-modal-overlay").remove();

    // Modal CSS (only add once)
    if (!document.getElementById("ELPrefill-modal-style")) {
      const styleTag = document.createElement("style");
      styleTag.id = "ELPrefill-modal-style";
      styleTag.innerHTML = `
      #ELPrefill-modal-overlay { position: fixed; top: 0; left: 0; right: 0; bottom: 0; background: rgba(0,0,0,0.5); z-index: 11000; display: flex; align-items: flex-start; justify-content: center; }
      #ELPrefill-modal { background: #fff; margin-top: 40px; border-radius: 8px; box-shadow: 0 4px 24px rgba(0,0,0,0.2); padding: 24px; width: 900px; max-width: 95vw; max-height: 80vh; overflow: auto; position: relative; }
      #ELPrefill-modal-close { position: absolute; top: 8px; right: 12px; font-size: 22px; color: #333; background: none; border: none; cursor: pointer; }
      #ELPrefill-tabs { display: flex; border-bottom: 1px solid #ddd; margin-bottom: 16px; }
      .el-prefill-tab { padding: 10px 24px; cursor: pointer; border: none; background: none; font-size: 16px; }
      .el-prefill-tab.active { border-bottom: 3px solid #1976d2; font-weight: bold; color: #1976d2; }
      .el-prefill-section { display: none; }
      .el-prefill-section.active { display: block; }
      #ELPrefill-modal table { border-collapse: collapse; width: 100%; table-layout: fixed; }
      #ELPrefill-modal th, #ELPrefill-modal td { border: 1px solid #ddd; padding: 6px 10px; font-size: 14px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
      #ELPrefill-modal th { background: #f5f5f5; position: sticky; top: 0; z-index: 1; }
      #ELPrefill-modal tbody tr.selected { background: #e0f7fa; }
      #ELPrefill-modal .select-radio { cursor: pointer; }
      #ELPrefill-modal .el-prefill-submit { margin-top: 20px; background: #1976d2; color: #fff; border: none; padding: 10px 24px; border-radius: 4px; font-size: 16px; cursor: pointer; }
      #ELPrefill-modal .el-prefill-submit:disabled { background: #aaa; cursor: not-allowed; }
      /* Fixed column widths */
      #ELPrefill-modal th, #ELPrefill-modal td { width: 120px; }
      #ELPrefill-modal th:nth-child(1), #ELPrefill-modal td:nth-child(1) { width: 130px; }
      #ELPrefill-modal th:last-child, #ELPrefill-modal td:last-child { width: 70px; }
      /* Spinner overlay */
      #ELPrefill-spinner-overlay {
        position: fixed; top: 0; left: 0; right: 0; bottom: 0;
        background: rgba(255,255,255,0.7); z-index: 11000; display: flex; align-items: center; justify-content: center;
      }
      .el-spinner {
        border: 8px solid #f3f3f3;
        border-top: 8px solid #1976d2;
        border-radius: 50%;
        width: 60px; height: 60px;
        animation: spin 1s linear infinite;
      }
      @keyframes spin {
        0% { transform: rotate(0deg);}
        100% { transform: rotate(360deg);}
      }
    `;
      document.head.appendChild(styleTag);
    }

    // Modal HTML
    const tabs = [{
      key: "auto",
      label: "Auto",
    },
    {
      key: "ho",
      label: "Homeowners",
    },
    {
      key: "yacht",
      label: "Yacht/Watercraft",
    },
    ];
    const sectionHtml = tabs
      .map(
        (tab) => `
    <div class="el-prefill-section" id="el-prefill-section-${tab.key}">
      ${buildSectionTable(tab.key, data[tab.key])}
    </div>
  `
      )
      .join("");

    const modalHtml = `
    <div id="ELPrefill-modal-overlay">
      <div id="ELPrefill-modal">
        <button id="ELPrefill-modal-close" title="Close">&times;</button>
        <h2>Prefill Data: Select Policy or Quote</h2>
        <div id="ELPrefill-tabs">
          ${tabs
        .map(
          (tab, i) =>
            `<button class="el-prefill-tab${i === 0 ? " active" : ""
            }" data-tab="${tab.key}">${tab.label}</button>`
        )
        .join("")}
        </div>
        ${sectionHtml}
        <button class="el-prefill-submit" id="el-prefill-submit-btn">Submit</button>
      </div>
    </div>
  `;
    document.body.insertAdjacentHTML("beforeend", modalHtml);

    // Tab logic
    $("#ELPrefill-tabs").on("click", ".el-prefill-tab", function () {
      const tab = $(this).data("tab");
      $(".el-prefill-tab").removeClass("active");
      $(this).addClass("active");
      $(".el-prefill-section").removeClass("active");
      $(`#el-prefill-section-${tab}`).addClass("active");
    });
    // Activate first tab/section
    $(".el-prefill-section").removeClass("active");
    $("#el-prefill-section-auto").addClass("active");

    // Close handlers
    $("#ELPrefill-modal-close").on("click", function () {
      $("#ELPrefill-modal-overlay").remove();
    });
    $("#ELPrefill-modal-overlay").on("click", function (e) {
      if (e.target.id === "ELPrefill-modal-overlay")
        $("#ELPrefill-modal-overlay").remove();
    });

    // Selection tracking
    const selectedRows = {
      yacht: null,
      ho: null,
      auto: null,
    };
    tabs.forEach((tab) => {
      $(`#el-prefill-section-${tab.key}`).on(
        "change",
        ".select-radio",
        function () {
          const idx = $(this).val();
          selectedRows[tab.key] = data[tab.key][idx];
          $(`#el-prefill-section-${tab.key} tr`).removeClass("selected");
          $(`#el-prefill-section-${tab.key} tr[data-rowidx="${idx}"]`).addClass(
            "selected"
          );
          // No radio button changes here!
        }
      );
    });

    // Submit logic with spinner and radio update
    $("#el-prefill-submit-btn").on("click", async function () {
      if (!selectedRows.yacht && !selectedRows.ho && !selectedRows.auto) {
        displayApiErrorMessage("Please select at least one policy or quote.");
        return;
      }
      // Show spinner
      showSpinner();
      $("#ELPrefill-modal-overlay").remove();

      // Set YN radios only on submit
      if (selectedRows.ho) {
        $("#PrefillHome_YNYes").prop("checked", true).trigger("click");
        console.log("Clicked Yes for Prefill");
      }
      if (selectedRows.auto) {
        $("#PrefillAuto_YNYes").prop("checked", true).trigger("click");
      }

      try {
        await handleUnifiedELSubmit(selectedRows, event);
      } finally {
        hideSpinner();
      }
    });
  }

  // 5. Section Table Builders
  //Integ
  function buildSectionTable(type, arr) {
    if (!arr || !arr.length) {
      return `<p>No ${type === "yacht"
        ? "Yacht/Watercraft"
        : type === "ho"
          ? "Homeowners"
          : "Auto"
        } data available.</p>`;
    }

    let headers, rowHtml;
    const safe = (v) => (v === null || v === undefined || v === "" ? "N/A" : v);

    if (type === "yacht") {
      headers = [
        "Policy Number",
        "Quote No",
        "Status",
        "Insured Name",
        "Address 1",
        "City",
        "State",
        "Select",
      ];
      rowHtml = arr
        .map(
          (ref, idx) => `
      <tr data-rowidx="${idx}">
        <td>${safe(ref.PolicyNumber)}</td>
        <td>${safe(ref.QuoteRef)}</td>
        <td>${safe(ref.SaleStage)}</td>
        <td>${safe(ref.NamedInsured_TXT)}</td>
        <td>${safe(ref.MA_AddressLine1_TXT)}</td>
        <td>${safe(ref.MA_City_TXT)}</td>
        <td>${safe(ref.MA_State_CHOICE)}</td>
        <td><input type="radio" class="select-radio" name="select-yacht" value="${idx}"></td>
      </tr>
    `
        )
        .join("");
    } else if (type === "ho") {
      headers = [
        "Policy Number",
        "Quote No",
        "Status",
        "Insured Name",
        "Address 1",
        "City",
        "State",
        "Select",
      ];
      rowHtml = arr
        .map(
          (ref, idx) => `
      <tr data-rowidx="${idx}">
        <td>${safe(ref.PolicyNumber)}</td>
        <td>${safe(ref.QuoteRef)}</td>
        <td>${safe(ref.SaleStage)}</td>
        <td>${safe(ref.NamedInsured_TXT)}</td>
        <td>${safe(ref.RiskAddressLine1RO_TXT)}</td>
        <td>${safe(ref.RiskCityRO_TXT)}</td>
        <td>${safe(ref.RiskStateRO_TXT)}</td>
        <td><input type="radio" class="select-radio" name="select-ho" value="${idx}"></td>
      </tr>
    `
        )
        .join("");
    } else if (type === "auto") {
      headers = [
        "Policy Number",
        "Quote No",
        "Status",
        "Insured Name",
        "Address 1",
        "City",
        "State",
        "Select",
      ];
      rowHtml = arr
        .map(
          (ref, idx) => `
      <tr data-rowidx="${idx}">
        <td>${safe(ref.PolicyNumber)}</td>
        <td>${safe(ref.QuoteRef)}</td>
        <td>${safe(ref.SaleStage)}</td>
        <td>${safe(ref.NamedInsured_TXT)}</td>
        <td>${safe(ref.RiskAddressLine1RO_TXT)}</td>
        <td>${safe(ref.RiskCityRO_TXT)}</td>
        <td>${safe(ref.RiskStateRO_TXT)}</td>
        <td><input type="radio" class="select-radio" name="select-auto" value="${idx}"></td>
      </tr>
    `
        )
        .join("");
    }

    return `
    <table>
      <thead>
        <tr>${headers.map((h) => `<th>${h}</th>`).join("")}</tr>
      </thead>
      <tbody>
        ${rowHtml}
      </tbody>
    </table>
  `;
  }

  // 6. Unified Submit Handler
  //Integ
  async function handleUnifiedELSubmit(selectedRows, event) {
    try {
      // Fetch full policy data for each selection
      const [yachtData, hoData, autoData] = await Promise.all([
        selectedRows.yacht ? getyachtdata(selectedRows.yacht.QuoteRef) : null,
        selectedRows.ho ? getHOdata(selectedRows.ho.QuoteRef) : null,
        selectedRows.auto ? getAutodata(selectedRows.auto.QuoteRef) : null,
      ]);
      // Build update body
      const updateBody = {
        ...(yachtData ? updatewatercraftdetailsfromPolicydata(yachtData) : {}),
        ...(hoData ? updateHOforEL(hoData) : {}),
        ...(autoData ? updateAutoforEL(autoData) : {}),
      };
      // Only call update once
      await updateQuoteorPolicydata(event, updateBody);
      displayApiSuccessMessage(
        "Your Quote/Policy has been updated successfully."
      );
      window.location.reload();
    } catch (err) {
      displayApiErrorMessage("Error updating quote/policy: " + err.message);
    }
  }
  //Integ
  async function getyachtdata(ref) {
    const quoteRef = typeof ref === "string" ? ref : ref.QuoteRef;
    if (!quoteRef)
      throw new Error("No valid quoteRef or PolicyNumber provided");

    const requestPayload = {
      method: "GET",
      query: {
        quoteRef: quoteRef,
      },
    };

    const {
      apiBaseUrl,
      subscriptionKey
    } = getApiEndpoint("phase2");
    const apiEndpoint = `${apiBaseUrl}/instanda/v1/manageQuotePolicy?resource=GetQuoteData&recordId=${quoteRef}`;

    const headers = {
      "pcsctx-appName": "Instanda",
      "pcsctx-traceId": generateUUID(),
      "pcsctx-sessionId": generateUUID(),
      "pcsctx-productType": "Yacht",
      "Content-Type": "application/json",
      "Ocp-Apim-Subscription-Key": subscriptionKey,
    };

    const response = await fetch(apiEndpoint, {
      method: "POST",
      headers: headers,
      body: JSON.stringify(requestPayload),
      redirect: "follow",
    });

    if (response.status === 202) {
      throw new Error("Data not ready (202 Accepted). Try again later.");
    }

    if (!response.ok) {
      const text = await response.text();
      throw new Error(`API error: ${response.status} - ${text}`);
    }

    const data = await response.json();
    if (data && data.targetResponse && data.targetResponse.response) {
      return data.targetResponse.response;
    } else {
      throw new Error("Error Fetching Yacht Data");
    }
  }
