  function validateBANandBillType() {
    const ban =
      $("#BillingAccountNumber_NUM").val() ||
      Instanda.Variables.BillingAccountNumber_NUM;
    const banString = ban ? String(ban).trim() : "";

    const billtypechoice =
      $('input[name="BillingType_CHOICE"]:checked').val() ||
      Instanda.Variables.BillingType_CHOICE;

    // expected 3rd-from-last digit (hundreds digit of last 3)
    const expectedThirdFromLast =
      billtypechoice === "Direct" ?
        "4" :
        billtypechoice === "Mortgagee" ?
          "8" :
          billtypechoice === "Agency" ?
            "6" :
            null;

    const thirdFromLast =
      banString.length >= 3 ? banString.charAt(banString.length - 3) : null;

    const isThirdDigitCorrect =
      expectedThirdFromLast !== null &&
      thirdFromLast !== null &&
      thirdFromLast === expectedThirdFromLast;

    // isThirdDigitCorrect is true/false
    return isThirdDigitCorrect;
  }

  if ($(".page-postquotequestions.page-number-4.package-24337").length > 0) {
    function billMortgagee() {
      if (typeof isReadOnlyView === "function" && isReadOnlyView()) return;

      const billMortgageeFlag = Instanda?.Variables?.BillThisMortagagee_FLAG; // note: keep your exact variable name
      const $billType = $('input[name="BillingType_CHOICE"]:checked');

      // Handle 1 / "1" / true
      const isBillMortgagee =
        billMortgageeFlag === 1 ||
        billMortgageeFlag === "1" ||
        billMortgageeFlag === true;

      if ($billType.length === 0 && isBillMortgagee) {
        const $mortgagee = $(
          'input[name="BillingType_CHOICE"][value="Mortgagee"]'
        );
        if ($mortgagee.length)
          $mortgagee.prop("checked", true).trigger("change");
      }

      if (isBillMortgagee) {
        setTimeout(function () {
          var $existing = $("#ExistingBillingAcc_CHOICE");
          if ($existing.length) {
            $existing.val("No");
            $existing.attr("readonly", true);
            $existing.attr(
              `style`,
              `pointer-events: none; cursor: not-allowed`
            );
          }
        }, 700);
      }
    }

    billMortgagee();
  }

