  //Safe Run Function
  //Common
  function safeRun(fn, ...args) {
    try {
      const result = fn(...args);
      if (result instanceof Promise) {
        return result.catch((err) => {
          console.error(
            "Error in async function:",
            fn.name || "anonymous",
            err
          );
        });
      }
    } catch (err) {
      console.error("Error in function:", fn.name || "anonymous", err);
    }
  }

  // Function to add validation classes inside Multi Items

  // Function to parse a date in MM/DD/YYYY format
  //Common
  function parseDate(dateString) {
    let parts = dateString.split("/");
    let month = parseInt(parts[0], 10) - 1; // Months are zero-based in JavaScript
    let day = parseInt(parts[1], 10);
    let year = parseInt(parts[2], 10);
    return new Date(year, month, day);
  }
  //Auto
  // Function to calculate the difference in months between two dates, considering days for accuracy
  function dateDifferenceInMonths(date1, date2) {
    let d1 = parseDate(date1);
    let d2 = parseDate(date2);

    let years = d2.getFullYear() - d1.getFullYear();
    let months = d2.getMonth() - d1.getMonth();
    let days = d2.getDate() - d1.getDate();

    // Adjust months if days are negative
    if (days < 0) {
      months -= 1;
      // Calculate the number of days in the previous month
      let previousMonth = new Date(d2.getFullYear(), d2.getMonth(), 0);
      days += previousMonth.getDate();
    }
    return years * 12 + months + days / 30; // Approximate the fraction of the month
  }
