  // Function to check duplicate Driver License - EL
  // SCRIPT 3: Duplicate Driver License Detection
  if ($(".page-quickquotequestions.page-number-2.package-24428").length > 0) {
    const checkDup = () => {
      const seen = new Set();
      const dup = Array.from(
        document.querySelectorAll("[id*='li_Driver_MI'][id*='LicenseNo_TXT']")
      ).some((el) => {
        const lic = el.textContent.trim();
        if (lic && seen.has(lic)) return true;
        seen.add(lic);
        return false;
      });
      const field = document.getElementById("DuplicateLicenseFound_TXT");
      if (field) field.value = dup ? "TRUE" : "FALSE";
    };

    const continueBtn = $("button[name='continueButton']");
    continueBtn.on("click.checkDup", function (e) {
      e.preventDefault();
      checkDup();
      continueBtn.off("click.checkDup"); // Only your handler is removed
      setTimeout(() => continueBtn.click(), 100);
    });

    new MutationObserver(checkDup).observe(document.body, {
      childList: true,
      subtree: true,
    });
  }

