  //Excess Liability to set the Drivers/DOB on the Infractions Screen
  $(document).ready(function () {
    if (!$(".page-quickquotequestions.page-number-4.package-24428").length) return;

    const driverSelector = "[id^='Infractions_MI'][id$='_DriverFullName_TXT']";

    function applyMIFromDriverFullName(inputEl) {
      const rawFull = (inputEl.value || "").trim();
      if (!rawFull) return;

      const idMatch = (inputEl.id || "").match(/^Infractions_MI(\d+)_DriverFullName_TXT$/);
      const miNumber = idMatch ? idMatch[1] : null;
      if (!miNumber) return;

      const hasIndexDot = /^\s*\d+\.\s*/.test(rawFull);
      const rest = rawFull.replace(/^\s*\d+\.\s*/, "");
      const parts = rest.split(/\s+/).filter(Boolean);

      const dobIdx = parts.findIndex(p =>
        /^(0?[1-9]|1[0-2])\/(0?[1-9]|[12]\d|3[01])\/(19|20)\d{2}$/.test(p)
      );

      const dob = dobIdx >= 0 ? parts[dobIdx] : "";
      const lname = dobIdx >= 0 ? parts.slice(0, dobIdx).join(" ").trim() : rest;

      const $dob = $(`#Infractions_MI${miNumber}_C_DateofBirth_Auto_DATE`);
      const $name = $(`#Infractions_MI${miNumber}_C_DriverFLName_TXT`);

      const allowOverwrite = ($el) => {
        const current = ($el.val() || "").trim();
        const wasAutofilled = !!$el.data("autofilled-by-mi");
        return !current || wasAutofilled;
      };

      const setField = ($el, val) => {
        if (!val) return;
        if (!allowOverwrite($el)) return;
        $el.val(val)
          .data("autofilled-by-mi", true)
          .trigger("input")
          .trigger("change")
          .trigger("blur");
      };

      if (hasIndexDot && dob) {
        setField($name, lname);
        setField($dob, dob);
        try {
          if (typeof $dob.wiDatePicker === "function") $dob.wiDatePicker("setDate", dob);
        } catch (e) { }
      } else {
        setField($name, rawFull);
      }
    }

    // Bind ONCE (delegated)
    $(document)
      .off("blur.setDriverDOBAndNameForMI change.setDriverDOBAndNameForMI", driverSelector)
      .on("blur.setDriverDOBAndNameForMI change.setDriverDOBAndNameForMI", driverSelector, function () {
        applyMIFromDriverFullName(this);
      });

    // Run once on page load for any already-filled inputs
    $(driverSelector).each(function () {
      applyMIFromDriverFullName(this);
    });

    // If add-row creates a prefilled value, run once after DOM inserts
    $("#Infractions_MIaddButton")
      .off("click.setDriverDOBAndNameForMI")
      .on("click.setDriverDOBAndNameForMI", function () {
        setTimeout(() => {
          $(driverSelector).each(function () {
            applyMIFromDriverFullName(this);
          });
        }, 0);
      });
  });

