  //BH-18865 starts
  // Excess Liability - Adding logic to make fields optional during conversion.
  function HandleUnderlyingFields(container, miNumber) {
    const ConvPolicy = Instanda.Variables.ConvertedPolicy_YNP;
    const allFields = container.querySelectorAll(".underlying");
    if (allFields.length > 0) {
      allFields.forEach((fieldContainer) => {
        if (ConvPolicy === "No") {
          const inputs = fieldContainer.querySelectorAll(
            "input, select, textarea"
          );
          inputs.forEach((input) => {
            $(input).prop("required", true).attr("required", "required");
          });
          const mainLabel = fieldContainer.querySelector("label");
          if (mainLabel && !mainLabel.querySelector(".required-asterisk")) {
            mainLabel.insertAdjacentHTML(
              "beforeend",
              '<span class="required-asterisk" style="color:red;font-size:16px;"> *</span>'
            );
          }
        } else if (ConvPolicy === "Yes") {
          const inputs = fieldContainer.querySelectorAll(
            "input, select, textarea"
          );
          inputs.forEach((input) => {
            $(input).prop("required", false).removeAttr("required");
          });
          const mainLabel = fieldContainer.querySelector("label");
          if (mainLabel) {
            const asterisk = mainLabel.querySelector(".required-asterisk");
            if (asterisk) asterisk.remove();
          }
        }
      });
    }
  }

