  //Clean policy discount setting to yes /no based on claims and infractions on EL-page 4 and page 5
  (function () {
    function extractMINumber(element, prefix) {
      let id = element.id || "";
      let match = id.match(new RegExp(prefix + "(\\d+)"));
      if (!match) {
        for (let cls of element.classList) {
          let m = cls.match(new RegExp(prefix + "(\\d+)"));
          if (m) {
            match = m;
            break;
          }
        }
      }
      return match ? match[1] : null;
    }

    function isWithinLast5Years(dateStr) {
      if (!dateStr) return false;
      let date = new Date(dateStr);
      if (isNaN(date)) {
        const parts = dateStr.split("/");
        if (parts.length === 3) {
          const [mm, dd, yyyy] = parts;
          date = new Date(
            `${yyyy}-${mm.padStart(2, "0")}-${dd.padStart(2, "0")}`
          );
        }
      }
      if (isNaN(date)) return false;
      const now = new Date();
      const fiveYearsAgo = new Date(
        now.getFullYear() - 5,
        now.getMonth(),
        now.getDate()
      );
      return date >= fiveYearsAgo && date <= now;
    }

    function captureClaimsAndInfractionsDataWithMI() {
      const claimsData = [];
      const infractionsData = [];
      const claimPrefix = "AddClaim_MI";

      document
        .querySelectorAll('[class*="instanda-multi-item-AddClaim_MI"]')
        .forEach((parent) => {
          const miNum = extractMINumber(parent, claimPrefix);
          if (!miNum) return;
          const paidLossInput = document.getElementById(
            `AddClaim_MI${miNum}_PaidLossAmount1_NUM`
          );
          const dateOfLossInput = document.getElementById(
            `AddClaim_MI${miNum}_AddClaimDateofLoss_Date`
          );
          const paidLoss = +(paidLossInput?.value.replace(/,/g, "") || 0);
          const dateOfLoss = dateOfLossInput?.value;
          if (paidLoss && dateOfLoss) {
            claimsData.push({
              paidLoss,
              dateOfLoss,
              packageId: "24428",
            });
          }
        });

      const infractionPrefix = "Infractions_MI";
      document
        .querySelectorAll('[class*="instanda-multi-item-Infractions_MI"]')
        .forEach((parent) => {
          const miNum = extractMINumber(parent, infractionPrefix);
          if (!miNum) return;
          // FIXED: pointsInput is now declared
          const pointsInput = document.getElementById(
            `Infractions_MI${miNum}_C_Points_DI_NUM`
          );
          const violationDateInput = document.getElementById(
            `Infractions_MI${miNum}_Infraction_ViolationAccident_DATE`
          );
          const points = +(pointsInput?.value || 0);
          const violationDate = violationDateInput?.value;
          if (points && violationDate) {
            infractionsData.push({
              points,
              violationDate,
              packageId: "24428",
            });
          }
        });

      localStorage.setItem("claimsData", JSON.stringify(claimsData));
      localStorage.setItem("infractionsData", JSON.stringify(infractionsData));
    }

    function setCleanPolDiscSelection(selectYes) {
      var yesInput = document.getElementById("CleanPolDisc_YNYes");
      var noInput = document.getElementById("CleanPolDisc_YNNo");
      var yesLabel = yesInput ? yesInput.parentElement : null;
      var noLabel = noInput ? noInput.parentElement : null;

      if (yesInput && noInput && yesLabel && noLabel) {
        yesInput.removeAttribute("readonly");
        noInput.removeAttribute("readonly");
        yesInput.checked = !!selectYes;
        noInput.checked = !selectYes;
        yesLabel.classList.toggle("instanda-selected", !!selectYes);
        yesLabel.classList.toggle("instanda-unselected", !selectYes);
        noLabel.classList.toggle("instanda-selected", !selectYes);
        noLabel.classList.toggle("instanda-unselected", !!selectYes);
      }
    }

    function applyCleanPolicyDiscountWithMI() {
      const claimsData = JSON.parse(localStorage.getItem("claimsData")) || [];
      const infractionsData =
        JSON.parse(localStorage.getItem("infractionsData")) || [];
      let cleanDiscNo = false;
      claimsData.forEach((claim) => {
        if (claim.paidLoss >= 5000 && isWithinLast5Years(claim.dateOfLoss))
          cleanDiscNo = true;
      });
      infractionsData.forEach((infraction) => {
        if (
          infraction.points > 2 &&
          isWithinLast5Years(infraction.violationDate)
        )
          cleanDiscNo = true;
      });
      setCleanPolDiscSelection(!cleanDiscNo);
    }

    function onPageChange() {
      if (document.querySelector(".page-quickquotequestions.package-24428")) {
        const page4 = document.querySelector(
          ".page-quickquotequestions.page-number-4"
        );
        const page5 = document.querySelector(
          ".page-quickquotequestions.page-number-5"
        );
        if (page4) {
          document
            .querySelectorAll(
              '[class*="instanda-multi-item-AddClaim_MI"] input, [class*="instanda-multi-item-Infractions_MI"] input'
            )
            .forEach((input) => {
              if (!input._miListener) {
                input.addEventListener(
                  "change",
                  captureClaimsAndInfractionsDataWithMI
                );
                input.addEventListener(
                  "keyup",
                  captureClaimsAndInfractionsDataWithMI
                );
                input._miListener = true;
              }
            });
          captureClaimsAndInfractionsDataWithMI();
        }
        if (page5) {
          applyCleanPolicyDiscountWithMI();
        }
      }
    }

    let observer = new MutationObserver(() => {
      onPageChange();
    });
    observer.observe(document.body, {
      childList: true,
      subtree: true,
    });

    $(document).ready(function () {
      onPageChange();
    });
  })();

