  // this would make readonly questions editable during Conversion
  // should run only during conversion

  function removeReadonlyDuringConversion() {
    if (
      Instanda.Variables.ConvertedPolicy_YN === "Yes" ||
      Instanda.Variables.ConvertedPolicy_YNP === "Yes"
    ) {
      const targetQuestions = document.querySelectorAll(".conversion-editable");
      // Only proceed if elements with conversion-editable exist
      if (targetQuestions.length === 0) {
        return; // Nothing to do
      }
      console.log("inside removeReadonlyDuringConversion");
      targetQuestions.forEach((question) => {
        question.classList.remove("readonly");
        const input = question.querySelector("input");
        if (input) {
          input.removeAttribute("readonly");
          input.removeAttribute("disabled");
        }
        const select = question.querySelector("select");
        if (select) {
          select.removeAttribute("disabled");
          select.removeAttribute("readonly");
        }
      });
    }
  }

  $(document).ready(function () {
    removeReadonlyDuringConversion();
  });

