  ///////////////////////////////////////////////////// This code is on Policy Status - View Policy Page ////////////////////////////////////////////////////////////////////////////////////////////////////

  if ($(".page-viewquoteorpolicy").length > 0) {
    var today = new Date();
    var expirationDate = new Date(Instanda.Variables.ExpirationDate_DATE);

    function SetPolicyForNonRenewal(today, expirationDate) {
      if (
        Instanda.Variables.PolicyStatus_TXT === "Active" &&
        $(".block-renewals").find("input").is(":checked")
      ) {
        if (expirationDate > today) {
          $(".quote-card")
            .find("tr:nth-child(2)")
            .find("td:nth-child(1)")
            .text("Active and Set for Non-Renewal");
        } else if (
          expirationDate.getFullYear() === today.getFullYear() &&
          expirationDate.getMonth() === today.getMonth() &&
          expirationDate.getDate() === today.getDate()
        ) {
          $(".quote-card")
            .find("tr:nth-child(2)")
            .find("td:nth-child(1)")
            .text("Non-Renewed");
        }
      } else {
        $(".quote-card")
          .find("tr:nth-child(2)")
          .find("td:nth-child(1)")
          .text("Active");
      }
    }

    $(".block-renewals")
      .find("input")
      .on("change", () => {
        safeRun(() => SetPolicyForNonRenewal(today, expirationDate));
      });

    if ($(".block-renewals").find("input").is(":checked")) {
      safeRun(() => SetPolicyForNonRenewal(today, expirationDate));
    }
  }
