  // Parse vehicles for dropdown with index property for display
  function getVehiclesFromTextareaExcessLiability() {
    const textareaValue = Instanda.Variables.StoreVehicles_TXT;
    if (textareaValue) {
      const lines = textareaValue.split("\r\n");
      return lines
        .map((line) => {
          // Extract leading index before dot, if present
          const match = line.trim().match(/^(\d+)\.\s*(.*)$/);
          let idx, cleanLine;
          if (match) {
            idx = parseInt(match[1], 10);
            cleanLine = match[2];
          } else {
            idx = undefined; // fallback in case no leading number
            cleanLine = line.trim();
          }
          const parts = cleanLine.split(" ");
          const [year, make, ...rest] = parts;
          const model = rest.join(" ");
          return {
            year,
            make,
            model,
            idx,
          };
        })
        .filter((v) => v.idx && v.year && v.make && v.model);
    }
    return [];
  }

  function setupDropdownsForVehicleAssignmentsExcessLiability() {
    // vehicles list contains idx (from text, not line number)
    const vehicles = getVehiclesFromTextareaExcessLiability();
    document
      .querySelectorAll(
        ".prefill-vehicles .instanda-question-input, .instanda-well .prefill-vehicles .instanda-question-input"
      )
      .forEach((row) => {
        const vehicleInput = row.querySelector("input");
        if (vehicleInput) {
          bindInputWithDropdown(
            vehicleInput,
            vehicles,
            (v) => `${v.idx}. ${v.year} ${v.make} ${v.model}`
          );
        }
      });
  }

  // Initialize dropdowns for vehicle assignment (for page 5)
  if ($(".page-quickquotequestions.page-number-5.package-24428").length > 0) {
    // Wait 10 seconds before initial setup
    setTimeout(() => {
      setupDropdownsForVehicleAssignmentsExcessLiability();
    }, 2);

    // Also setup on DOMContentLoaded with timer
    window.addEventListener("DOMContentLoaded", () => {
      setTimeout(() => {
        setupDropdownsForVehicleAssignmentsExcessLiability();
      }, 2);
    });

    // Listen for multi-item add button clicks (for when user adds new items)
    $(document).on("click", ".instanda-multi-item-add", function () {
      setTimeout(() => {
        setupDropdownsForVehicleAssignmentsExcessLiability();
      }, 2); // 1 second delay after adding new item
    });

    // Listen for multi-item remove button clicks
    $(document).on("click", ".instanda-multi-item-remove", function () {
      setTimeout(() => {
        setupDropdownsForVehicleAssignmentsExcessLiability();
      }, 2); // 1 second delay after removing item
    });

    // Use MutationObserver to detect when new multi-items are added to DOM
    const observer = new MutationObserver(function (mutations) {
      mutations.forEach(function (mutation) {
        if (mutation.addedNodes.length > 0) {
          mutation.addedNodes.forEach(function (node) {
            if (
              node.nodeType === 1 &&
              (node.classList?.contains("prefill-vehicles") ||
                node.querySelector?.(".prefill-vehicles"))
            ) {
              setTimeout(() => {
                setupDropdownsForVehicleAssignmentsExcessLiability();
              }, 2);
            }
          });
        }
      });
    });

    // Observe the main content area for changes
    const targetNode =
      document.querySelector(".instanda-question-group") || document.body;
    observer.observe(targetNode, {
      childList: true,
      subtree: true,
    });
  }

