  //BH - 19595 Support for Conversion and NB Go Live – Auto and Excess Liability (PEL) Lines
  $(document).ready(function () {
    if (
      $(".page-quickquotequestions.page-number-6.package-24338").length > 0 ||
      $(".page-quickquotequestions.page-number-3.package-24428").length > 0
    ) {
      function mmddyyyyToDate(str) {
        const [mm, dd, yyyy] = str.split("/");
        return new Date(`${yyyy}-${mm}-${dd}`);
      }

      function restrictOpts(id, remove) {
        const s = document.getElementById(id);
        if (!s) return;
        Array.from(s.options).forEach((o) => {
          o.style.display = remove.includes(o.value) ? "none" : "";
          // If the currently selected value is now hidden, clear it and trigger change
          if (s.value === o.value && remove.includes(o.value)) {
            s.value = "";
            s.dispatchEvent(new Event("change"));
          }
        });
      }

      const effDate = formatDateToMMDDYYYY(
        Instanda.Variables.EffectiveDate_DATE
      );

      // Hawaii restrictions
      if (
        $(".package-24338").length > 0 &&
        Instanda.Variables.PremiumState_CHOICE === "Hawaii" &&
        mmddyyyyToDate(effDate) >= mmddyyyyToDate("01/01/2026") &&
        Instanda.Variables.ConvertedPolicy_YN === "Yes"
      ) {
        const fieldLimitMap = {
          BodilyInjValueOtStates: ["$20,000/$40,000", "$35,000/$70,000"],
          UMBILimitVal: ["$20,000/$40,000", "$35,000/$70,000"],
          UIMBILimitVal: ["$20,000/$40,000", "$35,000/$70,000"],
          UMPDLimitValue: ["$10,000", "$15,000"],
          PDLimitValue: ["$10,000.00", "$15,000.00"],
        };
        Object.entries(fieldLimitMap).forEach(([fieldId, restrictedValues]) =>
          restrictOpts(fieldId, restrictedValues)
        );
      } else if (
        $(".package-24338").length > 0 &&
        Instanda.Variables.PremiumState_CHOICE === "Hawaii"
      ) {
        restrictOpts("BodilyInjValueOtStates", ["$40,000/$80,000"]);
        restrictOpts("UMBILimitVal", ["$40,000/$80,000"]);
        restrictOpts("UIMBILimitVal", ["$40,000/$80,000"]);
      }

      // New Jersey restrictions
      if (
        $(".package-24338").length > 0 &&
        Instanda.Variables.PremiumState_CHOICE === "New Jersey" &&
        mmddyyyyToDate(effDate) >= mmddyyyyToDate("01/01/2026") &&
        Instanda.Variables.PolicyType_CHOICE === "STANDARD" &&
        Instanda.Variables.ConvertedPolicy_YN === "Yes"
      ) {
        restrictOpts("BodilyInjValueNJ", ["$25,000/$50,000"]);
        restrictOpts("PDLimitValue", ["$25,000.00", "$50,000.00"]);
        restrictOpts("UMBILimitVal", [
          "$25,000/$50,000",
          "$20,000/$40,000",
          "$15,000/$30,000",
          "$15,000/$30,000",
          "$20,000/$40,000",
          "$25,000/$50,000",
        ]);
        restrictOpts("UMPDLimitValue", ["$25,000", "$50,000"]);
      } else if (
        $(".package-24338").length > 0 &&
        Instanda.Variables.PremiumState_CHOICE === "New Jersey"
      ) {
        restrictOpts("BodilyInjValueNJ", ["$35,000/$70,000"]);
        restrictOpts("UMBILimitVal", ["$35,000/$70,000"]);
      }

      // EPLICov restrictions (after Dec 2025)
      if (
        $(".package-24428").length > 0 &&
        mmddyyyyToDate(effDate) >= mmddyyyyToDate("12/01/2025") &&
        Instanda.Variables.ConvertedPolicy_YNP === "Yes" &&
        Instanda.Variables.ProductCode_CHOICE === "Non-Admitted"
      ) {
        function updateEPLICov() {
          const d = $("#DefenseCosts_CHOICE").val();
          const n = parseInt($("#NoOfEmployees_CHOICE").val(), 10);
          if (d === "Outside Limit" && n <= 10) {
            restrictOpts("EPLIPerOccLimitNA_CHOICE", [
              "$1,000,000",
              "$2,000,000",
              "$3,000,000",
              "$4,000,000",
              "$5,000,000",
            ]);
            restrictOpts("EPLIAggregateLimNA_CHOICE", [
              "$1,000,000",
              "$2,000,000",
              "$3,000,000",
              "$4,000,000",
              "$5,000,000",
            ]);
          } else {
            restrictOpts("EPLIPerOccLimitNA_CHOICE", []); // No restrictions: show all
            restrictOpts("EPLIAggregateLimNA_CHOICE", []);
          }
        }
        $("#DefenseCosts_CHOICE, #NoOfEmployees_CHOICE").on(
          "change",
          updateEPLICov
        );
        updateEPLICov();
      }
    }
  });

