  function getCountOfCustomerNotices() {
    if (isReadOnlyView()) {
      console.log('Read-only view');
      return;
    }

    const qRef = String(Instanda?.Variables?.QuoteRef || '');
    const customerId = String(Instanda?.Variables?.CustomerID_TXT || '');
    const policyNum = String(Instanda?.Variables?.PolicyNumber || '');

    const body = {
      quoteDetails: {
        quoteRef: qRef
      },
      CustomerDetails: {
        Id: customerId
      },
      policyDetails: {
        policyNumber: policyNum,
        numberOfYears: '5'
      }
    };

    console.log('Request Body:', body)

    const endpointConfig = getApiEndpoint('customerNotices');

    if (!endpointConfig?.apiBaseUrl || !endpointConfig?.subscriptionKey) {
      console.error('Missing API endpoint configuration for customerNotices');
      return;
    }

    const {
      apiBaseUrl,
      subscriptionKey
    } = endpointConfig;

    const siteCssLink = document.querySelector('link[href*="SiteCustomCss"]');
    const siteId = siteCssLink?.href?.match(/siteId=(\d+)/)?.[1] || null;

    const apiEndpoint =
      siteId === '2913' ?
        `${apiBaseUrl}/dcbilling/v1.2/getCustomerNotices` :
        `${apiBaseUrl}/dcbilling/v1/getCustomerNotices`;

    fetch(apiEndpoint, {
      method: 'POST',
      headers: generateHeaders(subscriptionKey),
      body: JSON.stringify(body)
    })
      .then(async (res) => {
        if (!res.ok) {
          const text = await res.text().catch(() => '');
          throw new Error(`HTTP ${res.status}: ${text || res.statusText}`);
        }
        const text = await res.text();
        return text ? JSON.parse(text) : null;
      })
      .then((data) => {
        console.log('Customer notices response:', data);

        const notices = data?.targetResponse?.response ?? [];

        let frnCount = 0;
        let cncCount = 0;
        let nocCount = 0;

        for (const n of notices) {
          const t = (n?.noticeType ?? '').toString().toUpperCase();
          if (t === 'FRN') frnCount += 1;
          else if (t === 'CNC') cncCount += 1;
          else if (t === 'NOC') nocCount += 1;
        }

        console.log('FRN:', frnCount);
        console.log('CNC:', cncCount);
        console.log('NOC:', nocCount);
        console.log('All counts:', {
          frnCount,
          cncCount,
          nocCount
        });

        $('#frnCount_NUM').val(frnCount)
        $('#cncCount_NUM').val(cncCount)
        $('#nocCount_NUM').val(nocCount)

      })
      .catch((error) => {
        console.error('Error:', error);
        if (Instanda.Variables.PCSReferralLevel <= 3) {
          displayApiErrorMessage(
            'Please contact Customer Care Center 866-856-6858 or reach out to the underwriter.'
          );
        } else {
          displayApiErrorMessage(
            'An error occurred while retrieving cancellation notices: ' + error.message
          );
        }
      });
  }


  // Calling getCountOfCustomerNotices function
  $(document).ready(function () {
    const onTargetPage = $('.page-quickquotequestions.page-number-4.package-24338').length > 0;
    const isMtaOrRenewal = !!(Instanda?.Variables?.IsRenewal || Instanda?.Variables?.IsMTA);

    if (!onTargetPage || !isMtaOrRenewal) return;
    getCountOfCustomerNotices(); // call it
  });

