  function retrievePolicyId() {
    return new Promise(async (resolve, reject) => {
      const policyNumber = Instanda?.Variables?.PolicyNumber ?
        formatToTenDigits(String(Instanda.Variables.PolicyNumber)) :
        "";

      const {
        apiBaseUrl,
        subscriptionKey
      } = getApiEndpoint("phase2");
      const siteCssLink = document.querySelector('link[href*="SiteCustomCss"]');
      let siteId = null;

      if (siteCssLink) {
        const match = siteCssLink.href.match(/siteId=(\d+)/);
        if (match) {
          siteId = match[1];
        }
      }

      let apiEndpoint;
      if (siteId === "2913") {
        apiEndpoint = `${apiBaseUrl}/salesforce/v1.2/retrievePolicyId`;
      } else {
        apiEndpoint = `${apiBaseUrl}/salesforce/v1/retrievePolicyId`;
      }

      const body = {
        policyNumber,
      };

      console.log("Request Body:", body);

      try {
        const response = await fetch(apiEndpoint, {
          method: "POST",
          headers: generateHeaders(subscriptionKey),
          body: JSON.stringify(body),
        });

        if (!response.ok) {
          throw new Error(`API request failed with status ${response.status}`);
        }

        const data = await response.json();
        console.log(data);
        const recordID = data.targetResponse?.response?.sfPolicyId;
        console.log(recordID);

        resolve(recordID);
      } catch (error) {
        displayApiErrorMessage(
          "Error retrieving policy ID or opening Salesforce record:",
          error
        );
        console.error(
          "Error retrieving policy ID or opening Salesforce record:",
          error
        );
        reject(null);
      }
    });
  }

  //OFAC Handling ///

  async function getOfacScreeningResult(event) {
    showSpinner();

    try {
      // Read-only check
      if (
        (typeof isReadOnlyView === "function" && isReadOnlyView()) ||
        $(".readonlymode").length > 0
      ) {
        hideSpinner();
        console.log("Read-only view");
        return false; // This prevents further OFAC logic!
      }

      if (
        Instanda.Variables.OFAC_STATUS_TXT === "Cleared" || $("#OFAC_STATUS_TXT").val() === "Cleared") {
        return false;
      }

      const quoteData = await getQuoteData(event);
      const quoteRef = Instanda?.Variables?.QuoteRef;

      // Helper to get address fields
      function getAddressFields(qd) {
        return {
          addressLine1: qd.MA_AddressLine1_TXT ||
            qd.RiskAddressLine1RO_TXT ||
            qd.CO_RiskAddressLine1RO_TXT ||
            "",
          addressLine2: qd.MA_AddressLine2_TXT ||
            qd.RiskAddressLine2RO_TXT ||
            qd.CO_RiskAddressLine2RO_TXT ||
            "",
          city: qd.MA_City_TXT || qd.RiskCityRO_TXT || qd.CO_RiskCityRO_TXT || "",
          stateProvince: qd.MA_State_CHOICE ||
            qd.RiskStateRO_TXT ||
            qd.CO_RiskStateRO_TXT ||
            "",
          country: qd.MA_Country_CHOICE ||
            qd.RiskCountryRO_TXT ||
            qd.CO_RiskCountryRO_TXT ||
            "",
          postalCode: qd.MA_Zip_NUM ||
            qd.RiskPostCodeRO_TXT ||
            qd.CO_RiskPostCodeRO_TXT ||
            "",
        };
      }

      // Main insured
      let entityType1 = quoteData.Name_Type_CHOICEP;
      let entityType =
        entityType1 === "Individual" ?
          "Individual" :
          entityType1 === "Business" ?
            "Business" :
            "Unknown";
      let mainEntity = {
        entityType: entityType,
        firstName: entityType === "Individual" ? quoteData.FirstName_TXT : "NA",
        middleName: entityType === "Individual" ? quoteData.MiddleName_TXT : "",
        lastName: entityType === "Individual" ? quoteData.LastName_TXT : "NA",
        name: quoteData.NamedInsured_TXT ||
          quoteData.FirstName_TXT + quoteData.LastName_TXT,
        dob: entityType === "Individual" ?
          formatDateToDDMMYYYY(quoteData.DOB_DATE) : "",
        ...getAddressFields(quoteData),
      };

      // Country/State logic for main insured
      if (!["US", "CA"].includes(mainEntity.country)) {
        mainEntity.stateProvince = "INT";
      }

      // Additional Named Insureds handling
      const packageID = Instanda?.Variables?.PackageId;

      // Helper to push additional insureds
      function getAdditionalEntities(arr, mappingFn) {
        let entities = [];
        if (Array.isArray(arr) && arr.length > 0) {
          arr.forEach((additional) => {
            let entity = mappingFn(additional, quoteData);
            entities.push(entity);
          });
        }
        return entities;
      }

      // Initialize entityDetails with just mainEntity
      let entityDetails = [mainEntity];

      // Package-specific logic for additional named insureds
      let additionalEntities = [];

      if ([24428, 24338].includes(packageID)) {
        additionalEntities = getAdditionalEntities(
          quoteData.AdditionalNameInsured_MI,
          (add, qd) => {
            // Normalize entity type for additional insured
            let entityType1 = add.AdditionalNamedType_CHOICEP;
            let entityType =
              entityType1 === "Individual" ?
                "Individual" :
                entityType1 === "Business" ?
                  "Business" :
                  "Unknown";

            return {
              entityType: entityType,
              firstName: entityType === "Individual" ?
                add.AddInsuredFirstName_TXT : "NA",
              middleName: entityType === "Individual" ?
                add.AddInsuredMiddleName_TXT || "" : "",
              lastName: entityType === "Individual" ? add.AddInsuredLastName_TXT : "NA",
              name: add.AdditionalName_TXT ||
                add.AddInsuredFirstName_TXT + add.AddInsuredLastName_TXT,
              dob: entityType === "Individual" ?
                add.AddInsuredDOB_DATE ?
                  formatDateToDDMMYYYY(add.AddInsuredDOB_DATE) :
                  "" : "",
              ...getAddressFields(qd),
            };
          }
        );
      }

      // Drivers for Auto and EL
      if ([24428, 24338].includes(packageID)) {
        additionalEntities = additionalEntities.concat(
          getAdditionalEntities(quoteData.Driver_MI, (add, qd) => ({
            entityType: "Individual",
            firstName: add.D_FirstName_TXT,
            middleName: add.D_MiddleName_TXT || "",
            lastName: add.D_LastName_TXT,
            name: add.D_FirstName_TXT + add.D_LastName_TXT,
            dob: formatDateToDDMMYYYY(add.D_DOB_DATE),
            ...getAddressFields(qd),
          }))
        );
      }

      // LienHolders
      if ([24338].includes(packageID)) {
        additionalEntities = additionalEntities.concat(
          getAdditionalEntities(quoteData.Lienholder_MI, (add, qd) => {
            let country = add.Lienh_Country_CHOICE;
            let stateProvince = add.Lienh_State_CHOICE;
            return {
              entityType: "Business",
              firstName: add.Lienh_Name_TXT,
              middleName: "",
              lastName: add.Lienh_Name_TXT,
              name: add.Lienh_Name_TXT,
              dob: "",
              addressLine1: add.Lienh_AddressLine1_TXT,
              addressLine2: add.Lienh_AddressLine2_TXT,
              city: add.Lienh_City_TXT,
              stateProvince: stateProvince,
              country: country,
              postalCode: add.Lienh_ZipCode_TXT,
            };
          })
        );
      }

      if ([24518, 24588, 24337].includes(packageID)) {
        additionalEntities = getAdditionalEntities(
          quoteData.AdditionalNameInsured_MI,
          (add, qd) => ({
            entityType: "Individual",
            firstName: add.AddInsuredFirstName_TXT,
            middleName: add.AddInsuredMiddleName_TXT || "",
            lastName: add.AddInsuredLastName_TXT,
            name: add.AdditionalName_TXT ||
              add.AddInsuredFirstName_TXT + add.AddInsuredLastName_TXT,
            dob: formatDateToDDMMYYYY(add.AddInsuredDOB_DATE),
            ...getAddressFields(qd),
          })
        );
      }

      // Mortgagee
      if ([24337].includes(packageID)) {
        additionalEntities = additionalEntities.concat(
          getAdditionalEntities(quoteData.Mortgagee_MI, (add, qd) => {
            let country = add.MortgageeCountry_TXT1;
            let stateProvince = add.MortgageeState1_TXT;
            return {
              entityType: "Business",
              firstName: add.Mortgagee_NameOfLender1_TXT,
              middleName: "",
              lastName: add.Mortgagee_NameOfLender1_TXT,
              name: add.Mortgagee_NameOfLender1_TXT,
              dob: "",
              addressLine1: add.MortgageeAddressLine1_TXT1,
              addressLine2: add.MortgageeAddressLine2_TXT1,
              city: add.MortgageeCity_TXT1,
              stateProvince: stateProvince,
              country: country,
              postalCode: add.MortgageePostcode_TXT1,
            };
          })
        );
      }

      if ([24518, 24588].includes(packageID)) {
        additionalEntities = additionalEntities.concat(
          getAdditionalEntities(quoteData.MortgageeSchedule_MI, (add, qd) => {
            let country = add.Mrtg_CountryMR_TXT;
            let stateProvince = add.Mrtg_State_TXT;
            return {
              entityType: "Business",
              firstName: add.MortgageeName_TXT,
              middleName: "",
              lastName: add.MortgageeName_TXT,
              name: add.MortgageeName_TXT,
              dob: "",
              addressLine1: add.Mrtg_AddressLine1_TXT,
              addressLine2: add.Mrtg_AddressLine2_TXT,
              city: add.Mrtg_City_TXT,
              stateProvince: stateProvince,
              country: country,
              postalCode: add.Mrtg_Postcode_TXT,
            };
          })
        );
      }

      if (packageID === 23424) {
        additionalEntities = getAdditionalEntities(
          quoteData.AdditionalNameInsured_MI,
          (add, qd) => ({
            entityType: "Individual",
            firstName: add.CO_AdditionalName_TXT,
            middleName: "",
            lastName: add.CO_AdditionalName_TXT,
            name: add.CO_AdditionalName_TXT,
            dob: formatDateToDDMMYYYY(add.AddlDOB_DATE),
            ...getAddressFields(qd),
          })
        );
      }

      if (packageID === 23423) {
        additionalEntities = getAdditionalEntities(
          quoteData.YT_AdditionalNamedInsuredMI,
          (add, qd) => {
            let country = add.YT_AddInsuredCountry_CHOICE;
            let stateProvince = add.YT_AddInsuredState_CHOICE;
            return {
              entityType: "Individual",
              firstName: add.YT_AdditionalNamedInsured_TXT,
              middleName: "",
              lastName: add.YT_AdditionalNamedInsured_TXT,
              name: add.NamedAddInsured_TXT || add.YT_AdditionalNamedInsured_TXT,
              dob: formatDateToDDMMYYYY(add.AddlDOB_DATE),
              addressLine1: add.YT_AddInsuredAddressLine1_TXT,
              addressLine2: add.YT_AddInsuredAddressLine2_TXT,
              city: add.YT_AddInsuredCity_CHOICE,
              stateProvince: stateProvince,
              country: country,
              postalCode: add.YT_AddInsuredZip_NUM,
            };
          }
        );
      }

      // Apply country/state logic for all additionalEntities
      additionalEntities = additionalEntities.map((entity) => {
        if (!["US", "CA"].includes(entity.country)) {
          return {
            ...entity,
            stateProvince: "INT",
          };
        }
        return entity;
      });

      // If there are additional named insureds, add them to entityDetails
      if (additionalEntities.length > 0) {
        entityDetails = [mainEntity, ...additionalEntities];
      }

      // Prepare request body
      const body = {
        quoteRef: String(quoteRef),
        quoteStatus: "Active",
        entityDetails: entityDetails,
      };

      // API call
      const {
        apiBaseUrl,
        subscriptionKey
      } = getApiEndpoint("phase2");
      const apiEndpoint = `${apiBaseUrl}/lexisnexis/v1/getOfacScreeningResult`;
      const headers = generateHeaders(subscriptionKey);

      const response = await fetch(apiEndpoint, {
        method: "POST",
        headers: headers,
        body: JSON.stringify(body),
        redirect: "follow",
      });

      if (!response.ok) {
        throw new Error("Ofac Screening Failed. Please try again later");
      }

      // Parse response and extract screeningStatus
      const vendorResponse = await response.json();
      const screeningStatus =
        vendorResponse?.vendorResponse?.response?.screeningStatus;

      // Update quote/policy data with screeningStatus
      const updateBody = {
        OFAC_STATUS_TXT: screeningStatus,
      };
      await updateQuoteorPolicydata(event, updateBody);

      hideSpinner();

      // Return full response and screeningStatus for further use
      return {
        vendorResponse,
        screeningStatus,
      };
    } catch (error) {
      hideSpinner();
      console.error(error);
      throw error;
    }
  }

  // Calling ofac on quote for all products
  if ($(".page-quote").length > 0) {
    var isConvertedPolicyNo =
      Instanda.Variables.ConvertedPolicy_YN === "Yes" ||
      Instanda.Variables.ConvertedPolicy_YNP === "Yes";
    var isExcludedPackage =
      $(".package-23423").length > 0 || $(".package-23424").length > 0;
    if (!(isConvertedPolicyNo && isExcludedPackage)) {
      getOfacScreeningResult();
    }
  }

  //Hide issue button if ofac status is Hit/Blocked
  async function handleOfacButtonHide(event) {
    if (
      $(".page-postquotequestions.page-number-2.package-24338").length > 0 ||
      $(".page-postquotequestions.page-number-2.package-24428").length > 0 ||
      $(".page-postquotequestions.page-number-3.package-24518").length > 0 ||
      $(".page-postquotequestions.page-number-4.package-24588").length > 0 ||
      $(".page-postquotequestions.page-number-5.package-24337").length > 0 ||
      $(".page-postquotequestions.page-number-1.package-23423").length > 0 ||
      $(".page-postquotequestions.page-number-2.package-23424").length > 0
    ) {
      // const quoteData = await getQuoteData(event);
      if (
        //  quoteData.OFAC_STATUS_TXT === "Hit" ||
        //  quoteData.OFAC_STATUS_TXT === "Blocked" ||
        Instanda.Variables.OFAC_STATUS_TXT === "Hit" ||
        Instanda.Variables.OFAC_STATUS_TXT === "Blocked" ||
        $("#OFAC_STATUS_TXT").val() === "Hit" ||
        $("#OFAC_STATUS_TXT").val() === "Blocked"
      ) {
        // $('.instanda-quote-button').addClass('ofac-hide-issuance-btn');
        if (Instanda.Variables.SalespersonReferralLevel <= 3) {
          displayApiErrorMessage(
            "Requires PCS Review Prior to Issuance. Try again in 24 hours."
          );
        } else if (Instanda.Variables.SalespersonReferralLevel > 3) {
          displayApiErrorMessage(
            "Potential OFAC Issue: Case is under review. Try again in 24 hours."
          );
        }
        return false; // OFAC check failed
      } else {
        //  $('.instanda-quote-button').removeClass('ofac-hide-issuance-btn');
        return true; // OFAC check passed
      }
    }
    return true; // No OFAC check needed for non-specified pages
  }

