  function mapLicenseStatusToInitCap(status) {
    const mapping = {
      VALID: "Valid",
      "": "Valid",
      EXPIRED: "Expired",
      UNKNOWN: "Unknown",
      "SUSPENDED/REVOKED": "Suspended/Revoked",
      SUSPENDED: "Suspended/Revoked",
      REVOKED: "Suspended/Revoked",
      INACTIVE: "Expired",
    };
    return mapping[status] || "Unknown";
  }

  function formatDateToMMDDYYYYbackup(date, addDays = 0) {
    if (!(date instanceof Date)) date = new Date(date);
    if (addDays) date.setDate(date.getDate() + addDays);
    const mm = String(date.getMonth() + 1).padStart(2, "0");
    const dd = String(date.getDate()).padStart(2, "0");
    const yyyy = date.getFullYear();
    return `${mm}/${dd}/${yyyy}`;
  }
  // BH-20730 added below function by renaming above function formatDateToMMDDYYYYbackup to backup. Managequote api was failing due to NaNaNa DOB.
  function formatDateToMMDDYYYY(date, addDays = 0) {
    if (!date) return ""; // Handle empty/null/undefined input up front
    if (!(date instanceof Date)) date = new Date(date);
    if (isNaN(date.getTime())) return ""; // Check for invalid date
    if (addDays) date.setDate(date.getDate() + addDays);
    const mm = String(date.getMonth() + 1).padStart(2, "0");
    const dd = String(date.getDate()).padStart(2, "0");
    const yyyy = date.getFullYear();

    return `${mm}/${dd}/${yyyy}`;
  }

  function addOneDay(dateStr) {
    if (!dateStr) return "";
    let parts;
    if (dateStr.includes("/")) {
      parts = dateStr.split("/");
      if (parts[2].length === 4 && parts[0].length === 2) {
        // dd/mm/yyyy
        const date = new Date(`${parts[2]}-${parts[1]}-${parts[0]}`);
        if (isNaN(date)) return "";
        date.setDate(date.getDate() + 1);
        return formatDateToMMDDYYYY(date, 0);
      }
    }
    const date = new Date(dateStr);
    if (isNaN(date)) return "";
    date.setDate(date.getDate() + 1);
    return formatDateToMMDDYYYY(date, 0);
  }

  function addOneDayUTC(dateStr) {
    if (!dateStr) return "";

    let parts;
    let yyyy, mm, dd;

    if (dateStr.includes("/")) {
      parts = dateStr.split("/");
      if (parts[2].length === 4 && parts[0].length === 2) {
        // dd/mm/yyyy
        dd = parseInt(parts[0], 10);
        mm = parseInt(parts[1], 10) - 1;
        yyyy = parseInt(parts[2], 10);
        // Use Date.UTC to avoid local timezone interpretation
        const date = new Date(Date.UTC(yyyy, mm, dd));
        if (isNaN(date)) return "";
        // Add a day (in UTC)
        date.setUTCDate(date.getUTCDate() + 1);

        return formatDateToMMDDYYYYUTC(date, 1); // 1 if format function expects UTC
      }
    }
    const date = new Date(dateStr);
    if (isNaN(date)) return "";

    date.setUTCDate(date.getUTCDate() + 1);

    return formatDateToMMDDYYYYUTC(date, 1);
  }

  function formatDateToDDMMYYYYUTCCreditscore(input) {
    if (input == null) return "";

    const pad2 = (n) => String(n).padStart(2, "0");

    // If it's already a Date, format using UTC parts (prevents local TZ shifts)
    if (input instanceof Date) {
      const d = input.getUTCDate();
      const m = input.getUTCMonth() + 1;
      const y = input.getUTCFullYear();
      return `${pad2(d)}/${pad2(m)}/${y}`;
    }

    const s = String(input).trim();

    // Handles ISO strings like "1980-07-03T04:00:00" / "1980-07-03T04:00:00Z" / "1980-07-03"
    // Uses the YYYY-MM-DD part as-written (no timezone shifting)
    let match = s.match(/^(\d{4})-(\d{2})-(\d{2})(?:[T\s]|$)/);
    if (match) {
      const y = match[1];
      const m = match[2];
      const d = match[3];
      return `${d}/${m}/${y}`;
    }

    // Input is MM/DD/YYYY (optionally with time) -> output DD/MM/YYYY
    match = s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})(?:\s|$)/);
    if (match) {
      const mm = Number(match[1]);
      const dd = Number(match[2]);
      const yyyy = Number(match[3]);
      return `${pad2(dd)}/${pad2(mm)}/${yyyy}`;
    }

    // Last-resort fallback: parse as Date and format in UTC (may vary if input is ambiguous)
    const dt = new Date(s);
    if (Number.isNaN(dt.getTime())) return "";

    return `${pad2(dt.getUTCDate())}/${pad2(
      dt.getUTCMonth() + 1
    )}/${dt.getUTCFullYear()}`;
  }

  function formatDateToYYYYMMUTCCreditscore(input) {
    if (input == null) return "";

    const pad2 = (n) => String(n).padStart(2, "0");

    if (input instanceof Date) {
      return `${input.getUTCFullYear()}/${pad2(input.getUTCMonth() + 1)}/${pad2(
        input.getUTCDate()
      )}`;
    }

    const s = String(input).trim();

    let match = s.match(/^(\d{4})-(\d{2})-(\d{2})(?:[T\s]|$)/);
    if (match) return `${match[1]}/${match[2]}/${match[3]}`;

    match = s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})(?:\s|$)/);
    if (match)
      return `${match[3]}/${pad2(Number(match[1]))}/${pad2(Number(match[2]))}`;

    const dt = new Date(s);
    if (Number.isNaN(dt.getTime())) return "";
    return `${dt.getUTCFullYear()}/${pad2(dt.getUTCMonth() + 1)}/${pad2(
      dt.getUTCDate()
    )}`;
  }

  function formatDateToMMDDYYYYUTC(date, utcFlag) {
    const mm = utcFlag ? date.getUTCMonth() + 1 : date.getMonth() + 1;
    const dd = utcFlag ? date.getUTCDate() : date.getDate();
    const yyyy = utcFlag ? date.getUTCFullYear() : date.getFullYear();
    return (
      (mm < 10 ? "0" : "") + mm + "/" + (dd < 10 ? "0" : "") + dd + "/" + yyyy
    );
  }

  // Helper for date formatting
  function formatDateToDDMMYYYY(dateStr) {
    if (!dateStr) return "";
    const date = new Date(dateStr);
    const mm = String(date.getMonth() + 1).padStart(2, "0");
    const dd = String(date.getDate()).padStart(2, "0");
    const yyyy = date.getFullYear();
    return `${dd}/${mm}/${yyyy}`;
  }

  // Start :BH-11174 API
  async function getSoilGradeAndDistance() {
    let errorMessage = [];
    try {
      const packageId = Instanda.Variables.PackageId;
      if (packageId != 24337 || isReadOnlyView()) {
        return;
      }
      if (typeof showSpinner === "function") {
        showSpinner();
      }
      const quoteData = Instanda.Variables;
      if (quoteData.RiskStateRO_TXT != "CA") {
        return;
      }
      const body = {
        quoteDetails: {
          quoteRef: quoteData.QuoteRef,
        },
        address: {
          admin1Code: quoteData.RiskStateRO_TXT, //mandatory state ?
          cityName: quoteData.RiskCityRO_TXT,
          countryCode: "US", //mandatory
          countryName: "United States",
          countryScheme: "ISO2A", //mandatory ? constant
          latitude: quoteData.RiskAddress_Latitude_TXT, //mandatory
          longitude: quoteData.RiskAddress_Longitude_TXT, //mandatory
          postalCode: String(quoteData.RiskPostCodeRO_TXT),
          streetAddress: quoteData.RiskAddressLine1RO_TXT,

          countryRmsCode: "US", //mandatory ? constant
          rmsGeoModelResolutionCode: 2, //mandatory ? constant
        },
      };
      if (!body.address.longitude || !body.address.latitude) {
        return;
      }

      const {
        apiBaseUrl,
        subscriptionKey
      } = getApiEndpoint("phase2");
      const headers = generateHeaders(subscriptionKey);
      // soil details api endpoint
      const apiEndpointSoilGrade = `${apiBaseUrl}/moodys/v1/getSoilTypeDetails`;
      // distance to fault api endpoint
      const apiEndPointDistanceToFault = `${apiBaseUrl}/moodys/v1/getDistanceToFaultDetails`;
      // Get Soil Grade..
      const fetchSoilGrade = fetch(apiEndpointSoilGrade, {
        method: "POST",
        headers: headers,
        body: JSON.stringify(body),
      });
      // Get Distance Fault
      const fetchDistanceFault = fetch(apiEndPointDistanceToFault, {
        method: "POST",
        headers: headers,
        body: JSON.stringify({
          ...body,
          measurementUnit: {
            distanceUnit: "miles", //mandatory?
          },
        }),
      });
      const [soilRes, distanceFRes] = await Promise.all([
        fetchSoilGrade,
        fetchDistanceFault,
      ]);

      if (!soilRes.ok) {
        console.log(
          "BH-11174 No Soil grade information found for current detials"
        );
        try {
          const errorDetails = await soilRes.json();
          if (errorDetails.details) {
            errorMessage.push(errorDetails.details);
          }
        } catch (error) {
          errorMessage.push("API Failed to fetch data for Soil Grade");
        }
      }
      if (!distanceFRes.ok) {
        console.log(
          "BH-11174 No Distance Fault information found for current detials"
        );
        try {
          const errorDetails = await distanceFRes.json();
          if (errorDetails.details) {
            errorMessage.push(errorDetails.details);
          }
        } catch (error) {
          errorMessage.push("API Failed to fetch data for Fault Distance");
        }
      }

      const soilGradeData = await soilRes.json();
      // console.log(soilGradeData);
      if (
        soilGradeData &&
        typeof soilGradeData == "object" &&
        soilGradeData.vendorResponse &&
        soilGradeData.vendorResponse?.response
      ) {
        const soilIndex = soilGradeData.vendorResponse?.response?.soilIndex;
        const soilgradeEl = document.getElementById("SoilGrade_TXT");
        if (soilgradeEl) {
          soilgradeEl.value = `${soilIndex}`;
          console.log("BH-11174 Filled Soil grade value Successfully!");
        }
      }
      const disFaultData = await distanceFRes.json();
      // console.log(disFaultData)
      if (
        disFaultData &&
        typeof disFaultData == "object" &&
        disFaultData.vendorResponse &&
        disFaultData.vendorResponse?.response
      ) {
        const distances = disFaultData.vendorResponse?.response?.faults || [];
        if (distances.length > 0) {
          let shortest = distances[0].distance || 0;
          for (let i = 0; i < distances.length; i++) {
            if (distances[i].distance < shortest) {
              shortest = distances[i].distance;
            }
          }
          const distanceEl = document.getElementById("DistancetoFault_TXT");
          if (distanceEl) {
            distanceEl.value = `${shortest || 0}`;
          }
        }
      }
      return true;
    } catch (error) {
      console.log("BH-11174 Soil Grade/Distance to Fault Error: ", error);
      errorMessage.push(
        "Soil Grade/Distance to Fault API Error:  " + error.message
      );
      return false;
    } finally {
      if (errorMessage.length > 0) {
        displayApiErrorMessage(errorMessage.join("</br>"));
      }
      if (typeof hideSpinner === "function") hideSpinner();
      console.log("BH-11174 Run Successfully!");
    }
  }
