  async function AutoCreditScore(event) {
    if (
      $('.page-quickquotequestions.page-number-2.package-24338').length === 0 ||
      $('.readonlymode').length !== 0
    ) return

    const convertedpol =
      Instanda.Variables.ConvertedPolicy_YN || Instanda.Variables.ConvertedPolicy_YNP
    const createdFrom = Instanda.Variables.CreatedFrom
    const state = Instanda.Variables.PremiumState_CHOICE

    // Your new master gate
    if (
      Instanda.Variables.RiskCountryRO_TXT !== 'US' ||
      !((createdFrom === 'NewBusiness' && convertedpol === 'No') || createdFrom === 'Renewal')
    ) return

    const neverCall = ['Alaska', 'California', 'Delaware', 'Hawaii']
    const newAndRenewal = [
      'District Of Columbia', 'Indiana', 'Kansas', 'Michigan', 'Louisiana', 'Minnesota', 'Alabama',
      'Colorado', 'Nevada', 'Illinois', 'Pennsylvania', 'Utah'
    ]
    const newAndEvery3rdRenewal = ['Arkansas', 'Oklahoma', 'New York', 'Virginia']
    const newAndRenewal3Plus = [
      'Iowa', 'Mississippi', 'North Carolina', 'North Dakota', 'Maine', 'Nebraska',
      'New Mexico', 'South Dakota', 'Vermont', 'West Virginia'
    ]

    const transactionType = createdFrom
    const renewalCount = parseInt(Instanda.Variables.RENEWAL_COUNT, 10) || 0

    const effDateStr = formatDateToDDMMYYYY(Instanda.Variables.EffectiveDate_DATE)
    const effDateObj = parseDDMMYYYYtoDate(effDateStr)
    const effCutoff1 = new Date('2025-12-31') // for unconverted new business

    if (neverCall.includes(state)) return

    if (newAndRenewal.includes(state)) return getCreditScore(event)

    if (newAndEvery3rdRenewal.includes(state)) {
      if (transactionType === 'NewBusiness' || (transactionType === 'Renewal' && renewalCount > 0 && renewalCount % 3 === 0)) {
        return getCreditScore(event)
      }
      return
    }

    if (newAndRenewal3Plus.includes(state)) {
      if (transactionType === 'NewBusiness' || (transactionType === 'Renewal' && renewalCount >= 3)) {
        return getCreditScore(event)
      }
      return
    }

    if (state === 'Montana') {
      if (transactionType === 'NewBusiness' || (transactionType === 'Renewal' && renewalCount > 0 && renewalCount % 3 === 0)) {
        return getCreditScore(event)
      }
      return
    }

    if (state === 'Florida') {
      if (transactionType === 'NewBusiness' || (transactionType === 'Renewal' && renewalCount >= 2)) {
        return getCreditScore(event)
      }
      return
    }

    if (state === 'Texas') {
      if (
        (transactionType === 'NewBusiness' && convertedpol === 'No' && effDateObj > effCutoff1) ||
        (transactionType === 'Renewal' && renewalCount > 0 && renewalCount % 3 === 0)
      ) {
        return getCreditScore(event)
      }
      return
    }

    // All other states: only on NewBusiness
    if (transactionType === 'NewBusiness') return getCreditScore(event)
  }

