  //start vivek
  // Added New code as part of VINLOOKUP Button
  (function () {
    if (
      !document.querySelector(
        ".page-quickquotequestions.page-number-4.package-24338"
      )
    )
      return;

    // CONFIG
    const BUTTON_TEXT = "VIN Lookup";
    const LOADING_TEXT = "Loading...";
    const PROVIDER = "CARFAX";
    const HANDLER = "phase2";

    // Hide button for these vehicle types (by select value OR selected text)
    const HIDE_FOR_VEH_TYPES = new Set(
      [
        "Misc. - Recreational Trailer",
        "Misc. - Other Trailer",
        "Misc. - Motor Home",
        "Misc. - Motorcycle",
        "Misc. - Snowmobile",
        "Misc. - Nonreg. Dune Buggy",
        "Misc. - Golf Cart",
        "Misc. - Nonreg. Golf Cart",
        "Misc. - All Terrain Vehicle",
        "Misc. - Registered Dune Buggy",
        "Collector - Antique",
        "Collector - Classic",
        "Collector - Exotic",
      ].map((s) => String(s).trim().toLowerCase())
    );

    // Spinner CSS (inject once)
    const injectSpinnerCSS = () => {
      if (document.getElementById("vin-lookup-spinner-style")) return;
      const style = document.createElement("style");
      style.id = "vin-lookup-spinner-style";
      style.textContent = `
      .vin-lookup-spinner {
        display: inline-block;
        width: 12px; height: 12px; margin-right: 6px;
        border: 2px solid #fff; border-radius: 50%;
        border-top-color: transparent;
        animation: vin-spin .8s linear infinite;
        vertical-align: middle;
      }
      @keyframes vin-spin { to { transform: rotate(360deg); } }
      .custom-vin-lookup-btn { min-width: 100px !important; position: relative; transition: all .2s; }
      .custom-vin-lookup-btn:disabled { opacity: 0.7; cursor: not-allowed; }
    `;
      document.head.appendChild(style);
    };

    // Add button to one .vinlookup field (unless vehicle type is in hide list)
    const addButtonToVinField = (vinFieldElement) => {
      if (!vinFieldElement) return;

      const $vinField = $(vinFieldElement);

      // Idempotent: remove any existing button first
      $vinField.siblings(".custom-vin-lookup-btn").remove();

      // Find multi-item container and MI
      const vehicleContainer = vinFieldElement.closest(
        '[class*="instanda-multi-item-Vehicle_MI"]'
      );
      if (!vehicleContainer) return;

      const miMatch = vehicleContainer.className.match(
        /instanda-multi-item-Vehicle_MI(\d+)/
      );
      const mi = miMatch ? parseInt(miMatch[1], 10) : null;
      if (!mi) return;

      // Determine vehicle type (value or selected text)
      const $sel = $(`#Vehicle_MI${mi}_VehType_CHOICEP`);
      if (!$sel.length) return; // don't render until dropdown exists

      const val = String($sel.val() || "")
        .trim()
        .toLowerCase();
      const text = String($sel.find("option:selected").text() || "")
        .trim()
        .toLowerCase();
      const shouldHide =
        HIDE_FOR_VEH_TYPES.has(val) || HIDE_FOR_VEH_TYPES.has(text);
      if (shouldHide) return;

      // Create button
      const btn = document.createElement("button");
      btn.type = "button";
      btn.className = "custom-vin-lookup-btn btn btn-primary btn-sm ms-2";
      btn.style.cssText = "margin-bottom:9px;";
      btn.innerHTML = BUTTON_TEXT;

      // Avoid duplicate handlers (new element each time)
      btn.addEventListener("click", function (e) {
        e.preventDefault();
        e.stopPropagation();
        if (btn.disabled) return;

        // Re-check hide rule at click time (in case dropdown changed)
        const $selNow = $(`#Vehicle_MI${mi}_VehType_CHOICEP`);
        const valNow = String($selNow.val() || "")
          .trim()
          .toLowerCase();
        const textNow = String($selNow.find("option:selected").text() || "")
          .trim()
          .toLowerCase();
        if (HIDE_FOR_VEH_TYPES.has(valNow) || HIDE_FOR_VEH_TYPES.has(textNow)) {
          $(btn).remove();
          return;
        }

        // Show loading
        btn.disabled = true;
        btn.innerHTML = `<span class="vin-lookup-spinner"></span><span>${LOADING_TEXT}</span>`;

        // Your handler
        handleCall(e, HANDLER, vehicleContainer, mi, PROVIDER);

        // Fallback reset
        setTimeout(() => {
          if (!document.body.contains(btn)) return;
          if (btn.disabled) {
            btn.disabled = false;
            btn.innerHTML = BUTTON_TEXT;
          }
        }, 5000);
      });

      // Place button after field
      $vinField.after(btn);
    };

    // Add button for all .vinlookup fields in any multi-item
    const refreshAllVinButtons = () => {
      document.querySelectorAll(".vinlookup").forEach((vinField) => {
        if (vinField.closest('[class*="instanda-multi-item-Vehicle_MI"]')) {
          addButtonToVinField(vinField);
        }
      });
    };

    injectSpinnerCSS();

    // Run initially after DOM settles
    $(document).ready(() => setTimeout(refreshAllVinButtons, 300));

    // After add button
    $(document).on("click", "#Vehicle_MIaddButton", () =>
      setTimeout(refreshAllVinButtons, 350)
    );

    // After remove
    $(document).on("click", '[id*="Vehicle_MI"][id$="_removeButton"]', () =>
      setTimeout(refreshAllVinButtons, 200)
    );

    // On vehicle type choice
    $(document).on("change", '[id$="_VehType_CHOICEP"]', () =>
      setTimeout(refreshAllVinButtons, 50)
    );

    // Observer spots newly rendered fields after AJAX/additions
    const observer = new MutationObserver((muts) => {
      const hasVin = muts.some((m) =>
        Array.from(m.addedNodes || []).some(
          (n) =>
            n &&
            n.nodeType === 1 &&
            ((typeof n.matches === "function" && n.matches(".vinlookup")) ||
              (typeof n.querySelector === "function" &&
                n.querySelector(".vinlookup")))
        )
      );
      if (hasVin) setTimeout(refreshAllVinButtons, 250);
    });

    observer.observe(document.body, {
      childList: true,
      subtree: true,
    });

    // Final run
    setTimeout(refreshAllVinButtons, 800);

    window.refreshVinButtons = refreshAllVinButtons;
    console.log("VIN Lookup + Spinner → ACTIVE");
  })();

