  //vivek start
  //Vivek new code
  async function handleCall(event, type, parent, miNumberAdd, apiName) {
    event.preventDefault();
    // Overlay animation starts
    //showSpinner();

    const button = $(event.target);
    const uniqueClass = button.data("unique-class");
    const container = $(`.${uniqueClass}`);
    const qtref = String(Instanda.Variables.QuoteRef);
    const vinText = parent.querySelector(`#Vehicle_MI${miNumberAdd}_Vin_TXT`);
    const greyMarket = parent.querySelector(
      `#Vehicle_MI${miNumberAdd}_GreyMarketVeh_YNNo`
    );
    const extndNonOwner = parent.querySelector(
      `#Vehicle_MI${miNumberAdd}_ExtendNonOwnVehReg_YNNo`
    );

    let vinNum = null;
    if (vinText) {
      vinNum = vinText.value; // For input or textarea elements
    }
    let modelYearNum = $(`#Vehicle_MI${miNumberAdd}_ModYear_NUM`).val().trim();

    //NADA Request Variables
    const stateCd = Instanda.Variables.StateShort;
    const vehMileage = $(
      `#Vehicle_MI${miNumberAdd}_ReportedAvgAnnualMiles_NUM`
    ).val();
    const vehType = $(`#Vehicle_MI${miNumberAdd}_VehType_CHOICEP`).val();

    console.log("Constainer handleCarFaxCall qtref :", qtref);
    console.log("VIN inside handleCarFaxCall :", vinNum);

    if (!vinNum || vinNum.trim() === "") {
      alert("Please enter a VIN.");
      return false;
    }
    if (!modelYearNum || modelYearNum.trim() === "") {
      alert("Please enter model year.");
      return false;
    }

    //VIN Validation called here
    if (Instanda.Variables.NamedNonOwnPol_YN != "Yes") {
      const premiumState = Instanda.Variables.PremiumState_CHOICE;
      const skipVinRulesStates = new Set([
        "Florida",
        "Colorado",
        "Connecticut",
        "Georgia",
        "Missouri",
        "Montana",
        "Indiana",
        "Wyoming",
        "Idaho",
        "Alabama",
        "Tennessee",
        "Illinois",
        "Kentucky",
        "Ohio",
        "Arkansas",
        "Arizona",
        "New Hampshire",
        "Maryland",
        "Oregon",
        "Virginia",
        "Utah",
        "Washington",
        "Kansas",
        "Michigan",
        "Minnesota",
      ]);

      const greyMarketYes = parent.querySelector(
        `#Vehicle_MI${miNumberAdd}_GreyMarketVeh_YNYes`
      );
      const greyMarketNo = parent.querySelector(
        `#Vehicle_MI${miNumberAdd}_GreyMarketVeh_YNNo`
      );
      const isGreyMarketYes = greyMarketYes?.checked === true;
      const isGreyMarketNo = greyMarketNo?.checked === true;
      const shouldSkipVinRules =
        skipVinRulesStates.has(premiumState) && isGreyMarketYes;
      // If either field is missing, ignore them and still run vinRulesAuto (for Regular only)
      const missingEither = (!greyMarketNo && !greyMarketYes) || !extndNonOwner;

      if (
        !shouldSkipVinRules &&
        ((missingEither && extndNonOwner?.checked === true) ||
          (isGreyMarketNo && extndNonOwner?.checked === true)) &&
        vehType == "Regular"
      ) {
        vinRulesAuto(vinNum, Number(modelYearNum));
      }
    }

    let apiType = "";
    let requestData = "";
    if (apiName === "CARFAX") {
      apiType = "carfax";
      requestData = {
        quoteRef: qtref,
        vin: vinNum,
      };
    } else if (apiName === "VINMASTER") {
      apiType = "vinmaster";
      requestData = {
        quoteDetails: {
          quoteRef: qtref,
        },
        vehicleDetails: {
          vin: vinNum,
          modelYear: modelYearNum,
        },
        lpmpFilingDate: "2014",
      };
    } else if (apiName === "NADA") {
      requestData = {
        quoteDetails: {
          quoteRef: qtref,
        },
        vehicleDetails: {
          period: formatDate(),
          //period: new Date().toISOString().slice(0, 10),
          stateCode: stateCd,
          vin: vinNum,
          mileage: vehMileage,
          vehicleType: vehType,
        },
      };
    }
    console.log("type valuee:", type);
    if (!$(".readonlymode").length > 0) {
      if (apiName === "CARFAX" || apiName === "VINMASTER") {
        const {
          apiBaseUrl,
          subscriptionKey
        } = getApiEndpoint(type);
        const apiEndpoint = `${apiBaseUrl}/${apiType}/v1/getVehicleDetails`;
        sendIntegRequest(
          apiEndpoint,
          requestData,
          subscriptionKey,
          type,
          container,
          event,
          miNumberAdd,
          apiName,
          vinNum,
          parent
        );
      } else if (apiName === "NADA") {
        const {
          apiBaseUrl,
          subscriptionKey
        } = getApiEndpoint(type);
        const apiEndpoint = `${apiBaseUrl}/nada/v1/getAutoValuation`;
        try {
          await sendIntegRequest(
            apiEndpoint,
            requestData,
            subscriptionKey,
            type,
            container,
            event,
            miNumberAdd,
            apiName,
            vinNum,
            parent
          );
        } catch (error) {
          console.error("NADA API call failed:", error);
          // Try VINMASTER, and catch its errors too!
          try {
            const vehMIContainer = event.target.closest(
              '[class*="instanda-multi-item-Vehicle_MI"]'
            );
            //await handleCall(event, 'getVehicleDetails', vehMIContainer, miNumberAdd, 'VINMASTER');
            await handleCall(
              event,
              "phase2",
              vehMIContainer,
              miNumberAdd,
              "VINMASTER"
            );
          } catch (vmError) {
            console.error("VINMASTER API call also failed:", vmError);
            // Optionally show a user-friendly error message here
            //handleApiErrorResponse(data, apiName);
          }
        }
      }
    }
  }
  //vivek new ends here
  async function sendIntegRequest(
    apiEndpoint,
    requestBody,
    subscriptionKey,
    type,
    container,
    event,
    miNumberAdd,
    apiName,
    vinInp,
    parent
  ) {
    console.log(`Sending ${type} request to ${apiEndpoint}`);
    console.log("Request body:", requestBody);
    const response = await fetch(apiEndpoint, {
      method: "POST",
      headers: generateHeaders(subscriptionKey),
      body: JSON.stringify(requestBody),
    });

    const data = await response.json();

    if (!response.ok) {
      // Call handleApiErrorResponse to display a user-friendly message
      await handleApiErrorResponse(data, apiName);
      // Throw an error to ensure the catch block in handleCall runs
      console.log(" after handleApiErrorResponse");
      throw new Error(data.message || "API Error");
    }

    processIntegResponse(
      data,
      type,
      container,
      event,
      miNumberAdd,
      apiName,
      parent
    );
    return data;
  }
  // Function to handle both JSON and non-JSON API error responses
  async function handleApiErrorResponse(response, apiName) {
    let errorData = null;
    let errorCode = "";
    let detailedMessage = "";
    let userMessage = "";
    errorData = response;
    if (errorData) {
      if (Array.isArray(errorData.error) && errorData.error.length > 0) {
        errorCode = String(errorData.error[0].code || "");
        detailedMessage = errorData.error[0].message || "";
      } else {
        errorCode = String(errorData.code || errorData.status || "");
        detailedMessage = errorData.message || "";
      }
    }
    console.log("detailedMessage from server response:", detailedMessage);
    if (detailedMessage !== "The VIN you entered was invalid") {
      // Map error codes to user-friendly messages
      switch (errorCode) {
        case "400":
          userMessage =
            "Data passed to vendor did not find a record in their database";
          break;
        case "404":
          userMessage = "Requested resource was not found.";
          break;
        case "500":
        case "503":
          userMessage = "Our system failed to send the request to the vendor.";
          break;
        case "502":
        case "504":
        case "403":
        case "401":
          userMessage =
            "Vendor system failed to send us a response due to technical issue.";
          break;
        default:
          userMessage = detailedMessage || "An unknown error occurred.";
      }
      if (apiName === "NADA") {
        apiName = "the Vehicle Valuation & Pricing Auto details";
        userMessage = userMessage + " for " + apiName;
        displayApiErrorMessage(userMessage);
      } else if (apiName === "VINMASTER") {
        apiName = "Vehicle Details";
        userMessage = userMessage + " for " + apiName;
        displayApiErrorMessage(userMessage);
      } else {
        displayApiErrorMessage(userMessage);
      }
      hideSpinner();
    } else {
      displayApiErrorMessage(detailedMessage);
      hideSpinner();
    }
  }

  function processIntegResponse(
    data,
    type,
    container,
    event,
    miNumberAdd,
    apiName,
    parent
  ) {
    if (apiName === "CARFAX") {
      prepareCarFaxResponse(data, container, event, miNumberAdd, parent);
    } else if (apiName === "NADA") {
      prepareNADAResponse(data, container, event, miNumberAdd, parent);
    } else if (apiName === "VINMASTER") {
      prepareVINMasterResponse(data, container, event, miNumberAdd);
    }
  }
