  //check if inscipher is needed or not
  function checkIfInscipherTaxAndFeesNeeded() {
    const state =
      Instanda.Variables.CO_RiskStateRO_TXT ||
      Instanda.Variables.RiskStateRO_TXT ||
      Instanda.Variables.MA_State_CHOICE;
    const admittedNonAdmitted = Instanda.Variables.ProductCode_CHOICE;
    const filing =
      Instanda.Variables.CO_SurplusFilling_CHOICEP ||
      Instanda.Variables.SurplusFilling_CHOICEP;
    if (
      (admittedNonAdmitted === "Admitted" && state === "KY") ||
      (admittedNonAdmitted === "Non-Admitted" && filing === "PCS")
    ) {
      return true;
    }
    return false;
  }

  // Coherent Premium Events

  // Robust recursive sanitization function for all update payloads
  function sanitizeUpdatePayload(obj) {
    const errorValues = [
      null,
      undefined,
      "",
      "#N/A",
      "N/A",
      "#VALUE!",
      "#DIV/0!",
      "All",
      "NaN",
      "-",
      "!CALC",
      "null",
      "undefined",
    ];
    if (Array.isArray(obj)) return obj.map(sanitizeUpdatePayload);
    if (obj && typeof obj === "object") {
      Object.keys(obj).forEach(
        (key) => (obj[key] = sanitizeUpdatePayload(obj[key]))
      );
      return obj;
    }
    return errorValues.includes(obj) ? 0 : obj;
  }

  // ========== CSV Helpers ==========

  function safeStringify(obj) {
    try {
      if (typeof obj === "object") return JSON.stringify(obj, null, 2);
      if (typeof obj === "string") return obj;
      return String(obj);
    } catch (e) {
      return String(obj);
    }
  }

  function safeParseObj(val) {
    if (typeof val === "object" && val !== null) return val;
    if (typeof val === "string") {
      try {
        let parsed = JSON.parse(val);
        if (parsed && typeof parsed === "object") return parsed;
      } catch (e) { }
    }
    return {};
  }

  function extractPremiumResponseFields(responseObj) {
    if (!responseObj || typeof responseObj !== "object") return {};

    let outputs = responseObj?.outputs || {};
    let warnings = responseObj?.warnings || [];
    let errors = responseObj?.errors;

    let result = {
      ...outputs,
    };

    warnings.forEach((cur, idx) => {
      result[`Warning_${idx + 1}`] = cur.message || JSON.stringify(cur);
    });

    if (errors) {
      if (typeof errors === "string") {
        result.Error = errors;
      } else if (typeof errors === "object") {
        Object.entries(errors).forEach(([k, v]) => {
          result[`Error_${k}`] = v;
        });
      }
    }

    return result;
  }

  function flattenFields(obj, prefix = "") {
    const result = [];
    Object.entries(obj).forEach(([key, value]) => {
      const fullKey = prefix ? `${prefix}.${key}` : key;
      if (Array.isArray(value)) {
        value.forEach((item, idx) => {
          if (typeof item === "object" && item !== null) {
            Object.entries(item).forEach(([subKey, subVal]) => {
              result.push([`${fullKey}[${idx}].${subKey}`, subVal]);
            });
          } else {
            result.push([`${fullKey}[${idx}]`, item]);
          }
        });
      } else if (typeof value === "object" && value !== null) {
        // Nested objects: recurse!
        result.push(...flattenFields(value, fullKey));
      } else {
        result.push([fullKey, value]);
      }
    });
    return result;
  }

  function arrayToLogRowCSV(logs) {
    const rows = ["Request,Response"];
    logs.forEach((row) => {
      const reqFields = extractPremiumRequestFields(safeParseObj(row.request));
      const respFields = extractPremiumResponseFields(
        safeParseObj(row.response)
      ); // ***IMPORTANT!***

      console.log("REQUEST FIELDS:", reqFields);
      console.log("RESPONSE FIELDS:", respFields);

      const reqFieldEntries = flattenFields(reqFields);
      const respFieldEntries = flattenFields(respFields);

      const maxRows = Math.max(reqFieldEntries.length, respFieldEntries.length);
      for (let i = 0; i < maxRows; i++) {
        const reqKV = reqFieldEntries[i];
        const respKV = respFieldEntries[i];
        const reqString = reqKV ? `${reqKV[0]}: ${reqKV[1]}` : "";
        const respString = respKV ? `${respKV[0]}: ${respKV[1]}` : "";
        rows.push(`"${reqString}","${respString}"`);
      }
    });
    return rows.join("\n");
  }

  function updateRaterTxtWithLogRowCSV(logs) {
    let csv = arrayToLogRowCSV(logs);
    let base64 = window.btoa(unescape(encodeURIComponent(csv)));
    $("#Rater_TXT").val(
      JSON.stringify({
        CurrentRatingWorksheetCSV: base64,
      })
    );
  }

  function extractPremiumRequestFields(requestObj) {
    // NO JSON.stringify - just pass real objects
    if (!requestObj || typeof requestObj !== "object") return {};
    return {
      ...requestObj,
    };
  }

  async function logAndCallPremiumFn(fn, fnArgs, label, logArray) {
    let resRaw, reqPayload;
    try {
      resRaw = await fn(...fnArgs);
      reqPayload = resRaw._premiumRequestPayload;
    } catch (err) {
      resRaw = {
        error: err && err.message ? err.message : String(err),
      };
      reqPayload = {};
    }

    // Debug: Verify the response object is FULL
    console.log("RAW resRaw at logging:", resRaw);

    logArray.push({
      label: label,
      request: reqPayload, // RAW object
      response: resRaw, // RAW object
      warnings: "...",
      time: new Date().toISOString(),
    });

    updateRaterTxtWithLogRowCSV(logArray); // Regenerate worksheet
    return resRaw;
  }

  function downloadCSVFile(csvContent, filename) {
    const blob = new Blob([csvContent], {
      type: "text/csv;charset=utf-8;",
    });
    const link = document.createElement("a");
    if (navigator.msSaveBlob) {
      navigator.msSaveBlob(blob, filename);
    } else {
      const url = URL.createObjectURL(blob);
      link.setAttribute("href", url);
      link.setAttribute("download", filename);
      link.style.visibility = "hidden";
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
  }

