  function buildAALFields(initialOutputsHO) {
    const updateAALFields = {};
    if (initialOutputsHO.updatedQuote !== undefined) {
      updateAALFields["WindstormAAL_TXT"] =
        initialOutputsHO.updatedQuote?.GRLoss_AAL_Wind;
      updateAALFields["EarthquakeAAL_TXT"] =
        initialOutputsHO.updatedQuote?.GRLoss_AAL_EQ;
      updateAALFields["WildfireAAL_TXT"] =
        initialOutputsHO.updatedQuote?.GRLoss_AAL_WF;
      // update Override variable on first page - BH-24262
      updateAALFields["RI_AlignPremium_YN"] =
        initialOutputsHO?.updatedQuote?.RO_AlignPremium_YN || "No";
      // update Override variable on first page - BH-24262 ends
    }
    return updateAALFields;
  }

