  // Utility to filter out catFieldsHO from an output object
  function filtercatFieldsHO(outputs, catFieldsHO) {
    const filtered = {};
    Object.keys(outputs).forEach((key) => {
      if (!catFieldsHO.includes(key)) {
        filtered[key] = outputs[key];
      }
    });
    return filtered;
  }

  // Utility to extract only catFieldsHO from an output object
  function extractcatFieldsHO(outputs, catFieldsHO) {
    const extracted = {};
    catFieldsHO.forEach((field) => {
      if (outputs.hasOwnProperty(field)) {
        extracted[field] = outputs[field];
      }
    });
    return extracted;
  }

