  /* Special Format Date function for getPremiumsAuto */
  // This function will work only for Date formats such as: "1956-06-20T00:00:00+00:00" //
  function premiumsAutoFormatDate(date) {
    // Helper to get today's date in YYYY-MM-DD
    function getToday() {
      const d = new Date();
      const year = d.getFullYear();
      const month = String(d.getMonth() + 1).padStart(2, "0");
      const day = String(d.getDate()).padStart(2, "0");
      return `${year}-${month}-${day}`;
    }

    if (!date) return getToday();

    const strDate = String(date).trim();

    // ISO format or already YYYY-MM-DD (with or without time component)
    const isoMatch = strDate.match(/^(\d{4})-(\d{2})-(\d{2})/);
    if (isoMatch) {
      return `${isoMatch[1]}-${isoMatch[2]}-${isoMatch[3]}`;
    }

    // US format: MM/DD/YYYY or M/D/YYYY (with optional leading zeros)
    const usaMatch = strDate.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
    if (usaMatch) {
      const month = usaMatch[1].padStart(2, "0");
      const day = usaMatch[2].padStart(2, "0");
      return `${usaMatch[3]}-${month}-${day}`;
    }

    // Try JavaScript Date parsing as a fallback (catch invalid dates)
    const parsed = new Date(strDate);
    if (!isNaN(parsed)) {
      const year = parsed.getFullYear();
      const month = String(parsed.getMonth() + 1).padStart(2, "0");
      const day = String(parsed.getDate()).padStart(2, "0");
      return `${year}-${month}-${day}`;
    }

    // If nothing matches, return today's date
    return getToday();
  }

