      function mapMultiItems(miArray, keyArray, refArray) {
        const overrideDomAlias = {
          CP_Factor_Ovrd_NUM: "Comp_Factor_Ovrd_NUM",
          CP_FlatAmt_Ovrd_NUM: "Comp_FlatAmt_Ovrd_NUM",
        };

        const containsFactorOvrdNum = (s) =>
          typeof s === "string" && s.includes("Factor_Ovrd_NUM");

        const mappedRaw = (miArray || []).map((item, idx) => {
          const out = {};

          keyArray.forEach((key, i) => {
            const ref = refArray[i];
            let val = item?.[ref] ?? null;

            if (val && /(_DATE_DEF|_DATE|date)$/i.test(ref)) {
              val = premiumsAutoFormatDate(val);
            }

            if (ref.includes("_Ovrd_NUM")) {
              const domKey = overrideDomAlias[key] || key;
              const $el = $(`#VehiclePremiums_MI${idx + 1}_${domKey}`);
              var tempVal = $el.length && $el.closest(".questionItem.instanda-question-item").parent().is(":visible") ? $el.val() : null;

              if (typeof tempVal === "string") tempVal = tempVal.trim();

              if (tempVal !== null && tempVal !== undefined && tempVal !== "") {
                // DOM wins
                val = Number(String(tempVal).replace(/,/g, ""));
              } else {
                // Fallback: quotedata.VehiclePremiums_MI[idx]
                const q = quotedata?.VehiclePremiums_MI?.[idx] || null;

                let qVal =
                  q?.[key] ??
                  q?.[ref] ??
                  (overrideDomAlias[key] ? q?.[overrideDomAlias[key]] : null) ??
                  null;

                if (typeof qVal === "string") qVal = qVal.trim();

                // Only backfill if we don't already have something
                if (
                  (val === null || val === undefined || val === "") &&
                  qVal !== null &&
                  qVal !== undefined &&
                  qVal !== ""
                ) {
                  val =
                    typeof qVal === "string" ?
                      Number(qVal.replace(/,/g, "")) :
                      qVal;
                }
              }

              // Only check Factor_Ovrd_NUM; if value is 0, replace with null
              if (containsFactorOvrdNum(key) || containsFactorOvrdNum(ref)) {
                const n =
                  typeof val === "string" ?
                    Number(val.trim().replace(/,/g, "")) :
                    Number(val);

                if (Number.isFinite(n) && n === 0) val = null;
              }
            }

            out[key] = val;
          });

          return out;
        });

        return autoFormatDates(mappedRaw);
      }

