          null : createdFrom === "Cancellation" ?
            Instanda.Variables.VehLawEnfmntFeeTerm_NUM || null : Instanda.Variables.Old_VehLawEnfmntFeeTerm_NUM || null,
        Old_VehLawEnfmntFeeTermBld_NUM: createdFrom === "NewBusiness" || createdFrom === "Renewal" ?
          null : createdFrom === "Cancellation" ?
            Instanda.Variables.VehLawEnfmntFeeTermBld_NUM || null : Instanda.Variables.Old_VehLawEnfmntFeeTermBld_NUM || null,
