          null : createdFrom === "Cancellation" ?
            Instanda.Variables.WVFireSURTerm_NUM || null : Instanda.Variables.Old_WVFireSURTerm_NUM || null,
        Old_WVFireSURTermBld_NUM: createdFrom === "NewBusiness" || createdFrom === "Renewal" ?
          null : createdFrom === "Cancellation" ?
            Instanda.Variables.WVFireSURTermBld_NUM || null : Instanda.Variables.Old_WVFireSURTermBld_NUM || null,
