  //Defaulting Aggregate Limit same as the Occurence Limit
  (function ($) {
    let syncing = false;

    function extractAmountLabel(text) {
      const m = (text || "").match(/\$\s*\d[\d,]*/); // "$250,000" from "$250,000 (Standard)"
      return m ? m[0].replace(/\s+/g, "") : "";
    }

    function setSelectToAmount($sel, amountLabel) {
      if (!$sel || !$sel.length || !amountLabel) return;

      const $match = $sel
        .find("option")
        .filter(function () {
          return extractAmountLabel($(this).text()) === amountLabel;
        })
        .first();

      if ($match.length) $sel.val($match.val()).trigger("change");
    }

    function syncLimitsFrom(sourceSelector) {
      if (!$(".page-quickquotequestions.page-number-3.package-24428").length)
        return;

      const $occ = $("#EPLIPerOccLimitNA_CHOICE");
      const $agg = $("#EPLIAggregateLimNA_CHOICE");
      const $cov = $("#EPLICovLimit_CHOICE");
      if (!$occ.length || !$agg.length || !$cov.length) return;

      if (syncing) return;
      syncing = true;

      const sourceText = $(sourceSelector).find("option:selected").text();
      const amount = extractAmountLabel(sourceText);

      setSelectToAmount($occ, amount);
      setSelectToAmount($agg, amount);
      setSelectToAmount($cov, amount); // will pick "$250,000 (Standard)" when amount is "$250,000"

      syncing = false;
    }

    $(document).ready(function () {
      // Initialize based on Coverage
      syncLimitsFrom("#EPLICovLimit_CHOICE");

      $("#EPLIPerOccLimitNA_CHOICE").on("change", () =>
        syncLimitsFrom("#EPLIPerOccLimitNA_CHOICE")
      );
      $("#EPLIAggregateLimNA_CHOICE").on("change", () =>
        syncLimitsFrom("#EPLIAggregateLimNA_CHOICE")
      );
      $("#EPLICovLimit_CHOICE").on("change", () =>
        syncLimitsFrom("#EPLICovLimit_CHOICE")
      );

      $("#question510125").on("change", () =>
        syncLimitsFrom("#EPLIPerOccLimitNA_CHOICE")
      );
      $("#question510126").on("change", () =>
        syncLimitsFrom("#EPLIAggregateLimNA_CHOICE")
      );
      $("#question494384").on("change", () =>
        syncLimitsFrom("#EPLICovLimit_CHOICE")
      );
    });
  })(jQuery);


