  // This code will run quick quote calculations on premium override
  async function runQuickQuoteCalculations() {
    try {
      if (isReadOnlyView()) {
        console.log("Read-only view");
        return;
      }
      showSpinner();
      const PackageId = Instanda.Variables.PackageId;
      if (![24518, 24337, 24428].includes(PackageId)) {
        return;
      }
      const url = new URL(window.location.href);
      const newUrl = new URL(
        url.origin +
        `/Public/QuickQuoteQuestions?questionPlacementStage=PreQuote&IsCalledFromFailedAutorenewals=False&quoteIsReadOnly=False&pageNumber=${PackageId == 24337 ? "7" : "6"
        }`
      );
      newUrl.searchParams.set("quoteRef", url.searchParams.get("quoteRef"));
      newUrl.searchParams.set("PackageId", url.searchParams.get("PackageId"));
      await fetch(newUrl, {
        cache: "no-store",
      });
    } catch (error) {
      console.log("Error while running Quick Quote Calcs");
    } finally {
      hideSpinner();
    }
  }
  if ($(".page-quickquote.page-number-1").length > 0) {
    runQuickQuoteCalculations();
  }

