  function overridePremiums() {
    if (isReadOnlyView()) {
      console.log("Read-only view");
      return;
    }

    async function submitMyFormFetch(form) {
      const data = new FormData(form);
      await fetch(form.action, {
        method: form.method || "POST",
        body: data
      })
    }

    $('button[name="updateButton"]').one("click", async function (e) {
      e.preventDefault();
      try {

        await coherentpremiumevents(e);
        showSpinner();
        await submitMyFormFetch($(this).closest("form")[0])
        hideSpinner()

        await runQuickQuoteCalculations()

        window.location.reload();
      } catch (error) {
        console.log("some Errors on API", error);
        $(this).closest("form").submit();
      }
    });
  }

