  async function refreshBcegOnYearChange() {
    // Call ONLY BCEGS endpoint (avoid re-calling PPC & Premium Tax on every year edit)
    const body = buildIsoPassportBody();
    const {
      apiBaseUrl,
      subscriptionKey
    } = getApiEndpoint("phase2");

    const targetYear = getMostRecentBuildOrRenoYear();
    if (!Number.isFinite(targetYear)) {
      $("#BCEG_CHOICE").val("");
      return;
    }

    try {
      const data = await callIsoApi(
        `${apiBaseUrl}/verisk/v1/getBCEGSNetwork`,
        body,
        subscriptionKey
      );

      if (data?.status === "Error") {
        $("#BCEG_CHOICE").val("");
        return;
      }

      const details = data?.vendorResponse?.response?.bcegsriskDetails || [];
      const mapped = mapBcegPersonalCode(details, targetYear);
      $("#BCEG_CHOICE").val(mapped || "");
    } catch (e) {
      $("#BCEG_CHOICE").val("");
    }
  }

