  // Handles only Wind Detailed Network endpoint
  async function getWindDetailedNetwork() {
    if (typeof isReadOnlyView === "function" && isReadOnlyView()) return;
    const isoApiErrors = [];
    const body = buildIsoPassportBody();
    const {
      apiBaseUrl,
      subscriptionKey
    } = getApiEndpoint("phase2");
    const endpoint = "/verisk/v1/getWindDetailedNetwork";

    try {
      const data = await callIsoApi(
        `${apiBaseUrl}${endpoint}`,
        body,
        subscriptionKey
      );

      if (data.status === "Error") {
        let userMessage = data.message;
        if (
          userMessage &&
          userMessage.includes("No results found for the search criteria")
        ) {
          userMessage =
            "No results were found for the information you provided. Please check your details and try again.";
        }
        let errorMsg = userMessage;
        if (Array.isArray(data.error) && data.error.length > 0) {
          errorMsg +=
            "<br>" +
            data.error
              .map((err) => `Code: ${err.code}, Message: ${err.message}`)
              .join("<br>");
        }
        isoApiErrors.push(errorMsg);
      } else {
        // Distance mapping
        const apiToSiteDistanceMap = {
          "0 to 500 feet": "0 to 500 feet",
          "501 to 1000 feet": "501 to 1000 feet",
          "1001 to 1500 feet": "1001 to 1500 feet",
          "1501 to 2000 feet": "1501 to 2000 feet",
          "2001 feet to 2500 feet": "2001 to 2500 feet",
          "2501 ft to less than 1 mi": "2501 feet to less than 1 mile",
          "1 mi to less than 2 mi": "1 mile to less than 2 miles",
          "2 mi to less than 3 mi": "2 miles to less than 3 miles",
          "3 mi to less than 4 mi": "3 miles to less than 4 miles",
          "4 mi to less than 5 mi": "4 miles to less than 5 miles",
          "5 mi to less than 10 mi": "5 miles to less than 10 miles",
          "10 mi to less than 15 mi": "10 miles to less than 15 miles",
          "15 mi to less than 20 mi": "15 miles to less than 20 miles",
          "20 mi to less than 25 mi": "20 miles to less than 25 miles",
          "25 mi to less than 30 mi": "25 miles to less than 30 miles",
          "30 mi and above": "30 miles and above",
          "30 mi and greater": "30 miles and above",
        };
        const apiToSiteDistanceMapLower = {};
        Object.keys(apiToSiteDistanceMap).forEach((key) => {
          apiToSiteDistanceMapLower[key.toLowerCase()] =
            apiToSiteDistanceMap[key];
        });

        /**
         * Parse a vendor distance string and return its "lower bound" in miles.
         * Examples handled:
         *  - "0 to 500 feet" -> 0
         *  - "2501 ft to less than 1 mi" -> 2501/5280 miles (~0.473)
         *  - "2 mi to less than 3 mi" -> 2
         *  - "30 mi and greater" -> 30
         */
        function parseLowerBoundMiles(str) {
          if (!str || typeof str !== "string") return Infinity;
          const s = str.toLowerCase().trim();

          // If pattern "X ... feet" or "X ft"
          const feetMatch = s.match(/([0-9]+(?:\.[0-9]+)?)\s*(ft|feet)/);
          if (feetMatch) {
            const feet = parseFloat(feetMatch[1]);
            if (!isNaN(feet)) return feet / 5280;
          }

          // If pattern starts with "X mi" or "X mile(s)" or "X mi to..."
          const miMatch = s.match(/([0-9]+(?:\.[0-9]+)?)\s*(mi|mile|miles)/);
          if (miMatch) {
            const miles = parseFloat(miMatch[1]);
            if (!isNaN(miles)) return miles;
          }

          // If pattern like "0 to 500" and unit appears later as feet
          const rangeFeetLater = s.match(
            /([0-9]+(?:\.[0-9]+)?)\s*to\s*[0-9]+(?:\.[0-9]+)?\s*(ft|feet|mi|mile|miles)/
          );
          if (rangeFeetLater) {
            const num = parseFloat(rangeFeetLater[1]);
            const unit = rangeFeetLater[2];
            if (!isNaN(num)) {
              if (unit.startsWith("ft")) return num / 5280;
              return num; // miles
            }
          }

          // Fallback: try to find any number (take first) and assume miles if "mi" exists anywhere, otherwise treat as miles
          const anyNum = s.match(/([0-9]+(?:\.[0-9]+)?)/);
          if (anyNum) {
            const n = parseFloat(anyNum[1]);
            if (!isNaN(n)) {
              if (s.includes("ft") || s.includes("feet")) return n / 5280;
              return n; // assume miles
            }
          }

          // Could not parse -> infinity to exclude from min selection
          return Infinity;
        }

        function pickClosestToShore(distArray) {
          if (!Array.isArray(distArray) || distArray.length === 0) return null;
          let best = null;
          let bestVal = Infinity;
          distArray.forEach((entry) => {
            const val = parseLowerBoundMiles(
              entry?.distanceFromShore || entry?.nearestBodyOfWater
            );
            if (val < bestVal) {
              bestVal = val;
              best = entry;
            }
          });
          return best;
        }

        const distanceFromShoreResp =
          data.vendorResponse?.response?.distToCoastDetails || [];
        const nearestBodyResp =
          data.vendorResponse?.response?.distToWaterDetails || [];

        const minDistObj = pickClosestToShore(distanceFromShoreResp);
        const nearestBodyWater = pickClosestToShore(nearestBodyResp);

        // Get distance values from both objects
        const minDistValue = parseLowerBoundMiles(
          minDistObj?.distanceFromShore || ""
        );
        const bodyWaterValue = parseLowerBoundMiles(
          nearestBodyWater?.nearestBodyOfWater || ""
        );

        /// Determine which one is smaller and get the appropriate values
        let selectedDistanceValue = "";
        let selectedBodyName = "";

        if (minDistValue < bodyWaterValue) {
          // Shore distance is smaller
          selectedDistanceValue = (
            minDistObj?.distanceFromShore || ""
          ).toLowerCase();
          selectedBodyName = minDistObj?.distToCoastOceanGulfName || "";
        } else {
          // Water distance is smaller
          selectedDistanceValue = (
            nearestBodyWater?.nearestBodyOfWater || ""
          ).toLowerCase();
          selectedBodyName = nearestBodyWater?.distToWaterBodyOfWaterName || "";
        }

        // Map distance to site format
        const siteDistance =
          apiToSiteDistanceMapLower[selectedDistanceValue] || "";

        // Populate the fields
        $("#DistancefromShore1_CHOICE").val(siteDistance);
        $("#NearestBodyOfWaterPrefill_TXT").val(selectedBodyName);
        // Wind pool: prefer new array structure windPoolEligibilityDetails (pick 'Y'/'Yes' if present, otherwise first valid entry), fallback to old field
        let windPoolVal = "";
        const wpDetails =
          data.vendorResponse?.response?.windPoolEligibilityDetails;

        if (Array.isArray(wpDetails) && wpDetails.length > 0) {
          const norm = (v) =>
            String(v ?? "")
              .trim()
              .toLowerCase();

          // 1) Prefer any entry explicitly set to 'Y' or 'Yes' (case-insensitive)
          const foundYes = wpDetails.find((d) => ["y", "yes"].includes(norm(d?.windPoolEligibility)));

          if (foundYes) {
            windPoolVal = foundYes.windPoolEligibility ?? "";
          } else {
            // 2) Otherwise pick the first element that contains a non-null/defined non-empty value
            const found = wpDetails.find(
              (d) =>
                d?.windPoolEligibility !== undefined &&
                d?.windPoolEligibility !== null &&
                String(d.windPoolEligibility).trim() !== ""
            );
            windPoolVal =
              found?.windPoolEligibility ??
              wpDetails[0]?.windPoolEligibility ??
              "";
          }
        } else {
          windPoolVal =
            data.vendorResponse?.response?.windPoolEligibility ?? "";
        }
        $("#WindPoolPrefill_TXT").val(windPoolVal);

        // ISO prop/pers code: prefer new array isoPropPersCodeDetails and pick the one with the lowest numeric value,
        // fallback to old single field isoPropPersCode
        let isoPropCode = "";
        const isoDetails =
          data.vendorResponse?.response?.isoPropPersCodeDetails;
        if (Array.isArray(isoDetails) && isoDetails.length > 0) {
          // convert to numbers where possible and pick the minimum
          const numericValues = isoDetails
            .map((d) => {
              const v = d?.isoPropPersCode;
              const n = Number(v);
              return isNaN(n) ? null : n;
            })
            .filter((n) => n !== null);

          if (numericValues.length > 0) {
            isoPropCode = String(Math.min(...numericValues));
          } else {
            // none numeric — fallback to the first non-empty string
            const first = isoDetails.find(
              (d) =>
                d?.isoPropPersCode !== undefined &&
                d?.isoPropPersCode !== null &&
                String(d.isoPropPersCode).trim() !== ""
            );
            isoPropCode = first?.isoPropPersCode ?? "";
          }
        } else {
          isoPropCode = data.vendorResponse?.response?.isoPropPersCode ?? "";
        }
        $("#TerritoryPrefill_TXT").val(isoPropCode);
      }
    } catch (error) {
      // let userMessage = '';
      if (error && error.type === "http" && error.status === 400) {
        console.log("No Wind Network details found for this address");
        //  userMessage = 'No Wind Network details found for this address.';
      } else {
        //   userMessage = 'No Wind Network found for this address.';
        console.log("No Wind Network found for this address");
      }
      // isoApiErrors.push(userMessage);
    }

    if (isoApiErrors.length > 0) {
      //    displayApiErrorMessage(isoApiErrors.join('<br>'));
      console.log("isoApoErrors");
    }
  }

