  // Function to trigger Get Quote function
  function getQuoteData(event) {
    return new Promise((resolve, reject) => {
      // event.preventDefault();

      if (
        (typeof isReadOnlyView === "function" && isReadOnlyView()) ||
        $(".readonlymode").length > 0
      ) {
        hideSpinner();
        console.log("Read-only view");
        return false;
      }
      // Optionally handle read-only view here if needed

      let quoteRef = Instanda?.Variables?.QuoteRef;
      if (!quoteRef) {
        quoteRef = Instanda?.Variables?.OriginalQuoteRef;
      }
      if (!quoteRef) {
        quoteRef = getQuoteRefFromModal();
      }

      if (!quoteRef) {
        reject("QuoteRef not found from any source");
        return;
      }

      const requestPayload = {
        method: "GET",
        query: {
          quoteRef: quoteRef,
        },
      };

      const {
        apiBaseUrl,
        subscriptionKey
      } = getApiEndpoint("phase2");
      const apiEndpoint = `${apiBaseUrl}/instanda/v1/manageQuotePolicy?resource=GetQuoteData&recordId=${quoteRef}`;
      const headers = generateHeaders(subscriptionKey);

      fetch(apiEndpoint, {
        method: "POST",
        headers: headers,
        body: JSON.stringify(requestPayload),
        redirect: "follow",
      })
        .then((response) => response.json())
        .then((data) => {
          // Defensive: check for expected structure
          if (data && data.targetResponse && data.targetResponse.response) {
            resolve(data.targetResponse.response);
          } else {
            reject(
              new Error("Failure fetching policy number from INSTANDA API")
            );
          }
        })
        .catch((error) => {
          console.error("Error:", error);
          reject("Failure fetching policy number from INSTANDA API");
        });
    });
  }

  function updateQuoteorPolicydata(event, body = {}) {
    return new Promise((resolve, reject) => {
      try {
        // Prevent default event behavior if event is provided
        if (event && typeof event.preventDefault === "function") {
          //    event.preventDefault();
        }

        // Optional: Check for read-only mode
        if (
          (typeof isReadOnlyView === "function" && isReadOnlyView()) ||
          $(".readonlymode").length > 0
        ) {
          hideSpinner();
          console.log("Read-only view");
          return false; // This prevents further OFAC logic!
        }

        // Get quote reference from global or context variable
        const quoteRef =
          Instanda?.Variables?.QuoteRef || getQuoteRefFromModal();

        if (!quoteRef) {
          reject("QuoteRef not found");
          return;
        }

        // function to extract quoteref from elements
        function getQuoteRefFromModal() {
          try {
            // Select the element containing the quoteRef
            const modalTitleElement = document.querySelector(".modal-title");
            if (!modalTitleElement) {
              console.error("Modal title element not found");
              return null;
            }

            // Extract the text content and use a regular expression to find the quoteRef
            const textContent = modalTitleElement.textContent;
            // Adjust the regex as needed based on your modal's format
            const match = textContent.match(/{{{{\(([^)]+)\)}}}}/); // Matches text within parentheses

            if (match && match[1]) {
              console.log("Extracted quoteRef from modal:", match[1]);
              return match[1];
            } else {
              console.warn("No quoteRef found in modal title");
              return null;
            }
          } catch (error) {
            console.error("Error in getQuoteRefFromModal:", error);
            return null;
          }
        }

        // Build the request payload
        const raw = JSON.stringify({
          method: "Post",
          query: {
            quoteRef,
          },
          body: body, // Accepts any dynamic structure
        });

        // Get API endpoint and subscription key
        const {
          apiBaseUrl,
          subscriptionKey
        } = getApiEndpoint("phase2");
        const apiEndpoint = `${apiBaseUrl}/instanda/v1/manageQuotePolicy?resource=updateQuoteorPolicydata&recordId=${quoteRef}`;

        // Prepare headers
        const headers = generateHeaders(subscriptionKey);
        //headers.append("Content-Type", "application/json");

        // Make the API request
        fetch(apiEndpoint, {
          method: "POST",
          headers: headers,
          body: raw,
          redirect: "follow",
        })
          .then((response) => {
            if (!response.ok) throw new Error("Update Quote data failed");
            return response.json();
          })
          .then((data) => {
            resolve(data); // Return the actual response data if needed
          })
          .catch((error) => {
            console.error("Error updating quote:", error);
            reject(error);
          });
      } catch (err) {
        console.error("Unexpected error in updateQuoteorPolicydata:", err);
        reject(err);
      }
    });
  }

