  // Extract street number and name

  function extractStreetNumberAndName(addressLine) {
    if (!addressLine)
      return {
        streetNumber: "0",
        streetName: "",
      };
    const match = addressLine.match(/^(\d+)\s+(.*)$/);
    if (match) {
      return {
        streetNumber: match[1],
        streetName: match[2],
      };
    }
    return {
      streetNumber: "0",
      streetName: addressLine,
    };
  }

