      C_AddLine1_TXT: claim.address ? claim.address.split(",")[0] || "" : "",
      C_AddLine2_TXT: claim.address ? claim.address.split(",")[1] || "" : "",
      C_City_TXT: claim.address ? claim.address.split(",")[2] || "" : "",
