  // Function to get dropdown value based on insured and API values
  // This function checks if the insured and API values match in a componentized way.
  function getClaimCategoryDDValue(
    insuredName,
    apiName,
    insuredStreetNum,
    apiStreetNum,
    insuredStreetName,
    apiStreetName,
    insuredCity,
    apiCity,
    insuredState,
    apiState,
    insuredZip,
    apiZip
  ) {
    const norm = (str) => (str || "").trim().toLowerCase();

    // Name partial/case-insensitive match
    const nameInsured = norm(insuredName);
    const nameApi = norm(apiName);
    const nameMatch =
      nameInsured &&
      nameApi &&
      (nameInsured.includes(nameApi) || nameApi.includes(nameInsured));

    // Address component-wise partial/case-insensitive match
    const streetNumMatch =
      norm(insuredStreetNum) &&
      norm(apiStreetNum) &&
      (norm(insuredStreetNum).includes(norm(apiStreetNum)) ||
        norm(apiStreetNum).includes(norm(insuredStreetNum)));
    const streetNameMatch =
      norm(insuredStreetName) &&
      norm(apiStreetName) &&
      (norm(insuredStreetName).includes(norm(apiStreetName)) ||
        norm(apiStreetName).includes(norm(insuredStreetName)));
    const cityMatch =
      norm(insuredCity) &&
      norm(apiCity) &&
      (norm(insuredCity).includes(norm(apiCity)) ||
        norm(apiCity).includes(norm(insuredCity)));
    const stateMatch =
      norm(insuredState) &&
      norm(apiState) &&
      (norm(insuredState).includes(norm(apiState)) ||
        norm(apiState).includes(norm(insuredState)));
    const zipMatch =
      norm(insuredZip) &&
      norm(apiZip) &&
      (norm(insuredZip).includes(norm(apiZip)) ||
        norm(apiZip).includes(norm(insuredZip)));

    const addressMatch =
      streetNumMatch && streetNameMatch && cityMatch && stateMatch && zipMatch;

    if (nameMatch && addressMatch) {
      return "RISK FULL - CUSTOMER & LOCATION";
    } else if (addressMatch) {
      return "RISK LIMITED - LOCATION ONLY";
    } else if (nameMatch) {
      return "SUBJECT - CUSTOMER ONLY";
    } else {
      return "NO MATCH";
    }
  }

