  // Get Auto Claims (returns array, does NOT update)
  // Retrieves CLUE Auto claims and maps them according to package.

  /**
   * Merges manual infractions with new vendor infractions.
   * Manual infractions are preserved; vendor infractions are appended.
   */
  function normalizeText(v) {
    return String(v ?? "")
      .trim()
      .toLowerCase()
      .replace(/\s+/g, " ")
      .replace(/[^\p{L}\p{N} ]/gu, "");
  }

  function pickFirst(obj, keys) {
    for (const k of keys) {
      const v = obj?.[k];
      if (v !== undefined && v !== null && String(v).trim() !== "") return v;
    }
    return "";
  }

  function toISODate(v) {
    if (v == null) return "";

    // Date object: format in *local* date parts (no UTC conversion).
    if (v instanceof Date && !isNaN(v)) {
      const y = v.getFullYear();
      const m = String(v.getMonth() + 1).padStart(2, "0");
      const d = String(v.getDate()).padStart(2, "0");
      return `${y}-${m}-${d}`;
    }

    // Epoch millis (or epoch-like string)
    if (typeof v === "number" && isFinite(v)) {
      const dt = new Date(v);
      if (isNaN(dt)) return "";
      const y = dt.getUTCFullYear();
      const m = String(dt.getUTCMonth() + 1).padStart(2, "0");
      const d = String(dt.getUTCDate()).padStart(2, "0");
      return `${y}-${m}-${d}`;
    }

    const s = String(v).trim();
    if (!s) return "";

    // If it already starts with YYYY-MM-DD, prefer that (prevents TZ drift)
    const m1 = s.match(/^(\d{4}-\d{2}-\d{2})/);
    if (m1) {
      const hasExplicitTZ = /([zZ]|[+\-]\d{2}:\d{2})$/.test(s) || /([zZ]|[+\-]\d{2}:\d{2})/.test(s);
      if (!hasExplicitTZ) return m1[1]; // "floating" local timestamp: DO NOT convert
      // Explicit TZ: safe to normalize via Date -> UTC date
      const dt = new Date(s);
      if (isNaN(dt)) return m1[1]; // fallback to date part
      const y = dt.getUTCFullYear();
      const m = String(dt.getUTCMonth() + 1).padStart(2, "0");
      const d = String(dt.getUTCDate()).padStart(2, "0");
      return `${y}-${m}-${d}`;
    }

    // Fallback: try Date parse, then output UTC date
    const dt = new Date(s);
    if (isNaN(dt)) return "";
    const y = dt.getUTCFullYear();
    const m = String(dt.getUTCMonth() + 1).padStart(2, "0");
    const d = String(dt.getUTCDate()).padStart(2, "0");
    return `${y}-${m}-${d}`;
  }



  function getSource(rec) {
    const src = [
      rec?.Infraction_Source_CHOICEP,
      rec?.Con_Source_TXT,
      rec?.Acc_Source_TXT,
      rec?.Claim_Source_CHOICEP,
      rec?.AddClaimSource_CHOICE,
    ]
      .map((x) => String(x ?? "").trim().toLowerCase())
      .filter(Boolean);

    if (src.includes("manual")) return "Manual";
    if (src.includes("vendor")) return "Vendor";
    return "Unknown";
  }

  function isAccidentLike(rec) {
    const t = String(rec?.Infraction_Type_CHOICEP ?? rec?.Infraction_Type_CHOICE ?? "").toLowerCase();
    return (
      t.includes("accident") ||
      !!rec?.Infraction_ClaimNumber_TXT ||
      !!rec?.ClaimNumber_TXT ||
      !!rec?.Claim_ViolationAccident_DATE ||
      !!rec?.Infraction_AccidentState_CHOICE ||
      !!rec?.AccDescValuesIntg_TXT
    );
  }

  function sumAccidentAmounts(rec) {
    const keys = [
      "Infraction_CollClaimAmount_NUM",
      "Infraction_BIClaimAmount_NUM",
      "Infraction_PDClaimAmount_NUM",
      "Infraction_RentCovClaimAmount_NUM",
      "Infraction_TowLaborClaimAmount_NUM",
      "Infraction_PIPClaimAmount_NUM",
      "Infraction_OtherClaimAmount_NUM",
      "Infraction_OthCollClaimAmount_NUM",
    ];
    return keys.reduce((acc, k) => acc + (Number(rec?.[k]) || 0), 0);
  }

  function driverIdentity(rec) {
    const rawName = pickFirst(rec, [
      "C_DriverFLName_TXT",
      "Claim_Driver_TXT",
      "Claim_DriverFLName_TXT",
      "Infraction_Driver_TXT",
      "Inf_DriverFLName_TXT",
      "DriverFullName_TXT",
    ]);
    return normalizeText(rawName);
  }

  function recordCompletenessScore(rec) {
    const fields = [
      "Infraction_ClaimNumber_TXT",
      "Claim_ViolationAccident_DATE",
      "Infraction_ViolationAccident_DATE",
      "Infraction_Conviction_DATE",
      "Infraction_LexNexAccVialCode_TXT",
      "Infraction_OrigAccViolCode_TXT",
      "LexNexCode_TXT",
      "Infraction_viodesc_TXT",
      "AccDescValuesIntg_TXT",
      "ClaimStatus_Auto_CHOICE",
      "C_FaultIndicator_Auto_TXT",
    ];

    let score = 0;
    for (const f of fields) {
      const v = rec?.[f];
      if (v !== undefined && v !== null && String(v).trim() !== "") score += 2;
    }
    if (sumAccidentAmounts(rec) > 0) score += 3;

    const src = getSource(rec);
    if (src === "Vendor") score += 1;
    if (src === "Unknown") score -= 1;

    return score;
  }

  function infractionKey(rec) {
    const driver = driverIdentity(rec);

    if (isAccidentLike(rec)) {
      const claimNo = String(pickFirst(rec, ["Infraction_ClaimNumber_TXT", "ClaimNumber_TXT"])).trim();
      const lossDate = toISODate(pickFirst(rec, ["Claim_ViolationAccident_DATE", "Infraction_ViolationAccident_DATE"]));
      const state = normalizeText(pickFirst(rec, ["Infraction_AccidentState_CHOICE", "AccidentState_TXT", "InfractionState"]));
      const desc = normalizeText(pickFirst(rec, ["AccDescValuesIntg_TXT", "AccidentValues_TXT"]));
      const amt = sumAccidentAmounts(rec);

      if (claimNo) return `A|${claimNo}|${driver}`;
      return `A|${lossDate}|${state}|${driver}|${desc}|${amt}`;
    }

    const code = normalizeText(
      pickFirst(rec, ["Infraction_LexNexAccVialCode_TXT", "Infraction_OrigAccViolCode_TXT", "LexNexCode_TXT"])
    );
    const violDate = toISODate(pickFirst(rec, ["Infraction_ViolationAccident_DATE", "Claim_ViolationAccident_DATE"]));
    const convDate = toISODate(pickFirst(rec, ["Infraction_Conviction_DATE"]));
    const desc = normalizeText(pickFirst(rec, ["Infraction_viodesc_TXT", "ConvictionValues_TXT"]));
    const points = String(pickFirst(rec, ["C_Points_DI_NUM", "ConvictionPoints", "points"])).trim();

    return `C|${driver}|${code}|${violDate}|${convDate}|${desc}|${points}`;
  }

  function mergeManualAndVendorInfractions(existingInfractions, newVendorInfractions) {
    const existing = Array.isArray(existingInfractions) ? existingInfractions : [];
    const incoming = Array.isArray(newVendorInfractions) ? newVendorInfractions : [];

    const keepNonVendor = existing.filter((r) => getSource(r) !== "Vendor");
    const existingVendor = existing.filter((r) => getSource(r) === "Vendor");
    const allVendor = [...existingVendor, ...incoming];

    const bestByKey = new Map();
    for (const rec of allVendor) {
      const key = infractionKey(rec);
      const prev = bestByKey.get(key);
      if (!prev || recordCompletenessScore(rec) > recordCompletenessScore(prev)) {
        bestByKey.set(key, rec);
      }
    }

    return [...keepNonVendor, ...bestByKey.values()];
  }

  function mergeManualAndVendorClaims(existingClaims, newVendorClaims) {
    const existing = Array.isArray(existingClaims) ? existingClaims : [];
    const incoming = Array.isArray(newVendorClaims) ? newVendorClaims : [];

    const keepNonVendor = existing.filter((r) => getSource(r) !== "Vendor");
    const existingVendor = existing.filter((r) => getSource(r) === "Vendor");
    const allVendor = [...existingVendor, ...incoming];

    const bestByKey = new Map();
    for (const c of allVendor) {
      const claimNo = String(pickFirst(c, ["Infraction_ClaimNumber_TXT", "ClaimNumber_TXT", "claimNumber"])).trim();
      const driver = driverIdentity(c);
      const lossDate = toISODate(pickFirst(c, ["Claim_ViolationAccident_DATE", "claimDate"]));

      const key = claimNo ? `CL|${claimNo}|${driver}` : `CL|${driver}|${lossDate}`;

      const prev = bestByKey.get(key);
      if (!prev || recordCompletenessScore(c) > recordCompletenessScore(prev)) {
        bestByKey.set(key, c);
      }
    }

    return [...keepNonVendor, ...bestByKey.values()];
  }
  /**
   * Splits an array of drivers into batches of a given size.
   * Useful for API calls with batch limits.
   */
  function batchDrivers(drivers, batchSize = 5) {
    const batches = [];
    for (let i = 0; i < drivers.length; i += batchSize) {
      batches.push(drivers.slice(i, i + batchSize));
    }
    return batches;
  }

  // Map a driver to the API payload structure, based on package ID
  /**
   * Maps a driver object into the API payload structure, based on package ID.
   * Handles differences in address structure for each package.
   */
  function mapDriverForPackage(
    driver,
    packageID,
    quoteData,
    globalDriverNumber,
    driverIndexInBatch
  ) {
    if (packageID === 24338) {
      return {
        personalDetails: {
          driverIndex: driverIndexInBatch,
          driverNumber: globalDriverNumber,
          firstName: driver.D_FirstName_TXT,
          middleName: driver.D_MiddleName_TXT || "",
          lastName: driver.D_LastName_TXT,
          suffix: driver.D_Suffix_TXT || "",
          dateOfBirth: formatDateToDDMMYYYY(driver.D_DOB_DATE),
        },
        driverLicenseDetails: {
          driversLicenseNumber: driver.LicenseNo_TXT,
          driversLicenseState: getStateCode(driver.LicenseState_CHOICE),
        },
        address: {
          streetNumber: quoteData.RiskAddressLine1RO_TXT ?
            extractStreetNumberAndName(quoteData.RiskAddressLine1RO_TXT)
              .streetNumber : "",
          streetName: quoteData.RiskAddressLine1RO_TXT ?
            extractStreetNumberAndName(quoteData.RiskAddressLine1RO_TXT)
              .streetName : "",
          unitNumber: "",
          city: quoteData.RiskCityRO_TXT || "",
          state: quoteData.RiskStateRO_TXT || "",
          postalCode: extractZipCode(quoteData.RiskPostCodeRO_TXT) || "",
          addressType: "Risk",
        },
      };
    } else if (packageID === 24428) {
      return {
        personalDetails: {
          driverIndex: driverIndexInBatch,
          driverNumber: globalDriverNumber,
          firstName: driver.D_FirstName_TXT,
          middleName: driver.D_MiddleName_TXT || "",
          lastName: driver.D_LastName_TXT,
          suffix: driver.D_Suffix_TXT || "",
          dateOfBirth: formatDateToDDMMYYYY(driver.D_DOB_DATE),
        },
        driverLicenseDetails: {
          driversLicenseNumber: driver.LicenseNo_TXT,
          driversLicenseState: getStateCode(driver.LicenseState_CHOICE),
        },
        address: {
          streetNumber: quoteData.RiskAddressLine1RO_TXT ?
            extractStreetNumberAndName(quoteData.RiskAddressLine1RO_TXT)
              .streetNumber : "",
          streetName: quoteData.RiskAddressLine1RO_TXT ?
            extractStreetNumberAndName(quoteData.RiskAddressLine1RO_TXT)
              .streetName : "",
          unitNumber: "",
          city: quoteData.RiskCityRO_TXT || "",
          state: quoteData.RiskStateRO_TXT || "",
          postalCode: extractZipCode(quoteData.RiskPostCodeRO_TXT) || "",
          addressType: "Risk",
        },
      };
    }
    return {};
  }

  /**
   * Filters claims for last N years and max count.
   */
  function filterRecentClaims(claims, maxClaims = 10, yearsBack = 5) {
    const now = new Date();
    const cutoffDate = new Date(
      now.getFullYear() - yearsBack,
      now.getMonth(),
      now.getDate()
    );

    function newParseClaimDate(dateStr) {
      if (!dateStr) return null;
      const parts = dateStr.split("/");
      if (parts.length === 3) {
        const day = parseInt(parts[0], 10);
        const month = parseInt(parts[1], 10) - 1;
        const year = parseInt(parts[2], 10);
        return new Date(year, month, day);
      }
      return null;
    }

    return claims
      .filter((claim) => {
        const claimDate = newParseClaimDate(claim.claimDate);
        return claimDate && claimDate >= cutoffDate;
      })
      .slice(0, maxClaims);
  }

