  async function getCLUEAutoClaims(event, options = {}) {
    console.log("Fetching CLUE Auto Claims with batching and package-specific mapping...");

    if (
      (Instanda.Variables.ConvertedPolicy_YNP === "Yes" ||
        Instanda.Variables.ConvertedPolicy_YN === "Yes") &&
      Instanda.Variables.CreatedFrom === "NewBusiness"
    ) {
      console.log("Converted Policy exiting Clue Auto Call");
      return false;
    }

    const quoteData = await getQuoteData(event);
    const {
      apiBaseUrl,
      subscriptionKey
    } = getApiEndpoint("phase2");

    // NOTE: keeping your endpoint as-is
    const apiEndpoint = `${apiBaseUrl}/lexisnexis/v1/getCLUEAutoReport`;

    const packageID = Instanda.Variables.PackageId;
    const quoteRef = quoteData.QuoteRef || "UNKNOWN";

    // Attach global index for batching only (DO NOT persist this field)
    const drivers = (quoteData.Driver_MI || []).map((driver, idx) => ({
      ...driver,
      _globalIndex: idx,
    }));

    // Only order CLUE for drivers that have NOT already ordered reports
    const driversToOrder = drivers.filter((d) => {
      const ordered = String(d.IsReportsOrdered_YN || "").trim().toLowerCase() === "yes";
      return !ordered;
    });

    // Helper to create stable key for attempted set (must match processClueApiResponse logic)
    const normalizeNameKey = (s) =>
      String(s || "")
        .toUpperCase()
        .replace(/[^A-Z ]+/g, " ")
        .replace(/\s+/g, " ")
        .trim();

    const normalizeDob = (d) => {
      const s = String(d || "").trim();
      return s.length >= 10 ? s.slice(0, 10) : s;
    };

    const driverKeyFromMI = (driver) => {
      const nm = normalizeNameKey(
        `${driver?.D_FirstName_TXT || ""} ${driver?.D_LastName_TXT || ""}`.trim()
      );
      const dob = normalizeDob(
        driver?.D_DateofBirth_DATE ||
        driver?.D_DOB_DATE ||
        driver?.Dateofbirth_DATE ||
        driver?.DateOfBirth_DATE ||
        driver?.DateofBirth_DATE ||
        driver?.IntegDOB_DATE ||
        ""
      );
      return `${nm}|${dob}`;
    };

    // If nothing to order, just persist current drivers (without _globalIndex) and return
    if (driversToOrder.length === 0) {
      console.log("All drivers already have IsReportsOrdered_YN = Yes. Skipping CLUE Auto call(s).");

      const driversToPersist = drivers.map(({
        _globalIndex,
        ...rest
      }) => rest);

      if (!options.skipUpdate) {
        await updateQuoteorPolicydata(event, {
          Driver_MI: driversToPersist
        });
      }

      // Keep shape consistent
      if (packageID === 24428) {
        return {
          Driver_MI: driversToPersist,
          Infractions_MI: [],
          meta: {
            attemptedDriverNumbers: [],
            attemptedDriverKeys: [],
            anyAttempted: false,
            skippedBecauseAlreadyOrdered: true,
          },
        };
      }

      return {
        Driver_MI: driversToPersist,
        Claim_MI: [],
        meta: {
          attemptedDriverNumbers: [],
          attemptedDriverKeys: [],
          anyAttempted: false,
          skippedBecauseAlreadyOrdered: true,
        },
      };
    }

    // Attempted sets (prevents batching from overwriting non-attempted drivers)
    const attemptedDriverNumbers = driversToOrder
      .map((d) => (d._globalIndex ?? -1) + 1)
      .filter((n) => Number.isFinite(n) && n > 0);

    const attemptedDriverKeys = driversToOrder
      .map((d) => driverKeyFromMI(d))
      .filter((k) => k && k !== "|");

    const attemptedDriverNumberSet = new Set(attemptedDriverNumbers);
    const attemptedDriverKeySet = new Set(attemptedDriverKeys);

    // Batch only the drivers we still need to order for
    const driverBatches = batchDrivers(driversToOrder, 5);
    const allBatchResponses = [];

    for (let batchIdx = 0; batchIdx < driverBatches.length; batchIdx++) {
      const batch = driverBatches[batchIdx];

      const driverDetails = batch.map((driver, idx) => {
        const globalDriverNumber = driver._globalIndex + 1; // keep original numbering
        const driverIndexInBatch = idx + 1;

        return mapDriverForPackage(
          driver,
          packageID,
          quoteData,
          globalDriverNumber,
          driverIndexInBatch
        );
      });

      if (!driverDetails.length) {
        allBatchResponses.push({
          vendorResponse: []
        });
        continue;
      }

      const payload = {
        quoteDetails: {
          quoteRef
        },
        driverDetails,
      };

      const headers = generateHeaders(subscriptionKey);

      try {
        const response = await fetch(apiEndpoint, {
          method: "POST",
          headers,
          body: JSON.stringify(payload),
          redirect: "follow",
        });

        if (!response.ok) throw new Error(`CLUE Auto Report API failed for batch (HTTP ${response.status})`);

        const batchResult = await response.json();
        allBatchResponses.push(batchResult);
      } catch (err) {
        console.error(`Batch ${batchIdx + 1} failed:`, err);
        allBatchResponses.push({
          vendorResponse: []
        });
      }
    }

    // Compute final Driver_MI/Claims/Infractions safely (no overwrites for non-attempted)
    const result = processClueApiResponse(allBatchResponses, drivers, packageID, {
      attemptedDriverNumberSet,
      attemptedDriverKeySet,
    });

    // Strip _globalIndex before persisting
    const driversToPersist = (result?.Driver_MI || drivers).map(({
      _globalIndex,
      ...rest
    }) => rest);

    if (!options.skipUpdate) {
      const updatePayload = {
        Driver_MI: driversToPersist
      };

      if (packageID === 24428) {
        if (Array.isArray(result?.Infractions_MI) && result.Infractions_MI.length > 0) {
          updatePayload.Infractions_MI = result.Infractions_MI;
        }
      } else {
        if (Array.isArray(result?.Claim_MI) && result.Claim_MI.length > 0) {
          updatePayload.Claim_MI = result.Claim_MI;
        }
      }

      await updateQuoteorPolicydata(event, updatePayload);
    }

    // Return cleaned drivers too (optional, but prevents callers from seeing _globalIndex)
    if (packageID === 24428) {
      return {
        Driver_MI: driversToPersist,
        Infractions_MI: result?.Infractions_MI || [],
        meta: {
          attemptedDriverNumbers,
          attemptedDriverKeys,
          anyAttempted: attemptedDriverNumbers.length > 0,
          skippedBecauseAlreadyOrdered: false,
        },
      };
    }

    return {
      Driver_MI: driversToPersist,
      Claim_MI: result?.Claim_MI || [],
      meta: {
        attemptedDriverNumbers,
        attemptedDriverKeys,
        anyAttempted: attemptedDriverNumbers.length > 0,
        skippedBecauseAlreadyOrdered: false,
      },
    };
  }



  /**
   * Maps CLUE claims to infractions array for package 24428.
   */
  function mapAutoClueReportsToInfractionsMI(clueClaims, driverName = "", driverDOB = "") {
    const standardTypes = [
      "Collision",
      "Bodily Injury",
      "Physical/Property Damage",
      "Rental Reimbursement",
      "Towing and Labor",
      "Personal Injury Protection",
      "Other",
    ];

    function mapFaultIndicator(faultCode) {
      const code = String(faultCode || "").trim().toLowerCase();
      if (code === "at fault") return "At Fault";
      if (code === "not at fault") return "Not At Fault";
      if (code === "") return "Not At Fault";
      if (code.includes("comprehensive")) return "Comprehensive";
      if (code.includes("undetermined")) return "Unknown";
      return "Not At Fault";
    }

    function normalizeName(s) {
      return String(s || "")
        .toUpperCase()
        .replace(/[^A-Z ]+/g, " ")
        .replace(/\s+/g, " ")
        .trim();
    }

    function parseDriverStore(storeText) {
      const lines = String(storeText || "")
        .split(/\r?\n/)
        .map((l) => l.trim())
        .filter(Boolean);

      return lines.map((raw, i) => {
        const m = raw.match(/^\s*(\d+)\.\s*(.*?)\s{2,}(\d{1,2}\/\d{1,2}\/\d{4})\s{2,}(\S+)\s*$/);

        const num = m ? m[1] : String(i + 1);
        const name = m ? m[2].trim() : raw.replace(/^\s*\d+\.\s*/, "").trim();
        const dob = m ? m[3] : "";
        const id = m ? m[4] : "";

        const display = dob && id ? `${num}. ${name} ${dob} ${id}` : `${num}. ${name}`;

        return {
          raw,
          num,
          name,
          dob,
          id,
          display,
          key: normalizeName(name)
        };
      });
    }

    function findDriverDisplayValue(driverName, driverDOB, storeText) {
      const entries = parseDriverStore(storeText);
      const target = normalizeName(driverName);
      const dob = String(driverDOB || "").trim();

      let matches = entries.filter((e) => e.key === target);

      if (matches.length > 1 && dob) {
        const byDob = matches.filter((e) => e.dob === dob);
        if (byDob.length) matches = byDob;
      }

      if (!matches.length && target) {
        matches = entries.filter((e) => e.key.includes(target) || target.includes(e.key));
      }

      return matches.length ? matches[0].display : "";
    }

    function normalizeClaimNumber(claim, i) {
      const raw = String(claim?.claimNumber ?? "").trim();
      if (raw) return raw;

      // Deterministic composite key to prevent duplicates when claimNumber missing
      const parts = [
        String(claim?.claimDate ?? "").trim(),
        String(claim?.claimType ?? "").trim(),
        String(claim?.amountPaid ?? "").trim(),
        String(claim?.faultCode ?? "").trim(),
        String(claim?.state ?? "").trim(),
        String(i), // keep stable within a single payload if all else identical
      ];
      return `__missing_claimNumber__|${parts.join("|")}`;
    }

    function resolveState(claimState, riskState) {
      const cs = String(claimState ?? "").trim();
      const rs = String(riskState ?? "").trim();
      const use = cs !== "" ? cs : rs;
      return getStateName(use);
    }

    const claimMap = {};

    (clueClaims || []).forEach((claim, i) => {
      const store = Instanda?.Variables?.StoreDriverVehAssnmt_TXT || "";

      const dobForMatch =
        (typeof formatDateToMMDDYYYY === "function" && typeof addOneDay === "function" ?
          formatDateToMMDDYYYY(addOneDay(claim?.dateOfBirth)) :
          "") || "";

      const driverDisplay = findDriverDisplayValue(driverName, dobForMatch, store);

      const claimNumber = normalizeClaimNumber(claim, i);
      const claimType = claim?.claimType;
      const amountPaid = Number.parseFloat(claim?.amountPaid) || 0;
      const faultCode = String(claim?.faultCode || "").trim();

      const riskState = Instanda?.Variables?.RiskStateRO_TXT;
      const resolvedState = resolveState(claim?.state, riskState);

      if (!claimMap[claimNumber]) {
        claimMap[claimNumber] = {
          Infraction_ClaimNumber_TXT: claimNumber,
          Infraction_Type_CHOICEP: "Accident",
          Accident_NUM: 1, // recalculated later
          Acc_Source_TXT: "Vendor",
          C_FaultIndicator_Auto_TXT: mapFaultIndicator(faultCode),
          Acc_Fault_Indicator_CHOICE: mapFaultIndicator(faultCode),
          InfractionState: resolvedState,
          AccDescValuesIntg_TXT: claimType == null ? "A-GENERIC ACCIDENT - NAF" : claimType,
          PolType_Auto_CHOICE: "Auto",

          DriverFullName_TXT: driverDisplay || driverName,
          C_DriverFLName_TXT: driverName,

          C_DateofBirth_Auto_DATE: typeof formatDateToMMDDYYYY === "function" && typeof addOneDay === "function" ?
            formatDateToMMDDYYYY(addOneDay(claim?.dateOfBirth)) ||
            formatDateToMMDDYYYY(addOneDay(driverDOB)) : undefined,

          Infraction_AccidentState_CHOICE: resolvedState,
          Claim_Driver_TXT: driverName,
          ClaimStatus_Auto_CHOICE: claim?.disposition === "Subrogation" ? "Subro" : claim?.disposition,

          _faultCode: faultCode,
          _acc_fault_code: faultCode,

          Claim_ViolationAccident_DATE: typeof formatDateToMMDDYYYY === "function" && typeof addOneDayUTC === "function" ?
            formatDateToMMDDYYYY(addOneDayUTC(claim?.claimDate)) : undefined,

          Infraction_CollClaimAmount_NUM: 0,
          Infraction_BIClaimAmount_NUM: 0,
          Infraction_PDClaimAmount_NUM: 0,
          Infraction_RentCovClaimAmount_NUM: 0,
          Infraction_TowLaborClaimAmount_NUM: 0,
          Infraction_PIPClaimAmount_NUM: 0,
          Infraction_OtherClaimAmount_NUM: 0,
          Infraction_OthCollClaimAmount_NUM: 0,
        };
      } else {
        if ((!claimMap[claimNumber]._faultCode || claimMap[claimNumber]._faultCode === "") && faultCode) {
          claimMap[claimNumber]._faultCode = faultCode;
          claimMap[claimNumber]._acc_fault_code = faultCode;
        }
      }

      if (claimType === "Collision") claimMap[claimNumber].Infraction_CollClaimAmount_NUM += amountPaid;
      else if (claimType === "Bodily Injury") claimMap[claimNumber].Infraction_BIClaimAmount_NUM += amountPaid;
      else if (claimType === "Physical/Property Damage") claimMap[claimNumber].Infraction_PDClaimAmount_NUM += amountPaid;
      else if (claimType === "Rental Reimbursement") claimMap[claimNumber].Infraction_RentCovClaimAmount_NUM += amountPaid;
      else if (claimType === "Towing and Labor") claimMap[claimNumber].Infraction_TowLaborClaimAmount_NUM += amountPaid;
      else if (claimType === "Personal Injury Protection") claimMap[claimNumber].Infraction_PIPClaimAmount_NUM += amountPaid;
      else if (claimType === "Other") claimMap[claimNumber].Infraction_OtherClaimAmount_NUM += amountPaid;
      else if (!standardTypes.includes(claimType)) claimMap[claimNumber].Infraction_OthCollClaimAmount_NUM += amountPaid;
    });

    return Object.values(claimMap).map((result, idx) => {
      const {
        _faultCode,
        _acc_fault_code,
        ...rest
      } = result;

      return {
        ...rest,
        Accident_NUM: idx + 1,
        C_FaultIndicator_Auto_TXT: mapFaultIndicator(_faultCode),
        Acc_Fault_Indicator_CHOICE: mapFaultIndicator(_acc_fault_code),
      };
    });
  }


  // GetMVR Only get MVR infractions
  function isValidDate(dateStr) {
    const date = new Date(dateStr);
    return dateStr && !isNaN(date.getTime());
  }

  /**
   * Processes MVR details using shared quoteData and optionally updated drivers.
   * Returns infractions array.
   */

  /**
   * Utility: Chunk array into batches of given size for MVR processing
   */
  function chunkArray(array, chunkSize) {
    const results = [];
    for (let i = 0; i < array.length; i += chunkSize) {
      results.push(array.slice(i, i + chunkSize));
    }
    return results;
  }

  /**
   * Main MVR Details Function: Processes all drivers in batches of 10, parallelized
   */
  async function getMVRDetails(event, options = {}) {
    const skipSpinner = !!options.skipSpinner;

    if (!skipSpinner && typeof showSpinner === "function") showSpinner();

    try {
      if (typeof isReadOnlyView === "function" && isReadOnlyView()) {
        console.log("Read-only view in MVRDetails");
        return false;
      }

      if (
        (Instanda.Variables.ConvertedPolicy_YN === "Yes" ||
          Instanda.Variables.ConvertedPolicy_YNP === "Yes") &&
        Instanda.Variables.CreatedFrom === "NewBusiness"
      ) {
        console.log("Converted Policy exiting MVR Call");
        return false;
      }

      // Helper functions
      function parseDateFlexible(dateStr) {
        if (!dateStr || typeof dateStr !== "string") return null;
        const s = dateStr.trim();

        // dd/mm/yyyy
        const slash = s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
        if (slash) {
          const dd = Number(slash[1]);
          const mm = Number(slash[2]);
          const yyyy = Number(slash[3]);
          return new Date(Date.UTC(yyyy, mm - 1, dd));
        }

        // yyyy-mm-dd
        const dash = s.match(/^(\d{4})-(\d{1,2})-(\d{1,2})$/);
        if (dash) {
          const yyyy = Number(dash[1]);
          const mm = Number(dash[2]);
          const dd = Number(dash[3]);
          return new Date(Date.UTC(yyyy, mm - 1, dd));
        }

        const d = new Date(s);
        return Number.isNaN(d.getTime()) ? null : d;
      }

      function addOneDayFlexible(dateStr) {
        const date = parseDateFlexible(dateStr);
        if (!date) return null;
        date.setUTCDate(date.getUTCDate() + 1);
        return date;
      }

      function extractDriverName(firstNamelastNameAddress, fallbackFirst, fallbackLast) {
        if (typeof firstNamelastNameAddress === "string") {
          const parts = firstNamelastNameAddress.split(",");
          if (parts.length >= 2) {
            const last = parts[0].trim();
            const first = parts[1].trim();
            if (first && last) return `${first} ${last}`;
          }
          return firstNamelastNameAddress.trim();
        }
        return `${fallbackFirst || ""} ${fallbackLast || ""}`.trim();
      }

      function normalizePoints(raw) {
        if (raw === null || raw === undefined) return 0;
        const s = String(raw).trim();
        if (s === "") return 0;

        const n = Number(s);
        if (!Number.isFinite(n)) return 0;
        if (!Number.isInteger(n)) return 0;
        if (n < 0 || n > 12) return 0;
        return n;
      }

      // FIX: normalize PremiumState to a 2-letter code ("CA" or "California" -> "CA")
      function normalizeToStateCode(stateValue) {
        const s = String(stateValue || "").trim();
        if (!s) return null;

        // already a state code
        if (/^[A-Za-z]{2}$/.test(s)) return s.toUpperCase();

        // full state name -> code (uses your existing helper)
        if (typeof getStateCode === "function") {
          const code = getStateCode(s);
          return code ? String(code).toUpperCase() : null;
        }

        return null;
      }

      // Main logic
      console.log("Fetching MVR details...");

      const drivers = options.drivers;
      if (!Array.isArray(drivers)) {
        throw new Error("drivers is undefined or not an array");
      }

      // Attach global index to each driver
      const driversWithIndex = drivers.map((driver, idx) => ({
        ...driver,
        _globalIndex: idx,
      }));

      const quoteRef = options.quoteRef || Instanda?.Variables?.QuoteRef;
      const packageID = options.packageID || Instanda?.Variables?.PackageId;

      const premiumStateRaw =
        options.premiumState ||
        Instanda?.Variables?.PremiumState_CHOICE ||
        Instanda?.Variables?.RiskStateRO_TXT;

      const {
        apiBaseUrl,
        subscriptionKey
      } = getApiEndpoint("phase2");
      const apiEndpoint = `${apiBaseUrl}/lexisnexis/v1/getMVRDetails`;

      const premiumStatesList = [
        "Alaska", "Arizona", "California", "Connecticut", "Delaware", "Florida", "Georgia", "Iowa", "Idaho",
        "Illinois", "Indiana", "Maryland", "Maine", "Minnesota", "Missouri", "North Carolina", "North Dakota",
        "New Hampshire", "New Jersey", "Nevada", "Ohio", "Oklahoma", "Oregon", "Pennsylvania", "Rhode Island",
        "South Carolina", "South Dakota", "Tennessee", "Texas", "Utah", "Virginia", "Washington", "Wisconsin", "Wyoming",
      ];

      // Compare premium states using codes (not names)
      const premiumStateCodes = new Set(
        premiumStatesList
          .map((name) => normalizeToStateCode(name))
          .filter(Boolean)
      );

      const premiumStateCode = normalizeToStateCode(premiumStateRaw);

      let updatedDriversArray = [];
      let allInfractionsArray = [];
      let driverResults = []; // per-driver success status for caller

      const batchSize = 10;
      const driverBatches = chunkArray(driversWithIndex, batchSize);

      for (const batch of driverBatches) {
        const batchResults = await Promise.all(
          batch.map(async (driver) => {
            const driverNumber = driver._globalIndex + 1;

            const alreadyOrdered =
              String(driver.IsMVROrdered_YN || "").trim().toLowerCase() === "yes";

            const isPremiumState = premiumStateCodes.has(premiumStateCode);
            const subjectDriverRank = String(driver.SubjectDriverRank_TXT);
            const driverDOB = driver.D_DOB_DATE;

            // Calculate age
            const driverAge =
              typeof calculateAge === "function" ?
                calculateAge(driverDOB) :
                (() => {
                  const dob = parseDateFlexible(driverDOB);
                  if (!dob || isNaN(dob)) return null;
                  const today = parseDateFlexible(Instanda.Variables.EffectiveDate_DATE);
                  let age = today.getFullYear() - dob.getFullYear();
                  const m = today.getMonth() - dob.getMonth();
                  if (m < 0 || (m === 0 && today.getDate() < dob.getDate())) age--;
                  return age;
                })();

            // Determine if MVR should be ordered (never order again if already ordered)
            let shouldOrderMVR = !alreadyOrdered;

            if (shouldOrderMVR) {
              if (Instanda.Variables.PackageId === 24338) {
                const ageOrLicenseHit =
                  driverAge !== null &&
                  (driverAge < 25 || driverAge > 70) &&
                  driver.LicenseNo_TXT &&
                  driver.LicenseNo_TXT.length > 0;

                const priorityHit =
                  (driver.InsuRiskScoreSts_TXT === "Received" && subjectDriverRank === "1") ||
                  driver.InsuRiskScoreSts_TXT === "Failed";

                if (isPremiumState) {
                  shouldOrderMVR = !!priorityHit;
                } else {
                  shouldOrderMVR = !!ageOrLicenseHit;
                }
              } else {
                shouldOrderMVR = true; // keep existing behavior for other packages (e.g., 24428)
              }
            } else {
              console.log(`Skipping MVR API (already ordered) for driver #${driverNumber}`);
            }

            // Keep Driver_TXT consistent
            driver.Driver_TXT = `${driver.D_FirstName_TXT || ""} ${driver.D_LastName_TXT || ""}`.trim();

            // DOB formatted if valid
            let dobFormatted = "";
            if (driver.D_DOB_DATE && formatDateToDDMMYYYY(driver.D_DOB_DATE)) {
              dobFormatted = formatDateToDDMMYYYY(driver.D_DOB_DATE);
            }

            // Ensure license state is a code (supports "CA" or "California")
            const licenseStateCode = normalizeToStateCode(driver.LicenseState_CHOICE);

            const driverPayload = {
              quoteDetails: {
                quoteRef
              },
              personalDetails: {
                driverNumber,
                firstName: driver.D_FirstName_TXT,
                middleName: driver.D_MiddleName_TXT || "",
                lastName: driver.D_LastName_TXT,
                suffix: "",
                dob: dobFormatted,
              },
              driverLicenseDetails: {
                driverLicenseNumber: driver.LicenseNo_TXT || "",
                driverLicenseState: licenseStateCode,
              },
              mvrCount: driverNumber,
            };

            const headers = generateHeaders(subscriptionKey);

            let main = {};
            let attemptedMVR = false;
            let responseOk = false;
            let receivedPayload = false;
            let errorMessage = "";

            try {
              if (shouldOrderMVR) {
                attemptedMVR = true;

                const response = await fetch(apiEndpoint, {
                  method: "POST",
                  headers,
                  body: JSON.stringify(driverPayload),
                  redirect: "follow",
                });

                responseOk = !!response.ok;

                if (!response.ok) {
                  errorMessage = `HTTP ${response.status}`;
                  console.error(
                    `MVR API failed for driver global index ${driver._globalIndex}: ${errorMessage}`
                  );
                } else {
                  const mvrApiResponse = await response.json();
                  main = mvrApiResponse?.vendorResponse?.response || {};
                  receivedPayload = !!mvrApiResponse?.vendorResponse?.response;

                  let violations = Array.isArray(main.violations) ? main.violations : [];

                  // Filter to last 5 years, sort by date desc
                  const today = new Date();
                  const fiveYearsAgo = new Date(today.getFullYear() - 5, today.getMonth(), today.getDate());

                  violations = violations
                    .filter((v) => {
                      const vDate = parseDateFlexible(v.violationAccidentDate);
                      return vDate && vDate >= fiveYearsAgo;
                    })
                    .filter((v) => v.violationAccidentDate)
                    .sort((a, b) => {
                      const dateA = parseDateFlexible(a.violationAccidentDate);
                      const dateB = parseDateFlexible(b.violationAccidentDate);
                      return dateB - dateA;
                    });

                  const cappedViolations = violations.slice(0, 13);

                  cappedViolations.forEach((infraction, idx) => {
                    let baseInfraction;

                    extractDriverName(
                      main.firstNamelastNameAddress,
                      driver.D_FirstName_TXT,
                      driver.D_LastName_TXT
                    );

                    if (packageID === 24428) {
                      baseInfraction = {
                        DriverFullName_TXT: driver.D_FirstName_TXT + " " + driver.D_LastName_TXT,
                        C_DriverFLName_TXT: driver.D_FirstName_TXT + " " + driver.D_LastName_TXT,
                        C_ClueMVR_Status_Descr_TXT: main.mvrStatus || "",
                        C_DateofBirth_Auto_DATE: formatDateToMMDDYYYY(addOneDayFlexible(main.dob)),
                        PolType_Auto_CHOICE: "Auto",
                        Infraction_Type_CHOICEP: "Conviction",
                        Con_Source_TXT: "Vendor",
                        C_Points_DI_NUM: normalizePoints(infraction.points),
                        Infraction_LexNexAccVialCode_TXT: infraction.lexisNexisAccidentViolationCode || "XX",
                        Infraction_NUM: idx + 1,
                        Infraction_OrigAccViolCode_TXT: infraction.lexisNexisAccidentViolationCode || "XX",
                        Infraction_viodesc_TXT: infraction.standardViolationDescription,
                      };
                    } else if (packageID === 24338) {
                      baseInfraction = {
                        Infraction_Driver_TXT: driver.D_FirstName_TXT + " " + driver.D_LastName_TXT,
                        Inf_DriverFLName_TXT: driver.D_FirstName_TXT + " " + driver.D_LastName_TXT,
                        Infraction_Source_CHOICEP: "Vendor",
                        Infraction_Type_CHOICE: "Conviction",
                        C_Points_DI_NUM: normalizePoints(infraction.points),
                        Infraction_LexNexAccVialCode_TXT: infraction.lexisNexisAccidentViolationCode || "XX",
                        Infraction_viodesc_TXT: infraction.standardViolationDescription,
                        LexNexCode_TXT: infraction.lexisNexisAccidentViolationCode || "XX",
                      };
                    } else {
                      return;
                    }

                    if (infraction.convictionDate && infraction.convictionDate.trim() !== "") {
                      const convDate = addOneDayFlexible(infraction.convictionDate);
                      if (convDate) {
                        baseInfraction.Infraction_Conviction_DATE = formatDateToMMDDYYYY(convDate);
                      }
                    }

                    if (infraction.violationAccidentDate && infraction.violationAccidentDate.trim() !== "") {
                      const violDate = addOneDayFlexible(infraction.violationAccidentDate);
                      if (violDate) {
                        baseInfraction.Infraction_ViolationAccident_DATE = formatDateToMMDDYYYY(violDate);
                        if (packageID === 24428) {
                          baseInfraction.Claim_ViolationAccident_DATE = formatDateToMMDDYYYY(violDate);
                        }
                      }
                    }

                    allInfractionsArray.push(baseInfraction);
                  });
                }
              }
            } catch (err) {
              errorMessage = err?.message || String(err);
              console.error(`Error processing driver global index ${driver._globalIndex}:`, err);
            }

            // Decide success per driver
            const licenseDetails = Array.isArray(main.licenseDetails) ? main.licenseDetails : [];
            const hasValidMvrStatus = String(main.mvrStatus || "").trim() !== "";
            const mvrSuccess = shouldOrderMVR ?
              responseOk && receivedPayload && (hasValidMvrStatus || licenseDetails.length > 0) :
              null; // null = not attempted (skipped)

            // Update MVR-related fields ONLY when we attempted the call
            if (attemptedMVR) {
              const reportDate = formatDateToMMDDYYYY(new Date());
              const received = !!mvrSuccess;

              driver.MVRReport_TXT = received ?
                `MVR_Received_${reportDate ? " " + reportDate : ""}` :
                `MVR_Failed_${reportDate ? " " + reportDate : ""}`;

              driver.MVRStatus_TXT = main.mvrStatus || "";
              driver.IntegLicNo_TXT = main.licenseNumber || "";
              driver.IntegRelToInsured_CHOICE = driver.RelationToInsured_CHOICE;

              if (main.dob && String(main.dob).trim() !== "") {
                const dobObj = addOneDayFlexible(main.dob);
                if (dobObj) driver.IntegDOB_DATE = formatDateToMMDDYYYY(dobObj);
              }

              // BH-21125
              driver.UnverifyDriRecSurcharge_YNP = main.mvrStatus === "No Hit" ? "Yes" : "No";

              // Only mark ordered "Yes" when we actually received a valid response
              driver.IsMVROrdered_YN = received ? "Yes" : "No";

              const firstLicense = licenseDetails.find((ld) => ld.licenseStatus);
              if (firstLicense) {
                if (firstLicense.dateExpired && firstLicense.dateExpired.trim() !== "") {
                  const expDateObj = addOneDayFlexible(firstLicense.dateExpired);
                  if (expDateObj) driver.LicenseExpDate_DATE = formatDateToMMDDYYYY(expDateObj);
                }

                driver.LicenseSts_CHOICEP = mapLicenseStatusToInitCap(firstLicense.licenseStatus);

                const suspendedStatuses = ["SUSPENDED/REVOKED", "SUSPENDED", "REVOKED"];
                if (
                  suspendedStatuses.includes(firstLicense.licenseStatus) &&
                  firstLicense.dateExpired &&
                  firstLicense.dateExpired.trim() !== ""
                ) {
                  const susRevDateObj = addOneDayFlexible(firstLicense.dateExpired);
                  if (susRevDateObj) {
                    driver.LicenseSusRev_YNP = "Yes";
                    driver.SusRevDate_DATE = formatDateToMMDDYYYY(susRevDateObj);
                  }
                }
              }
            }

            const driverResult = {
              driverNumber,
              attempted: attemptedMVR,
              skipped: !shouldOrderMVR,
              alreadyOrdered,
              shouldOrderMVR,
              success: mvrSuccess === null ? null : !!mvrSuccess,
              mvrStatus: main.mvrStatus || "",
              licenseDetailsCount: Array.isArray(main.licenseDetails) ? main.licenseDetails.length : 0,
              errorMessage: errorMessage || "",
            };

            const cleanedDriver = {
              ...driver
            };
            delete cleanedDriver._globalIndex;

            return {
              cleanedDriver,
              driverResult
            };
          })
        );

        updatedDriversArray.push(...batchResults.map((r) => r.cleanedDriver));
        driverResults.push(...batchResults.map((r) => r.driverResult));
      }

      return {
        updatedDrivers: updatedDriversArray,
        newInfractions: allInfractionsArray,
        driverResults,
      };
    } catch (err) {
      console.error("Error in getMVRDetails:", err);
      alert("An error occurred while updating MVR details.");
    } finally {
      if (!skipSpinner && typeof hideSpinner === "function") hideSpinner();
    }
  }



  //End of MVR
  /**
   * Processes CLUE Auto Report using shared quoteData and updated drivers.
   * Returns mapped claims/infractions.
   */

  // Utility: Merge driver arrays so CLUE fields appear in final driver payload
  function mergeDriverArrays(mvrDrivers, clueDrivers) {
    const clueList = Array.isArray(clueDrivers) ? clueDrivers : [];
    const clueDriversByLicense = {};

    clueList.forEach((d) => {
      if (d && d.LicenseNo_TXT) clueDriversByLicense[d.LicenseNo_TXT] = d;
    });

    return (Array.isArray(mvrDrivers) ? mvrDrivers : []).map((mvrDriver) => {
      const clueDriver =
        (mvrDriver && mvrDriver.LicenseNo_TXT ?
          clueDriversByLicense[mvrDriver.LicenseNo_TXT] :
          null) ||
        clueList.find(
          (d) =>
            d &&
            d.D_FirstName_TXT === mvrDriver.D_FirstName_TXT &&
            d.D_LastName_TXT === mvrDriver.D_LastName_TXT
        );

      if (!clueDriver) return mvrDriver;

      return {
        ...mvrDriver,
        CLUEReport_TXT: clueDriver.CLUEReport_TXT || mvrDriver.CLUEReport_TXT,
        IsReportsOrdered_YN: clueDriver.IsReportsOrdered_YN || mvrDriver.IsReportsOrdered_YN,
      };
    });
  }

  /**
   * Main function to order CLUE Auto Reports for all drivers.
   */
  async function getCLUEAutoReport(event, quoteData) {
    if (
      Instanda.Variables.PackageId === 24428 &&
      Instanda.Variables.ConvertedPolicy_YNP === "Yes" &&
      Instanda.Variables.CreatedFrom === "NewBusiness"
    ) {
      console.log("Converted Policy exiting Clue Auto Call");
      return {
        Driver_MI: (quoteData && quoteData.Driver_MI) || [],
        Infractions_MI: []
      };
    }

    if (
      Instanda.Variables.PackageId === 24338 &&
      Instanda.Variables.ConvertedPolicy_YN === "Yes" &&
      Instanda.Variables.CreatedFrom === "NewBusiness" &&
      Instanda.Variables.PremiumState_CHOICE != "Texas"
    ) {
      console.log("Converted Policy exiting Clue Auto Call");
      return {
        Driver_MI: (quoteData && quoteData.Driver_MI) || [],
        Claim_MI: []
      };
    }

    const drivers = (quoteData && quoteData.Driver_MI) || [];

    const driversWithIndex = drivers.map((d, i) => ({
      ...d,
      _originalIndex: i,
    }));

    const driversToOrder = driversWithIndex.filter((d) => d.IsReportsOrdered_YN !== "Yes");

    if (driversToOrder.length === 0) {
      console.log("All drivers already have CLUE ordered.");
      // Return consistent object shape by package
      if (Instanda.Variables.PackageId === 24428) {
        return {
          Driver_MI: drivers,
          Infractions_MI: []
        };
      }
      return {
        Driver_MI: drivers,
        Claim_MI: []
      };
    }

    const packageID = Instanda.Variables.PackageId;
    const {
      apiBaseUrl,
      subscriptionKey
    } = getApiEndpoint("phase2");
    const apiEndpoint = `${apiBaseUrl}/lexisnexis/v1/getCLUEAutoReport`;
    const headers = generateHeaders(subscriptionKey);

    const allBatchResponses = [];
    const driverBatches = batchDrivers(driversToOrder, 5);

    for (let batchIdx = 0; batchIdx < driverBatches.length; batchIdx++) {
      const batch = driverBatches[batchIdx];

      const driverDetails = batch.map((driver, idx) => {
        const globalDriverNumber = driver._originalIndex + 1;
        const driverIndexInBatch = idx + 1;

        return mapDriverForPackage(
          driver,
          packageID,
          quoteData,
          globalDriverNumber,
          driverIndexInBatch
        );
      });

      const payload = {
        quoteDetails: {
          quoteRef: quoteData.QuoteRef || "UNKNOWN"
        },
        driverDetails,
      };

      try {
        const response = await fetch(apiEndpoint, {
          method: "POST",
          headers,
          body: JSON.stringify(payload),
          redirect: "follow",
        });

        if (!response.ok) throw new Error("CLUE Auto Report API failed for batch");

        const batchResult = await response.json();
        allBatchResponses.push(batchResult);
      } catch (err) {
        console.error(`Batch ${batchIdx + 1} failed:`, err);
        allBatchResponses.push(null); // ignored downstream
      }
    }

    // Process responses (and crucially: do NOT overwrite already-ordered drivers)
    const clueResult = processClueApiResponse(allBatchResponses, drivers, packageID, driversToOrder);

    // Messages (updated for consistent return shapes)
    if (packageID === 24338) {
      if (!clueResult.Claim_MI || clueResult.Claim_MI.length === 0) {
        displayApiSuccessMessage("No claims have been identified for the provided driver records.");
      }
    } else if (packageID === 24428) {
      if (!clueResult.Infractions_MI || clueResult.Infractions_MI.length === 0) {
        displayApiSuccessMessage("No claims have been identified for the provided driver records.");
      }
    }

    return clueResult;
  }


  /**
   * Helper for post-processing multiple batches of CLUE API responses.
   */
  function processClueApiResponse(allBatchResponses, drivers, packageID, driversToOrder = []) {
    const safeFormatDateToMMDDYYYY =
      typeof formatDateToMMDDYYYY === "function" ? formatDateToMMDDYYYY : () => "";

    const safeAddOneDayUTC =
      typeof addOneDayUTC === "function" ? addOneDayUTC : (d) => d;

    const safeFilterRecentClaims =
      typeof filterRecentClaims === "function" ?
        filterRecentClaims :
        (claims /*, yearsBack, maxClaims */) => (Array.isArray(claims) ? claims : []);

    const safeGetStateName =
      typeof getStateName === "function" ? getStateName : (s) => s;

    const safeMapAutoClueReportsToInfractionsMI =
      typeof mapAutoClueReportsToInfractionsMI === "function" ?
        mapAutoClueReportsToInfractionsMI :
        ( /* claims, driverName, driverDOB */) => [];

    const safePremiumStateChoice =
      typeof Instanda !== "undefined" && Instanda?.Variables?.PremiumState_CHOICE ?
        Instanda.Variables.PremiumState_CHOICE :
        undefined;

    function aggregateClaimsByClaimNumber(
      claims,
      driver,
      getStateNameFn,
      formatDateFn,
      addOneDayFn,
      standardTypes
    ) {
      const claimMap = {};

      const _getStateName = typeof getStateNameFn === "function" ? getStateNameFn : safeGetStateName;
      const _formatDate = typeof formatDateFn === "function" ? formatDateFn : safeFormatDateToMMDDYYYY;
      const _addOneDay = typeof addOneDayFn === "function" ? addOneDayFn : safeAddOneDayUTC;
      const _standardTypes = Array.isArray(standardTypes) ? standardTypes : [];

      (claims || []).forEach((claim) => {
        const claimNumber = claim?.claimNumber;
        const claimType = claim?.claimType;
        const amountPaid = parseFloat(claim?.amountPaid) || 0;

        const rawState = String(claim?.state || "").trim();
        const state = rawState !== "" ? _getStateName(rawState) : safePremiumStateChoice;

        if (!claimMap[claimNumber]) {
          claimMap[claimNumber] = {
            Infraction_Type_CHOICEP: "Accident",
            Claim_Source_CHOICEP: "Vendor",
            Infraction_ClaimNumber_TXT: claimNumber || "",
            Claim_Driver_TXT: `${driver?.D_FirstName_TXT || ""} ${driver?.D_LastName_TXT || ""}`,
            Claim_DriverFLName_TXT: `${driver?.D_FirstName_TXT || ""} ${driver?.D_LastName_TXT || ""}`,
            AccDescValuesIntg_TXT: claimType === null ? "A-GENERIC ACCIDENT - NAF" : claimType,
            ClaimStatus_Auto_CHOICE: claim?.disposition || "",
            Claim_ViolationAccident_DATE: claim?.claimDate && String(claim.claimDate).trim() !== "" ?
              _formatDate(_addOneDay(claim.claimDate)) : undefined,
            _faultCode: claim?.faultCode,
            Infraction_AccidentState_CHOICE: state,

            Infraction_CollClaimAmount_NUM: 0,
            Infraction_BIClaimAmount_NUM: 0,
            Infraction_PDClaimAmount_NUM: 0,
            Infraction_RentCovClaimAmount_NUM: 0,
            Infraction_TowLaborClaimAmount_NUM: 0,
            Infraction_PIPClaimAmount_NUM: 0,
            Infraction_OtherClaimAmount_NUM: 0,
            Infraction_OthCollClaimAmount_NUM: 0,
          };
        } else {
          if (
            (!claimMap[claimNumber]._faultCode || String(claimMap[claimNumber]._faultCode).trim() === "") &&
            claim?.faultCode &&
            String(claim.faultCode).trim() !== ""
          ) {
            claimMap[claimNumber]._faultCode = claim.faultCode;
          }
        }

        if (claimType === "Collision") claimMap[claimNumber].Infraction_CollClaimAmount_NUM += amountPaid;
        else if (claimType === "Bodily Injury") claimMap[claimNumber].Infraction_BIClaimAmount_NUM += amountPaid;
        else if (claimType === "Physical/Property Damage") claimMap[claimNumber].Infraction_PDClaimAmount_NUM += amountPaid;
        else if (claimType === "Rental Reimbursement") claimMap[claimNumber].Infraction_RentCovClaimAmount_NUM += amountPaid;
        else if (claimType === "Towing and Labor") claimMap[claimNumber].Infraction_TowLaborClaimAmount_NUM += amountPaid;
        else if (claimType === "Personal Injury Protection") claimMap[claimNumber].Infraction_PIPClaimAmount_NUM += amountPaid;
        else if (claimType === "Other") claimMap[claimNumber].Infraction_OtherClaimAmount_NUM += amountPaid;
        else if (!_standardTypes.includes(claimType)) claimMap[claimNumber].Infraction_OthCollClaimAmount_NUM += amountPaid;
      });

      function mapFaultIndicator(faultCode) {
        const code = String(faultCode || "").trim().toLowerCase();
        if (code === "at fault") return "At-Fault";
        if (code === "not at fault") return "Not At-Fault";
        if (code === "") return "Not At-Fault";
        if (code.includes("comprehensive")) return "Comprehensive";
        if (code.includes("undetermined")) return "Unknown/Un-determined";
        return "Unknown/Un-determined";
      }

      return Object.values(claimMap).map((record) => ({
        ...record,
        C_FaultIndicator_Auto_TXT: mapFaultIndicator(record._faultCode),
        _faultCode: undefined,
      }));
    }

    const allVendorResponses = (allBatchResponses || [])
      .filter((batch) => batch && batch.vendorResponse)
      .flatMap((batch) => batch.vendorResponse || []);

    // Which drivers did we actually order this run?
    const orderedDriverNumbers = new Set(
      (Array.isArray(driversToOrder) ? driversToOrder : [])
        .map((d) => (typeof d?._originalIndex === "number" ? d._originalIndex + 1 : null))
        .filter((n) => Number.isInteger(n))
    );

    // If caller didn't pass driversToOrder, assume we ordered all drivers
    const orderAll = orderedDriverNumbers.size === 0;

    if (packageID === 24338) {
      const Driver_MI = [];
      const Claim_MI = [];

      const standardTypes = [
        "Collision",
        "Bodily Injury",
        "Physical/Property Damage",
        "Rental Reimbursement",
        "Towing and Labor",
        "Personal Injury Protection",
        "Other",
      ];

      (drivers || []).forEach((driver, idx) => {
        const driverNumber = idx + 1;
        const shouldUpdateThisDriver = orderAll || orderedDriverNumbers.has(driverNumber);

        const vendorResp = allVendorResponses.find((vr) => vr?.response && vr.response.driverNumber === driverNumber);

        // Start from existing driver; only override fields if we ordered this driver in THIS run
        const updatedDriver = {
          ...(driver || {})
        };

        if (shouldUpdateThisDriver) {
          const vendorSuccess = !!vendorResp?.response;
          const repDate = safeFormatDateToMMDDYYYY(new Date());

          updatedDriver.CLUEReport_TXT = vendorSuccess ?
            `CLUE_Received_${repDate ? " " + repDate : ""}` :
            `CLUE_Failed_${repDate ? " " + repDate : ""}`;

          updatedDriver.IsReportsOrdered_YN = vendorSuccess ? "Yes" : "No";
        }

        Driver_MI.push(updatedDriver);

        // Only add claims for drivers we ordered AND got a response for
        if (shouldUpdateThisDriver && vendorResp?.response) {
          const allClaims = vendorResp.response.reportedClaimHistory || [];
          const filteredClaims = safeFilterRecentClaims(allClaims, 10, 5);

          const aggClaims = aggregateClaimsByClaimNumber(
            filteredClaims,
            driver,
            safeGetStateName,
            safeFormatDateToMMDDYYYY,
            safeAddOneDayUTC,
            standardTypes
          );

          Claim_MI.push(...aggClaims);
        }
      });

      const result = {
        Driver_MI
      };
      if (Claim_MI.length > 0) result.Claim_MI = Claim_MI;
      return result;
    }

    if (packageID === 24428) {
      // Build Driver_MI updates WITHOUT overwriting already-ordered drivers
      const Driver_MI = (drivers || []).map((driver, idx) => {
        const driverNumber = idx + 1;
        const shouldUpdateThisDriver = orderAll || orderedDriverNumbers.has(driverNumber);
        if (!shouldUpdateThisDriver) return {
          ...(driver || {})
        };

        const vendorResp = allVendorResponses.find((vr) => vr?.response && vr.response.driverNumber === driverNumber);
        const vendorSuccess = !!vendorResp?.response;
        const repDate = safeFormatDateToMMDDYYYY(new Date());

        return {
          ...(driver || {}),
          CLUEReport_TXT: vendorSuccess ?
            `CLUE_Received_${repDate ? " " + repDate : ""}` : `CLUE_Failed_${repDate ? " " + repDate : ""}`,
          IsReportsOrdered_YN: vendorSuccess ? "Yes" : "No",
        };
      });

      // Map infractions from vendor responses (only for drivers we ordered this run)
      const orderedVendorResponses = orderAll ?
        allVendorResponses :
        allVendorResponses.filter((vr) => {
          const dn = vr?.response?.driverNumber;
          return Number.isInteger(dn) && orderedDriverNumbers.has(dn);
        });

      const allFilteredClaims = orderedVendorResponses.map((vr) => ({
        claims: safeFilterRecentClaims(vr?.response?.reportedClaimHistory || [], 10, 5),
        driverName: vr?.response?.name || "",
        driverDOB: vr?.response?.dateOfBirth || "",
      }));

      const infractions = allFilteredClaims
        .map(({
          claims,
          driverName,
          driverDOB
        }) =>
          safeMapAutoClueReportsToInfractionsMI(claims, driverName, driverDOB)
        )
        .flat();

      return {
        Driver_MI,
        Infractions_MI: infractions,
      };
    }

    return {
      Driver_MI: drivers,
      Claim_MI: [],
      Infractions_MI: [],
    };
  }


  // * ORDER REPORTS BUTTON (pkg 24338) - preserves infractions when no attempts occur
  $(document).on("click", "#OrderReportsButton", async function (event) {
    if (
      $(".page-quickquotequestions.page-number-2").length > 0 &&
      Instanda.Variables["PackageId"] == 24338
    ) {
      await clickAndWaitForSave();

      try {
        showSpinner();

        await AutoCreditScore(event);

        const ConvPolicy =
          Instanda.Variables.ConvertedPolicy_YN || Instanda.Variables.ConvertedPolicy_YNP;
        const CreatedFrom = Instanda.Variables.CreatedFrom;
        const premiumstate = Instanda.Variables.PremiumState_CHOICE;

        if (ConvPolicy === "Yes" && CreatedFrom === "NewBusiness" && premiumstate != "Texas") {
          console.log("Order Reports not called for Converted Policies");
          hideSpinner();
          displayApiSuccessMessage("Reports are not ordered on first time Converted Policies.");
          return;
        }

        const quoteData = await getQuoteData(event);
        if (!quoteData || !Array.isArray(quoteData.Driver_MI)) {
          throw new Error("quoteData or quoteData.Driver_MI is undefined");
        }

        // Driver risk may update Driver_MI fields; use THAT as the single source of truth downstream
        const driverRiskResult = await getDriverRiskScore(event, quoteData);
        const driverBase = Array.isArray(driverRiskResult?.updatedDrivers) ?
          driverRiskResult.updatedDrivers :
          quoteData.Driver_MI;

        // Run MVR against the same driver list we will persist
        const mvrResult = await getMVRDetails(event, {
          drivers: driverBase,
          quoteRef: quoteData.QuoteRef,
          packageID: Instanda.Variables.PackageId,
          premiumState: Instanda.Variables.PremiumState_CHOICE,
        });

        if (!mvrResult || !Array.isArray(mvrResult.updatedDrivers)) {
          throw new Error("MVR details failed or returned invalid driver data.");
        }

        // Run CLUE against the SAME driver list (prevents field regressions / mismatched arrays)
        const quoteDataForClue = {
          ...quoteData,
          Driver_MI: driverBase
        };
        const clueResult = await getCLUEAutoReport(event, quoteDataForClue);

        if (!clueResult || !Array.isArray(clueResult.Driver_MI)) {
          throw new Error("CLUE report failed or returned invalid driver data.");
        }

        // Persist FULL Driver_MI (mvrResult.updatedDrivers is FULL due to your updated getMVRDetails)
        const mergedDrivers = mergeDriverArrays(mvrResult.updatedDrivers, clueResult.Driver_MI);

        const updatePayload = {
          Driver_MI: mergedDrivers
        };

        // MVR → Infraction_MI (24338 auto)
        if (Array.isArray(mvrResult.newInfractions) && mvrResult.newInfractions.length > 0) {
          updatePayload.Infraction_MI = mergeManualAndVendorInfractions(
            quoteData.Infraction_MI || [],
            mvrResult.newInfractions || []
          );
        } else if (Array.isArray(mvrResult.newInfractions) && mvrResult.newInfractions.length === 0) {
          displayApiSuccessMessage("No MVR infractions found for submitted drivers.");
        }

        // CLUE → Claim_MI (24338 auto)
        if (Array.isArray(clueResult.Claim_MI) && clueResult.Claim_MI.length > 0) {
          updatePayload.Claim_MI =
            mergeManualAndVendorClaims(quoteData.Claim_MI || [], clueResult.Claim_MI || []) || [];
        } else if (Array.isArray(clueResult.Claim_MI) && clueResult.Claim_MI.length === 0) {
          displayApiErrorMessage("No CLUE vendor claims found for submitted drivers.");
        }

        await clickAndWaitForSave();
        await updateQuoteorPolicydata(event, updatePayload);

        displayApiSuccessMessage("Driver details have been successfully retrieved");

        setTimeout(function () {
          window.location.reload();
        }, 2000);
      } catch (err) {
        console.error("Error ordering MVR/CLUE reports:", err);
        displayApiErrorMessage("There was an error retrieving Driver reports.");
      } finally {
        hideSpinner();
      }
    }
  });


