  // Orchestration on OrderReports //

  //// Calling on page 2 for HO only Home Clue and page 3 for Auto and Clue for EL ///
  /* ------------------------------ AUTO ORCHESTRATION (24337 / 24428) ------------------------------ */
  $(document).ready(function () {
    // Execute logic only if NOT in read-only mode and NOT reissue
    const isReadOnly = $(".readonlymode").length > 0;
    const changeReason =
      $("#ChangeReason_Choice").val() || Instanda.Variables.ChangeReason_Choice;
    const isReissue = changeReason === "Reissue";

    if (isReadOnly || isReissue) return;

    const onPkg24337Page =
      $(".page-quickquotequestions.page-number-2.package-24337").length > 0;
    const onPkg24428Page =
      $(".page-quickquotequestions.page-number-3.package-24428").length > 0;

    if (!onPkg24337Page && !onPkg24428Page) return;

    (async function () {
      showSpinner();

      try {
        // GUARD: Do not proceed for certain converted policies
        if (
          Instanda.Variables.PackageId === 24428 &&
          Instanda.Variables.ConvertedPolicy_YNP === "Yes"
        ) {
          console.log("Converted Policy exiting MVR Call");
          return false;
        }

        if (
          Instanda.Variables.PackageId === 24337 &&
          Instanda.Variables.ConvertedPolicy_YN === "Yes"
        ) {
          console.log("Converted Policy exiting MVR Call");
          return false;
        }

        // NOTE: `event` is not defined in document.ready scope
        const quoteData = await getQuoteData(null);

        // =========================
        // HOME CLAIMS (AddClaim_MI)
        // =========================

        // Vendor home claims:
        // - Array => refresh vendor data
        // - null/undefined => "no-change", DO NOT overwrite AddClaim_MI
        const homeVendorClaims = await getCLUEHomeClaims(null, quoteData);

        // Manual home claims, always flagged
        const homeManualClaims = Array.isArray(quoteData.AddClaim_MI) ?
          quoteData.AddClaim_MI
            .filter((c) => c.AddClaimSource_CHOICE === "Manual")
            .map((c) => ({
              ...c,
              AddClaimSource_CHOICE: "Manual"
            })) : [];

        // Decide whether we should update AddClaim_MI at all
        let homeAllClaimsToPersist = null;

        if (Array.isArray(homeVendorClaims)) {
          // We have a fresh vendor set; merge it with existing (keeps manual + picks best vendor)
          homeAllClaimsToPersist = mergeManualAndVendorClaims(
            quoteData.AddClaim_MI || [],
            [...homeVendorClaims, ...homeManualClaims]
          );
        } else if (homeManualClaims.length > 0) {
          // Vendor not refreshed, but manual exists; preserve vendor in quoteData and re-merge manual
          homeAllClaimsToPersist = mergeManualAndVendorClaims(
            quoteData.AddClaim_MI || [],
            homeManualClaims
          );
        } // else: no vendor refresh + no manual => leave AddClaim_MI untouched

        // ============================================
        // AUTO INFRACTIONS + DRIVER FLAGS (Pkg 24428)
        // ============================================
        let allAutoInfractions = []; // 24428 only (Infractions_MI)
        let totalVendorSourceCount = 0; // 24428 only (clue auto + mvr counts)
        let driversToPersist = null; // 24428 only (Driver_MI)

        if (onPkg24428Page) {
          const drivers = Array.isArray(quoteData.Driver_MI) ? quoteData.Driver_MI : [];

          const allDriversAlreadyOrdered = drivers.every(
            (d) => d.IsMVROrdered_YN === "Yes" && d.IsReportsOrdered_YN === "Yes"
          );

          if (allDriversAlreadyOrdered) {
            console.log("All drivers already have MVR + CLUE. Skipping API + update.");
            return;
          }

          if (drivers.length === 0) {
            console.warn("Package 24428: No drivers found; skipping CLUE Auto + MVR.");
          } else {
            const [clueAutoResult, mvrResult] = await Promise.all([
              getCLUEAutoReport(null, quoteData),
              getMVRDetails(null, {
                drivers,
                quoteRef: quoteData.QuoteRef,
                packageID: Instanda.Variables.PackageId,
                premiumState: Instanda.Variables.PremiumState_CHOICE,
                skipUpdate: true,
              }),
            ]);

            const clueAutoInfractions = Array.isArray(clueAutoResult?.Infractions_MI) ?
              clueAutoResult.Infractions_MI :
              Array.isArray(clueAutoResult) ?
                clueAutoResult : [];

            const clueAutoDrivers = Array.isArray(clueAutoResult?.Driver_MI) ?
              clueAutoResult.Driver_MI :
              drivers;

            const mvrInfractions = Array.isArray(mvrResult?.newInfractions) ?
              mvrResult.newInfractions :
              Array.isArray(mvrResult) ?
                mvrResult : [];

            const mvrUpdatedDrivers = Array.isArray(mvrResult?.updatedDrivers) ?
              mvrResult.updatedDrivers :
              drivers;

            totalVendorSourceCount =
              (clueAutoInfractions.length || 0) + (mvrInfractions.length || 0);

            driversToPersist = mergeDriverArrays(mvrUpdatedDrivers, clueAutoDrivers);

            allAutoInfractions = mergeManualAndVendorInfractions(
              quoteData.Infractions_MI || [],
              [...(clueAutoInfractions || []), ...(mvrInfractions || [])]
            );
          }
        }

        // =========================
        // UPDATE (single call)
        // =========================
        const payload = {};

        // IMPORTANT: only set AddClaim_MI if we intend to overwrite it
        if (Array.isArray(homeAllClaimsToPersist)) {
          payload.AddClaim_MI = homeAllClaimsToPersist;
        }

        if (onPkg24428Page) {
          if (Array.isArray(driversToPersist)) payload.Driver_MI = driversToPersist;
          if (Array.isArray(allAutoInfractions)) payload.Infractions_MI = allAutoInfractions;
          payload.vendorRecordInitCount_NUM = totalVendorSourceCount;
        }

        const hasHomeUpdate = Array.isArray(homeAllClaimsToPersist);
        const has24428Drivers = onPkg24428Page && Array.isArray(driversToPersist);
        const has24428Infractions =
          onPkg24428Page && Array.isArray(allAutoInfractions) && allAutoInfractions.length > 0;

        if (hasHomeUpdate || has24428Drivers || has24428Infractions) {
          await updateQuoteorPolicydata(null, payload);
        } else {
          console.log("No updates to persist. Skipping updateQuoteorPolicydata.");
        }
      } catch (error) {
        console.error("Error generating CLUE Home, Auto, or MVR Report:", error);
        displayApiErrorMessage(
          "An error occurred while trying to invoke CLUE Home, Auto, or MVR Report API. Please try again."
        );
      } finally {
        hideSpinner();
      }
    })();
  });



