  function clickAndWaitForSave() {
    return new Promise((resolve, reject) => {
      const saveBtn = document.querySelector('button[name="saveButton"]');
      const saveMsg = document.getElementById("savemsg");
      const validationUl = document.querySelector(
        ".validation-summary-valid ul"
      );

      if (!saveBtn || !saveMsg || !validationUl) {
        // Not enough to operate: resolve and proceed (or reject, as you prefer)
        return resolve({
          status: "init-missing",
        });
      }

      // Helper for checking if any visible li exists
      function hasVisibleLi() {
        const lis = validationUl.querySelectorAll("li");
        return Array.from(lis).some(
          (li) =>
            !!li.textContent.trim() &&
            (li.offsetParent !== null || li.style.display !== "none")
        );
      }

      // Initial quick check before observing
      if (hasVisibleLi())
        return reject({
          status: "validation-error",
        });
      if (saveMsg.offsetParent !== null)
        return resolve({
          status: "saved",
        });

      // Set up one shared observer for both saveMsg and validationUl
      const observer = new MutationObserver(() => {
        if (hasVisibleLi()) {
          observer.disconnect();
          reject({
            status: "validation-error",
          });
        } else if (saveMsg.offsetParent !== null) {
          observer.disconnect();
          resolve({
            status: "saved",
          });
        }
      });

      observer.observe(saveMsg, {
        attributes: true,
        attributeFilter: ["style", "class"],
      });
      observer.observe(validationUl, {
        childList: true,
        subtree: true,
        attributes: true,
      });
      saveBtn.click();
    });
  }

