  function separateNumberAndString(input) {
    console.log(" input valuee:", input);
    // Use a regular expression to match the number at the beginning of the string
    const match = input.match(/^([\d-]+)\s+(.*)$/);
    console.log(" match valuee:", match);
    if (match) {
      const numberPart = match[1]; // The number part
      const stringPart = match[2]; // The rest of the string
      console.log(" numberPart valuee:", numberPart);
      console.log(" stringPart valuee:", stringPart);
      return {
        insHouseNo: numberPart,
        insadd1: stringPart,
      };
    } else {
      // If no match is found, return empty
      console.log("inside else failed ehre");
      return {
        insHouseNo: "0",
        insadd1: input,
      };
    }
  }

  //corelogic flood Integ for HO for flood and elevation variance
  async function getCoreLogicFlood() {
    if (typeof isReadOnlyView === "function" && isReadOnlyView()) return;
    showSpinner();

    // Helper to clear multiple fields
    function clearFields(fields) {
      fields.forEach((f) => f.val(""));
    }

    try {
      // Extract and prepare address details
      const {
        insHouseNo,
        insadd1
      } = separateNumberAndString(
        Instanda.Variables.RiskAddressLine1RO_TXT
      );
      const inscity = Instanda.Variables.RiskCityRO_TXT;
      const insstate = Instanda.Variables.RiskStateRO_TXT;
      const inszip = Instanda.Variables.RiskPostCodeRO_TXT || "";
      const latitude = Instanda.Variables.RiskAddress_Latitude_TXT ?? null;
      const longitude = Instanda.Variables.RiskAddress_Longitude_TXT ?? null;
      if (!latitude || !longitude) {
        return;
      }
      // Cache jQuery selectors
      const fields = {
        floodZoneCF: $("#FloodZone_TXT"),
        elevationVarianceCF: $("#ElevationVariance_NUM"),
        riskScoreEF: $("#RiskScoreEF_TXT"),
        riskRatingEF: $("#RiskRatingEF_TXT"),
        propertyElevationEF: $("#PropertyElevationEF_TXT"),
        waterElevationEF: $("#WaterSurfaceElevEF_TXT"),
        distanceOneKEF: $("#DistOneKYearFloodEF_TXT"),
        distancefiveKEF: $("#DistFiveKYearFloodEF_TXT"),
        communityNameEF: $("#CommunityNameEF_TXT"),
        communityNumberEF: $("#CommunityNumberEF_TXT"),
        minHurricaneCategoryEF: $("#MinHurricaneCategoryEF_TXT"),
        surgeScoreEF: $("#SurgeScoreEF_TXT"),
        originalFirmDate: $("#OriginalFirmDate_TXT"),
      };

      // Prepare request body
      const body = {
        address: {
          streetNumber: insHouseNo,
          streetName: insadd1,
          city: inscity,
          state: insstate,
          postalCode: extractZipCode(inszip),
        },
        coordinates: {
          longitude,
          latitude,
        },
      };

      const {
        apiBaseUrl,
        subscriptionKey
      } = getApiEndpoint("phase2");
      const apiEndpoint = `${apiBaseUrl}/coreLogic/v1/getFloodDetails`;

      const response = await fetch(apiEndpoint, {
        method: "POST",
        headers: generateHeaders(subscriptionKey),
        body: JSON.stringify(body),
      });

      if (!response.ok) {
        clearFields([fields.floodZoneCF, fields.elevationVarianceCF]);
        let errorData;
        try {
          errorData = await response.json();
        } catch (e) {
          errorData = {
            message: "No JSON body in error response",
          };
        }

        const referralLevel = Instanda.Variables.SalespersonReferralLevel;

        // Show error for 404 only if referralLevel >= 4, else show all other errors to all users
        if (
          (response.status === 404 && referralLevel >= 4) ||
          response.status !== 404
        ) {
          displayApiErrorMessage(
            "CoreLogic getFloodDetails API failed to get Flood details. Please try again."
          );
        }

        console.error("Error response:", errorData);
        return false;
      }

      const data = await response.json();
      const res = data?.vendorResponse?.response || {};

      // Populate UI fields
      fields.floodZoneCF.val(res.floodZone || "");
      fields.elevationVarianceCF.val(res.elevationVariance || "");
      fields.riskScoreEF.val(res.riskScore || "");
      fields.riskRatingEF.val(res.riskRating || "");
      fields.propertyElevationEF.val(res.propertyElevationFt || "");
      fields.waterElevationEF.val(res.waterSurfaceElevationFt || "");
      fields.distanceOneKEF.val(res.distanceHundredYearFloodPlainFt || "");
      fields.distancefiveKEF.val(res.distanceFiveHundredYearFloodPlainFt || "");
      fields.communityNameEF.val(res.communityName || "");
      fields.communityNumberEF.val(res.communityNumber || "");
      fields.minHurricaneCategoryEF.val(res.stormSurge?.zone || "");
      fields.surgeScoreEF.val(res.stormSurge?.surgeScore || "");
      fields.originalFirmDate.val(res.originalFirmDate || "");

      // Handle COBRACommunity radio buttons

      if (!res.cobraDate || res.cobraDate != "") {
        $("#COBRACommunity_YNNo").prop("checked", true);
        $("#FRSCBRADate_TXT").val(res.cobraDate);
      } else {
        $("#COBRACommunity_YNYes").prop("checked", true);
      }

      return true;
    } catch (error) {
      console.error("Inside catch block of coreLogic flood", error);

      clearFields([$("#FloodZone_TXT"), $("#ElevationVariance_NUM")]);

      // In catch, we don't have response.status, so show error to all
      displayApiErrorMessage(
        "CoreLogic getFloodDetails API failed to get Flood details. Please try again."
      );
      return false;
    } finally {
      hideSpinner();
    }
  }

