  //////////// LexisNexis Call for PrefillHO and EL //
  // Helper function for robust fallback
  function robustValue(...values) {
    for (const val of values) {
      if (val !== null && val !== undefined && String(val).trim() !== "") {
        return val;
      }
    }
    return ""; // Default to empty string if none found
  }

  function getLexisNexisPrefillHO() {
    try {
      if (
        isReadOnlyView() ||
        ($("#ChangeReason_Choice").val() ||
          Instanda.Variables.ChangeReason_Choice) === "Reissue"
      ) {
        console.log("Read-only view in getLexisNexisPrefillHO");
        return false;
      }

      showSpinner();

      // Prefill variable check
      const prefillrequired =
        $('input[name="PrefillHome_YN"]:checked').val() ||
        Instanda.Variables.PrefillHome_YN;
      const lexprefillEL =
        $('input[name="LexisNexisPrefill_YN"]:checked').val() ||
        Instanda.Variables.LexisNexisPrefill_YN;

      if (
        typeof prefillrequired === "string" &&
        prefillrequired.trim().toLowerCase() === "yes"
      ) {
        hideSpinner();
        console.log("Prefill not required, skipping LexisNexis call.");
        return Promise.resolve(false);
      }
      if (
        typeof lexprefillEL === "string" &&
        lexprefillEL.trim().toLowerCase() === "yes"
      ) {
        hideSpinner();
        console.log("Prefill not required, skipping LexisNexis call.");
        return Promise.resolve(false);
      }

      // Get PackageId
      const packageId = Instanda.Variables.PackageId;

      // Prepare request body
      const isIndividual =
        Instanda.Variables.Name_Type_CHOICEP === "Individual";
      const personalDetails = {
        firstName: isIndividual ?
          Instanda.Variables.FirstName_TXT || "" : Instanda.Variables.PolicyHolderName_TXT,
        middleName: isIndividual ? Instanda.Variables.MiddleName_TXT || "" : "",
        lastName: isIndividual ? Instanda.Variables.LastName_TXT || "" : "",
        suffix: isIndividual ? Instanda.Variables.Suffix_CHOICE || "" : "",
        dateOfBirth: Instanda.Variables.DOB_DATE ?
          formatDateToDDMMYYYY(Instanda.Variables.DOB_DATE) : formatDateToDDMMYYYY(new Date()),
      };

      const body = {
        personalDetails,
        quoteDetails: {
          quoteRef: String(Instanda.Variables.QuoteRef),
        },
        address: {
          addressLine1: Instanda.Variables.RiskAddressLine1RO_TXT,
          city: Instanda.Variables.RiskCityRO_TXT,
          state: Instanda.Variables.RiskStateRO_TXT,
          zipCode: extractZipCode(Instanda.Variables.RiskPostCodeRO_TXT) || "",
          addressType: "risk",
        },
      };

      // Make API call
      const {
        apiBaseUrl,
        subscriptionKey
      } = getApiEndpoint("phase2");
      const apiEndpoint = `${apiBaseUrl}/lexisnexis/v1/getPrefillDataHome`;

      return ManageApiCache.cachedFetch(apiEndpoint, {
        method: "POST",
        headers: generateHeaders(subscriptionKey),
        body: JSON.stringify(body),
      })
        .then(async (response) => {
          if (!response.ok) {
            const errorData = await response.json();
            console.error("Error response:", errorData);
            throw new Error("API request failed");
          }
          return response.json();
        })
        .then(async (data) => {
          // --- Special handling for PackageId 24428 ---
          async function getExistingHomeMI() {
            if (typeof getQuoteorPolicydata === "function") {
              const q = await getQuoteorPolicydata(null);
              return Array.isArray(q?.Home_MI) ? q.Home_MI : [];
            }
            if (typeof getQuoteData === "function") {
              const q = await getQuoteData(null);
              return Array.isArray(q?.Home_MI) ? q.Home_MI : [];
            }
            throw new Error("No quote/policy GET helper available.");
          }

          if (packageId == 24428) {
            const resp = data.vendorResponse?.response || {};

            // Parse state and postal from stateCityZip
            let state = "",
              postal = "";
            const stateCityZip = resp.stateCityZip || "";
            const parts = stateCityZip.split(",");
            if (parts.length >= 2) {
              const statePostal = parts[1].trim().split(/\s+/);
              state = statePostal[0] || "";
              postal = statePostal[1] || "";
            }

            const homes = [...(await getExistingHomeMI())];

            let idx = homes.findIndex(
              (h) =>
                String(h?.H_Primary_YNP || "")
                  .trim()
                  .toLowerCase() === "yes"
            );
            if (idx === -1)
              idx = homes.findIndex((h) => Number(h?.Position) === 1);
            if (idx === -1) idx = 0;

            if (homes.length === 0) {
              homes.push({
                Position: 1,
                H_Primary_YNP: "Yes",
              });
              idx = 0;
            }

            // Only map fields that come from the response and are required
            const existing = homes[idx] || {};
            homes[idx] = {
              ...existing,
              H_AddressLine1_TXT: robustValue(
                resp.addressLine1,
                existing.H_AddressLine1_TXT
              ),
              H_AddressLine2_TXT: robustValue(
                resp.addressLine2,
                existing.H_AddressLine2_TXT
              ),
              H_City_TXT: robustValue(resp.city) === Instanda.Variables.RiskCityRO_TXT ?
                robustValue(resp.city) : robustValue(
                  Instanda.Variables.RiskCityRO_TXT,
                  existing.H_City_TXT
                ),
              H_Country_TXT: robustValue(
                existing.H_Country_TXT,
                Instanda.Variables.RiskCountryRO_TXT,
                "US"
              ),
              H_PostalCode_TXT: robustValue(
                postal,
                resp.zipCode,
                existing.H_PostalCode_TXT
              ),
              H_State_TXT: robustValue(
                Instanda.Variables.RiskStateRO_TXT,
                state,
                resp.state,
                existing.H_State_TXT
              ),
              H_SwimmingPool_YN: resp.poolIndicator === "Y" ?
                "Yes" : resp.poolIndicator === "N" ?
                  "No" : existing.H_SwimmingPool_YN || "",
              H_UnitApt_TXT: robustValue(
                Instanda.Variables.RiskAddress_Unit_TXT,
                resp.unit,
                existing.H_UnitApt_TXT
              ),
              Position: existing.Position ?? 1,
              RISKITEM_OID_Home: existing.RISKITEM_OID_Home,
            };

            // Update backend with Home_MI
            await updateQuoteorPolicydata(null, {
              Home_MI: homes,
              PrefillHome_YN: "Yes",
            });
            return true;
          }

          // --- Default handling for all other packages ---
          const response = data.vendorResponse?.response || {};
          const propertyCharacteristic = response.propertyCharacteristic || {};

          //setting no of mortages value for rating screen -using update quote API
          if (data.vendorResponse.response.mortgages) {
            const backendData = {
              NumOfMortgage_NUM: data.vendorResponse.response.mortgages?.length || "0",
            };
            updateQuoteorPolicydata(null, backendData)
              .then((response) => {
                console.log("Backend updated successfully");
              })
              .catch((error) => {
                console.error("Failed to update backend:", error);
              });
          }

          // Set property details (skip for NY condo/tenant)
          const nyCounties = [
            "New York",
            "Bronx",
            "Kings",
            "Queens",
            "Richmond",
          ];
          const county = Instanda.Variables.County_TXT;
          const policyForm = Instanda.Variables.PolicyType_CHOICE;
          const isNyCondoOrTenant =
            nyCounties.includes(county) &&
            (policyForm === "Condo/Cooperative" || policyForm === "Tenant");

          const constType = $("#ConstructionType_CHOICE");
          const constType2 = $("#ConstructionType2_CHOICE");
          const constType3 = $("#ConstructionType3_CHOICE");
          const yearBuiltHO = $("#YearBuilt_NUM");
          const aggregateSquareFootageHO = $("#AggregateSquareFootage_NUM");
          const rooftypeHO = $("#RoofType_CHOICE");
          const noOfStories1HO = $("#NumofStories1_CHOICE");
          const noOfStoriesFLHO = $("#NumofStoriesFL_CHOICE");
          const foundationHO = $("#Foundation_CHOICE");
          const noOfMortgagesHO = $("#NoOfMortgagesForRating_TXT");

          if (!isNyCondoOrTenant) {
            const state = Instanda.Variables.RiskStateRO_TXT;
            if (state === "NC") {
              rooftypeHO.val(
                normalizeMapping(
                  roofTypeNCMappingArray,
                  propertyCharacteristic.roofType
                )
              );
            } else {
              rooftypeHO.val(
                normalizeMapping(
                  roofTypeMappingArray,
                  propertyCharacteristic.roofType
                )
              );
            }
            if (state !== "NY") {
              constType.val(
                normalizeMapping(
                  constructionTypeMappingArray,
                  propertyCharacteristic.constructionType
                )
              );
              constType2.val(
                normalizeMapping(
                  constructionTypeMappingArrayTX,
                  propertyCharacteristic.constructionType
                )
              );
              constType3.val(
                normalizeMapping(
                  constructionTypeMappingArray,
                  propertyCharacteristic.constructionType
                )
              );
            }
          }

          // Set other property fields
          noOfStories1HO.val(
            normalizeMapping(storiesMappingArray, response.stories)
          );
          noOfStoriesFLHO.val(
            normalizeMapping(storiesMappingArray, response.stories)
          );
          $("#NumOfStoriesIns_TXT").val(response.stories || "0");
          yearBuiltHO.val(response.yearBuilt || "");
          aggregateSquareFootageHO.val(response.buildingSquareFootage || "0");
          // ===== FOUNDATION CHANGES START =====
          // Why: Network payload returns foundation at response.foundation (e.g., "SLAB").
          // Fixes:
          // 1) Read foundation from response.foundation first (fallback to propertyCharacteristic.foundation).
          // 2) Set dropdown only after options are populated (prevents defaulting to "Unknown" due to timing).
          // 3) Supports dropdown mismatch: option value vs option label.
          // 4) AC2: For PackageId 24337 + Non-Admitted + WA/CA/HI:
          //    If LN foundation missing OR unmapped => force "Unknown".
          const isTargetFlow =
            Number(Instanda.Variables.PackageId) === 24337 &&
            Instanda.Variables.ProductCode_CHOICE === "Non-Admitted";
          const isTargetState = ["WA", "CA", "HI"].includes(
            Instanda.Variables.RiskStateRO_TXT
          );
          const rawFoundation =
            response.foundation ?? propertyCharacteristic.foundation;
          const mappedFoundationKey = normalizeMapping(
            foundationTypeMappingArray,
            rawFoundation
          );
          const noFoundationFromLexis =
            rawFoundation == null ||
            String(rawFoundation).trim() === "" ||
            mappedFoundationKey == null ||
            String(mappedFoundationKey).trim() === "";
          if (isTargetFlow && isTargetState) {
            setSelectValueSmartAsync(
              foundationHO,
              noFoundationFromLexis ? "Unknown" : mappedFoundationKey,
              "Unknown"
            );
          } else {
            setSelectValueSmartAsync(
              foundationHO,
              mappedFoundationKey,
              "Unknown"
            );
          }
          // ===== FOUNDATION CHANGES END =====
          // Set the "Yes" radio for PrefillHome_YN and trigger click
          $("#PrefillHome_YNYes").prop("checked", true).trigger("click");
          return true;
        })
        .catch((error) => {
          console.error("Error:", error);
          // Reset fields for both flows
          const nyCounties = [
            "New York",
            "Bronx",
            "Kings",
            "Queens",
            "Richmond",
          ];
          const county = Instanda.Variables.County_TXT;
          const policyForm = Instanda.Variables.PolicyType_CHOICE;
          const isNyCondoOrTenant =
            nyCounties.includes(county) &&
            (policyForm === "Condo/Cooperative" || policyForm === "Tenant");
          resetFields(isNyCondoOrTenant, Instanda.Variables.RiskStateRO_TXT);
          const isTargetFlow =
            Number(Instanda.Variables.PackageId) === 24337 &&
            Instanda.Variables.ProductCode_CHOICE === "Non-Admitted";
          const riskState = Instanda.Variables.RiskStateRO_TXT;
          const isTargetState = ["WA", "CA", "HI"].includes(riskState);
          // ===== FOUNDATION CHANGE =====
          //BH-24635 AC2 on LN call failure: force "Unknown" (wait for options to load).
          if (isTargetFlow && isTargetState) {
            setSelectValueSmartAsync(
              $("#Foundation_CHOICE"),
              "Unknown",
              "Unknown"
            );
          }
          displayApiErrorMessage(
            "An error occurred while invoking LexisNexis API. Please try again."
          );
          return false;
        })
        .finally(() => {
          hideSpinner();
        });
    } catch (err) {
      hideSpinner();
      console.error("Synchronous error:", err);
      displayApiErrorMessage(
        "A critical error occurred. Please contact support."
      );
      return false;
    }
  }

  // Calling Prefill for EL on Page2 //

  $(document).ready(function () {
    if (
      $(".readonlymode").length ||
      !$(".page-quickquotequestions.page-number-2.package-24428").length > 0 ||
      Instanda.Variables.CreatedFrom === "MTA"
    )
      return;

    if (
      Instanda.Variables.PackageId === 24428 &&
      Instanda.Variables.ConvertedPolicy_YNP === "Yes"
    ) {
      console.log("Converted Policy exiting LN Call");
      return;
    }

    const reason =
      $("#ChangeReason_Choice").val() ||
      Instanda.Variables.ChangeReason_Choice ||
      "";
    if (reason === "Reissue") return;

    const quoteId = Instanda.Variables.QuoteRef;
    const key = `prefill_${quoteId}`;
    if (sessionStorage.getItem(key)) return;

    const needAuto =
      (Instanda.Variables.PrefillAuto_YN || "").toLowerCase() !== "yes";
    const needHome =
      (Instanda.Variables.PrefillHome_YN || "").toLowerCase() !== "yes";

    if (!needAuto && !needHome) return;
    (async () => {
      try {
        showSpinner();
        if (needAuto) await getPrefillDataAuto();
        if (needHome) await getLexisNexisPrefillHO();
        sessionStorage.setItem(key, "true");
        hideSpinner();
        location.reload();
      } catch (e) {
        hideSpinner();
        console.error("Prefill failed:", e);
      }
    })();
  });

  // Helper function to reset fields on error
  function resetFields(isNyCondoOrTenant, state) {
    hideSpinner();
    if (!isNyCondoOrTenant) {
      rooftypeHO.val("");
      if (state !== "NY") {
        constType.val("");
        constType2.val("");
        constType3.val("");
      }
    }
    yearBuiltHO.val("");
    noOfStories1HO.val("");
    noOfStoriesFLHO.val("");
    aggregateSquareFootageHO.val("0");
    foundationHO.val("");
    noOfMortgagesHO.val("0");
  }

  // Normalize mapping function
  function normalizeMapping(mappingArray, responseValue) {
    for (const [key, values] of Object.entries(mappingArray)) {
      if (values.includes(responseValue)) {
        return key;
      }
    }
    return mappingArray[""] ? "" : "Other";
  }

  /* ===== FOUNDATION-ONLY HELPERS (added, used only for Foundation) =====
   - setSelectValueSmart: sets a <select> by option value OR option text
   - setSelectValueSmartAsync: waits for options to load before setting
*/
  function setSelectValueSmart($el, desiredKey, fallbackKey) {
    const desired = desiredKey == null ? "" : String(desiredKey).trim();
    const desiredUpper = desired.toUpperCase();
    // Try by option value
    $el.val(desiredKey);
    const current =
      $el.val() == null ? "" : String($el.val()).trim().toUpperCase();
    if (current === desiredUpper) return true;
    // Try by option text
    const $match = $el
      .find("option")
      .filter(function () {
        const txt =
          $(this).text() == null ?
            "" :
            String($(this).text()).trim().toUpperCase();
        return txt === desiredUpper;
      })
      .first();
    if ($match.length) {
      $el.val($match.val());
      return true;
    }
    // Fallback
    $el.val(fallbackKey);
    return false;
  }

  function setSelectValueSmartAsync($el, desiredKey, fallbackKey, opts) {
    const maxTries = (opts && opts.maxTries) || 25; // ~5s
    const delayMs = (opts && opts.delayMs) || 200;
    let tries = 0;
    (function tick() {
      tries += 1;
      // Consider ready when options are present (beyond just a placeholder)
      const ready = $el && $el.length && $el.find("option").length > 1;
      if (ready) {
        setSelectValueSmart($el, desiredKey, fallbackKey);
        return;
      }
      if (tries >= maxTries) {
        $el.val(fallbackKey);
        return;
      }
      setTimeout(tick, delayMs);
    })();
  }

