  //show cancel inspection questions on detailchange
  if (
    $(
      ".page-postquotequestions.created-from-detailchange.page-number-1.package-24337"
    ).length
  ) {
    /////only do if order inspection is no
    if (Instanda.Variables.ManualOrderInspection_CHOICEP === "No") {
      ///////////////////show inspection cancellation questions and make them mandatory
      // Make all .detail-change fields required and remove the class
      $(".detail-change").each(function () {
        $(this).prop("required", true);
        $(this).removeClass("detail-change");
      });

      // Specifically handle the select field
      const $select = $(
        '#InspectionCancellationReason_CHOICE, [name="InspectionCancellationReason_CHOICE"]'
      );
      $select.prop("required", true);

      // Optional: trigger validation on change for immediate feedback
      $select.on("change", function () {
        if ($(this).val() === "") {
          // This will show the browser's validation message if the form is submitted
          this.setCustomValidity("Please select a reason.");
        } else {
          this.setCustomValidity("");
        }
      });
      //////////////////////////////////////////////////
      // call the inspection api on click of continue
      $('[name="continueButton"]').on("click", function (event) {
        event.preventDefault();
        try {
          putInspectionOnHold();
        } catch (error) { }
        $(this).closest("form")[0].submit();
      });
    }
  }
  //cancel inspection api
  async function putInspectionOnHold() {
    const quoteRef = String(Instanda.Variables.QuoteRef);
    const policyNum = formatToTenDigits(Instanda.Variables.PolicyNumber);
    const holdNotes = "NA";
    const authUser = Instanda.Variables.SalespersonEmail;
    const authUName = Instanda.Variables.SalespersonName;
    const inspectionNumber = Instanda.Variables.InspectionId1_NUM;

    const body = {
      inspectionDetails: {
        inspectionID: inspectionNumber,
        authorUserID: authUser,
        authorUserName: authUName,
        holdNotes: holdNotes,
      },
      policyDetails: {
        policyNumber: String(policyNum),
      },
      quoteDetails: {
        quoteRef: quoteRef,
      },
    };

    const {
      apiBaseUrl,
      subscriptionKey
    } = getApiEndpoint("phase2");
    const apiEndpoint = `${apiBaseUrl}/lc360/v1/holdInspection`;

    return fetch(apiEndpoint, {
      method: "POST",
      headers: generateHeaders(subscriptionKey),
      body: JSON.stringify(body),
    })
      .then(async (response) => {
        if (!response.ok) {
          const errorData = await response.json();
          console.error("Error response:", errorData);
        }
        return response.json();
      })
      .then((data) => {
        console.log("Cancel Success");
      })
      .catch((error) => {
        console.error("Fetch error:", error);
        // Optionally rethrow or handle error
        alert(error);
        throw new Error(error);
      });
  }

