  async function lexNexPrefillDataAuto(event) {
    const qRef = String(Instanda.Variables.QuoteRef);
    const fName = Instanda.Variables.PrefillFirstName_TXT;
    const mName = Instanda.Variables.PrefillMiddleName_TXT;
    const lName = Instanda.Variables.PrefillLastName_TXT;
    const dob = formatDateToDDMMYYYY(Instanda.Variables.PrefillDOB_DATE);
    const street = Instanda.Variables.PrefillAddressLine1_TXT;
    const city = Instanda.Variables.PrefillCity_TXT;
    const zip =
      Instanda.Variables.PrefillZipCode_TXT.toString().split("-")[0] ===
        "75217" &&
        /^1914 Houghton (Rd|Road)$/i.test(
          Instanda.Variables.PrefillAddressLine1_TXT
        ) &&
        Instanda.Variables.PrefillCity_TXT === "Dallas" &&
        Instanda.Variables.PrefillState_CHOICE === "TX" ?
        "75218" :
        Instanda.Variables.PrefillZipCode_TXT.toString().split("-")[0];
    const state = Instanda.Variables.PrefillState_CHOICE;
    console.log("Neeraj testing 3");
    // Check for firstName and lastName, use indnametxt if they are not available
    // Request Structure
    const body = {
      personalDetails: {
        firstName: fName,
        middleName: mName,
        lastName: lName,
        dateOfBirth: dob,
      },
      quoteDetails: {
        quoteRef: qRef,
      },
      address: {
        streetName: street,
        city: city,
        state: state,
        postalCode: zip,
      },
    };

    console.log(
      "Request Body for LexisNexis Prefill Data for Auto:",
      JSON.stringify(body)
    );
    //console.log('qRef= '||qRef);

    const {
      apiBaseUrl,
      subscriptionKey
    } = getApiEndpoint("phase2");
    const apiEndpoint = `${apiBaseUrl}/lexisnexis/v1/getPrefillDataAuto`;

    const response = await fetch(apiEndpoint, {
      method: "POST",
      headers: generateHeaders(subscriptionKey),
      body: JSON.stringify(body),
    });

    hideSpinner();

    // Check if the response status is not OK (e.g., 400, 500)
    if (!response.ok) {
      // Try to parse JSON error body
      let errorData;
      try {
        errorData = await response.json();
        await handleApiErrorResponse(errorData);
      } catch (e) {
        // If not JSON, pass the response object itself (for status/statusText)
        throw new Error("Handled API error");
      }
    }
    return true;
  }

