  function generateHeadersForStartQuote(productType, subscriptionKey) {
    return {
      "pcsctx-appName": "Instanda",
      "pcsctx-traceId": generateUUID(),
      "pcsctx-sessionId": generateUUID(),
      "pcsctx-productType": productType,
      "Content-Type": "application/json",
      "Ocp-Apim-Subscription-Key": subscriptionKey,
    };
  }

  async function startQuoteAPI(productType, body = {}) {
    // Setup quote reference and user context
    const quoteRef = "Test";
    let siteDomainName = "";
    let siteId = null;
    const CurrentUrl = window.location.href;
    const siteCssLink = document.querySelector('link[href*="siteId="]');

    // Extract siteId if present in the CSS link
    if (siteCssLink) {
      const match = siteCssLink.href.match(/siteId=(\d+)/);
      if (match) siteId = match[1];
    }

    // Site domain determination logic (priority order as per your requirements)
    if (
      siteId === "2913" &&
      CurrentUrl.includes("https://design.instanda.us/")
    ) {
      siteDomainName = "private-client-select-agent2.instanda.us";
    } else if (
      CurrentUrl.includes("private-client-select-agent-uat2.instanda.us")
    ) {
      siteDomainName = "private-client-select-agent2.instanda.us";
    } else if (CurrentUrl.includes("private-client-select-agent.instanda.us")) {
      siteDomainName = "private-client-select-agent.instanda.us";
    } else if (CurrentUrl.includes("https://design.instanda.us/")) {
      siteDomainName = "private-client-select-agent.instanda.us";
    } else {
      siteDomainName = "private-client-select-agent.instanda.us"; // Default fallback
    }

    // Determine user
    const salesPersonUserName = Instanda.Variables.SFusername_TXT ?
      Instanda.Variables.SFusername_TXT :
      "integration.user@privateclientselect.com"; // to be removed Monday

    const agentGroupName =
      Instanda.Variables.SelectedBrokerCode_TXT.toString().padStart(7, "0") +
      " - " +
      Instanda.Variables.SelectedBrokerName_TXT;

    const query = {
      siteDomainName: siteDomainName,
      salesPersonUserName: salesPersonUserName,
    };

    if (
      $(".logged-in-broker, .logged-in-internal, .logged-in-external").length >
      0
    ) {
      query.agentGroupName = agentGroupName;
    }

    const requestEnvelope = JSON.stringify({
      method: "PUT",
      query: query,
      body: body,
    });

    const {
      apiBaseUrl,
      subscriptionKey
    } = getApiEndpoint("phase2");
    const apiEndpoint = `${apiBaseUrl}/instanda/v1/manageQuotePolicy?resource=StartQuote&recordId=${quoteRef}`;

    // API call
    const response = await fetch(apiEndpoint, {
      method: "POST",
      headers: generateHeadersForStartQuote(productType, subscriptionKey),
      body: requestEnvelope,
    });

    // Error handling, similar to your LexisNexis example
    if (response.status === 429) {
      throw new Error(
        "Start Quote failed due to too many requests.\nPlease try again."
      );
    } else if (response.status === 500) {
      throw new Error(
        "Start Quote failed due to Internal Server Error.\nPlease try again."
      );
    } else if (!response.ok) {
      let errorData;
      try {
        errorData = await response.json();
        // You can add a custom error handler here if needed
        throw new Error(
          "Error(" +
          response.status +
          ") occurred while starting a new quote:\n" +
          (errorData?.message || "Please try again.")
        );
      } catch (e) {
        throw new Error(
          "Error(" +
          response.status +
          ") occurred while starting a new quote.\nPlease try again."
        );
      }
    }

    return await response.json();
  }

  function navigateToNewScreen() {
    const newTab = window.open("", "_blank");

    if (!newTab) return null;

    const styles = newTab.document.createElement("style");
    styles.innerHTML = `
                body { 
                    display: flex; 
                    flex-direction: column; 
                    align-items: center; 
                    justify-content: center; 
                    height: 100vh; 
                    margin: 0; 
                    font-family: Arial, sans-serif; 
                    background: #f9f9f9;
                }
                .pre-existing-spinner {
                    border: 4px solid #f3f3f3;
                    border-top: 4px solid #041e42;
                    border-radius: 50%;
                    width: 30px;
                    height: 30px;
                    animation: spin 1s linear infinite;
                    margin-bottom: 20px;
                }
                @keyframes spin {
                    0% { transform: rotate(0deg); }
                    100% { transform: rotate(360deg); }
                }
                .pre-existing-msg {
                    font-size: 1.2em;
                    color: #333;
                }
            `;
    newTab.document.head.appendChild(styles);

    const spinner = newTab.document.createElement("div");
    spinner.classList.add("pre-existing-spinner");
    newTab.document.body.appendChild(spinner);

    const helpText = document.createElement("div");
    helpText.classList.add("pre-existing-msg");
    helpText.textContent = `Please wait while we setup your quote`;
    newTab.document.body.appendChild(helpText);

    return newTab;
  }

