  function getPrefillVar(nextProductType) {
    let productType = Instanda.Variables.PackageId;
    if (productType === 23424) {
      productType = "COL";
    } else if (productType === 23423) {
      productType = "Yacht";
    } else if (productType === 24338) {
      productType = "Auto";
    } else if (productType === 24428) {
      productType = "EL";
    } else if (productType === 24337) {
      productType = "HO";
    } else if (productType === 24518) {
      productType = "EQ";
    } else if (productType === 24588) {
      productType = "EFL";
    }
    const prefillData = {};
    const productVarMap = varMap[nextProductType];
    for (let key in productVarMap) {
      if (key === "CustomerID_TXT")
        prefillData[productVarMap[key]] = String(
          Instanda.Variables[varMap[productType][key]]
        ).padStart(10, "0");
      else if (key === "Broker_ZIP_NUM" || key === "ZIP")
        prefillData[productVarMap[key]] = String(
          Instanda.Variables[varMap[productType][key]]
        ).padStart(5, "0");
      else
        prefillData[productVarMap[key]] =
          Instanda.Variables[varMap[productType][key]];
    }

    // BH-20721 sending Auto prefill section fields to next auto

    if (
      productType === "Auto" &&
      nextProductType === "Auto" &&
      (Instanda.Variables.Name_Type_CHOICEP === "Individual" ||
        Instanda.Variables.PrefillFirstName_TXT)
    ) {
      const autoPrefillSectionVars = {
        FirstName_TXT: "PrefillFirstName_TXT",
        MiddleName_TXT: "PrefillMiddleName_TXT",
        LastName_TXT: "PrefillLastName_TXT",
        DOB_DATE: "PrefillDOB_DATE",
        Address_Line1: "PrefillAddressLine1_TXT",
        Address_Line2: "PrefillAddressLine2_TXT",
        City: "PrefillCity_TXT",
        State: "PrefillState_CHOICE",
        ZIP: "PrefillZipCode_TXT",
        Country: "PrefillCountry_CHOICE",
      };

      const autoInsuredSectionVars = {
        FirstName_TXT: "FirstName_TXT",
        MiddleName_TXT: "MiddleName_TXT",
        LastName_TXT: "LastName_TXT",
        DOB_DATE: "DOB_DATE",
        Address_Line1: "RiskAddressLine1RO_TXT",
        Address_Line2: "RiskAddressLine2RO_TXT",
        Unit_Apt: "RiskAddress_Unit_TXT",
        City: "RiskCityRO_TXT",
        State: "RiskStateRO_TXT",
        ZIP: "RiskPostCodeRO_TXT",
        Country: "RiskCountryRO_TXT",
      };

      if (Instanda.Variables.PrefillFirstName_TXT) {
        for (let keyVar in autoPrefillSectionVars) {
          prefillData[autoPrefillSectionVars[keyVar]] =
            Instanda.Variables[autoPrefillSectionVars[keyVar]];
        }
      } else if (Instanda.Variables.Name_Type_CHOICEP === "Individual") {
        for (let keyVar in autoPrefillSectionVars) {
          prefillData[autoPrefillSectionVars[keyVar]] =
            Instanda.Variables[autoInsuredSectionVars[keyVar]];
        }
      }
    }

    if (
      productType === "HO" &&
      nextProductType === "Auto" &&
      Instanda.Variables.Name_Type_CHOICEP === "Individual"
    ) {
      const autoPrefillSectionVars = {
        FirstName_TXT: "PrefillFirstName_TXT",
        MiddleName_TXT: "PrefillMiddleName_TXT",
        LastName_TXT: "PrefillLastName_TXT",
        DOB_DATE: "PrefillDOB_DATE",
        Address_Line1: "PrefillAddressLine1_TXT",
        Address_Line2: "PrefillAddressLine2_TXT",
        City: "PrefillCity_TXT",
        State: "PrefillState_CHOICE",
        ZIP: "PrefillZipCode_TXT",
        Country: "PrefillCountry_CHOICE",
      };

      const hoInsuredDetails = {
        FirstName_TXT: "FirstName_TXT",
        MiddleName_TXT: "MiddleName_TXT",
        LastName_TXT: "LastName_TXT",
        DOB_DATE: "DOB_DATE",
        Address_Line1: "RiskAddressLine1RO_TXT",
        Address_Line2: "RiskAddressLine2RO_TXT",
        City: "RiskCityRO_TXT",
        State: "RiskStateRO_TXT",
        ZIP: "RiskPostCodeRO_TXT",
        Country: "RiskCountryRO_TXT",
      };

      for (let keyVar in hoInsuredDetails) {
        prefillData[autoPrefillSectionVars[keyVar]] =
          Instanda.Variables[hoInsuredDetails[keyVar]];
      }
    }

    console.log(prefillData);
    return prefillData;
  }

  function startNextQuote() {
    return new Promise(async (resolve) => {
      if (Instanda.Variables.IsMultilineQuote_YN === "No") return;

      if (Instanda.Variables.IsMultilineQuote_YN === "Yes") {
        let prefillData = {};

        let nextProductType;
        let nextProductTypeVariable;
        let nextProductCountVariable;
        let nextProductChosen = false;
        let restOfProductCount = 0;
        for (let product of productOrder) {
          if (
            !nextProductChosen &&
            Instanda.Variables[product.productTypeVariable] === "Yes" &&
            Instanda.Variables[product.productCountVariable] > 0
          ) {
            nextProductType = product.productType;
            nextProductTypeVariable = product.productTypeVariable;
            nextProductCountVariable = product.productCountVariable;
            nextProductChosen = true;
            if (Instanda.Variables[nextProductCountVariable] - 1 === 0)
              prefillData[`${nextProductTypeVariable}`] = "No";
            else
              prefillData[`${nextProductTypeVariable}`] =
                Instanda.Variables[nextProductTypeVariable];
            prefillData[`${nextProductCountVariable}`] =
              Instanda.Variables[nextProductCountVariable] - 1;
            restOfProductCount +=
              Instanda.Variables[nextProductCountVariable] - 1;
          } else {
            prefillData[`${product.productTypeVariable}`] =
              Instanda.Variables[product.productTypeVariable];
            prefillData[`${product.productCountVariable}`] =
              Instanda.Variables[product.productCountVariable];
            restOfProductCount +=
              Instanda.Variables[product.productCountVariable];
          }
        }

        if (nextProductType) {
          const newTab = navigateToNewScreen();
          try {
            showSpinner();
            prefillData = Object.assign(
              prefillData,
              getPrefillVar(nextProductType)
            );
            prefillData["QuoteCreatedIn_TXT"] = "Instanda";
            prefillData["SelectedBrokerName_TXT"] =
              Instanda.Variables.SelectedBrokerName_TXT;
            prefillData["sfdccustomerId_TXT"] =
              Instanda.Variables.sfdccustomerId_TXT;
            prefillData["sfdcAccountId_TXT"] =
              Instanda.Variables.sfdcAccountId_TXT;
            prefillData["AccountID_TXT"] =
              `${Instanda.Variables.AccountID_TXT}`.padStart(10, "0") //BH-28401 passing Account ID
            prefillData["SFusername_TXT"] = Instanda.Variables.SFusername_TXT; // added by soumya to pass SF Username to next quote
            prefillData["PrefilledBrokerSelection_TXT"] =
              `${Instanda.Variables.PrefilledBrokerSelection_TXT}`.padStart(
                7,
                "0"
              ); // sending PrefilledBrokerSelectionTXT
            if (restOfProductCount === 0)
              prefillData["IsMultilineQuote_YN"] = "No";
            else prefillData["IsMultilineQuote_YN"] = "Yes";
            console.log(
              "next calling start quoute with\n",
              nextProductType,
              prefillData
            );

            const response = await startQuoteAPI(nextProductType, prefillData);
            const nextQuoteUrl =
              response?.targetResponse?.response?.urlSingleUse;
            // if(response.status!==200) throw new Error("Failed")
            if (response && nextQuoteUrl) {
              const locStore = localStorage.getItem("Quote_Sequence");
              if (locStore) {
                const quoteSeq = JSON.parse(locStore);
                quoteSeq.push({
                  productType: nextProductType,
                  quoteRef: response.targetResponse.response.quoteRef,
                });
                localStorage.setItem(
                  "Quote_Sequence",
                  JSON.stringify(quoteSeq)
                );
              } else
                localStorage.setItem(
                  "Quote_Sequence",
                  JSON.stringify([{
                    productType: nextProductType,
                    quoteRef: response.targetResponse.response.quoteRef,
                  },])
                );

              const updateBody = {};
              updateBody["NextQuoteCreated_YN"] = "Yes";
              updateBody[`${nextProductCountVariable}`] =
                Instanda.Variables[`${nextProductCountVariable}`] - 1;
              if (!Instanda.Variables.PolicyNumber)
                await updateQuoteorPolicydata(new Event("change"), updateBody);

              // newTab.document.open()
              newTab.location = nextQuoteUrl;

              console.log("End of Continue to next Quote");
              resolve(true);
            }
          } catch (e) {
            console.log(e);

            newTab.close();

            setTimeout(() => {
              alert(e);
            }, 100);
            resolve(false);
          } finally {
            hideSpinner();
          }
        }
      }
    });
  }

  $(document).ready(function () {
    const referralPage = document.querySelector(
      ".page-reviewreferrals.created-from-newbusiness:not(.readonlymode)"
    );
    const quoteSumPage = document.querySelector(
      ".page-quote.created-from-newbusiness:not(.readonlymode)"
    );
    const salesPage = document.querySelector(
      ".page-confirmation2.sale-stage-salecomplete.created-from-newbusiness:not(.readonlymode)"
    );

    if (
      Instanda.Variables.IsMultilineQuote_YN === "No" ||
      Instanda.Variables.NextQuoteCreated_YN === "Yes"
    )
      return;

    if (quoteSumPage) {
      const nextQuoteBtn = document.createElement("button");
      nextQuoteBtn.textContent = "Continue to next Quote";
      nextQuoteBtn.id = "startNextQuoteBtn";

      nextQuoteBtn.addEventListener("click", async (e) => {
        e.preventDefault();
        const response = await startNextQuote();
        if (response === true) nextQuoteBtn.disabled = true;
      });
      document.querySelector(".pull-right").prepend(nextQuoteBtn);
    }

    if (referralPage) {
      const nextQuoteBtn = document.createElement("button");
      nextQuoteBtn.textContent = "Continue to next Quote";
      nextQuoteBtn.id = "startNextQuoteBtn";

      //Custom alert

      function insertNextQuotePopup() {
        if (document.getElementById("nextQuotePopup")) return; // Prevent duplicates

        const modal = document.createElement("div");
        modal.id = "nextQuotePopup";
        modal.style.display = "none";
        modal.style.position = "fixed";
        modal.style.top = 0;
        modal.style.left = 0;
        modal.style.width = "100vw";
        modal.style.height = "100vh";
        modal.style.background = "rgba(0,0,0,0.5)";
        modal.style.zIndex = 9999;
        modal.style.justifyContent = "center";
        modal.style.alignItems = "center";
        modal.innerHTML = `
    <div style="background:#fff;padding:20px;border-radius:8px;max-width:90vw;width:350px;box-shadow:0 0 10px #333;">
      <p style="margin-bottom:25px;">
        Please click on “Refer to Underwriter” to ensure the referral is submitted, or confirm that you want to move to the next quote without referring.
      </p>
      <button id="goBackBtn" class = "btn btn-primary">Go Back and Refer</button>
      <button id="confirmBtn"class = "btn btn-primary">Confirm</button>
    </div>
  `;
        document.body.appendChild(modal);
      }

      function showNextQuotePopup() {
        return new Promise((resolve) => {
          $("#nextQuotePopup").css("display", "flex");
          $("#goBackBtn")
            .off("click")
            .on("click", function () {
              $("#nextQuotePopup").hide();
              resolve("goBack");
            });
          $("#confirmBtn")
            .off("click")
            .on("click", function () {
              $("#nextQuotePopup").hide();
              resolve("confirm");
            });
        });
      }
      // Call this function once on page load (or before first use)
      insertNextQuotePopup();

      nextQuoteBtn.addEventListener("click", async (e) => {
        e.preventDefault();
        if (
          $("#RefCaseId").val() == "" &&
          Instanda.Variables.SalespersonReferralLevel < 4
        ) {
          const result = await showNextQuotePopup();
          if (result === "goBack") {
            return; // stop further processing
          }
        }
        const response = await startNextQuote();
        if (response === true) nextQuoteBtn.disabled = true;
      });

      document
        .querySelector(
          "button[name='saveButton'][formnovalidate='formnovalidate']"
        )
        .before(nextQuoteBtn);
    }

    if (salesPage) {
      const nextQuoteBtn = document.createElement("button");
      nextQuoteBtn.textContent = "Continue to next Quote";
      nextQuoteBtn.id = "startNextQuoteBtn";

      nextQuoteBtn.addEventListener("click", async (e) => {
        e.preventDefault();
        const response = await startNextQuote();
        if (response === true) nextQuoteBtn.disabled = true;
      });

      document
        .querySelector(".container.instanda-lower-content > div:nth-of-type(2)")
        .prepend(nextQuoteBtn);

      const returnBtn = document.querySelector(
        ".container.instanda-lower-content > div:nth-of-type(2) .btn.btn-primary"
      );
      returnBtn.textContent = "Return to Dashboard";
      returnBtn.addEventListener("click", function (e) {
        e.preventDefault();
        const cancelQuotes = confirm(
          "Leaving this page?\nQuotes you've already started will be saved. Any unstarted quotes in this series will be lost if you return to the dashboard."
        );
        if (cancelQuotes) window.location = returnBtn.href;
      });
    }
  });

