  // reducing primary quote by 1
  function reducePrimaryQuoteCount() {
    if (
      document.querySelector(
        ".page-quickquotequestions.page-number-1 input[name='QuoteCreatedIn_TXT']"
      ) ||
      document.querySelector(
        ".page-prequotequestions.page-number-1 input[name='QuoteCreatedIn_TXT']"
      )
    ) {
      const flag = document.querySelector(
        "input[name='QuoteCreatedIn_TXT']"
      ).value;
      if (
        flag === "Instanda" ||
        document.querySelector('input[name="IsMultilineQuote_YN"]').value ===
        "No"
      )
        return;
      if (
        document.querySelector(".package-24338") &&
        Instanda.Variables.ProductAuto_YN === "Yes"
      ) {
        document.querySelector('input[name="AutoCount_Num"]').value -= 1;
        document.querySelector('input[name="QuoteCreatedIn_TXT"]').value =
          "Instanda";
      } else if (
        document.querySelector(".package-23424") &&
        Instanda.Variables.ProductCollection_YN === "Yes"
      ) {
        document.querySelector('input[name="CollectionCount_NUM"]').value -= 1;
        document.querySelector('input[name="QuoteCreatedIn_TXT"]').value =
          "Instanda";
      } else if (
        document.querySelector(".package-24428") &&
        Instanda.Variables.ProductExcessLiability_YN === "Yes"
      ) {
        document.querySelector(
          'input[name="ExcessLiabilityCount_NUM"]'
        ).value -= 1;
        document.querySelector('input[name="QuoteCreatedIn_TXT"]').value =
          "Instanda";
      } else if (
        document.querySelector(".package-24518") &&
        Instanda.Variables.ProductEarthquake_YN === "Yes"
      ) {
        document.querySelector('input[name="EarthquakeCount_NUM"]').value -= 1;
        document.querySelector('input[name="QuoteCreatedIn_TXT"]').value =
          "Instanda";
      } else if (
        document.querySelector(".package-24588") &&
        Instanda.Variables.ProductExcessFlood_YN === "Yes"
      ) {
        document.querySelector('input[name="ExcessFloodCount_NUM"]').value -= 1;
        document.querySelector('input[name="QuoteCreatedIn_TXT"]').value =
          "Instanda";
      } else if (
        document.querySelector(".package-24337") &&
        Instanda.Variables.ProductHomeowners_YN === "Yes"
      ) {
        document.querySelector('input[name="HomeownersCount_NUM"]').value -= 1;
        document.querySelector('input[name="QuoteCreatedIn_TXT"]').value =
          "Instanda";
      } else if (
        document.querySelector(".package-23423") &&
        Instanda.Variables.ProductYacht_YN === "Yes"
      ) {
        document.querySelector('input[name="YachtCount_NUM"]').value -= 1;
        document.querySelector('input[name="QuoteCreatedIn_TXT"]').value =
          "Instanda";
      }
    }
  }

