  // Adding SF dashboard link
  function configureNavLink() {
    const currentUrl = window.location.href;
    const environments = {
      dev: "dev",
      uat1: "uat1",
      uat2: "uat2",
      prod: "prod",
    };

    const environment = currentUrl.includes("https://design.instanda.us") ?
      environments.dev :
      currentUrl.includes(
        "https://private-client-select-agent-uat.instanda.us"
      ) ?
        environments.uat1 :
        currentUrl.includes(
          "https://private-client-select-agent-uat2.instanda.us"
        ) ?
          environments.uat2 :
          currentUrl.includes(
            "https://private-client-select-agent.instanda.us"
          ) || currentUrl.includes("https://pcsuw.com") ?
            environments.prod :
            null;

    const sfBaseUrls = {
      dev: "https://pcsmga--devph2.sandbox.lightning.force.com/lightning/page/home",
      uat2: "https://pcsmgu--qapcs.sandbox.lightning.force.com/lightning/page/home",
      uat1: "https://pcsmgu--uat.sandbox.lightning.force.com/lightning/page/home",
      prod: "https://pcsmgu.lightning.force.com/lightning/page/home",
    };

    const sfBaseUrlsBroker = {
      dev: "https://pcsmgu--qapcs.sandbox.my.site.com/brokerportalapp",
      uat2: "https://pcsmgu--qapcs.sandbox.my.site.com/brokerportalapp",
      uat1: "https://pcsmgu--uat.sandbox.my.site.com/brokerportalapp",
      prod: "https://broker.pcsuw.com/",
    };

    const sfBaseUrl = sfBaseUrls[environment];

    const sfBaseUrlBroker = sfBaseUrlsBroker[environment];

    const dashInterval = setInterval(() => {
      const navItem = document.querySelector(
        ".instanda-nav-item-link.sf-dashboard-link"
      );
      const staticDashLink = document.querySelector(
        ".custom-pcslogo-sflink.mySFLink"
      );
      const customStaticTop = $(
        '.custom-static-top a, .page-agentalldocs a[href="/Public/AgentDashboard"], .page-cancelpolicy a[href="/Public/AgentDashboard"]'
      );
      if (
        $(".logged-in-broker, .logged-in-internal, .logged-in-external")
          .length > 0
      ) {
        if (navItem) navItem.href = sfBaseUrlBroker;
        if (staticDashLink) staticDashLink.href = sfBaseUrlBroker;
        if (customStaticTop.length > 0)
          customStaticTop.attr("href", sfBaseUrlBroker);
        if (navItem && staticDashLink && customStaticTop.length > 0)
          clearInterval(dashInterval);
      } else {
        if (navItem) navItem.href = sfBaseUrl;
        if (staticDashLink) staticDashLink.href = sfBaseUrl;
        if (customStaticTop.length > 0) customStaticTop.attr("href", sfBaseUrl);
        if (navItem && staticDashLink && customStaticTop.length > 0)
          clearInterval(dashInterval);
      }
    }, 1000);

    const salesPage = $(
      ".page-confirmation2.sale-stage-salecomplete, .page-cancellationcomplete.sale-stage-cancelled"
    );

    if (salesPage.length > 0) {
      const updateDashLinkInterval = setInterval(() => {
        const returnBtn = document.querySelector(
          ".container.instanda-lower-content > div:nth-of-type(2) .btn.btn-primary"
        );
        if (returnBtn) {
          returnBtn.textContent = "Return to Dashboard";
          returnBtn.href =
            Number.parseInt(Instanda.Variables.PCSReferralLevel) > 3 ||
              Number.parseInt(Instanda.Variables.PCSReferralLevel_TXT) > 3 ||
              Number.parseInt(Instanda.Variables.SalespersonReferralLevel) > 3 ||
              $(".logged-in-broker, .logged-in-external, .logged-in-internal")
                .length === 0 ?
              sfBaseUrl :
              sfBaseUrlBroker;
        }
      }, 500);
    }
  }
