  function aprraisalUpload() {
    if (
      Instanda.Variables.CO_ScheduleUp_Lim250_NUM_Count > 0 &&
      document.querySelector(
        ".instanda-post-quote-questions .questionList .questionItem.instanda-question-item.form-group:has(+ .questionItem .confirmQuestionCheckbox):not(#question465642)"
      )
    ) {
      // Select the parent with id #question438456
      var parent = document.getElementById("question438456");
      if (parent) {
        // Check for .instanda-document-upload-input inside the parent
        var uploadInput = parent.querySelector(
          ".instanda-document-upload-input"
        );
        // Select the second label inside the parent with id #question438456
        var label = parent.querySelector(
          ".instanda-document-upload-input:nth-child(2) .instanda-file-input-label-btn"
        );
        // Check for .instanda-document-upload-file-container inside uploadInput
        var hasFileContainer =
          uploadInput &&
          uploadInput.querySelector(".instanda-document-upload-file-container");
        if (uploadInput && label) {
          if (!hasFileContainer) {
            // Add the asterisk if not present
            if (!label.classList.contains("red-asterisk")) {
              label.classList.add("red-asterisk");
              var asterisk = document.createElement("span");
              asterisk.textContent = " *";
              asterisk.style.color = "red";
              asterisk.style.fontWeight = "bold";
              label.appendChild(asterisk);
            }
          } else {
            // Remove the asterisk if present
            if (label.classList.contains("red-asterisk")) {
              label.classList.remove("red-asterisk");
              // Remove the span with the red asterisk
              var spans = label.querySelectorAll("span");
              spans.forEach(function (span) {
                if (span.textContent.trim() === "*") {
                  label.removeChild(span);
                }
              });
            }
          }
        }
      }
    }
  }

  function validateAppraisalFileInput() {
    let errors = [];
    const parent = document.getElementById("question438456");
    if (!parent) {
      // console.log('Parent #question438456 not found');
      return errors;
    }
    const fileContainer = parent.querySelector(
      ".instanda-document-upload-file-container"
    );
    if (!fileContainer) {
      // console.log('No .instanda-document-upload-file-container found');
      return errors;
    }
    const inputContainer = fileContainer.querySelector(
      ".instanda-document-upload-input-container"
    );
    if (!inputContainer) {
      // console.log('No .instanda-document-upload-input-container found');
      return errors;
    }
    const fileInput = inputContainer.querySelector('input[type="file"]');
    if (!fileInput) {
      // console.log('No file input found');
      return errors;
    }
    if (!fileInput.value) {
      errors.push("Please upload a file for appraisal.");
    }
    return errors;
  }

