  function setSubjectivityReviewIfUploadRequired() {
    // Check if any visible file input is required
    var isAnyUploadRequired =
      $('input[type="file"]:visible[required]').length > 0;

    // Check if any visible .instanda-file-input-selected label says "No file selected"
    var isNoFileSelected =
      $(".instanda-file-input-selected:visible").filter(function () {
        return $(this).text().trim().toLowerCase() === "no file selected";
      }).length > 0;

    if (isAnyUploadRequired) {
      // Set the "Yes" radio button
      $('input[name="IsSubjectivityReviewRequired_YN"][value="Yes"]').prop(
        "checked",
        true
      );
    } else {
      // Set the "No" radio button
      $('input[name="IsSubjectivityReviewRequired_YN"][value="No"]').prop(
        "checked",
        true
      );
    }
  }

