  //Document upload date conversion to EST
  function convertToEDT(utcDateString) {
    const utcDate = new Date(utcDateString);

    // Check for invalid date
    if (isNaN(utcDate.getTime())) {
      throw new Error("Invalid date string provided");
    }

    // Use toLocaleString with 'America/New_York' to handle EDT/EST automatically
    const options = {
      year: "numeric",
      month: "numeric",
      day: "numeric",
      hour: "numeric",
      minute: "numeric",
      second: "numeric",
      hour12: true,
      timeZone: "America/New_York",
    };

    return utcDate.toLocaleString("en-US", options);
  }

