  /// Readonly View Function ////////

  function isReadOnlyView() {
    // Get current quote reference
    var quoteRef =
      window.Instanda && Instanda.Variables && Instanda.Variables.QuoteRef ?
        Instanda.Variables.QuoteRef :
        null;

    if (!quoteRef) return false; // No quoteRef available, default to not readonly

    var storageKey = "QuoteisReadonly" + String(quoteRef);

    // 1. Check for quoteIsReadOnly in URL (true or false, case-insensitive)
    var qsMatch = window.location.search.match(
      /quoteIsReadOnly\s*=\s*(true|false)/i
    );
    if (qsMatch) {
      var value = qsMatch[1].toLowerCase() === "true";
      sessionStorage.setItem(storageKey, String(value));
      return value;
    } else {
      // No param: clean out any old session value for this quote
      sessionStorage.removeItem(storageKey);
    }

    // 2. Check any inline script for var quoteIsReadOnly = true
    var foundInScripts = Array.from(document.scripts).some((script) => {
      try {
        return (
          script.textContent &&
          script.textContent.includes("var quoteIsReadOnly = true")
        );
      } catch (e) {
        return false;
      }
    });
    if (foundInScripts) {
      sessionStorage.setItem(storageKey, "true");
      return true;
    }

    // 3. Fallback to sessionStorage (if still set for some reason)
    var stored = sessionStorage.getItem(storageKey);
    if (stored !== null) {
      return stored === "true";
    }

    // Default to not readonly
    return false;
  }

