  ////////////////////////////////////////////////////////////Construction Type///////////////////////////////////////////////
  function collectionsMultiItems() {
    const miContainers = document.querySelectorAll(
      '[class*="instanda-multi-item-"]'
    ); // Use appropriate selector
    const prefix = "instanda-multi-item-";
    if (miContainers && prefix) {
      miContainers.forEach((container) => {
        const miNumber = extractMINumber(container, prefix);
        miConstructionType(container, miNumber);
      });
    }
  }

  function miConstructionType(container, miNumber) {
    function updateConstChoices() {
      const state = $(
        `#CO_SecondaryLocationCoverage_MI${miNumber}_CO_SecondaryAddressState_TXT`
      ).val();
      var constructionTypeDropdown = $(
        `#CO_SecondaryLocationCoverage_MI${miNumber}_CO_SPrimary_ConstructionType_CHOICE option`
      );
      if (constructionTypeDropdown) {
        constructionTypeDropdown.hide();
        if (state !== "TX") {
          constructionTypeDropdown
            .filter(function () {
              return (
                $(this).val() === "Aluminum or Plastic Siding" ||
                $(this).val() === "Frame" ||
                $(this).val() === "Brick Stone or Masonry" ||
                $(this).val() === "Brick Stone or Masonry Veneer" ||
                $(this).val() === "Superior or Fire Resistive"
              );
            })
            .show();
        } else {
          constructionTypeDropdown
            .filter(function () {
              return (
                $(this).val() === "Asbestos, Clad & Stucco" ||
                $(this).val() === "Brick" ||
                $(this).val() === "Brick Veneer" ||
                $(this).val() === "Frame" ||
                $(this).val() === "Synthetic Stucco"
              );
            })
            .show();
        }
        console.log(
          "Visible options miConstructionType:",
          constructionTypeDropdown
            .filter(":visible")
            .map(function () {
              return $(this).val();
            })
            .get()
        );
      }
    }
    updateConstChoices();
    $(
      `#CO_SecondaryLocationCoverage_MI${miNumber}_CO_SecondaryAddressState_TXT`
    ).on("change", function () {
      $(
        `#CO_SecondaryLocationCoverage_MI${miNumber}_CO_SPrimary_ConstructionType_CHOICE`
      ).val("");
      updateConstChoices();
    });
  }
  /////////////////////////////////////////////////////////////////////////////////////////Construction Type Multi Item Code ends

