  /////////////////////////////////////////////////Upload Doc//////////////////////////////////////////////////////////////////////

  if ($(".page-agentalldocs").length > 0) {
    function getQueryParams() {
      const params = {};
      const queryString = window.location.search.substring(1);
      const queries = queryString.split("&");
      queries.forEach((query) => {
        const pair = query.split("=");
        params[decodeURIComponent(pair[0])] = decodeURIComponent(pair[1] || "");
      });
      return params;
    }

    const ul = document.querySelector("#documentsList");

    function getLastElementDetails(fileName) {
      if (ul && ul.children.length > 0) {
        for (let i = 0; i < ul.children.length; i++) {
          const element = ul.children[i];
          const anchorTag = element.querySelector("a");
          if (anchorTag && anchorTag.textContent.includes(fileName)) {
            const href = anchorTag.getAttribute("href");
            let url = new URL(window.location.href);
            const fullUrl = `${url.origin}${href}`;
            return fullUrl;
          }
        }
      }
      return null;
    }

    function getFileTypeFromUrl(url) {
      const extension = url.split(".").pop().toLowerCase();
      const mimeTypes = {
        pdf: "application/pdf",
        doc: "application/msword",
        docx: "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
        xls: "application/vnd.ms-excel",
        xlsx: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        txt: "text/plain",
        // Add more file types and their MIME types as needed
      };
      return mimeTypes[extension] || "application/octet-stream";
    }

    function getExtensionFromUrl(url) {
      const extension = url.split(".").pop().toLowerCase();
      return extension;
    }

    const params = getQueryParams();
    const filenm = params.fileName;
    const fileUrl = getLastElementDetails(filenm);

    window.onload = function () {
      const event = new Event("submit"); // Create a synthetic event
      if (params.alfrescoup) {
        redirectbacktoUpload(event, fileUrl);
      }
    };

    const CreatedFrom = Instanda.Variables.CreatedFrom;
    const accountIdUpload = formatToTenDigits(
      String(Instanda.Variables.AccountID_TXT)
    );
    const username = Instanda.Variables.SalespersonEmail;
    const custNum = formatToTenDigits(
      String(Instanda.Variables.CustomerID_TXT)
    );
    const accRef =
      typeof Instanda.Variables.BillingAccountNumber_NUM !== "undefined" &&
        Instanda.Variables.BillingAccountNumber_NUM !== null ?
        String(Instanda.Variables.BillingAccountNumber_NUM) :
        "";
    const polnum =
      typeof Instanda.Variables.PolicyNumber !== "undefined" &&
        Instanda.Variables.PolicyNumber !== null ?
        formatToTenDigits(String(Instanda.Variables.PolicyNumber)) :
        "";
    const documentType = params.documentType;
    const filename = filenm;
    const contentType = getFileTypeFromUrl(filenm);
    const extens = getExtensionFromUrl(filenm);
    const categoryType = params.category;
    const subcategoryType = params.subCategory;
    const brokercode = Instanda.Variables.SelectedBrokerCode_TXT;
    const qtref = String(Instanda.Variables.QuoteRef);
    const polEffDate = formatDate(Instanda.Variables.EffectiveDate_DATE);
    const polExpDate = formatDate(Instanda.Variables.ExpirationDate_DATE);
    const quoteCreateDate = formatDate(Instanda.Variables.CreatedOn);
    const transtypcode =
      CreatedFrom === "NewBusiness" &&
        Instanda.Variables.ConvertedPolicy_YN === "Yes" ?
        "RENEWAL" :
        CreatedFrom;
    const polStateCd =
      Instanda.Variables.MA_State_CHOICE ||
      Instanda.Variables.CO_RiskStateRO_TXT;
    const billtypechoice = Instanda.Variables.BillingType_CHOICE;

    // Ensure transType is defined
    const transType = params.documentType; // Replace with actual value

    async function redirectbacktoUpload(event, fileUrl) {
      if (window.location.href.includes("AgentAllDocs")) {
        await alfrescoUploadDocument(event, fileUrl);

        setTimeout(function () {
          let url = new URL(window.location.href);
          let params = new URLSearchParams(url.search);

          let quoteRef = params.get("quoteRef");
          let packageid = params.get("packageId");

          // Create new URL with only quoteRef and packageid
          let newUrl =
            url.origin +
            url.pathname.replace("AgentAllDocs", "UploadDocuments");
          if (quoteRef || packageid) {
            newUrl += "?";
            if (quoteRef) {
              newUrl += "quoteRef=" + quoteRef;
            }
            if (packageid) {
              if (quoteRef) {
                newUrl += "&";
              }
              newUrl += "packageid=" + packageid;
            }
          }

          window.location.href = newUrl;
        }, 100);
      }
    }

    async function alfrescoUploadDocument(event, fileUrl) {
      event.preventDefault();
      showSpinner();

      try {
        // Fetch the file content from the URL
        const base64Content = await fetchFileAsBase64(fileUrl);

        const raw = JSON.stringify({
          metadata: [{
            value: CreatedFrom,
            name: String(transType),
          },],
          custNum: formatToTenDigits(String(custNum)),
          sourceCreatedBy: String(username),
          sourceSys: "Instanda",
          billActNum: accRef,
          category: String(categoryType),
          subcategory: String(subcategoryType),
          accountId: String(accountIdUpload),
          docType: String(documentType),
          domain: "Policy",
          contentType: String(contentType),
          fileName: String(filename),
          content: base64Content,
          policyNum: polnum,
          brokerCode: formatToSevenDigits(String(brokercode)),
          quoteNum: String(qtref),
          docExt: String(extens),
          createdOn: quoteCreateDate,
          transDate: quoteCreateDate,
          transID: qtref,
          transType: transtypcode,
          effDate: String(polEffDate),
          expDate: String(polExpDate),
          policyPrimState: polStateCd,
          segment: "",
          billType: billtypechoice,
          billRecipient: transtypcode,
          billEffDay: polEffDate,
          billEffMonth: polEffDate,
          billEffYear: polEffDate,
        });

        const {
          apiBaseUrl,
          subscriptionKey
        } =
          getApiEndpoint("uploaddocument");
        const siteCssLink = document.querySelector(
          'link[href*="SiteCustomCss"]'
        );
        let siteId = null;
        if (siteCssLink) {
          // Extract siteId from the href using a regular expression
          const match = siteCssLink.href.match(/siteId=(\d+)/);
          if (match) {
            siteId = match[1];
          }
        }
        let apiEndpoint;
        if (siteId === "2913") {
          apiEndpoint = `${apiBaseUrl}/alfresco/v1.2/uploaddocument`;
        } else {
          apiEndpoint = `${apiBaseUrl}/alfresco/v1/uploaddocument`;
        }

        const response = await fetch(apiEndpoint, {
          method: "POST",
          headers: generateHeaders(subscriptionKey),
          body: raw, // Use raw instead of body
          redirect: "follow",
        });

        hideSpinner();

        if (!response.ok) {
          const errorData = await response.json();
          throw new Error(
            `Document upload to alfresco failed: ${errorData.message}`
          );
        }

        const data = await response.json();
        console.log("Response Data:", data);
        return true;
      } catch (error) {
        hideSpinner();
        console.error("Error:", error);
        displayApiErrorMessage(error.message);
        return Promise.reject(false);
      }
    }

    // Function to fetch file content from URL and convert to base64
    async function fetchFileAsBase64(url) {
      const response = await fetch(url);
      const blob = await response.blob();
      return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result.split(",")[1]); // Get base64 part
        reader.onerror = (error) => reject(error);
        reader.readAsDataURL(blob);
      });
    }
  }

