  //common - function to add commas for number inputs

  // David Darcy 2025-06-20 -- replacing format function with hopefully faster one.

  // Format a single input element (used for event listener and page load)
  function formatSingleInput(input) {
    if (!(input instanceof HTMLInputElement)) return;

    const prepend = input.closest(".instanda-input-prepend");
    if (!prepend) return;

    const prefix = prepend.querySelector(".instanda-number-prefix");
    if (!prefix || !prefix.textContent.includes("$")) return;

    let value = input.value;
    let cursorPosition = input.selectionStart;

    // Remove all non-digit characters except the decimal point and leading minus
    let number = value.replace(/(?!^)-|[^\d.-]/g, "");
    // Allowing user to type - character in currency input
    if (number === "-") {
      input.value = "-";
      input.setSelectionRange(1, 1);
      return;
    }
    // Only allow single leading minus
    if (number.startsWith("-")) {
      number = "-" + number.slice(1).replace(/-/g, "");
    } else {
      number = number.replace(/-/g, "");
    }
    // Only allow one decimal point
    let parts = number.split(".");
    let integerPart = parts[0];
    let decimalPart = parts.length > 1 ? "." + parts[1].replace(/\./g, "") : "";

    // Add commas to the integer part (after handling minus sign)
    let formattedValue =
      integerPart.replace(/\B(?=(\d{3})+(?!\d))/g, ",") + decimalPart;

    // Maintain minus sign in output
    if (integerPart.startsWith("-")) {
      formattedValue = "-" + formattedValue.replace(/^-/, "");
    }

    // Calculate the new cursor position
    let newCursorPosition =
      cursorPosition + (formattedValue.length - value.length);

    // Set the formatted value and cursor position
    input.value = formattedValue;
    input.setSelectionRange(newCursorPosition, newCursorPosition);

    if (number === "" || number === "-") {
      input.value = "";
    }
  }

  // Run on page load: format all matching inputs
  function formatAllNumberInputs() {
    const inputs = document.querySelectorAll(
      ".instanda-input-prepend .instanda-number-prefix"
    );
    inputs.forEach((prefix) => {
      if (prefix.textContent.includes("$")) {
        const prepend = prefix.closest(".instanda-input-prepend");
        if (!prepend) return;
        const input = prepend.querySelector("input");
        if (input) formatSingleInput(input);
      }
    });
  }

  // Run on page load
  $(document).ready(function () {
    formatAllNumberInputs();
  });

  // Run on input change (event delegation)
  document.addEventListener("input", function (e) {
    if (e.target.tagName === "INPUT") {
      formatSingleInput(e.target);
    }
  });

