  // Common - Function to toggle visibility of MI Summary Header based on input value
  function toggleDivMI(inputElement) {
    // Find the closest preceding div sibling with 'multiItemSummary_' in its ID
    let sibling = inputElement.previousElementSibling;
    while (sibling) {
      if (sibling.id && sibling.id.includes("multiItemSummary_")) break;
      sibling = sibling.previousElementSibling;
    }
    if (!sibling) return;

    const inputValue = parseInt(inputElement.value, 10) || 0;
    sibling.style.display = inputValue > 0 ? "block" : "none";
  }
  // Ensure there is at least one multiItemSummary div before running the script
  if (document.querySelector("div[id^='multiItemSummary_']")) {
    document.querySelectorAll("input[id*='_Count']").forEach((inputElement) => {
      toggleDivMI(inputElement); // Initial check

      // Observe changes in the input value
      const observer = new MutationObserver(() => toggleDivMI(inputElement));
      observer.observe(inputElement, {
        attributes: true,
        attributeFilter: ["value"],
      });

      inputElement.addEventListener("input", () => toggleDivMI(inputElement));
      inputElement.addEventListener("change", () => toggleDivMI(inputElement));
    });
  }

