  // Function to handle the button click for prequotequestions and execute the passed async function
  function loadingBtnClick() {
    const continueButtons = document.querySelectorAll(
      'button[name="continueButton"]'
    );

    // Handler for read-only: just move to next page
    function readonlyContinueHandler(event) {
      event.preventDefault();
      if (event.currentTarget.form) {
        event.currentTarget.form.submit();
      }
    }

    // Handler with loading, integration, etc.
    async function handleContinue(event) {
      event.preventDefault();

      continueButtons.forEach((btn) => {
        btn.innerHTML =
          '<span class="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span><span class="visually-hidden">Loading</span>';
        btn.disabled = true;
      });

      try {
        // 1. MTA (Mid-Term Adjustment) required fields check (package 23424, page 1)
        if (
          $(".page-prequotequestions.page-number-1.package-23424").length > 0 &&
          Instanda.Variables.CreatedFrom === "MTA"
        ) {
          let missingFields = [];
          if (!$("#EffectiveChangeDate").val()) {
            missingFields.push("Change Effective Date is required.");
          }
          if (!$("#ChangeReason_Choice").val()) {
            missingFields.push("Change Reason Code is required.");
          }
          if (!$("#DescriptionOfChange_TXT").val()) {
            missingFields.push("Description of Change is required.");
          }
          if (missingFields.length > 0) {
            displayApiErrorMessage(missingFields.join("<br>"));
            continueButtons.forEach((btn) => {
              btn.innerHTML = "Continue";
              btn.disabled = false;
            });
            hideSpinner();
            // return;
          }
        }

        // 2. Broker and producer selection mandatory check (all page 1s)
        if (
          $(".page-prequotequestions.page-number-1.package-23424").length > 0 ||
          $(".page-prequotequestions.page-number-1.package-23423").length > 0
        ) {
          let brokerdetails = [];
          if (!$("#SelectedAgentGroupName").val()) {
            brokerdetails.push("Broker Selection is a required field");
          }
          if (!$("#AssignedSalesPersonId").val()) {
            brokerdetails.push("Producer Selection is a required field");
          }
          if (brokerdetails.length > 0) {
            displayApiErrorMessage(brokerdetails.join("<br>"));
            continueButtons.forEach((btn) => {
              btn.innerHTML = "Continue";
              btn.disabled = false;
            });
            hideSpinner();
            // return;
          }
        }


        if (
          (
            $(".page-quickquotequestions.page-number-1").length > 0 ||
            $(".page-prequotequestions.page-number-1.package-23424").length > 0 ||
            $(".page-prequotequestions.page-number-1.package-23423").length > 0
          ) &&
          (
            $("#SelectedBrokerName_TXT").val() === "Private Client Select (PCS)" ||
            $("#SelectedAgentGroupName").val() === "Private Client Select (PCS)"
          )
        ) {
          displayApiErrorMessage(
            "Cannot proceed when Private Client Select (PCS) is selected as Broker"
          );

          continueButtons.forEach((btn) => {
            btn.innerHTML = "Continue";
            btn.disabled = false;
          });

          hideSpinner();

          return;
        }


        // 3. Special "Reissue" date match check
        if (
          $("#ChangeReason_Choice").val() === "Reissue" &&
          formatDateCancel($("#EffectiveChangeDate").val()) !==
          formatDateCancel(Instanda.Variables.EffectiveDate_DATE)
        ) {
          alert(
            "For Reissue, Change Effective Date should match Policy effective Date"
          );
          continueButtons.forEach((btn) => {
            btn.innerHTML = "Continue";
            btn.disabled = false;
          });
          hideSpinner();
          return;
        }

        // 4. Field validation and create customer for package 23424, page 1 (with blocking)
        if (
          $(".page-prequotequestions.page-number-1.package-23424").length > 0 &&
          !$(".readonlymode").length > 0
        ) {
          // fieldValidationCollectionsP1 must return true on success, false on failure
          if (
            typeof fieldValidationCollectionsP1 === "function" &&
            !fieldValidationCollectionsP1()
          ) {
            continueButtons.forEach((btn) => {
              btn.innerHTML = "Continue";
              btn.disabled = false;
            });
            hideSpinner();
            // return;
          }
          if (!isProducerCodeValid()) {
            displayApiErrorMessage(
              "Please select a valid producer to proceed with Policy Issuance."
            );
            continueButtons.forEach((btn) => {
              btn.innerHTML = "Continue";
              btn.disabled = false;
            });
            hideSpinner();
            // return;
          }
          let integcallsapi = await createCustomer(event);
          if (!integcallsapi) {
            displayApiErrorMessage(
              "Customer information could not be created, please contact Customer Care Center 866-856-6858."
            );
            continueButtons.forEach((btn) => {
              btn.innerHTML = "Continue";
              btn.disabled = false;
            });
            hideSpinner();
            return;
          }
        }

        // 5. Field validation and create customer for package 23423, page 1 (with blocking)
        if (
          $(".page-prequotequestions.page-number-1.package-23423").length > 0 &&
          !$(".readonlymode").length > 0
        ) {
          // fieldValidationYacht must return true on success, false on failure
          if (
            typeof fieldValidationYacht === "function" &&
            !fieldValidationYacht()
          ) {
            continueButtons.forEach((btn) => {
              btn.innerHTML = "Continue";
              btn.disabled = false;
            });
            hideSpinner();
            // return;
          }
          if (!isProducerCodeValid()) {
            displayApiErrorMessage(
              "Please select a valid producer to proceed with Policy Issuance."
            );
            continueButtons.forEach((btn) => {
              btn.innerHTML = "Continue";
              btn.disabled = false;
            });
            hideSpinner();
            // return;
          }
          let integcallsapi = await createCustomer(event);
          if (!integcallsapi) {
            displayApiErrorMessage(
              "Customer information could not be created, please contact Customer Care Center 866-856-6858."
            );
            continueButtons.forEach((btn) => {
              btn.innerHTML = "Continue";
              btn.disabled = false;
            });
            hideSpinner();
            return;
          }
        }

        // 6. Moratoriums logic for page 5, package 23423
        if (
          $(".page-prequotequestions.page-number-5.package-23423").length > 0
        ) {
          await moratoriums(event);
        }

        // 7. Coherent premium events logic for page 9 (package 23423) or page 24 (package 23424)
        if (
          $(".page-prequotequestions.page-number-9.package-23423").length > 0 ||
          $(".page-prequotequestions.page-number-24.package-23424").length > 0
        ) {
          await coherentpremiumevents(event);
        }

        // 8. Form submission for prequote questions
        let formAction = null;
        if ($(".page-prequotequestions").length > 0) {
          formAction = "PreQuoteQuestionsContinue";
        }
        continueButtons.forEach((btn) => {
          if (formAction && btn.form) {
            btn.form.action = formAction;
            btn.form.submit();
          }
        });
      } catch (error) {
        continueButtons.forEach((btn) => {
          btn.innerHTML = "Continue";
          btn.disabled = false;
        });
        hideSpinner();
        console.error("Error:", error);
      }
    }

    // Attach/hookup event handlers appropriately
    continueButtons.forEach((btn) => {
      btn.removeEventListener("click", handleContinue);
      btn.removeEventListener("click", readonlyContinueHandler);

      if (isReadOnlyView()) {
        btn.addEventListener("click", readonlyContinueHandler);
      } else {
        btn.addEventListener("click", handleContinue);
      }
    });
  }

