  ///////////////////////////////////////////////////////////////////////////////////////////////County ////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

  $(document).ready(function () {
    // Early exit if we're not on the right page/package
    const isTargetPage =
      $(
        ".page-prequotequestions.page-number-4.package-23423, .page-prequotequestions.page-number-4.package-23424"
      ).length > 0;
    if (
      !isTargetPage &&
      !document.querySelector(".instanda-address-country select")
    )
      return;

    const processedContainers = new Set();

    // Main logic — only runs on containers that actually have a county field
    const processCountyRules = () => {
      document
        .querySelectorAll(".instanda-address-country select")
        .forEach((countrySelect) => {
          const $country = $(countrySelect);
          const $container = $country.closest(
            ".address, .questionItem, .instanda-multi-item"
          );
          const containerKey = $container[0] ?
            $container[0].id || $container[0].className :
            null;
          if (!containerKey || processedContainers.has(containerKey)) return;

          const $countyInput = $container.find(".county input");
          if ($countyInput.length === 0) return; // ← This is your request: only run if county exists

          const $countyContainer = $countyInput.closest(".county");
          const $label = $countyContainer.find("label").first();

          // Remove any existing dynamic asterisk
          $label.find("span.required-asterisk").remove();

          const isUS = $country.val() === "US";
          const hasYes469176 =
            $("#question469176 .instanda-selected input").val() === "Yes";
          const hasYes469184 =
            $("#question469184 .instanda-selected input").val() === "Yes";
          const isConverted = Instanda.Variables.ConvertedPolicy_YN === "Yes";
          const isPackage23423 =
            $(".page-prequotequestions.page-number-4.package-23423").length > 0;
          const isSpecialPackage = ["23423", "23424"].includes(
            Instanda.Variables.PackageId
          );

          let shouldRequire = true;
          let shouldReadonly = false;

          if (
            !isUS ||
            hasYes469176 ||
            hasYes469184 ||
            isConverted ||
            isPackage23423
          ) {
            shouldRequire = false;
          }

          if (isSpecialPackage) {
            shouldReadonly = true;
          } else {
            shouldReadonly = false;
          }

          // Apply rules
          $countyInput
            .prop("required", shouldRequire)
            .prop("readonly", shouldReadonly);

          if (
            shouldRequire &&
            !$label.text().trim().endsWith("*") &&
            $label.find("span.required-asterisk").length === 0
          ) {
            $label.append(
              '<span class="required-asterisk" style="color:red;font-size:16px;">*</span>'
            );
          }

          processedContainers.add(containerKey);
        });
    };

    // State visibility toggle (US/CA/GB only for certain packages)
    const processStateVisibility = () => {
      if (!["23423", "23424"].includes(Instanda.Variables.PackageId)) return;

      $('[id*="country-selection"]').each(function () {
        const $country = $(this);
        const selected = $country.val();
        const $address = $country.closest(".address");
        const showState = ["US", "CA", "GB"].includes(selected);
        $address.find('[id*="state-container"]').toggle(showState);
      });
    };

    // Summer/Winter/Primary Berth address rules
    const processSeasonalAddresses = () => {
      if ($(".page-prequotequestions.page-number-4.package-23423").length === 0)
        return;
      ["primberth", "summer", "winter"].forEach((className) => {
        const $block = $(`.${className}`);
        $block
          .find(
            ".instanda-address-line-1 input, .instanda-address-postcode-label input"
          )
          .prop("required", false);
        $block
          .find(
            "label span.required-asterisk, .instanda-address-postcode-label span"
          )
          .remove();
      });

      // Specific YT fields
      [
        "YTWinter_County_TXT",
        "YTSummer_County_TXT",
        "YT_PrimaryBerthLoc_County_TXT",
        "YT_PrimaryBerth_PostCode_TXT468389",
        "YTSummer_Zip_NUM468565",
        "YTWinter_Zip_NUM468591",
      ].forEach((id) => {
        $(`#${id}`).prop({
          required: false,
          readonly: false,
        });
        $(`#${id}`)
          .closest(".questionItem, .instanda-question-item")
          .find("label span")
          .remove();
      });

      if (Instanda.Variables.ConvertedPolicy_YN === "No") {
        ["summer", "winter", "primberth"].forEach((className) => {
          $(`.${className}`)
            .find(
              ".instanda-address-city input, .instanda-address-state select, .instanda-address-country select"
            )
            .prop("required", true);
        });
      } else {
        ["summer", "winter", "primberth"].forEach((className) => {
          $(`.${className}`)
            .find(
              ".instanda-address-city input, .instanda-address-state select, .instanda-address-country select"
            )
            .prop("required", false);
          $(`.${className}`)
            .find(
              ".instanda-address-city-label span, .instanda-address-state-label span, .instanda-address-country-label span"
            )
            .remove();
        });
      }
    };

    // YT Manager address — always optional
    const processYtManager = () => {
      $(".ytmanager")
        .find(
          ".instanda-address-city input, .instanda-address-state select, .instanda-address-country select"
        )
        .prop("required", false);
      $(".ytmanager")
        .find(
          "label span.required-asterisk, .instanda-address-postcode-label span"
        )
        .remove();
    };

    // Run all
    const runAll = () => {
      processCountyRules();
      processStateVisibility();
      processSeasonalAddresses();
      processYtManager();
    };

    runAll(); // Initial run

    // Efficient event listeners
    $(document)
      .off(".addressrules2025")
      .on(
        "change.addressrules2025",
        '.instanda-address-country select, [id*="country-selection"]',
        runAll
      )
      .on(
        "click.addressrules2025",
        "#question469176 label, #question469184 label, .instanda-multi-item-add",
        () => setTimeout(runAll, 100)
      );

    // Observe DOM changes for multi-item adds
    new MutationObserver((mutations) => {
      if (
        mutations.some((m) => [...m.addedNodes].some(
          (n) =>
            n.nodeType === 1 &&
            n.querySelector &&
            n.querySelector(".instanda-address-country select")
        ))
      ) {
        processedContainers.clear();
        setTimeout(runAll, 150);
      }
    }).observe(document.body, {
      childList: true,
      subtree: true,
    });
  });

