  // Common - Formatting Agent Id by appending - "00" for API
  function formatToSevenDigits(number) {
    let numberStr = number.toString();
    if (numberStr.length < 7) {
      numberStr = numberStr.padStart(7, "0");
    }
    return numberStr;
  }

  // Format ZipCode to 5 digits by appending 0 for zipcode less than 5 digits on prefill to billing screen
  function formatToFiveDigits(number) {
    if (number === undefined || number === null || number === "") {
      return "";
    }
    let zipStr = number.toString();
    zipStr = zipStr.replace(/\D/g, ""); // Optional: remove non-digits
    if (zipStr.length < 5) {
      zipStr = zipStr.padStart(5, "0");
    }
    return zipStr;
  }

  // Format Policynumber to 10 digits
  function formatToTenDigits(number) {
    let numberStr = number.toString();
    if (numberStr.length < 10) {
      numberStr = numberStr.padStart(10, "0");
    }
    return numberStr;
  }

  function formatToThirteenDigits(number) {
    let numberStr = number.toString();
    if (numberStr.length < 13) {
      numberStr = numberStr.padStart(13, "0");
    }
    return numberStr;
  }

