  //Function to convert date type for cancellation - MM/DD/YYYY
  function formatDateCancel(date) {
    //Change logic for BH-10759
    const getFormatDate = formatDate(date);
    const [year, month, day] = getFormatDate.split("-");
    const formattedMonth = parseInt(month, 10);

    return `${formattedMonth}/${day}/${year}`;
  }

  const effectiveDate = formatDateCancel(Instanda.Variables.EffectiveDate_DATE); // mm/dd/yyyy
  const $cancelMethodChoice = $("#CancelMethod_CHOICE");
  const $cancellationDate = $("#CancellationDate");
  const pageName = Instanda.Variables.PageName;

  // Log initial values
  console.log("Initial Values:", {
    effectiveDate,
    cancelMethodChoice: $cancelMethodChoice.val(),
    cancellationDate: formatDateCancel($cancellationDate.val()), // Ensure initial log shows formatted date
    pageName,
  });
  // Function to update Cancellation Date and Cancel Method Choice
  function extractDateOnly(dateTimeString) {
    var date = new Date(dateTimeString);
    var month = (date.getMonth() + 1).toString().padStart(1, "0");
    var day = date.getDate().toString().padStart(1, "0");
    var year = date.getFullYear();
    return month + "/" + day + "/" + year;
  }

  function updateCancellationDetails() {
    const cancelMethodChoice = $cancelMethodChoice.val();
    const cancellationDate = extractDateOnly($cancellationDate.val());
    var effectiveDateRaw = Instanda.Variables.EffectiveDate_DATE;
    var effectiveDate1 = extractDateOnly(effectiveDateRaw);

    if (cancellationDate !== effectiveDate1 && cancellationDate) {
      $("#CancelMethod_CHOICE").val("Pro-Rated");
      console.log("Cancel Method Choice set to Pro-Rated");
    } else if (cancellationDate) {
      console.log("Cancel Method Choice set to Flat");
      $("#CancelMethod_CHOICE").val("Flat");
      console.log("Cancel Method Choice set to Flat");
    }
  }

  $(document).ready(function () {
    if (pageName === "cancelpolicy") {
      console.log("On cancelpolicy page, initializing event handlers.");

      $cancellationDate.on("change input blur", function () {
        console.log(
          "Cancellation Date changed to:",
          formatDateCancel($cancellationDate.val())
        );
        if (Instanda.Variables.EffectiveChangeDate) {
          if (
            Date.parse($cancellationDate.val()) <
            Date.parse(Instanda.Variables.EffectiveChangeDate)
          ) {
            alert("This will trigger an OOS cancellation transaction.");
          }
        }
        updateCancellationDetails();
      });

      $cancelMethodChoice.on("change", function () {
        const cancelMethodChoice = $cancelMethodChoice.val();
        const cancellationDate = $cancellationDate.val();
        console.log(
          "Cancel Method Choice changed to:",
          $cancelMethodChoice.val()
        );
        if (cancelMethodChoice === "Flat") {
          $cancellationDate.val(effectiveDate);
          $cancelMethodChoice.val("Flat");
          console.log(
            "Cancellation Date updated to Effective Date:",
            effectiveDate
          );
        }
        updateCancellationDetails();
      });

      $cancellationDate.trigger("change");
    }
  });

  // Pre-populate the Named Insured for Yacht Coll Auto and EL
  $(document).ready(function () {
    const quickQuotePackages = [24428, 24338];
    const preQuotePackages = [23423, 23424];
    const packageID = Instanda.Variables.PackageId;

    if (
      ($(".page-quickquotequestions.page-number-1").length > 0 &&
        quickQuotePackages.includes(packageID)) ||
      ($(".page-prequotequestions.page-number-1").length > 0 &&
        preQuotePackages.includes(packageID))
    ) {
      function updateNamedInsured() {
        const nametypech = $("#Name_Type_CHOICEP").val();
        let name = "";
        switch (nametypech) {
          case "Business":
            name = $("#Name_TXT").val();
            break;
          case "Individual":
            const prefix = $("#Prefix_TXT").val();
            const firstName = $("#FirstName_TXT").val();
            const middleName = $("#MiddleName_TXT").val();
            const lastName = $("#LastName_TXT").val();
            const suffix = $("#Suffix_CHOICE").val();
            name = [prefix, firstName, middleName, lastName, suffix]
              .filter(Boolean)
              .join(" ");
            break;
          case "LLC/Other":
            name = $("#Name1_TXT").val();
            break;
          case "Non Individual":
            name = $("#Name2_TXT").val();
            break;
          case "Personal Trust":
            name = $("#Name3_TXT").val();
            break;
          default:
            name = "";
        }
        // Only update if not already present
        if (
          $("#NamedInsured_TXT").val() &&
          !$("#NamedInsured_TXT").val().includes(name.trim())
        ) {
          $("#NamedInsured_TXT").val(name.trim());
        } else if (!$("#NamedInsured_TXT").val()) {
          $("#NamedInsured_TXT").val(name.trim());
        }
      }

      function clearNamedInsured() {
        $("#NamedInsured_TXT").val("");
      }

      $("#Name_Type_CHOICEP").on("change", function () {
        if ($("#NamedInsured_TXT").val() === "") {
          clearNamedInsured();
          updateNamedInsured();
        }
      });

      $(
        "#Name_TXT,#Prefix_TXT,#Suffix_CHOICE,#FirstName_TXT,#MiddleName_TXT,#LastName_TXT,#Name1_TXT,#Name2_TXT,#Name3_TXT"
      ).on("change", updateNamedInsured);

      if ($("#NamedInsured_TXT").val() === "") {
        updateNamedInsured();
      }
    }
  });

