  //RAP code
  $(document).ready(function () {
    // Check if the page number is between 7 and 21 and the package ID is 23424
    if (
      $(".page-prequotequestions.package-23424").filter(function () {
        var pageNumber = parseInt(
          $(this)
            .attr("class")
            .match(/page-number-(\d+)/)[1],
          10
        );
        return pageNumber >= 7 && pageNumber <= 21;
      }).length > 0
    ) {
      // Code 1: Calculate Sum
      function calculateSum() {
        $(".questionItem.instanda-question-item.form-group.container").each(
          function () {
            let mainParent = $(this);
            if (
              mainParent
                .find(
                  ".instanda-question-parent-yes-no .instanda-question-input > label:first-child"
                )
                .hasClass("instanda-selected")
            ) {
              let mainParentName = mainParent
                .find(
                  ".instanda-question-parent-yes-no .instanda-question-input > label > input"
                )
                .attr("name");
              let mainParentChildrenId = `#${mainParentName}_Children`;
              let sum = 0;
              $(
                `${mainParentChildrenId} .questionItem.instanda-question-item.form-group.container`
              ).each(function () {
                let child = $(this);
                let childName = child
                  .find(
                    ".instanda-question-parent-yes-no .instanda-question-input > label > input"
                  )
                  .attr("name");
                let childChildrenId = `#${childName}_Children`;
                if (
                  child
                    .find(
                      ".instanda-question-parent-yes-no .instanda-question-input > label:first-child"
                    )
                    .hasClass("instanda-selected")
                ) {
                  let secondValue =
                    parseFloat(
                      $(
                        `${childChildrenId} .questionItem:nth-child(2) input`
                      ).val()
                    ) || 0;
                  let firstValue =
                    parseFloat(
                      $(
                        `${childChildrenId} .questionItem:nth-child(1) input`
                      ).val()
                    ) || 0;
                  sum += secondValue !== 0 ? secondValue : firstValue;
                }
              });
              $(
                `${mainParentChildrenId} .questionItem.instanda-question-item.form-group.rapminmax.readonly`
              )
                .find("input")
                .val(sum);
            }
          }
        );
      }

      $(document).on(
        "change",
        ".questionItem.instanda-question-item.form-group.container input",
        function () {
          calculateSum();
        }
      );

      calculateSum();

      // Code 2: Hide Elements Based on RiskRatingState_CHOICE
      if (
        Instanda.Variables.RiskRatingState_CHOICE === "NJ" &&
        Instanda.Variables.ProductCode_CHOICE === "Admitted"
      ) {
        $(".instanda-number-input.instanda-question-input").each(function () {
          var inputElement = $(this).find("input");
          var dataBind = inputElement.attr("data-bind");
          var questionId = dataBind ?
            (dataBind.match(/value:\s*(question\d+)/) || [])[1] :
            null;
          if (questionId && !$("#" + questionId).hasClass("readonly")) {
            $("#" + questionId).hide();
          }
        });
      }
      //Code New
      if (
        Instanda.Variables.ProductCode_CHOICE === "Non-Admitted" &&
        Instanda.Variables.RiskRatingState_CHOICE === "VA"
      ) {
        const prefixes = [
          "Jwel",
          "JwelinVlt",
          "Fineart",
          "Silver",
          "Coins",
          "Camera",
          "Wine",
          "Collec",
          "Mus",
          "Furs",
          "Stamp",
          "MonWin",
          "ValArt",
          "Gun",
          "ColVec",
        ];
        const suffixes = [
          "Sched_InsuredLossExperience_YNPNo",
          "Blank_InsuredLossExperience_YNPNo",
        ];

        prefixes.forEach((prefix) => {
          suffixes.forEach((suffix) => {
            const variableName = `CO_${prefix}${suffix}`;
            $(`#${variableName}`).closest(".questionItem").hide();
            $(`#${variableName}`).click();
          });
        });
      }

      // Code 3: Set Default Values
      if (Instanda.Variables.ProductCode_CHOICE === "Admitted") {
        const prefixes = [
          "Jwel",
          "JwelinVlt",
          "Fineart",
          "Silver",
          "Coins",
          "Camera",
          "Wine",
          "Collec",
          "Mus",
          "Furs",
          "Stamp",
          "MonWin",
          "ValArt",
          "Gun",
          "ColVec",
        ];
        const baseVariables = {
          InsuredLossExperience_NUM_DEFAULT: -10,
          InsuredPublicExposure_NUM_DEFAULT: 5,
          TravelTransitFreqNature_NUM_DEFAULT: -5,
          ResidenceType_NUM_DEFAULT: -5,
          ResidenceOccupancy_NUM_DEFAULT: -5,
          ResidenceProximityFire_NUM_DEFAULT: 5,
          PremisesUseStorage_NUM_DEFAULT: -5,
          PremisesTempPermLoans_NUM_DEFAULT: 5,
          CollectionMaintManagement_NUM_DEFAULT: -5,
          LossLimitAbsolute_NUM_DEFAULT: -10,
          TravelTheftSecPersonnel_NUM_DEFAULT: -10,
          FireProtResistive2Hr_NUM_DEFAULT: -10,
          FireProtAutoSprinkler_NUM_DEFAULT: -5,
          Coll_50PctNoVaultWorn_NUM_DEFAULT: 5,
          ShipPackByPros_NUM_DEFAULT: -5,
          Coll_ItemMore75Pct_NUM_DEFAULT: 50,
        };

        function setDefaultValues() {
          const RiskRatingState_CHOICE =
            Instanda.Variables.RiskRatingState_CHOICE;
          const conditionalStates = ["NJ", "NY", "MT", "NE", "WA", "HI", "MD"];

          if (conditionalStates.includes(RiskRatingState_CHOICE)) {
            prefixes.forEach((prefix) => {
              Object.keys(baseVariables).forEach((baseVariable) => {
                let value = baseVariables[baseVariable];

                // Adjust values based on RiskRatingState_CHOICE
                if (RiskRatingState_CHOICE === "NJ") {
                  if (baseVariable === "InsuredLossExperience_NUM_DEFAULT")
                    value = -5;
                  else if (baseVariable === "InsuredPublicExposure_NUM_DEFAULT")
                    value = 10;
                  else if (
                    baseVariable === "TravelTransitFreqNature_NUM_DEFAULT"
                  )
                    value = -10;
                  else if (baseVariable === "ResidenceType_NUM_DEFAULT")
                    value = 5;
                  else if (baseVariable === "ResidenceOccupancy_NUM_DEFAULT")
                    value = 5;
                  else if (
                    baseVariable === "ResidenceProximityFire_NUM_DEFAULT"
                  )
                    value = 10;
                  else if (baseVariable === "PremisesUseStorage_NUM_DEFAULT")
                    value = -15;
                  else if (baseVariable === "PremisesTempPermLoans_NUM_DEFAULT")
                    value = 25;
                  else if (
                    baseVariable === "CollectionMaintManagement_NUM_DEFAULT"
                  )
                    value = -10;
                  else if (baseVariable === "LossLimitAbsolute_NUM_DEFAULT")
                    value = -5;
                } else if (
                  RiskRatingState_CHOICE === "NY" &&
                  (prefix === "Jwel" || prefix === "JwelinVlt")
                ) {
                  if (baseVariable === "TravelTheftSecPersonnel_NUM_DEFAULT")
                    value = -5;
                  else if (baseVariable === "FireProtResistive2Hr_NUM_DEFAULT")
                    value = -5;
                  else if (baseVariable === "FireProtAutoSprinkler_NUM_DEFAULT")
                    value = -2;
                  else if (baseVariable === "Coll_50PctNoVaultWorn_NUM_DEFAULT")
                    value = 10;
                } else if (
                  ["MT", "NE", "WA"].includes(RiskRatingState_CHOICE)
                ) {
                  if (baseVariable === "ShipPackByPros_NUM_DEFAULT") value = 10;
                } else if (["HI", "NY"].includes(RiskRatingState_CHOICE)) {
                  if (baseVariable === "Coll_50PctNoVaultWorn_NUM_DEFAULT")
                    value = 10;
                } else if (RiskRatingState_CHOICE === "MD") {
                  if (baseVariable === "Coll_ItemMore75Pct_NUM_DEFAULT")
                    value = 40;
                }

                // Adjust suffix for special cases
                let suffix = "_DEFAULT";
                if (
                  prefix === "JwelinVlt" ||
                  baseVariable === "CollectionMaintManagement_NUM_DEFAULT" ||
                  (baseVariable === "TravelTransitFreqNature_NUM_DEFAULT" &&
                    prefix === "Fineart")
                ) {
                  suffix = "_DEF";
                  if (
                    prefix === "JwelinVlt" &&
                    baseVariable === "CollectionMaintManagement_NUM_DEFAULT"
                  ) {
                    suffix = "_D";
                  }
                }

                const variableNameBlank = `CO_${prefix}Blank_${baseVariable.replace(
                  "_DEFAULT",
                  suffix
                )}`;
                const variableNameSched = `CO_${prefix}Sched_${baseVariable.replace(
                  "_DEFAULT",
                  suffix
                )}`;

                $(`input[name=${variableNameBlank}]`).val(value);
                $(`input[name=${variableNameSched}]`).val(value);
              });
            });
          }
        }

        setDefaultValues();
      }
    }
  });

  ///// Function to update the total premium and make the field non-editable

  $(document).ready(function () {
    setTimeout(function () {
      // 1. Page type check
      const $postQuoteQuestions = $(".page-postquotequestions");
      if ($postQuoteQuestions.length === 0) return;

      // 2. Defensive data check
      if (typeof Instanda === "undefined" || !Instanda.Variables) return;

      const pageChecks = [{
        pageSelector: ".page-number-1",
        packageIds: [23423, 24338, 24428],
      },
      {
        pageSelector: ".page-number-2",
        packageIds: [23424, 24518, 24588],
      },
      {
        pageSelector: ".page-number-4",
        packageIds: [24337],
      },
      ];

      const CreatedFrom = Instanda.Variables.CreatedFrom;
      const packageId = Instanda.Variables["PackageId"];

      if (!["NewBusiness", "Renewal", "MTA"].includes(CreatedFrom)) return;

      // 3. Check page-number and packageId match
      let totalPremium;

      // -- For each relevant page/package combo, calculate and update --
      if ($(".page-number-1").length > 0 && packageId === 23423) {
        totalPremium = Instanda.Variables.YT_CmlBilledPremTaxFeeTotal_NUM;
      } else if ($(".page-number-2").length > 0 && packageId === 23424) {
        totalPremium = Instanda.Variables.CO_CmlBilledPremTaxFeeTotal_NUM;
      } else if (
        ($(".page-number-1").length > 0 && [24338, 24428].includes(packageId)) ||
        ($(".page-number-2").length > 0 && [24518, 24588].includes(packageId)) ||
        ($(".page-number-4").length > 0 && packageId === 24337)
      ) {
        totalPremium =
          Instanda.Variables.TotalTermBldPremTaxFee_NUM ||
          Instanda.Variables.TotalTermBldPremTaxFee_NUM_DEF;
      } else {
        // Not our target scenario: do nothing
        return;
      }

      // -- Only update fields if we found a premium --
      function updateTotalPremiumField(totalPremium) {
        const formatted = totalPremium ?
          Number(totalPremium).toLocaleString("en-US", {
            minimumFractionDigits: 2,
            maximumFractionDigits: 2,
          }) :
          "0.00";
        $("#TotalPremium_NUM").val(formatted);
        $("#question427214, #question436056").addClass("non-editable");
        $("#TotalPremium_NUM").prop("readonly", true);
      }

      if (typeof totalPremium !== "undefined") {
        updateTotalPremiumField(totalPremium);
      }
    }, 700);
  });

