  //Yacht Coverage screen hull and machinary ded option order
  $(document).ready(function () {
    var dropdown = $("#YT_ReqCov_HullMachineryDed_CHOICEP");
    var optionsOrder = [
      "250",
      "500",
      "1000",
      "5000",
      "0.5%",
      "1%",
      "2%",
      "3%",
      "5%",
      "10%",
      "Other",
    ];
    var selectedValue = dropdown.val(); // Store current selection

    // Store the "Please Select" option if it exists
    var pleaseSelectOption = dropdown.find('option[value=""]').clone();
    var hasPleaseSelect = pleaseSelectOption.length > 0;

    // Clone existing options with their data attributes
    var existingOptions = {};
    dropdown.find("option").each(function () {
      existingOptions[$(this).val()] = $(this).clone();
    });

    // Clear the dropdown
    dropdown.empty();

    // Ensure "Please Select" is the first option
    if (hasPleaseSelect) {
      dropdown.append(pleaseSelectOption);
    } else {
      dropdown.append(
        $("<option>", {
          value: "",
          text: "Please Select",
        })
      );
    }

    // Append options in the given order while preserving data attributes
    let seen = new Set();
    optionsOrder.forEach(function (value) {
      if (!seen.has(value) && existingOptions[value]) {
        dropdown.append(existingOptions[value]); // Append the cloned option
        seen.add(value);
      }
    });

    // Restore the previous selection if still available, otherwise set default to "1%"
    dropdown.val(optionsOrder.includes(selectedValue) ? selectedValue : "1%");

    // Handle "Other" selection toggle
    dropdown
      .change(function () {
        $("#YT_ReqCov_HullMachineryDed_CHOICEP_Children22223").toggle(
          dropdown.val() === "Other"
        );
      })
      .trigger("change");
  });

