  //Yacht - Hull Value Calculation
  $(document).ready(function () {
    // Input elements
    var hullValueAmountInput = $("#YT_Vessel_HullValueAmount_NUM");
    var totalValueInput = $("#YT_Vessel_TotalValue_NUM");
    var increasedValueAmountInput = $("#YT_Vessel_IncreasedValueAmount_NUM");
    var hullValuePercentageInput = $("#YT_Vessel_HullValue_NUM");
    var increasedValuePercentageInput = $("#YT_Vessel_IncreasedValue_NUM");
    var addIncreasedValueRadioYes = $("#YT_Vessel_AddIncreasedValue_YNPYes");

    // Function to format numbers according to en-US locale
    function formatNumber(value, decimals = 0) {
      return new Intl.NumberFormat("en-US", {
        minimumFractionDigits: decimals,
        maximumFractionDigits: decimals,
      }).format(value);
    }

    // Function to parse numbers from en-US locale formatted strings
    function parseNumber(value) {
      return parseFloat(value.replace(/,/g, ""));
    }

    // Function to set default values
    function setDefaultValues() {
      if (hullValueAmountInput.val() !== "") {
        if (addIncreasedValueRadioYes.is(":checked")) {
          calculateDefaultValues();
        }
      }
    }

    // Function to calculate default values
    function calculateDefaultValues() {
      var hullValueAmount = parseNumber(hullValueAmountInput.val());
      var hullValuePercentage =
        parseNumber(hullValuePercentageInput.val()) / 100;
      var increasedValuePercentage =
        parseNumber(increasedValuePercentageInput.val()) / 100;

      // Calculate increased value amount
      var increasedValueAmount = hullValueAmount * increasedValuePercentage;
      increasedValueAmountInput.val(formatNumber(increasedValueAmount, 0));

      // Calculate total value
      var totalValue = hullValueAmount * hullValuePercentage;
      totalValueInput.val(formatNumber(totalValue, 0));
    }

    // Set values on initial page load
    setDefaultValues();

    // Set values on change of Hull amount
    hullValueAmountInput.on("input", function () {
      setDefaultValues();
    });

    // Set values on click of Yes No radio button
    addIncreasedValueRadioYes.on("click", function () {
      setDefaultValues();
    });

    // Update values upon changing individual inputs
    hullValuePercentageInput.on("input", function () {
      var updatedHullPercentage =
        100 - parseNumber(hullValuePercentageInput.val());
      increasedValuePercentageInput.val(formatNumber(updatedHullPercentage, 0));
      calculateDefaultValues();
    });

    increasedValuePercentageInput.on("input", function () {
      var updatedIncValPercentage =
        100 - parseNumber(increasedValuePercentageInput.val());
      hullValuePercentageInput.val(formatNumber(updatedIncValPercentage, 0));
      calculateDefaultValues();
    });

    increasedValueAmountInput.on("input", function () {
      var hullValueAmount = parseNumber(hullValueAmountInput.val());
      var increasedValueAmount = parseNumber(increasedValueAmountInput.val());
      var totalValue =
        hullValueAmount * (parseNumber(hullValuePercentageInput.val()) / 100);
      totalValueInput.val(formatNumber(totalValue, 0));
      var updatedIncPercent = (increasedValueAmount / hullValueAmount) * 100;
      increasedValuePercentageInput.val(formatNumber(updatedIncPercent, 0));
      var updatedHullPercent = 100 - updatedIncPercent;
      hullValuePercentageInput.val(formatNumber(updatedHullPercent, 0));
    });

    totalValueInput.on("input", function () {
      var hullValueAmount = parseNumber(hullValueAmountInput.val());
      var totalValue = parseNumber(totalValueInput.val());
      var increasedValueAmount =
        totalValue -
        hullValueAmount * (parseNumber(hullValuePercentageInput.val()) / 100);
      increasedValueAmountInput.val(formatNumber(increasedValueAmount, 0));
      var updatedIncTotPercent = (increasedValueAmount / hullValueAmount) * 100;
      increasedValuePercentageInput.val(formatNumber(updatedIncTotPercent, 0));
      var updatedHullTotPercent = 100 - updatedIncTotPercent;
      hullValuePercentageInput.val(formatNumber(updatedHullTotPercent, 0));
    });
  });

