  //breadcrumb link generation - to access PQPage 1 to 9 from other pages
  function generateTabId() {
    // Generate a unique identifier for each tab
    var tabId = sessionStorage.getItem("tabId");
    if (!tabId) {
      tabId = Date.now().toString() + Math.floor(Math.random() * 1000);
      sessionStorage.setItem("tabId", tabId);
    }
    return tabId;
  }

  function urlBuilderPQ(pageNumber, currentId) {
    var tabId = generateTabId(); // Get or generate a unique tab identifier
    var urlOrigin = window.location.origin;

    var quickQuestionsUrl = "/Public/QuickQuoteQuestions";
    var quickQuestionsContinueUrl = "/Public/QuickQuoteQuestionsContinue";
    var preQuestionsUrl = "/Public/PreQuoteQuestions";
    var preQuestionsContinueUrl = "/Public/PreQuoteQuestionsContinue";
    var postQuestionsUrl = "/Public/PostQuoteQuestions";
    var postQuestionsContinueUrl = "/Public/PostQuoteQuestionsContinue";

    var urlParameters = new URL(window.location.href).search;
    var tabSpecificKey = "previousURL_" + tabId;
    const targetQuickURL = urlOrigin + quickQuestionsContinueUrl;
    const targetPreURL = urlOrigin + preQuestionsContinueUrl;
    const targetPostURL = urlOrigin + postQuestionsContinueUrl;
    const fullURL = window.location.href;
    var storedURL = localStorage.getItem(tabSpecificKey);

    if (currentId.startsWith("prequote")) {
      if (fullURL !== targetPreURL) {
        storedURL = urlOrigin + preQuestionsUrl + urlParameters;
        localStorage.setItem(tabSpecificKey, storedURL); // Store the URL specific to this tab
      } else {
        storedURL = localStorage.getItem("previousURL");
        if (storedURL) {
          var currentUrl = storedURL; // Redirect to the stored URL
        }
      }
    } else if (currentId.startsWith("quickquote")) {
      if (fullURL !== targetQuickURL) {
        storedURL = urlOrigin + quickQuestionsUrl + urlParameters;
        localStorage.setItem(tabSpecificKey, storedURL); // Store the URL specific to this tab
      } else {
        storedURL = localStorage.getItem("previousURL");
        if (storedURL) {
          var currentUrl = storedURL; // Redirect to the stored URL
        }
      }
    } else if (currentId.startsWith("postquote")) {
      if (fullURL !== targetPostURL) {
        storedURL = urlOrigin + postQuestionsUrl + urlParameters;
        localStorage.setItem(tabSpecificKey, storedURL); // Store the URL specific to this tab
      } else {
        storedURL = localStorage.getItem("previousURL");
        if (storedURL) {
          var currentUrl = storedURL; // Redirect to the stored URL
        }
      }
    }

    var url = new URL(storedURL);
    url.searchParams.set("pageNumber", pageNumber);
    var newUrl = url.href;
    $("#" + currentId).attr("href", newUrl);
  }

