  //Renewal - Term Number Increment
  function setTermNumber() {
    try {
      const $termInputByName = $("input[name='TermNumber_NUM']");
      const $termInputById = $("#TermNumber_NUM");

      const setTermInputs = (val) => {
        if ($termInputByName.length)
          $termInputByName
            .val(String(val))
            .trigger("change")
            .attr("data-term-number", String(val));
        if ($termInputById.length)
          $termInputById
            .val(String(val))
            .trigger("change")
            .attr("data-term-number", String(val));
      };

      // default
      setTermInputs(1);

          const isRenewalOrConverted =
        $(".page-quickquotequestions.created-from-renewal.page-number-1").length > 0 ||
        $(".page-prequotequestions.created-from-renewal.page-number-1").length > 0 ||
        (
          (
            $(".page-quickquotequestions.page-number-1").length > 0 ||
            $(".page-prequotequestions.page-number-1").length > 0
          ) &&
          $("#ConvertedPolicy_YNYes").is(":checked")
        ) ||
        $("#ConvertedPolicy_YNPYes").is(":checked");

      if (!isRenewalOrConverted) return;

      // Set expiry date as 1 year after effective date
      const $eff = $("#EffectiveDate_DATE");
      const $exp = $("#ExpirationDate_DATE");

      const effVal = ($eff.val() || "").trim();
      const expVal = ($exp.val() || "").trim();

      if (effVal) {
        const effParts = effVal.split("/");
        if (effParts.length === 3) {
          const mm = parseInt(effParts[0], 10);
          const dd = parseInt(effParts[1], 10);
          const yyyy = parseInt(effParts[2], 10);

          if (!Number.isNaN(mm) && !Number.isNaN(dd) && !Number.isNaN(yyyy)) {
            const expDate = new Date(yyyy, mm - 1, dd);
            expDate.setFullYear(expDate.getFullYear() + 1);

            const expStr =
              expDate.getMonth() +
              1 +
              "/" +
              expDate.getDate() +
              "/" +
              expDate.getFullYear();

            // Enter this block if Expiration is blank/whitespace OR same as Effective OR exp element missing
            const shouldSetExp = !$exp.length || !expVal || expVal === effVal;

            if (shouldSetExp && $exp.length) {
              $exp.val(expStr).trigger("change");
            }
          }
        }
      }

      // Renewal Insured screen Term value increment by 1 (year difference)
      const inceptionVal = ($("#InceptionDate_DATE").val() || "").trim();
      const expirationVal = ($("#ExpirationDate_DATE").val() || "").trim();

      const y1 = parseInt(inceptionVal.split("/")[2] || "", 10);
      const y2 = parseInt(expirationVal.split("/")[2] || "", 10);

      if (!Number.isNaN(y1) && !Number.isNaN(y2)) {
        const termNumber = y2 - y1;

        $("#YearDifference").val(String(termNumber)).trigger("change");

        setTermInputs(termNumber);

        // Update the visible number after the input (only if hidden input with a text node sibling)
        const $input = $termInputById.length ?
          $termInputById :
          $termInputByName;
        const inputEl = $input[0];
        const nextNode = inputEl && inputEl.nextSibling;

        if (
          nextNode &&
          nextNode.nodeType === 3 &&
          $input.attr("type") === "hidden"
        ) {
          nextNode.nodeValue = " " + termNumber;
        }
      }
    } catch (error) {
      console.log("Term Number Throwing Error ", error);
    }
  }

  // Renewal - Term Number Increment
