  //Name Type change in the position of dropdown list values - collections
  $(document).ready(function () {
    // Select the Dropdown Element
    var dropdown = $("#NameType_CHOICEP");

    // Store the Options
    var options = dropdown.children("option").toArray();

    // Clear the Dropdown
    dropdown.empty();

    // Add the additional option at the top
    dropdown.append(
      '<option data-id="-1" label="Please select..." value="">Please select...</option>'
    );

    // Add Options in New Order
    var newOrder = [
      "Please select...",
      "Individual",
      "Non Individual",
      "Business",
      "Personal Trust",
      "LLC/Other",
    ];
    newOrder.forEach(function (value) {
      var option = options.find((opt) => opt.value === value);
      if (option) dropdown.append(option);
    });
  });

  // Function to add validation classes inside Multi Items
  // Utility function to extract MI number from an element
  function extractMINumber(element, prefix) {
    const match = element.className.match(/MI[_]?(\d+)/);
    return match ? match[1] : null;
  }

  //Default Overland Transportation Coverage in yacht Coverages screen - BH-14445
  $(document).ready(function () {
    function formatCurrencyOvrland(value) {
      return value.toLocaleString("en-US", {
        style: "currency",
        currency: "USD",
        maximumFractionDigits: 0,
      });
    }

    function getDeductible(CHOICEP, LIMIT_NUM, OVRDE_NUM_DEFAULT) {
      switch (CHOICEP) {
        case "0.5%":
          return formatCurrencyOvrland(0.005 * LIMIT_NUM);
        case "1%":
          return formatCurrencyOvrland(0.01 * LIMIT_NUM);
        case "2%":
          return formatCurrencyOvrland(0.02 * LIMIT_NUM);
        case "3%":
          return formatCurrencyOvrland(0.03 * LIMIT_NUM);
        case "5%":
          return formatCurrencyOvrland(0.05 * LIMIT_NUM);
        case "10%":
          return formatCurrencyOvrland(0.1 * LIMIT_NUM);
        case "250":
          return "$250";
        case "500":
          return "$500";
        case "1000":
          return "$1,000";
        case "5000":
          return "$5,000";
        case "Other":
          return formatCurrencyOvrland(
            OVRDE_NUM_DEFAULT !== -999999999 ? OVRDE_NUM_DEFAULT : 0
          );
        default:
          return "";
      }
    }

    if ($(".page-prequotequestions.page-number-5.package-23423").length > 0) {
      function handleOverlandPolicyTypeChange() {
        var policyType = Instanda.Variables.YT_PolicyType_CHOICE;

        if (policyType === "P&I Only") {
          $("#YT_OverlandTransLimit_NUM").attr("placeholder", "N/A");
          $("#YT_OverlandTransDed_NUM").attr("placeholder", "N/A");
          $("#YT_OverlandTransPrem_NUM").attr("placeholder", "N/A");
          $("#question509856, #question509859, #question509861").addClass(
            "readonly"
          );
        } else {
          $("#YT_OverlandTransLimit_NUM").attr(
            "placeholder",
            "incl. in Yacht Hull Limit"
          );

          // Extract values from the relevant fields (assuming input or select elements)
          var CHOICEP = $("#YT_ReqCov_HullMachineryDed_CHOICEP").val();
          var LIMIT_NUM =
            parseFloat(
              $("#YT_ReqCov_HullMachineryLimit_NUM")
                .val()
                .replace(/[^0-9.]/g, "")
            ) || 0;
          var OVRDE_NUM_DEFAULT =
            parseFloat(
              $("#YT_ReqCov_HullMachineryDedOverride_NUM")
                .val()
                .replace(/[^0-9.]/g, "")
            ) || -999999999;

          // Calculate deductible and set as default
          var deductible = getDeductible(CHOICEP, LIMIT_NUM, OVRDE_NUM_DEFAULT);
          $("#YT_OverlandTransDed_NUM").val(deductible);

          $("#YT_OverlandTransPrem_NUM").attr("placeholder", "incl.");
          $("#question509856, #question509859, #question509861").addClass(
            "readonly"
          );
        }
      }

      $("#YT_PolicyType_CHOICE").change(handleOverlandPolicyTypeChange);
      $("#YT_ReqCov_HullMachineryDed_CHOICEP").change(
        handleOverlandPolicyTypeChange
      );
      handleOverlandPolicyTypeChange(); // initialize on page load
    }
  });

  //Collections - Page 22 Schedule Manual Multi Item

  ///////////////////////////////////////////////////////////////// // Function to add validation classes to address fields inside Multi Items///////////////////////
  function addValidationClassesMI() {
    // Select all multi-item parent containers
    const parents = document.querySelectorAll(
      '[class*="instanda-multi-item-CO_SecondaryLocationCoverage_MI"]'
    );
    const prefix = "instanda-multi-item-CO_SecondaryLocationCoverage_MI";

    parents.forEach((parent) => {
      // Extract the MI number using the utility function
      const miNumberAdd = extractMINumber(parent, prefix);

      if (miNumberAdd) {
        const validationClass = `address-question-${miNumberAdd}`;
        const geocodeClass = `geocode-address-${miNumberAdd}`;

        // Locate the address field within the parent
        const addressField = parent.querySelector(".address-question");
        const geocodeField = parent.querySelector(".geocode-address");
        const validateButtonMI = parent.querySelector(".AddressValidBtn");
        const geoValidateButtonMI = parent.querySelector(".GeocodeBtn");

        if (addressField && geocodeField) {
          if (miNumberAdd === "1") {
            addressField.classList.remove("address-question-1");
            geocodeField.classList.remove("geocode-address-1");
            addressField.classList.add("address-question-mi-1");
            geocodeField.classList.add("geocode-address-mi-1");
            validateButtonMI.setAttribute(
              "data-unique-class",
              "address-question-mi-1"
            );
            geoValidateButtonMI.setAttribute(
              "data-unique-class",
              "geocode-address-mi-1"
            );
          } else {
            addressField.classList.remove("address-question-1");
            addressField.classList.add(validationClass);
            geocodeField.classList.add(geocodeClass);
            validateButtonMI.setAttribute("data-unique-class", validationClass);
            geoValidateButtonMI.setAttribute("data-unique-class", geocodeClass);
          }

          // Remove any existing event handlers to prevent multiple alerts
          $(validateButtonMI)
            .off("click")
            .on("click", function (event) {
              handleValidation(event, "precisely");
            });

          $(geoValidateButtonMI)
            .off("click")
            .on("click", function (event) {
              handleValidation(event, "coreLogic");
            });
        }
      }
    });
  }

