  $(document).ready(function () {
    if (isReadOnlyView()) {
      console.log("Read-only view");
      hideSpinner(); // Hide spinner on early return
      return "Read-only view";
    }
    // -------- 1. Page/package checks ---------
    const isTargetPage =
      $(".page-prequotequestions.page-number-9.package-23423").length > 0 ||
      $(".page-prequotequestions.page-number-24.package-23424").length > 0 ||
      $(".page-prequotequestions.page-number-1.package-24338").length > 0 ||
      $(".page-quickquote.package-24428").length > 0 ||
      $(".page-quickquotequestions.page-number-6.package-24337").length > 0 ||
      $(".page-quickquotequestions.page-number-4.package-24518").length > 0 ||
      $(".page-quickquotequestions.page-number-3.package-24588").length > 0;

    if (!isTargetPage) return; // Not a page of interest—exit early

    // -------- 2. Business rules ---------
    const commissionInput = $("#CommissionRateOnFile_NUM");
    const commissionVal = commissionInput.val();
    const continueBtn = document.querySelector('button[name="continueButton"]');

    if (
      Instanda.Variables.CreatedFrom !== "MTA" ||
      Instanda.Variables.ChangeReason_Choice === "Reissue"
    ) {
      if (!continueBtn) {
        console.warn("Continue button not found!");
        return;
      }

      showSpinner();
      continueBtn.disabled = true;

      getcommissionRates()
        .then(() => {
          continueBtn.disabled = false;
          hideSpinner();
        })
        .catch((error) => {
          console.error("Error getting commission rate:", error);
          continueBtn.disabled = false;
          hideSpinner();
        });
    }
  });

  // Commission rates function
  async function getcommissionRates() {
    return new Promise((resolve, reject) => {
      try {
        // Clear fields for Renewal
        if (Instanda.Variables.CreatedFrom === "Renewal") {
          $("#BC_PLANID").val("");
          $("#BC_TotalCommissionRate").val("");
          $("#BC_mgaCcommissionRate").val("");
          $("#CommissionRateOnFile_NUM").val("");
        }

        if ($(".si-init-done").length > 0) {
          hideSpinner();
          return;
        }

        if (isReadOnlyView()) {
          console.log("Read-only view");
          hideSpinner(); // Hide spinner on early return
          return "Read-only view";
        }
        // Extract variables from Instanda.Variables
        const createdfrom = Instanda.Variables.CreatedFrom;
        const AgencyId =
          createdfrom === "MTA" ?
            Instanda.Variables.SelectedBrokerCodeBC_TXT :
            Instanda.Variables.SelectedBrokerCode_TXT;

        const convertedpolicy =
          Instanda.Variables.ConvertedPolicy_YNP ||
          Instanda.Variables.ConvertedPolicy_YN;

        const polProdCd = Instanda.Variables.admittedNonAdmittedCode;
        const productcode = Instanda.Variables.ProductCode_CHOICE;

        // Order of preference: RiskState, CO_RiskState, MA_State
        let stateCd;
        if (Instanda.Variables.PackageId === 24338) {
          stateCd = getStateCode(Instanda.Variables.PremiumState_CHOICE);
        } else {
          stateCd =
            Instanda.Variables.RiskStateRO_TXT ||
            Instanda.Variables.CO_RiskStateRO_TXT ||
            Instanda.Variables.MA_State_CHOICE;
        }

        const polEffDate = formatDate(Instanda.Variables.EffectiveDate_DATE);
        const polExpDate = formatDate(Instanda.Variables.ExpirationDate_DATE);
        const inceptiondate = formatDate(Instanda.Variables.InceptionDate_DATE);
        const changereason =
          Instanda.Variables.ChangeReason_Choice ||
          Instanda.Variables.ChangeReason_Choice_DEFAULT;
        const rewritetype = Instanda.Variables.CancelReissueOrRewrite_CHOICE;
        const IsPolRewrite = Instanda.Variables.IsPolRewrite_YNP;
        const rewritetype1 = safeString(Instanda.Variables.IsRenewalRewrite_YN);
        const cocApplicableraw = Instanda.Variables.CourseofConstruction_YN;
        const cocApplicable = cocApplicableraw === "Yes" ? "Y" : "N";
        const renewalcount = Instanda.Variables.RENEWAL_COUNT;
        // Deductible fields
        const HurrDed = Instanda.Variables.HurricaneDeductible_CHOICE;
        const NamedStorm = Instanda.Variables.NamedStormDeductible_CHOICE;
        const WindStormHail = Instanda.Variables.WindStormDeductible_CHOICE;
        const WindHail = Instanda.Variables.WindHailDeductible_CHOICE_CALC;

        // Utility function for the business rule
        function atLeastOneApplicableY(...values) {
          return values.some(
            (val) =>
              val !== undefined &&
              val !== null &&
              val !== "" &&
              val !== "Excluded"
          ) ?
            "Y" :
            "N";
        }

        const wdApplicable = atLeastOneApplicableY(
          HurrDed,
          NamedStorm,
          WindStormHail,
          WindHail
        );

        // Transaction type code logic remains unchanged
        const transtypcode =
          renewalcount > 0 ?
            "RENEWAL" :
            createdfrom === "NewBusiness" && convertedpolicy === "Yes" ?
              "RENEWAL" :
              createdfrom === "NewBusiness" && IsPolRewrite === "Yes" ?
                "RENEWAL" :
                createdfrom === "NewBusiness" && rewritetype1 === "Yes" ?
                  "RENEWAL" :
                  createdfrom === "NewBusiness" && rewritetype === "Rewrite" ?
                    "NBUS" :
                    changereason === "Reissue" && renewalcount > 0 ?
                      "RENEWAL" :
                      createdfrom;

        // Map lineOfBusiness
        let lineOfBusiness = Instanda.Variables.LOBType_Text;
        if (lineOfBusiness === "Yacht") {
          lineOfBusiness = "YACH";
        } else if (lineOfBusiness === "Collections") {
          lineOfBusiness = "PCOL";
        } else if (lineOfBusiness === "Auto") {
          lineOfBusiness = "AUTO";
        } else if (lineOfBusiness === "Excess Liability") {
          lineOfBusiness = "PEL";
        } else if (lineOfBusiness === "Home") {
          lineOfBusiness = "HOME";
        } else if (lineOfBusiness === "Earthquake") {
          lineOfBusiness = "EQ";
        } else if (lineOfBusiness === "Excess Flood") {
          lineOfBusiness = "EXFL";
        }

        if (
          createdfrom === "Cancellation" ||
          (createdfrom === "MTA" && changereason !== "Reissue")
        ) {
          resolve({
            createdfrom: "Cancellation",
          });
          return;
        }

        // Prepare the request payload
        const body = {
          brokerCode: formatToSevenDigits(String(AgencyId)),
          lineOfBusiness: lineOfBusiness,
          companyCode: "AIG",
          planEffectiveDate: polEffDate,
          planExpirationDate: polExpDate,
          policyInceptionDate: inceptiondate,
          admittedNonAdmittedCode: polProdCd,
          primaryLocationInd: "Y",
          state: stateCd,
          transactionType: transtypcode,
        };

        // Only add these for HOME
        if (lineOfBusiness === "HOME") {
          body.cocApplicable = cocApplicable;

          // States as an array for easy checking;
          const nonAdmittedStates = [
            "NY",
            "AZ",
            "CO",
            "CT",
            "FL",
            "GA",
            "MA",
            "NC",
            "TX",
            "VA",
            "NJ",
            "SC",
            "MT",
            "RI",
          ];
          if (productcode === "Admitted" && stateCd === "FL") {
            body.wdApplicable = wdApplicable;
          } else if (
            productcode === "Non-Admitted" &&
            nonAdmittedStates.includes(stateCd)
          ) {
            body.wdApplicable = wdApplicable;
          }
        }

        console.log("Request Body:", body);

        // API endpoint extraction
        const {
          apiBaseUrl,
          subscriptionKey
        } = getApiEndpoint("commissions");
        const siteCssLink = document.querySelector(
          'link[href*="SiteCustomCss"]'
        );
        let siteId = null;
        if (siteCssLink) {
          const match = siteCssLink.href.match(/siteId=(\d+)/);
          if (match) {
            siteId = match[1];
          }
        }

        let apiEndpoint;
        if (siteId === "2913") {
          apiEndpoint = `${apiBaseUrl}/dcbilling/v1.2/getCommissionRates`;
        } else {
          apiEndpoint = `${apiBaseUrl}/dcbilling/v1/getCommissionRates`;
        }

        // Make the API call
        fetch(apiEndpoint, {
          method: "POST",
          headers: generateHeaders(subscriptionKey),
          body: JSON.stringify(body),
        })
          .then((response) => response.json())
          .then((data) => {
            // Check for empty PlanID and throw error if so
            if (!data.planId || data.planId === "") {
              const errorMsg =
                "Commission rate could not be retrieved, please contact Customer Care Center 866-856-6858.";
              if (Instanda.Variables.PCSReferralLevel <= 3) {
                displayApiErrorMessage(
                  "Please contact Customer Care Center 866-856-6858 or reach out to the underwriter."
                );
              } else {
                displayApiErrorMessage(errorMsg);
              }
              reject(new Error(errorMsg));
              return;
            }
            $("#BC_PLANID").val(Number(data.planId));
            $("#BC_TotalCommissionRate").val(Number(data.totalCommissionRate));
            $("#BC_mgaCcommissionRate").val(Number(data.mgaCcommissionRate));
            $("#CommissionRateOnFile_NUM").val(
              Number(data.agencyCommissionRate)
            );
            if (lineOfBusiness === "AUTO") {
              $("#CommissionRateOnFile_NUM").trigger("change");
            }
            resolve(data);
          })
          .catch((error) => {
            console.error("Error:", error);
            if (Instanda.Variables.PCSReferralLevel <= 3) {
              displayApiErrorMessage(
                "Please contact Customer Care Center 866-856-6858 or reach out to the underwriter."
              );
            } else {
              displayApiErrorMessage(
                "Commission rate could not be retrieved, please contact Customer Care Center 866-856-6858."
              );
            }
            reject(error);
          });
      } catch (error) {
        if (Instanda.Variables.PCSReferralLevel <= 3) {
          displayApiErrorMessage(
            "Please contact Customer Care Center 866-856-6858 or reach out to the underwriter."
          );
        } else {
          displayApiErrorMessage(
            "Commission rate could not be retrieved, please contact Customer Care Center 866-856-6858."
          );
        }
        reject(error);
      }
    });
  }

  ////////////////////////////////////////// Commission Rates///////////////////////////////////////////////////////

  ///////////////////////////////////API - Create Notes/ Sync Notes to SF/////////////////////////////////////////////////////

  function createNotes() {
    const notetxt = $('[id^="txtNotes"]').val();
    console.log(notetxt);

    const creator = "Instanda";
    const effDate = Instanda.Variables.EffectiveDate_DATE;
    const salestage = Instanda.Variables.SaleStage; // Dynamically set sales stage
    const quoteStatus =
      salestage === "AboutToQuote" ?
        "Quote" :
        salestage === "Quote" ?
          "Quote" :
          salestage === "Referred" ?
            "Quote" :
            salestage === "ReferralRejected" ?
              "Quote" :
              salestage === "ReferralCleared" ?
                "Quote" :
                salestage === "Binder" ?
                  "Quote" :
                  salestage === "AboutToPay" ?
                    "Quote" :
                    "Policy";

    // Determine the appropriate QuoteID based on the salestage
    const QuoteID =
      quoteStatus === "Policy" ?
        formatToTenDigits(Instanda.Variables.PolicyNumber) :
        String(Instanda.Variables.QuoteRef) ||
        formatToTenDigits(Instanda.Variables.PolicyNumber);

    const body = {
      note: notetxt,
      createdBy: creator,
      createdOn: formatDate(effDate),
      entityType: quoteStatus,
      entityId: String(QuoteID),
    };

    console.log("Request Body:", body);

    const {
      apiBaseUrl,
      subscriptionKey
    } = getApiEndpoint("createnotes");
    const siteCssLink = document.querySelector('link[href*="SiteCustomCss"]');
    let siteId = null;
    if (siteCssLink) {
      // Extract siteId from the href using a regular expression
      const match = siteCssLink.href.match(/siteId=(\d+)/);
      if (match) {
        siteId = match[1];
      }
    }
    let apiEndpoint;
    if (siteId === "2913") {
      apiEndpoint = `${apiBaseUrl}/salesforce/v1.2/createNotes`;
    } else {
      apiEndpoint = `${apiBaseUrl}/salesforce/v1/createNotes`;
    }

    fetch(apiEndpoint, {
      method: "POST",
      headers: generateHeaders(subscriptionKey),
      body: JSON.stringify(body),
    })
      .then((response) => response.json())
      .then((data) => {
        if (data.status === "Error") {
          console.error("Error fetching createnotes details:", data.message);
          console.error("Error details:", data.details);
          data.error.forEach((err) => {
            console.error(`Error Code: ${err.code}, Message: ${err.message}`);
          });
          alert(
            "Notes information could not be created, please contact Customer Care Center 866-856-6858."
          );
          return;
        }
        console.log("Notes created successfully:", data);
      })
      .catch((error) => {
        console.error("Error fetching createnotes details:", error);
        alert(
          "Notes information could not be created, please contact Customer Care Center 866-856-6858."
        );
      });
  }

  // Triggering Sync/Create notes API on save of notes
  $('[id^="responsive-agent-notes"]').on("click", function () {
    createNotes();
  });

