  /////////////////////////////////////////////////////////////////////////////////////////////////////////////
  //trigger quotesync & Policytransactions
  $(document).ready(async function () {
    const continueBtn = document.querySelector('button[name="continueButton"]');

    async function runQuotesync({ disableButton = null } = {}) {
      try {
        if (disableButton) disableButton.disabled = true;
        await quotesync();

        // After a successful quotesync, flip No -> Yes (all scenarios)
        if (Instanda?.Variables?.QuoteSyncSF_YN === "No") {
          await updateQuoteorPolicydata(null, { QuoteSyncSF_YN: "Yes" });
        }

        await consumePolicyWebhooks();
      } catch (error) {
        console.error("Error:", error);
      } finally {
        if (disableButton) disableButton.disabled = false;
      }
    }

    // Quick-Quote or Pre-Quote Questions
    if (
      $(".page-prequotequestions.page-number-2").length > 0 ||
      $(".page-prequotequestions.page-number-3").length > 0 ||
      $(".page-quickquotequestions.page-number-4").length > 0 ||
      $(".page-quickquotequestions.page-number-2").length > 0
    ) {
      await runQuotesync({ disableButton: continueBtn });
    }

    // ViewQuoteOrPolicy (non-reinstatement): trigger only when QuoteSyncSF_YN === "Yes"
    if ($(".page-viewquoteorpolicy").length > 0 && Instanda.Variables.IsReinstatement !== true) {
      if (Instanda.Variables.QuoteSyncSF_YN === "Yes") {
        await runQuotesync({ disableButton: continueBtn });
      }
    }

    if ($(".page-reviewreferrals").length > 0) await runQuotesync();
    if ($(".page-quote").length > 0) await runQuotesync();
    if ($(".page-confirmation2.sale-stage-salecomplete").length > 0) await runQuotesync();

    const isPostQuote1 =
      $(".page-postquotequestions.page-number-1").length > 0 &&
      Instanda.Variables["PackageId"] == 23423;

    const isPostQuote2 =
      $(".page-postquotequestions.page-number-2").length > 0 &&
      Instanda.Variables["PackageId"] == 23424;

    if (isPostQuote1 || isPostQuote2) await runQuotesync();
  });


