  /////////////////////////////////////////// Moratoriums Function //////////////////////////////////////////////////////////////////

  function moratoriums(event) {
    return new Promise((resolve, reject) => {
      // Check if the event object is defined and the page is not 'prequotequestions'
      if (event && Instanda.Variables.PageName !== "prequotequestions") {
        event.preventDefault();
      }

      const createdfrom = Instanda.Variables.CreatedFrom;
      const convertedpolicy = Instanda.Variables.ConvertedPolicy_YN;

      if (convertedpolicy === "Yes") {
        resolve({
          convertedpolicy: "Yes",
        });
        return;
      }
      if (createdfrom === "Cancellation") {
        resolve({
          createdfrom: "Cancellation",
        });
        return;
      }
      if (isReadOnlyView()) {
        console.log("Read-only view");
        resolve("Read-only view");
        return;
      }

      const product = Instanda.Variables.LOBType_Text;
      const capacityProvider = Instanda.Variables.CapacityProvider_TXT;
      const effectivedate = formatDate(Instanda.Variables.EffectiveDate_DATE);
      const prodCode = Instanda.Variables.ProductCode_CHOICE;
      const summercounty =
        Instanda.Variables.YTSummer_County_TXT ||
        Instanda.Variables.YT_PrimaryBerthLoc_County_TXT;
      const summerState =
        Instanda.Variables.YT_BerthSummer_State_CHOICE ||
        Instanda.Variables.YT_PrimaryBerth_State_TXT;
      const winterCounty =
        Instanda.Variables.YTWinter_County_TXT ||
        Instanda.Variables.YT_PrimaryBerthLoc_County_TXT;
      const winterState =
        Instanda.Variables.YT_BerthWinter_State_CHOICE ||
        Instanda.Variables.YT_PrimaryBerth_State_TXT;
      const collcounty =
        Instanda.Variables.CO_RiskAddress_County_TXT ||
        Instanda.Variables.MA_County1_TXT;
      const distanceFromShore =
        Instanda.Variables.CO_Primary_DistanceFromShore_CHOICE;
      const collstate = Instanda.Variables.CO_RiskStateRO_TXT;
      const collzip =
        Instanda.Variables.CO_RiskPostCodeRO_TXT ||
        Instanda.Variables.MA_Zip_NUM;
      const lobtype = Instanda.Variables.LOBType_Text;
      const countyultimate = summercounty || winterCounty || collcounty || "";

      const body = {
        product: product,
        capacityProvider: capacityProvider,
        createdFrom: createdfrom,
        effectiveDate: effectivedate,
        prodCode: prodCode,
        county: countyultimate,
        distanceFromShore: distanceFromShore,
        state: collstate,
        zipCode: extractZipCode(collzip),
      };
      if (lobtype === "Yacht") {
        body["summercounty"] = summercounty;
        body["summerState"] = summerState;
        body["winterCounty"] = winterCounty;
        body["winterState"] = winterState;
      } else if (lobtype === "Collections") {
        body["collcounty"] = collcounty;
        body["distanceFromShore"] = distanceFromShore;
        body["collstate"] = collstate;
        body["collzip"] = extractZipCode(collzip);
      }

      console.log("Request Body:", body);

      const {
        apiBaseUrl,
        subscriptionKey
      } = getApiEndpoint("getMoratorium");
      const apiEndpoint = `${apiBaseUrl}/coherent/v1/getMoratorium`;

      fetch(apiEndpoint, {
        method: "POST",
        headers: generateHeaders(subscriptionKey),
        body: JSON.stringify(body),
      })
        .then((response) => response.json())
        .then((data) => {
          console.log("Success:", data);

          // Set form fields as before...
          [
            [
              "catMoratoriumExternalReferral",
              data.catMoratoriumExternalReferral,
            ],
            [
              "catMoratoriumExternalReferral_TXT",
              data.catMoratoriumExternalReferral,
            ],
            ["catMoratoriumExternalRule", data.catMoratoriumExternalRule],
            ["catMoratoriumExternalRule_TXT", data.catMoratoriumExternalRule],
            ["catMoratoriumInternalRule", data.catMoratoriumInternalRule],
            ["catMoratoriumInternalRule_TXT", data.catMoratoriumInternalRule],
            ["catMoratoriumUWReferral", data.catMoratoriumUWReferral],
            ["catMoratoriumUWReferral_TXT", data.catMoratoriumUWReferral],
            [
              "uwAppetiteMoratoriumExternalReferral",
              data.uwAppetiteMoratoriumExternalReferral,
            ],
            [
              "uwAppetiteMoratoriumExternalReferral_TXT",
              data.uwAppetiteMoratoriumExternalReferral,
            ],
            [
              "uwAppetiteMoratoriumExternalRule",
              data.uwAppetiteMoratoriumExternalRule,
            ],
            [
              "uwAppetiteMoratoriumExternalRule_TXT",
              data.uwAppetiteMoratoriumExternalRule,
            ],
            [
              "uwAppetiteMoratoriumInternalRule",
              data.uwAppetiteMoratoriumInternalRule,
            ],
            [
              "uwAppetiteMoratoriumInternalRule_TXT",
              data.uwAppetiteMoratoriumInternalRule,
            ],
            ["uwAppetiteMoratoriumReferral", data.uwAppetiteMoratoriumReferral],
            [
              "uwAppetiteMoratoriumReferral_TXT",
              data.uwAppetiteMoratoriumReferral,
            ],
          ].forEach(([id, val]) => $("#" + id).val(val));

          let errorMessage = null;

          const pageName = Instanda.Variables.PageName;
          const packageId = Instanda.Variables.PackageId;

          // ===== EXTERNAL USER: HARD STOP =====
          if (Instanda.Variables.SalespersonReferralLevel <= 3) {
            if (data.uwAppetiteMoratoriumExternalRule === "Hard Stop") {
              errorMessage = data.uwAppetiteMoratoriumExternalReferral;
            } else if (data.catMoratoriumExternalRule === "Hard Stop") {
              errorMessage = data.catMoratoriumExternalReferral;
            }

            if (
              data.uwAppetiteMoratoriumExternalRule === "Hard Stop" ||
              data.catMoratoriumExternalRule === "Hard Stop"
            ) {
              // Only BLOCK on post-quote screens (not on quote screen)
              if (
                (packageId === 23424 && Instanda.Variables.PageNumber !== 25) ||
                (packageId === 23423 && Instanda.Variables.PageNumber !== 9) ||
                pageName === "postquotequestions"
              ) {
                alert(
                  errorMessage ||
                  "A moratorium prevents policy action at this time."
                );
                reject(
                  new Error(
                    "Moratorium: " +
                    (errorMessage ||
                      "A moratorium prevents policy issuance for this region/product.")
                  )
                );
                return;
              } else {
                alert(
                  errorMessage ||
                  "A moratorium prevents policy action at this time."
                );
                resolve("Process completed but with moratorium constraints.");
                return;
              }
            }
          }

          // ===== EXTERNAL USER: UW Referral =====
          if (Instanda.Variables.SalespersonReferralLevel <= 3) {
            if (data.uwAppetiteMoratoriumExternalRule === "UW Referral") {
              errorMessage = data.uwAppetiteMoratoriumExternalReferral;
            } else if (data.catMoratoriumExternalRule === "UW Referral") {
              errorMessage = data.catMoratoriumExternalReferral;
            }

            if (
              data.uwAppetiteMoratoriumExternalRule === "UW Referral" ||
              data.catMoratoriumExternalRule === "UW Referral"
            ) {
              if (pageName === "postquotequestions") {
                reject(
                  new Error(
                    "Moratorium: " +
                    (errorMessage ||
                      "Underwriting must review moratorium in this region.")
                  )
                );
                return;
              } else {
                alert(
                  errorMessage ||
                  "Underwriting review for moratorium in this region."
                );
                resolve("Process completed successfully.");
                return;
              }
            }
          }

          // ===== INTERNAL USER: HARD STOP =====
          if (Instanda.Variables.SalespersonReferralLevel > 3) {
            if (data.uwAppetiteMoratoriumInternalRule === "Hard Stop") {
              errorMessage = data.uwAppetiteMoratoriumReferral;
            } else if (data.catMoratoriumInternalRule === "Hard Stop") {
              errorMessage = data.catMoratoriumUWReferral;
            }

            if (
              data.catMoratoriumInternalRule === "Hard Stop" ||
              data.uwAppetiteMoratoriumInternalRule === "Hard Stop"
            ) {
              // Only BLOCK on post-quote screens (not on quote screen)
              if (
                (packageId === 23424 && Instanda.Variables.PageNumber !== 25) ||
                (packageId === 23423 && Instanda.Variables.PageNumber !== 9) ||
                pageName === "postquotequestions"
              ) {
                alert(
                  errorMessage ||
                  "A moratorium prevents policy action at this time."
                );
                reject(
                  new Error(
                    "Moratorium: " +
                    (errorMessage ||
                      "A moratorium prevents policy issuance for this region/product.")
                  )
                );
                return;
              } else {
                alert(
                  errorMessage ||
                  "A moratorium prevents policy action at this time."
                );
                resolve("Process completed but with moratorium constraints.");
                return;
              }
            }
          }

          // ===== INTERNAL USER: UW Referral =====
          if (Instanda.Variables.SalespersonReferralLevel > 3) {
            if (data.uwAppetiteMoratoriumInternalRule === "UW Referral") {
              errorMessage = data.uwAppetiteMoratoriumReferral;
            } else if (data.catMoratoriumInternalRule === "UW Referral") {
              errorMessage = data.catMoratoriumUWReferral;
            }

            if (
              data.uwAppetiteMoratoriumInternalRule === "UW Referral" ||
              data.catMoratoriumInternalRule === "UW Referral"
            ) {
              if (pageName === "prequotequestions") {
                alert(
                  errorMessage ||
                  "Underwriting review for moratorium in this region."
                );
                resolve("Process completed successfully.");
                return;
              } else {
                // --- INLINE MODAL HANDLING (OVERLAY/MESSAGE CLEANUP) ---
                $("#policy-issuing-overlay").hide();
                $(".continueButton-message").remove();

                const moratmodelhtml = `
                <div id="custom-modal" class="modalmoratorium" style="display: block; text-align: center; color: black; background-color: white; position: fixed; top: 50%; left: 50%; transform: translate(-50%, -50%); padding: 20px; border: 1px solid black; z-index: 11000;">
                  <div class="modal-content-moratorium">
                    <h6>There is currently a moratorium in place for this region.</h6>
                    <h6>Do you still want to proceed to issuance?</h6>
                    <button id="yes-button" class="btn brokerchildbtn">Yes</button>
                    <button id="no-button" class="btn brokerchildbtn">No</button>
                  </div>
                </div>`;
                $("body").append(moratmodelhtml);

                $("#yes-button").on("click", function () {
                  $("#custom-modal").remove();
                  $("#policy-issuing-overlay").show();
                  resolve("User chose to proceed.");
                });

                $("#no-button").on("click", function () {
                  $("#custom-modal").remove();
                  displayApiErrorMessage(errorMessage);
                  reject(
                    new Error(
                      "Moratorium: " +
                      (errorMessage ||
                        "You declined to proceed due to a moratorium.")
                    )
                  );
                });

                return; // Wait for user input
              }
            }
          }

          // If got here, allow normal flow
          resolve("Process executed successfully");
        })
        .catch((error) => {
          // Always show error via handler, not alert()
          displayApiErrorMessage(
            error && error.message ? error.message : "Unknown error"
          );
          reject(error instanceof Error ? error : new Error(String(error)));
        });
    });
  }

