                        $("#CancelMethod_CHOICE").val() !== "Flat" ?
                        "PCAN" :
                        "NBUS";
      const electronicinv = "0";
      const UWname = Instanda.Variables.UWCompany_CHOICE;
      const commissionrateonfile = Instanda.Variables.CommissionRateOnFile_NUM;
      const totalcommissionRate = Instanda.Variables.BC_TotalCommissionRate;
      const totalcommission =
        totalcommissionRate !== undefined ? totalcommissionRate : 0;
