  // function for creating dummy policies for rolled off quotes
  var bodyOOS = {
    OOSquotes: [],
  };

  var ROPolicies = "";
  async function callOOSDWHSync() {
    if (typeof showSpinner === "function") showSpinner();

    try {
      // Read-only guard, skip API if so
      if (typeof isReadOnlyView === "function" && isReadOnlyView()) {
        console.log("Read-only view in OOSDWHSync");
        return false;
      }

      // Optionally, extract or sanitize your body payload
      if (
        !bodyOOS ||
        !Array.isArray(bodyOOS.OOSquotes) ||
        bodyOOS.OOSquotes.length === 0
      ) {
        console.log("No OOSquotes to process in callOOSDWHSync");
        return false;
      }

      // Get dynamic API info
      const {
        apiBaseUrl,
        subscriptionKey
      } = getApiEndpoint("phase2");
      const apiEndpoint = `${apiBaseUrl}/instanda/v1/OOSDWHSync`;

      // Set headers, include any custom context
      const headers = generateHeaders(subscriptionKey);
      headers["pcsctx-agentGroupName"] = "Private Client Select (PCS)";
      //headers["pcsctx-salesPersonUserName"] = Instanda.Variables.PCSAgentName;
      headers["pcsctx-salesPersonUserName"] =
        " integration.user@privateclientselect.com"; //This needs a Integration User to be created
      // Call the API
      const response = await fetch(apiEndpoint, {
        method: "POST",
        headers: headers,
        body: JSON.stringify(bodyOOS),
      });

      // Handle response
      // let ROPolicies = "";
      if (!response.ok) {
        const errorPayload = await response.text();
        console.error(
          `OOSDWHSync Failed: ${response.status} ${response.statusText}`
        );
        console.error("Error details:", errorPayload);
        throw new Error(
          `The rolled-off transaction process failed due to a backend exception. Please try the issuance process again.\nIf the issue persists, contact system support with error reference:\n${errorPayload}`
        );
      }

      console.log(`This is response for OOSDWHSync:\t${response}`);
      // Parse and process data
      const responseBody = await response.json();
      console.log("API Success Response:", responseBody);
      console.log(
        `This is responsebody:\t${typeof responseBody}\n${responseBody}`
      );

      if (
        responseBody &&
        responseBody.data &&
        (responseBody.data.rolledOffQuotes ||
          responseBody.data.rolledOffErrorDetails) &&
        Array.isArray(responseBody.data.rolledOffQuotes)
      ) {
        let d = $("#RolledOffPolicyNumbers_TXT").val();
        let r = d;
        console.log(`This is 'd' in OOSDWHSync upfront:\t${typeof d}\t${d}`);
        if (responseBody.data.rolledOffQuotes) {
          responseBody.data.rolledOffQuotes.forEach((e) => {
            if (!Array.isArray(e.Success) && e.Success.PolicyNumber) {
              if (!d.includes(e.Success.PolicyNumber)) {
                if (d !== "") d += ",";
                d += e.Success.PolicyNumber;
              }
            }
            if (Array.isArray(e.Success)) {
              e.Success.forEach((t) => {
                if (
                  t.errorMessage &&
                  t.errorMessage === "Duplicate policy number"
                ) {
                  let policyNum = `${Instanda.Variables.PolicyNumber}`;
                  policyNum = policyNum.toString().padStart(10, "0");
                  if (!d.includes(`${policyNum}-RO-${e.QuoteRef}`)) {
                    if (d !== "") d += ",";
                    d += `${policyNum}-RO-${e.QuoteRef}`;
                  }
                }
              });
            }
          });
        }
        console.log(`This is updated d:\t${d}`);
        ROPolicies = d;
      }
      // Fallback if no rolledOffQuotes
      if (!ROPolicies) ROPolicies = "originalpolicynumber-RO-MTAQuoteref";
      return true;
    } catch (error) {
      console.error("Exception in callOOSDWHSync:", error);
      displayApiErrorMessage(error.message);
      return false;
    } finally {
      if (typeof hideSpinner === "function") hideSpinner();
    }
  }

