  // Helper to check ODS and conditionally trigger OOS billing once
  var normalizedOffsets = [];
  var usedQuotes = "";
  async function checkAndMaybeTriggerOOS(
    event,
    shouldTriggerBillingOOS = true
  ) {
    event.preventDefault();
    try {
      // If no offsets found, skip OOS billing and proceed with normal flow
      if (!Array.isArray(normalizedOffsets) || normalizedOffsets.length === 0) {
        console.log(
          "No OOS offsets found - skipping OOS billing and proceeding with normal MTA flow."
        );
        return true;
      }

      if (shouldTriggerBillingOOS) {
        const billingResult = await billingreceivablesOOS(
          event,
          normalizedOffsets
        ); // <-- Pass in offsets!
        if (!billingResult) {
          displayApiErrorMessage(
            "Submission blocked: Billing receivables failed."
          );
          return false;
        } else if (billingResult === 1) {
          console.log("Going by workaround");
        }
      }

      return true;
    } catch (err) {
      displayApiErrorMessage("Submission blocked: Error during OOS check.");
      return false;
    }
  }

  // Helper to MAP ODS Premium results

  function getODSOffsetPremium(rec) {
    const fields = [
      "CO_RO_TxnBilledPremTotal_NUM",
      "YT_RO_TxnBilledPremTotal_NUM",
      "TotalTxnBldPrem_NUM",
    ];
    for (const field of fields) {
      const value = Number(rec[field]);
      if (!isNaN(value) && value !== 0) {
        return value;
      }
    }
    return 0;
  }

  function normalizeODSOffsets(odsOffsets) {
    return odsOffsets.map((rec) => ({
      ...rec,
      premium: getODSOffsetPremium(rec),
    }));
  }

  // =======================================
  // 2. Global ODS Offset Fetch
  // =======================================
  async function fetchODSOffsetsGlobal(
    packageID,
    policyNumber,
    quoteRef,
    siteEnv
  ) {
    const tableName = packageToOOSViewTable[packageID];
    if (!tableName) throw new Error(`Unknown table for packageID ${packageID}`);
    const query = `
        SELECT * FROM ${tableName}
        WHERE CreatedFrom = 'MTA' AND SaleStage = 'SaleComplete' AND EffectiveDate_DATE = (SELECT EffectiveDate_DATE FROM ${tableName} WHERE QuoteRef = '${quoteRef}' AND PolicyNumber = '${policyNumber}')
          AND ExpirationDate_DATE = (SELECT ExpirationDate_DATE FROM ${tableName} WHERE QuoteRef = '${quoteRef}' AND PolicyNumber = '${policyNumber}')
          AND EffectiveChangeDate > (SELECT EffectiveChangeDate FROM ${tableName} WHERE QuoteRef = '${quoteRef}' AND PolicyNumber = '${policyNumber}')
          AND PolicyNumber = '${policyNumber}'
          AND SiteEnvironment = '${siteEnv}'
        ORDER BY EffectiveChangeDate
    `;
    const odsOffsets = await queryODS(query);

    // Defensive normalization for nested arrays
    if (
      Array.isArray(odsOffsets) &&
      odsOffsets.length === 1 &&
      Array.isArray(odsOffsets[0])
    ) {
      return odsOffsets[0];
    }
    return odsOffsets;
  }

  // =======================================
  // 2.5. OOS Reonset Duplicacy Fix //gokrishna
  // =======================================

  function reOnsetFormatter(reonset) {
    let queryFormat = ``;
    for (let i = 0; i < reonset.length; i++) {
      queryFormat += `${i ? `OR` : ``} PolicyNumber LIKE '%-RO-${reonset[i]}%'`;
    }
    return queryFormat;
  }

  async function fetchReOnset(packageID, siteEnv, reonset) {
    if (reonset.length) {
      const tableName = packageToOOSViewTable[packageID];
      if (!tableName)
        throw new Error(`Unknown table for packageID ${packageID}`);
      const query = `
        SELECT PolicyNumber FROM ${tableName}
        WHERE SaleStage = 'SaleComplete'
        AND (${reOnsetFormatter(reonset)})
        AND SiteEnvironment = '${siteEnv}'
    `;
      const odsOffsets = await queryODS(query);

      // Defensive normalization for nested arrays
      if (
        Array.isArray(odsOffsets) &&
        odsOffsets.length === 1 &&
        Array.isArray(odsOffsets[0])
      ) {
        return odsOffsets[0];
      }
      return odsOffsets;
    }
    return [];
  }

