  ///////////////////////////////////////////// Function to add the "Issue" button and bind the event //////////////////////////////////////////////
  function addIssueButton(pageNumber, packageId) {
    // Only run on the correct page and package
    if (
      $(`.page-postquotequestions.page-number-${pageNumber}`).length > 0 &&
      Number(Instanda.Variables["PackageId"]) === packageId
    ) {
      const generateBinder = $(
        `.page-postquotequestions.page-number-${pageNumber} #instandaquestions > .container .row .pull-right button[name="continueButton"][formaction="BindQuote"]`
      );

      // Hide and disable the old system buttons
      $(
        `.page-postquotequestions.page-number-${pageNumber} button[name="continueButton"][formaction="BindQuote"]`
      ).hide();
      $(
        `.page-postquotequestions.page-number-${pageNumber} button[name="continueButton"][formaction="CreatePolicyFromQuote"]`
      ).hide();

      // Only add the custom button if not already present
      if (
        $(`.page-postquotequestions.page-number-${pageNumber} .generatebinder`)
          .length === 0
      ) {
        const bindPolicyButton = $("<button>", {
          class: "btn btn-primary generatebinder",
          html: 'Issue Policy <i class="fa fa-caret-right"></i>',
        }).on("click", async function (event) {
          event.preventDefault();

          const proceed = await handleOfacButtonHide(event);
          if (!proceed) {
            // OFAC check failed, block further action
            console.log("ofac failed");
            return;
          }
          // Disable button right away to prevent double submissions
          const $btn = $(this);
          $btn.prop("disabled", true).addClass("disabled");
          showSpinner();

          try {
            await dcbillingevents(event);
            // If on success you want to keep the button disabled and
            // not allow resubmit, keep as is.
            // If you want to re-enable on success, uncomment below:
            // $btn.prop("disabled", false).removeClass("disabled");
          } catch (error) {
            console.log(error);
            hideSpinner();
            if (
              error &&
              error.message &&
              error.message.toLowerCase().includes("moratorium")
            ) {
              displayApiErrorMessage(error.message);
            } else {
              displayApiErrorMessage(
                "There is currently an issue with Policy Issuance. Please contact Customer Care Center 866-856-6858."
              );
            }
            $btn.prop("disabled", false).removeClass("disabled");
          } finally {
            // Optionally add a finally block if you always want to re-enable
            $btn.prop("disabled", false).removeClass("disabled");
          }
        });

        generateBinder.after(bindPolicyButton);
      }
    }
  }

  function showButtonMessageAfterParent(message, btnid) {
    $(".continueButton-message").remove();
    var $btn = $("" + btnid + "");
    var $parentDiv = $btn.closest("div").parent();
    var $msg = $(
      '<div class="continueButton-message" style="color:red; margin-top:50px; font-size:90%; display:block;">' +
      message +
      "</div>"
    );
    $parentDiv.after($msg);
  }

