  function toggleButtons(pageNumber, packageId) {
    const vars = Instanda.Variables;
    if (
      vars.PageName !== "postquotequestions" ||
      vars.PageNumber !== pageNumber ||
      vars.PackageId !== packageId
    )
      return;

    const $continueBtn = $(
      'button[name="continueButton"][formaction="BindQuote"]'
    );
    const $generateBinder = $(".generatebinder");
    const $issueBtn = $('button[class="btn btn-primary issuepolicy"]');

    function handleScheduleValidation() {
      if (!vars.ScheduleUpload_Validation) {
        let alertMessage =
          vars.Message_SchedUpload &&
          vars.Message_SchedUpload.replace(/, $/, ""); //whichever has value
        let btnid = null;
        if (vars.CreatedFrom === "MTA")
          btnid = 'button[class="btn btn-primary issuepolicy"]';
        else btnid = 'button[name="continueButton"][formaction="BindQuote"]';
        showButtonMessageAfterParent(alertMessage, btnid);
        if (vars.CreatedFrom === "MTA")
          $issueBtn.show().addClass("disabled-isbtn");
        else $continueBtn.show().addClass("disabled-isbtn");
      } else {
        if (vars.CreatedFrom === "MTA")
          $issueBtn.show().removeClass("disabled-isbtn");
        else $continueBtn.show().removeClass("disabled-isbtn");
        hideButtonMessage();
      }
    }

    if (packageId === 23424) {
      // Only enforce schedule upload validation for Collections
      if (
        vars.PolicyNumber === undefined ||
        vars.CreatedFrom === "MTA" ||
        vars.CreatedFrom === "Renewal"
      ) {
        handleScheduleValidation();
        $generateBinder.hide();
      } else {
        $continueBtn.hide();
        //$generateBinder.show();
        $generateBinder
          .css("display", "block")
          .get(0)
          .style.setProperty("display", "inline-block", "important");
      }
    } else if (
      packageId === 23423 ||
      packageId === 24338 ||
      packageId === 24428 ||
      packageId === 24337 ||
      packageId === 24518 ||
      packageId === 24588
    ) {
      if (vars.PolicyNumber === undefined) {
        $continueBtn.show();
        $generateBinder.hide();
      } else {
        $continueBtn.hide();
        $generateBinder.show();
      }
    } else {
      if (vars.PolicyNumber === undefined) {
        handleScheduleValidation();
      } else if (vars.CreatedFrom === "MTA") {
        handleScheduleValidation();
      }
    }
  }

