  // Auto Click Issue policy on Post quote
  async function issuepolicy() {
    showSpinner();
    try {
      const issuePolicyButton = document.querySelector(
        'button[type="submit"][name="continueButton"][formaction="CreatePolicyFromQuote"]'
      );

      if (issuePolicyButton) {
        console.log("Inside Issue Button");

        // If the button is disabled, enable it, click, then (optionally) restore state
        const wasDisabled = issuePolicyButton.disabled;
        if (wasDisabled) {
          issuePolicyButton.disabled = false;
        }
        issuePolicyButton.click();
        if (wasDisabled) {
          issuePolicyButton.disabled = true;
        }

        // Wait for redirect, DOM update, etc.
        await new Promise((resolve) => {
          setTimeout(resolve, 200);
        });
        // Continue logic here that needs to wait...
      } else {
        console.warn("Issue Policy button not found.");
      }
    } finally {
      hideSpinner();
    }
  }
  ///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

  /////////////////////////////////////////////Zipcode to 5 Characters//////////////////////////////////////////////////

  function extractZipCode(zipCode) {
    if (zipCode == null) return "";
    zipCode = String(zipCode).trim();
    if (!zipCode || /^(undef|undefined|null|nan)$/i.test(zipCode)) return "";

    if (/[a-z]/i.test(zipCode)) {
      zipCode = zipCode.toUpperCase().replace(/[^A-Z0-9]/g, "");
      return zipCode.length > 3 ?
        zipCode.slice(0, -3) + " " + zipCode.slice(-3) // CF103EA -> CF10 3EA
        :
        zipCode;
    }

    // Convert to string, trim spaces
    zipCode = String(zipCode).trim();
    // If ZIP+4, split at the dash and take the first part
    if (zipCode.includes("-")) {
      zipCode = zipCode.split("-")[0];
    }
    // Pad with leading zeros if necessary, then take first 5 digits
    zipCode = zipCode.padStart(5, "0").substring(0, 5);
    return zipCode;
  }

