  // Making rate effective date  field editable when is policy Rewrite field is set to yes- Auto/EQ/EL/EF/HO-page 1

  $(function () {
    if ($(".created-from-newbusiness.page-number-1").length > 0) {
      const rewtype =
        Instanda.Variables.CancelReissueOrRewrite_CHOICE ||
        $("#CancelReissueOrRewrite_CHOICE").val();
      if (rewtype === "Rewrite") {
        function updatePolicyRewrite() {
          if (
            $("#IsPolRewrite_YNPYes").parent().hasClass("instanda-selected")
          ) {
            $('input[name="RateEffectiveDate_Date"]').addClass(
              "policyRewriteYes"
            );
            $('input[name="RateEffectiveDate_Date"]').removeAttr("readonly");
          } else {
            $('input[name="RateEffectiveDate_Date"]').removeClass(
              "policyRewriteYes"
            );
            $('input[name="RateEffectiveDate_Date"]').attr("readonly", true);
          }
        }

        $('input[name="IsPolRewrite_YNP"]').on("change", updatePolicyRewrite);
      }
    }
  });

