  ////////////////////////////////////////////////////// Incipher Taxes and Fees //////////////////////////////////////////////////////////////////////

  function calculateCustomFMTax({
    state,
    premium,
    fireTaxRate,
    inspectionFee,
    brokerFee,
    lineOfBusiness,
  }) {
    premium = Number(premium) || 0;
    inspectionFee = Number(inspectionFee) || 0;
    brokerFee = Number(brokerFee) || 0;

    switch (state) {
      case "IL":
        if (lineOfBusiness === "GEN-1092") {
          return +(premium * 0.01 * 0.4).toFixed(0);
        } else if (lineOfBusiness === "GEN-1094") {
          return +(premium * 0.01 * 0.15).toFixed(0);
        }
        break;

      case "MT":
        if (lineOfBusiness === "GEN-1092") {
          return +(premium * 0.6 * 0.025).toFixed(2);
        } else if (lineOfBusiness === "GEN-1094") {
          return +(premium * 0.6 * 0.025).toFixed(2);
        }
        break;

      case "OR":
        return +((premium + inspectionFee + brokerFee) * 0.003).toFixed(2);
        break;
      case "SD":
        if (lineOfBusiness === "GEN-1092") {
          return +((premium + inspectionFee + brokerFee) * 0.00175).toFixed(2);
        } else if (
          lineOfBusiness === "GEN-1075" ||
          lineOfBusiness === "GEN-1094"
        ) {
          return +((premium + inspectionFee + brokerFee) * 0.00075).toFixed(2);
        }
        break;
      default:
        return null;
    }
  }

  function containsPOBox(addressLine1) {
    const s = String(addressLine1 ?? "")
      .toUpperCase()
      .replace(/[^A-Z0-9]/g, "");
    return s.includes("POBOX") || s.includes("POSTOFFICEBOX");
  }

  function isGaragingUSCountry(countryValue) {
    const c = String(countryValue ?? "")
      .trim()
      .toUpperCase();
    return (
      c === "US" ||
      c === "USA" ||
      c === "UNITED STATES" ||
      c === "UNITED STATES OF AMERICA"
    );
  }

  function toStateCode(value) {
    const v = String(value ?? "").trim();
    if (!v) return "";
    if (v.length === 2) return v.toUpperCase();
    try {
      return String(getStateCode(v) ?? "")
        .trim()
        .toUpperCase();
    } catch (_) {
      return v.toUpperCase();
    }
  }

  function getBaseRiskStateCode() {
    const s =
      Instanda.Variables.CO_RiskStateRO_TXT ||
      Instanda.Variables.RiskStateRO_TXT ||
      Instanda.Variables.MA_State_CHOICE ||
      "";
    return toStateCode(s);
  }

  /**
   * Auto rule:
   * - ALWAYS prefer garaging (CM first, then Vehicle_MI/Vehicles_MI)
   * - Candidate must be US, non-PO Box, and state must match PremiumState_CHOICE
   * - Only fall back to base if base state matches PremiumState_CHOICE
   */
  function selectAutoAddressPreferGaraging({
    premiumStateCode,
    base,
    quoteCm,
    vehicles,
  }) {

    const target = toStateCode(premiumStateCode);
    const vehicleCandidates = [];

    const buildCandidate = ({
      line1,
      city,
      zip,
      state,
      country,
      source,
      enforceUS,
    }) => {

      const addressLine1 = String(line1 ?? "").trim();
      const cty = String(city ?? "").trim();
      const z = extractZipCode(String(zip ?? "").trim());
      const st = toStateCode(state);

      if (!addressLine1 || !cty || !z) return null;

      if (containsPOBox(addressLine1)) return null;

      // allow temporarily blank state (BOT timing)
      if (st && st !== target) return null;

      if (enforceUS && !isGaragingUSCountry(country)) return null;

      return {
        addressLine1,
        city: cty,
        zipCode: z,
        stateCode: st || target,
        source,
      };
    };

    // 1️⃣ Quote CM garaging first
    if (quoteCm) {

      const cm = buildCandidate({
        line1: quoteCm.line1,
        city: quoteCm.city,
        zip: quoteCm.zip,
        state: quoteCm.state,
        country: quoteCm.country,
        source: "quote_cm_garaging",
        enforceUS: true,
      });

      if (cm) return cm;
    }

    // 2️⃣ Vehicle garaging next
    if (Array.isArray(vehicles)) {

      for (const vRaw of vehicles) {

        if (!vRaw) continue;

        let v = vRaw;

        try {
          v = setGaragingAddressDefs({
            ...vRaw
          });
        } catch (_) { }

        const country =
          v?.Coh_GaragingAddrCountry_DEF ??
          v?.Coh_GaragingCountryMI_TXT_DEF ??
          v?.Coh_GaragingCountryCm_TXT_DEF;

        const cand = buildCandidate({
          line1: v?.Coh_GaragingAddrLine1_DEF ??
            v?.Coh_GaragingAddressLine1MI_TXT_DEF ??
            v?.Coh_GaragingAddressLine1Cm_TXT_DEF,

          city: v?.Coh_GaragingAddrCity_DEF ??
            v?.Coh_GaragingCityMI_TXT_DEF ??
            v?.Coh_GaragingCityCm_TXT_DEF,

          zip: v?.Coh_GaragingAddrPostCode_DEF ??
            v?.Coh_GaragingPostcodeMI_TXT_DEF ??
            v?.Coh_GaragingPostcodeCm_TXT_DEF,

          state: v?.Coh_GaragingAddrState_DEF ??
            v?.Coh_GaragingStateMI_TXT_DEF ??
            v?.Coh_GaragingStateCm_TXT_DEF,

          country,
          source: "vehicle_garaging",
          enforceUS: true,
        });

        if (cand) {
          vehicleCandidates.push(cand);
        }
      }

      if (vehicleCandidates.length) {
        return vehicleCandidates[0];
      }
    }

    // 3️⃣ Base last
    if (base && toStateCode(base.stateCode) === target) {

      const b = buildCandidate({
        line1: base.addressLine1,
        city: base.city,
        zip: base.zipCode,
        state: base.stateCode,
        country: "US",
        source: "base",
        enforceUS: false,
      });

      if (b) return b;
    }

    return null;
  }

  function hasValidNonPOGaragingForAuto({
    premiumStateChoice,
    quotedata,
    vehiclesFallback = [],
  }) {
    const targetState = toStateCode(getStateCode(premiumStateChoice));

    const quoteCm = {
      line1: quotedata?.GaragingAddressLine1Cm_TXT ??
        Instanda?.Variables?.GaragingAddressLine1Cm_TXT,
      city: quotedata?.GaragingCityCm_TXT ??
        Instanda?.Variables?.GaragingCityCm_TXT,
      zip: quotedata?.GaragingPostcodeCm_TXT ??
        Instanda?.Variables?.GaragingPostcodeCm_TXT,
      state: quotedata?.GaragingStateCm_TXT ??
        Instanda?.Variables?.GaragingStateCm_TXT,
      country: quotedata?.GaragingCountryCm_TXT ??
        Instanda?.Variables?.GaragingCountryCm_TXT,
    };

    const isValidCandidate = ({
      line1,
      city,
      zip,
      state,
      country
    }) => {
      const l1 = String(line1 ?? "").trim();
      const c = String(city ?? "").trim();
      const z = extractZipCode(String(zip ?? "").trim());
      const st = toStateCode(state);

      if (!l1 || !c || !z || !st) return false;
      if (containsPOBox(l1)) return false;
      if (st !== targetState) return false;
      if (!isGaragingUSCountry(country)) return false;
      return true;
    };

    // 1) CM garaging
    if (isValidCandidate(quoteCm)) return true;

    // 2) Vehicle garaging
    const vehicles =
      quotedata?.Vehicle_MI || quotedata?.Vehicles_MI || vehiclesFallback || [];

    if (Array.isArray(vehicles)) {
      for (const vRaw of vehicles) {
        if (!vRaw) continue;

        let v = vRaw;
        try {
          v = setGaragingAddressDefs({
            ...vRaw,
          });
        } catch (_) { }

        const country =
          v?.Coh_GaragingAddrCountry_DEF ??
          v?.Coh_GaragingCountryMI_TXT_DEF ??
          v?.Coh_GaragingCountryCm_TXT_DEF;

        const cand = {
          line1: v?.Coh_GaragingAddrLine1_DEF ??
            v?.Coh_GaragingAddressLine1MI_TXT_DEF ??
            v?.Coh_GaragingAddressLine1Cm_TXT_DEF,
          city: v?.Coh_GaragingAddrCity_DEF ??
            v?.Coh_GaragingCityMI_TXT_DEF ??
            v?.Coh_GaragingCityCm_TXT_DEF,
          zip: v?.Coh_GaragingAddrPostCode_DEF ??
            v?.Coh_GaragingPostcodeMI_TXT_DEF ??
            v?.Coh_GaragingPostcodeCm_TXT_DEF,
          state: v?.Coh_GaragingAddrState_DEF ??
            v?.Coh_GaragingStateMI_TXT_DEF ??
            v?.Coh_GaragingStateCm_TXT_DEF,
          country,
        };

        if (isValidCandidate(cand)) return true;
      }
    }

    return false;
  }

  // UPDATED: add quotedata as 3rd param
  function insciphertaxandfees(event, premiumOverride = null, quotedata = null) {
    return new Promise((resolve, reject) => {
      if (isReadOnlyView()) {
        console.log("Read-only view in insciphertaxandfees");
        resolve({
          status: "Read-only view",
        });
        return;
      }

      const createdfrom = Instanda.Variables.CreatedFrom;

      // ===== STATE (Auto uses PremiumState_CHOICE) =====
      let state;
      const isAuto = Instanda.Variables.PackageId === 24338;

      if (isAuto) {
        state = getStateCode(Instanda.Variables.PremiumState_CHOICE);
      } else {
        state =
          Instanda.Variables.CO_RiskStateRO_TXT ||
          Instanda.Variables.RiskStateRO_TXT ||
          Instanda.Variables.MA_State_CHOICE;
      }

      // ===== BASE ADDRESS (existing behavior) =====
      let address =
        Instanda.Variables.CO_RiskAddressLine1RO_TXT ||
        Instanda.Variables.RiskAddressLine1RO_TXT ||
        Instanda.Variables.MA_AddressLine1_TXT;

      let city =
        Instanda.Variables.CO_RiskCityRO_TXT ||
        Instanda.Variables.RiskCityRO_TXT ||
        Instanda.Variables.MA_City_TXT;

      let zipCode =
        Instanda.Variables.CO_RiskPostCodeRO_TXT ||
        Instanda.Variables.RiskPostCodeRO_TXT ||
        Instanda.Variables.MA_Zip_NUM;

      // ===== AUTO: ALWAYS prefer garaging; base allowed only if base state matches PremiumState_CHOICE =====
      if (isAuto) {
        const premiumStateCode = toStateCode(state); // PremiumState_CHOICE -> 2-letter

        const quoteCm = {
          line1: quotedata?.GaragingAddressLine1Cm_TXT ??
            Instanda?.Variables?.GaragingAddressLine1Cm_TXT,
          city: quotedata?.GaragingCityCm_TXT ??
            Instanda?.Variables?.GaragingCityCm_TXT,
          zip: quotedata?.GaragingPostcodeCm_TXT ??
            Instanda?.Variables?.GaragingPostcodeCm_TXT,
          state: quotedata?.GaragingStateCm_TXT ??
            Instanda?.Variables?.GaragingStateCm_TXT,
          country: quotedata?.GaragingCountryCm_TXT ??
            Instanda?.Variables?.GaragingCountryCm_TXT,
        };

        const vehicles = quotedata?.Vehicle_MI || quotedata?.Vehicles_MI || [];

        const selected = selectAutoAddressPreferGaraging({
          premiumStateCode,
          base: {
            addressLine1: address,
            city,
            zipCode,
            stateCode: getBaseRiskStateCode(),
          },
          quoteCm,
          vehicles,
        });

        if (!selected) {
          displayApiErrorMessage(
            "Need a US non-PO Box garaging address matching Premium State."
          );
          reject(
            new Error(
              "No valid non-PO Box garaging address found matching PremiumState_CHOICE."
            )
          );
          return;
        }

        address = selected.addressLine1;
        city = selected.city;
        zipCode = selected.zipCode;
        state = selected.stateCode;

        console.log(`Auto address used for InsCipher: ${selected.source}`);
      }

      // ===== the rest of your function remains the same =====
      const policyEffectiveDate = Instanda.Variables.EffectiveDate_DATE;

      const premium =
        premiumOverride !== null ?
          premiumOverride :
          createdfrom === "Cancellation" ?
            $("#CAN_YT_RO_TxnBilledPremTotal_NUM").val() ||
            $("#CAN_CO_RO_TxnBilledPremTotal_NUM").val() ||
            $("#CAN_TotalTxnBldPrem_NUM").val() :
            $("#YT_RO_TxnBilledPremTotal_NUM").val() ||
            $("#CO_RO_TxnBilledPremTotal_NUM").val() ||
            $("#TotalTxnBldPrem_NUM").val() ||
            Instanda.Variables.CO_RO_TxnBilledPremTotal_NUM ||
            Instanda.Variables.YT_RO_TxnBilledPremTotal_NUM ||
            Instanda.Variables.TotalTxnBldPrem_NUM ||
            Instanda.Variables.TotalTxnBldPrem_NUM_DEFAULT ||
            $("#TxnBldPrem_NUM").val();

      // Normalize premium for all numeric comparisons/calcs (handles commas)
      const premiumNumeric =
        Number(String(premium ?? 0).replace(/,/g, "")) || 0;

      const changereason = Instanda.Variables.ChangeReason;

      const convertedpolicy =
        Instanda.Variables.ConvertedPolicy || Instanda.Variables.ConvertedPolicy_YN;

      const admittedNonAdmitted = Instanda.Variables.ProductCode_CHOICE;

      const filing =
        Instanda.Variables.CO_SurplusFilling_CHOICEP ||
        Instanda.Variables.SurplusFilling_CHOICEP;

      const inspectionfee =
        $("#COH_InspectionPCSFEETxnBld_NUM").val() ||
        Instanda.Variables.COH_InspectionPCSFEETxnBld_NUM ||
        0;

      const brokerfee =
        $("#COH_PolicyBrokerPCSFEETxnBld_NUM").val() ||
        Instanda.Variables.COH_PolicyBrokerPCSFEETxnBld_NUM ||
        0;

      if (premiumNumeric === 0) {
        console.log("Premium is 0. Setting all variables to 0. API not called.");

        const zeroFields = {
          Sl_Tax_AnnualRateAmount_NUM: 0,
          Stamping_Fee_AnnualRateAmount_NUM: 0,
          SL_Service_Charge_AnnualRateAmount_NUM: 0,
          FM_Tax_AnnualRateAmount_NUM: 0,
          EMPA_AnnualRateAmount_NUM: 0,
          Municipal_Fee_AnnualRateAmount_NUM: 0,
          County_Fee_AnnualRateAmount_NUM: 0,
          TaxFeeRateAmount8_NUM: 0,
          INSBLD_SurplusLineTax_NUM: 0,
          INSBLD_StampingFee_NUM: 0,
          INSBLD_SLServiceCharge_NUM: 0,
          INSBLD_FMTax_NUM: 0,
          INSBLD_EMPA_NUM: 0,
          INSBLD_MuniFee_NUM: 0,
          INSBLD_CountyFee_NUM: 0,
          CAN_Sl_Tax_AnnualRateAmount_NUM: 0,
          CAN_Stamping_Fee_AnnualRateAmount_NUM: 0,
          CAN_SL_Service_Charge_AnnualRateAmount_NUM: 0,
          CAN_FM_Tax_AnnualRateAmount_NUM: 0,
          CAN_EMPA_AnnualRateAmount_NUM: 0,
          CAN_Municipal_Fee_AnnualRateAmount_NUM: 0,
          CAN_County_Fee_AnnualRateAmount_NUM: 0,
          CAN_TaxFeeRateAmount8_NUM: 0,
          CAN_INSBLD_SurplusLineTax_NUM: 0,
          CAN_INSBLD_StampingFee_NUM: 0,
          CAN_INSBLD_SLServiceCharge_NUM: 0,
          CAN_INSBLD_FMTax_NUM: 0,
          CAN_INSBLD_EMPA_NUM: 0,
          CAN_INSBLD_MuniFee_NUM: 0,
          CAN_INSBLD_CountyFee_NUM: 0,
        };

        Object.entries(zeroFields).forEach(([key, value]) => {
          $(`#${key}`).val(value);
        });

        resolve({
          ...zeroFields,
          FM_TAX: 0,
        });
        return;
      }

      let agencyFeeValue = 0;
      let inspectionFeeValue = 0;

      if (premiumNumeric > 0) {
        agencyFeeValue = Math.ceil(
          Number(String(brokerfee ?? 0).replace(/,/g, "")) || 0
        );
        inspectionFeeValue = Math.ceil(
          Number(String(inspectionfee ?? 0).replace(/,/g, "")) || 0
        );
      }

      // Only CA: premium sent to API includes fees; other states: base premium only
      const premiumForApi =
        (state === "CA") ?
          premiumNumeric + agencyFeeValue + inspectionFeeValue :
          premiumNumeric;

      if (admittedNonAdmitted === "Admitted" && state !== "KY") {
        const zeroFields = {
          Sl_Tax_AnnualRateAmount_NUM: 0,
          Stamping_Fee_AnnualRateAmount_NUM: 0,
          SL_Service_Charge_AnnualRateAmount_NUM: 0,
          FM_Tax_AnnualRateAmount_NUM: 0,
          EMPA_AnnualRateAmount_NUM: 0,
          Municipal_Fee_AnnualRateAmount_NUM: 0,
          County_Fee_AnnualRateAmount_NUM: 0,
          TaxFeeRateAmount8_NUM: 0,
          INSBLD_SurplusLineTax_NUM: 0,
          INSBLD_StampingFee_NUM: 0,
          INSBLD_SLServiceCharge_NUM: 0,
          INSBLD_FMTax_NUM: 0,
          INSBLD_EMPA_NUM: 0,
          INSBLD_MuniFee_NUM: 0,
          INSBLD_CountyFee_NUM: 0,
        };

        Object.entries(zeroFields).forEach(([key, value]) => {
          $(`#${key}`).val(value);
        });

        resolve({
          ...zeroFields,
          FM_TAX: 0,
        });
        return;
      }

      if (
        (admittedNonAdmitted === "Admitted" && state === "KY") ||
        (admittedNonAdmitted === "Non-Admitted" && filing === "PCS")
      ) {
        const transactionType =
          createdfrom === "NewBusiness" && convertedpolicy === "Yes" ?
            "PR" :
            createdfrom === "NewBusiness" ?
              "PN" :
              createdfrom === "MTA" && changereason === "Reissue" ?
                "APE" :
                createdfrom === "MTA" && premiumNumeric > 0 ?
                  "APE" :
                  createdfrom === "MTA" && premiumNumeric === 0 ?
                    "APE" :
                    createdfrom === "Renewal" ?
                      "PR" :
                      createdfrom === "Cancellation" &&
                        $("#CancelMethod_CHOICE").val() === "Flat" ?
                        "FC" :
                        createdfrom === "Cancellation" &&
                          $("#CancelMethod_CHOICE").val() !== "Flat" ?
                          "PC" :
                          "PN";

        let lineOfBusiness = Instanda.Variables.LOBType_Text;
        if (lineOfBusiness === "Yacht") lineOfBusiness = "GEN-1077";
        else if (lineOfBusiness === "Collections") lineOfBusiness = "GEN-1094";
        else if (lineOfBusiness === "Earthquake") lineOfBusiness = "GEN-1082";
        else if (lineOfBusiness === "Excess Flood") lineOfBusiness = "GEN-1049";
        else if (lineOfBusiness === "Home") lineOfBusiness = "GEN-1092";
        else if (lineOfBusiness === "Auto") lineOfBusiness = "GEN-1075";
        else if (lineOfBusiness === "Excess Liability") lineOfBusiness = "GEN-1095";

        const body = {
          state: state,
          address: address,
          city: city,
          zipCode: extractZipCode(zipCode),
          policyEffectiveDate: policyEffectiveDate,
          premium: Number(premiumForApi), // <-- CA only: premium uplifted for API
          transactionType: transactionType,
          lineOfBusiness: lineOfBusiness,
          agencyFee: agencyFeeValue,
          inspectionFee: inspectionFeeValue,
          commissionReceived: 0,
          rpg: 0,
          ecp: 0,
          taxExempt: 0,
          exportList: 0,
          accountWrittenAs: "B",
        };

        console.log("Request Body:", body);

        const {
          apiBaseUrl,
          subscriptionKey
        } = getApiEndpoint("gettaxdetails");
        const apiEndpoint = `${apiBaseUrl}/inscipher/v1/getTaxDetails`;

        fetch(apiEndpoint, {
          method: "POST",
          headers: generateHeaders(subscriptionKey),
          body: JSON.stringify(body),
        })
          .then((response) => {
            if (!response.ok) {
              displayApiErrorMessage("Error occurred while fetching tax details");
              throw new Error(`getTaxDetails failed: ${response.status}`);
            }
            return response.json();
          })
          .then((result) => {
            // ===== CUSTOM FM_TAX OVERRIDE START =====
            const fireTaxRate =
              Number(result.tax_rule?.fm_tax_rate) ||
              Number(result.fm_tax_rate) ||
              Number(result.fm_tax) ||
              0;

            const customFMTax = calculateCustomFMTax({
              state,
              premium: premiumNumeric, // keep FM tax logic on base premium
              fireTaxRate,
              inspectionFee: inspectionFeeValue,
              brokerFee: agencyFeeValue,
              lineOfBusiness,
            });

            if (customFMTax) {
              result.fm_tax = customFMTax;
            }
            // ===== CUSTOM FM_TAX OVERRIDE END =====

            const handleValue = (value, selector) => {
              const element = $(selector);
              if (value === null || value === "") {
                element.attr("required", false);
              } else {
                element.val(value).attr("required", true);
              }
            };

            let outputFields = {};

            // Admitted KY
            if (admittedNonAdmitted === "Admitted" && state === "KY") {
              if (lineOfBusiness === "GEN-1077" || lineOfBusiness === "GEN-1094") {
                outputFields = {
                  Sl_Tax_AnnualRateAmount_NUM: 0,
                  Stamping_Fee_AnnualRateAmount_NUM: 0,
                  SL_Service_Charge_AnnualRateAmount_NUM: 0,
                  FM_Tax_AnnualRateAmount_NUM: 0,
                  EMPA_AnnualRateAmount_NUM: 0,
                  County_Fee_AnnualRateAmount_NUM: 0,
                  Municipal_Fee_AnnualRateAmount_NUM: result.municipal_fee || 0,
                  TaxFeeRateAmount8_NUM: result.municipal_fee || 0,
                  Municipal_Fee_Description_TXT: result.tax_rule?.municipal_fee_title || "",
                  CAN_Municipal_Fee_Description_TXT: result.tax_rule?.municipal_fee_title || "",
                  CAN_Municipal_Fee_AnnualRateAmount_NUM: result.municipal_fee || 0,
                  CAN_TaxFeeRateAmount8_NUM: result.municipal_fee || 0,
                };

                if (
                  (result.municipal_fee === 0 || result.municipal_fee === "0") &&
                  result.county_fee != 0
                ) {
                  outputFields.TaxFeeRateAmount8_NUM = result.county_fee || 0;
                  outputFields.Municipal_Fee_AnnualRateAmount_NUM = result.county_fee || 0;
                  outputFields.CAN_Municipal_Fee_AnnualRateAmount_NUM = result.county_fee || 0;
                }

                handleValue(result.tax_rule?.municipal_fee_title, "#Municipal_Fee_Description_TXT");
                handleValue(result.tax_rule?.municipal_fee_title, "#CAN_Municipal_Fee_Description_TXT");
                handleValue(outputFields.TaxFeeRateAmount8_NUM, "#TaxFeeRateAmount8_NUM");
                handleValue(outputFields.CAN_TaxFeeRateAmount8_NUM, "#CAN_TaxFeeRateAmount8_NUM");
                handleValue(outputFields.Municipal_Fee_AnnualRateAmount_NUM, "#Municipal_Fee_AnnualRateAmount_NUM");
                handleValue(outputFields.CAN_Municipal_Fee_AnnualRateAmount_NUM, "#CAN_Municipal_Fee_AnnualRateAmount_NUM");
              } else {
                outputFields = {
                  INSBLD_SurplusLineTax_NUM: 0,
                  INSBLD_StampingFee_NUM: 0,
                  INSBLD_SLServiceCharge_NUM: 0,
                  INSBLD_FMTax_NUM: 0,
                  INSBLD_EMPA_NUM: 0,
                  INSBLD_MuniFee_NUM: result.municipal_fee || 0,
                  INSBLD_CountyFee_NUM: 0,
                  CAN_INSBLD_MuniFee_NUM: result.municipal_fee || 0,
                };

                if (
                  (result.municipal_fee === 0 || result.municipal_fee === "0") &&
                  result.county_fee != 0
                ) {
                  outputFields.INSBLD_MuniFee_NUM = result.county_fee || 0;
                  outputFields.CAN_INSBLD_MuniFee_NUM = result.county_fee || 0;
                }

                handleValue(outputFields.INSBLD_MuniFee_NUM, "#INSBLD_MuniFee_NUM");
                handleValue(outputFields.CAN_INSBLD_MuniFee_NUM, "#CAN_INSBLD_MuniFee_NUM");
              }
            }
            // Non-Admitted PCS
            else if (admittedNonAdmitted === "Non-Admitted" && filing === "PCS") {
              if (lineOfBusiness === "GEN-1077" || lineOfBusiness === "GEN-1094") {
                outputFields = {
                  Sl_Tax_AnnualRateAmount_NUM: result.sl_tax || 0,
                  CAN_Sl_Tax_AnnualRateAmount_NUM: result.sl_tax || 0,
                  Stamping_Fee_AnnualRateAmount_NUM: result.stamping_fee || 0,
                  CAN_Stamping_Fee_AnnualRateAmount_NUM: result.stamping_fee || 0,
                  SL_Service_Charge_AnnualRateAmount_NUM: result.sl_service_charge || 0,
                  CAN_SL_Service_Charge_AnnualRateAmount_NUM: result.sl_service_charge || 0,
                  FM_Tax_AnnualRateAmount_NUM: result.fm_tax || 0,
                  CAN_FM_Tax_AnnualRateAmount_NUM: result.fm_tax || 0,
                  EMPA_AnnualRateAmount_NUM: result.empa_tax || 0,
                  CAN_EMPA_AnnualRateAmount_NUM: result.empa_tax || 0,
                  County_Fee_AnnualRateAmount_NUM: result.county_fee || 0,
                  CAN_County_Fee_AnnualRateAmount_NUM: result.county_fee || 0,
                  Municipal_Fee_AnnualRateAmount_NUM: result.municipal_fee || 0,
                  CAN_Municipal_Fee_AnnualRateAmount_NUM: result.municipal_fee || 0,
                  TaxFeeRateAmount8_NUM: result.municipal_fee || 0,
                  SL_Tax_Description_TXT: result.tax_rule?.sl_tax_title || "",
                  CAN_SL_Tax_Description_TXT: result.tax_rule?.sl_tax_title || "",
                  Stamping_Fee_Description_TXT: result.tax_rule?.stamping_fee_title || "",
                  CAN_Stamping_Fee_Description_TXT: result.tax_rule?.stamping_fee_title || "",
                  SL_Service_Charge_Description_TXT: result.tax_rule?.sl_service_charge_title || "",
                  CAN_SL_Service_Charge_Description_TXT: result.tax_rule?.sl_service_charge_title || "",
                  FM_Tax_Description_TXT: result.tax_rule?.fm_tax_title || "",
                  CAN_FM_Tax_Description_TXT: result.tax_rule?.fm_tax_title || "",
                  EMPA_Description_TXT: result.tax_rule?.empa_tax_title || "",
                  CAN_EMPA_Description_TXT: result.tax_rule?.empa_tax_title || "",
                };

                handleValue(result.tax_rule?.sl_tax_title, "#SL_Tax_Description_TXT");
                handleValue(result.tax_rule?.sl_tax_title, "#CAN_SL_Tax_Description_TXT");
                handleValue(result.tax_rule?.stamping_fee_title, "#Stamping_Fee_Description_TXT");
                handleValue(result.tax_rule?.stamping_fee_title, "#CAN_Stamping_Fee_Description_TXT");
                handleValue(result.tax_rule?.sl_service_charge_title, "#SL_Service_Charge_Description_TXT");
                handleValue(result.tax_rule?.sl_service_charge_title, "#CAN_SL_Service_Charge_Description_TXT");
                handleValue(result.tax_rule?.fm_tax_title, "#FM_Tax_Description_TXT");
                handleValue(result.tax_rule?.fm_tax_title, "#CAN_FM_Tax_Description_TXT");
                handleValue(result.tax_rule?.empa_tax_title, "#EMPA_Description_TXT");
                handleValue(result.tax_rule?.empa_tax_title, "#CAN_EMPA_Description_TXT");

                handleValue(result.municipal_fee, "#Municipal_Fee_AnnualRateAmount_NUM");
                handleValue(result.municipal_fee, "#CAN_Municipal_Fee_AnnualRateAmount_NUM");
                handleValue(result.sl_tax, "#Sl_Tax_AnnualRateAmount_NUM");
                handleValue(result.sl_tax, "#CAN_Sl_Tax_AnnualRateAmount_NUM");
                handleValue(result.stamping_fee, "#Stamping_Fee_AnnualRateAmount_NUM");
                handleValue(result.stamping_fee, "#CAN_Stamping_Fee_AnnualRateAmount_NUM");
                handleValue(result.sl_service_charge, "#SL_Service_Charge_AnnualRateAmount_NUM");
                handleValue(result.sl_service_charge, "#CAN_SL_Service_Charge_AnnualRateAmount_NUM");
                handleValue(result.fm_tax, "#FM_Tax_AnnualRateAmount_NUM");
                handleValue(result.fm_tax, "#CAN_FM_Tax_AnnualRateAmount_NUM");
                handleValue(result.empa_tax, "#EMPA_AnnualRateAmount_NUM");
                handleValue(result.empa_tax, "#CAN_EMPA_AnnualRateAmount_NUM");
                handleValue(result.county_fee, "#County_Fee_AnnualRateAmount_NUM");
                handleValue(result.county_fee, "#CAN_County_Fee_AnnualRateAmount_NUM");
              } else {
                outputFields = {
                  INSBLD_SurplusLineTax_NUM: result.sl_tax || 0,
                  CAN_INSBLD_SurplusLineTax_NUM: result.sl_tax || 0,
                  INSBLD_StampingFee_NUM: result.stamping_fee || 0,
                  CAN_INSBLD_StampingFee_NUM: result.stamping_fee || 0,
                  INSBLD_SLServiceCharge_NUM: result.sl_service_charge || 0,
                  CAN_INSBLD_SLServiceCharge_NUM: result.sl_service_charge || 0,
                  INSBLD_FMTax_NUM: result.fm_tax || 0,
                  CAN_INSBLD_FMTax_NUM: result.fm_tax || 0,
                  INSBLD_EMPA_NUM: result.empa_tax || 0,
                  CAN_INSBLD_EMPA_NUM: result.empa_tax || 0,
                  INSBLD_MuniFee_NUM: result.municipal_fee || 0,
                  CAN_INSBLD_MuniFee_NUM: result.municipal_fee || 0,
                  INSBLD_CountyFee_NUM: result.county_fee || 0,
                  CAN_INSBLD_CountyFee_NUM: result.county_fee || 0,
                };

                handleValue(result.sl_tax, "#INSBLD_SurplusLineTax_NUM");
                handleValue(result.sl_tax, "#CAN_INSBLD_SurplusLineTax_NUM");
                handleValue(result.stamping_fee, "#INSBLD_StampingFee_NUM");
                handleValue(result.stamping_fee, "#CAN_INSBLD_StampingFee_NUM");
                handleValue(result.sl_service_charge, "#INSBLD_SLServiceCharge_NUM");
                handleValue(result.sl_service_charge, "#CAN_INSBLD_SLServiceCharge_NUM");
                handleValue(result.fm_tax, "#INSBLD_FMTax_NUM");
                handleValue(result.fm_tax, "#CAN_INSBLD_FMTax_NUM");
                handleValue(result.empa_tax, "#INSBLD_EMPA_NUM");
                handleValue(result.empa_tax, "#CAN_INSBLD_EMPA_NUM");
                handleValue(result.municipal_fee, "#INSBLD_MuniFee_NUM");
                handleValue(result.municipal_fee, "#CAN_INSBLD_MuniFee_NUM");
                handleValue(result.county_fee, "#INSBLD_CountyFee_NUM");
                handleValue(result.county_fee, "#CAN_INSBLD_CountyFee_NUM");
              }
            }

            resolve({
              ...outputFields,
              FM_TAX: result.fm_tax,
            });
          })
          .catch((error) => {
            console.error("Error:", error);
            displayApiErrorMessage(`API error ` + error);
            reject(error);
          });
      } else {
        console.log("Condition not met for making the API call.");
        resolve({
          status: "success",
        });
      }
    });
  }

