  function safeMerge(obj1, obj2, obj3) {
    const result = {
      ...obj1,
      ...obj3,
    };

    Object.keys(obj2).forEach((key) => {
      const isArr1 = Array.isArray(result[key]);
      const isArr2 = Array.isArray(obj2[key]);
      if (isArr1 && isArr2) {
        result[key] = [...result[key], ...obj2[key]];
      } else if (isArr1 !== isArr2 && result[key] !== undefined) {
        // Type mismatch: log a warning and overwrite
        console.warn(
          `Type mismatch for key "${key}": ${isArr1 ? "array" : typeof result[key]
          } vs ${isArr2 ? "array" : typeof obj2[key]}. Overwriting.`
        );
        result[key] = obj2[key];
      } else {
        result[key] = obj2[key];
      }
    });

    return result;
  }

  ////////////////////////////////////////////////////////////////////////////////// API - Location Details - Collections ////////////////////////////////////////////////////////////////////////////////////////////////////

  function getlocationDetails() {
    if (isReadOnlyView()) {
      console.log("Read-only view in getlocationDetails");
      resolve("Read-only view");
      return;
    }
    const customerId1 = formatToTenDigits(
      String(Instanda.Variables.CustomerID_TXT)
    );
    const agentRefID1 = Instanda.Variables.SelectedBrokerCode_TXT;
    const custPolId1 = Instanda.Variables.OriginalQuoteRef;
    const custQuoteRef1 = String(Instanda.Variables.QuoteRef);

    const body = {
      customerId: formatToTenDigits(String(customerId1)),
      brokerCode: formatToSevenDigits(agentRefID1),
      quoteId: custQuoteRef1,
      policyId: custPolId1,
    };

    console.log("Request Body:", body);

    const {
      apiBaseUrl,
      subscriptionKey
    } = getApiEndpoint("locationdetails");
    const siteCssLink = document.querySelector('link[href*="SiteCustomCss"]');
    let siteId = null;
    if (siteCssLink) {
      // Extract siteId from the href using a regular expression
      const match = siteCssLink.href.match(/siteId=(\d+)/);
      if (match) {
        siteId = match[1];
      }
    }
    let apiEndpoint;
    if (siteId === "2913") {
      apiEndpoint = `${apiBaseUrl}/dcbilling/v1.2/getLocationDetails`;
    } else {
      apiEndpoint = `${apiBaseUrl}/dcbilling/v1/getLocationDetails`;
    }

    fetch(apiEndpoint, {
      method: "POST",
      headers: generateHeaders(subscriptionKey),
      body: JSON.stringify(body),
    })
      .then((response) => response.json())
      .then((data) => {
        if (data.status === "Error") {
          console.error("Error fetching location details:", data.message);
          console.error("Error details:", data.details);
          data.error.forEach((err) => {
            console.error(`Error Code: ${err.code}, Message: ${err.message}`);
          });
          return;
        }

        if (data.primaryAddress.addressLine) {
          $("#CO_primary_AddressLine1_TXT").val(
            data.primaryAddress.addressLine
          );
          $("#CO_primary_AddressLine2_TXT").val(data.primaryAddress.unitNumber);
          $("#CO_primary_AddressCity_TXT").val(data.primaryAddress.city);
          $("#CO_primary_Country_CHOICE").val(data.primaryAddress.country);
          $("#CO_primary_State_CHOICE").val(data.primaryAddress.state);
          $("#CO_primary_Zip_NUM427353").val(
            extractZipCode(data.primaryAddress.zipCode)
          );
          $("#CO_inhomesafe_YNP").val(data.isThereAnInHomeSafe);
          $("#CO_safepermanently_YN").val(data.isSafePermanentlyAffixed);
          $("#CO_safehomealarm_YN").val(data.isSafeConnectedToHomeAlarmSystem);
          $("#CO_RoofTypeMaterial_CHOICE").val(data.roofTypeMaterial);
          $("#CO_Primary_ConstructionType_CHOICE").val(data.constructionType);
          $("#CO_PrimarySecondaryLocation_YN").val(
            data.primaryOrSecondaryResidence
          );
          $("#CO_Primary_YearBuilt_NUM").val(data.yearBuilt);
          $("#CO_Homebeenrenovated_YNP").val(data.hasHomeBeenRenovated);
          $("#CO_Primary_YearofElectricRenovation_NUM").val(
            data.yearElectricRenovation
          );
          $("#CO_Primary_YearofPlumbingRenovation_NUM").val(
            data.yearPlumbingRenovation
          );
          $("#CO_Primary_YearofHeatingRenovation_NUM").val(
            data.yearHeatingRenovation
          );
          $("#CO_Primary_YearofRoofReplacement_NUM").val(
            data.yearRoofReplacement
          );
          $("#CO_Primary_DistanceFromShore_CHOICE").val(data.distanceFromShore);
          $("#CO_AggregatedSquareFootage_NUM").val(
            data.aggregatedSquareFootage
          );
          $("#CO_NumberofFamiliesinHome_CHOICE").val(
            data.numberOfFamiliesInHome
          );
          $("#CO_Primary_ProtectionClass_CHOICE").val(data.protectionClass);
          $("#CO_NumberofStories_CHOICE").val(data.numberOfStories);
          $("#CO_PrimDet_AttachGaragDoorProt_CHOICE").val(
            data.attachedGarageDoorProtection
          );
          $("#CO_PrimDet_TerrExp_CHOICE").val(data.terrainExposure);
          $("#CO_PrimDet_WindBorDebReg_YN").val(data.windBorneDebrisRegion);
        }
      })
      .catch((error) =>
        console.error("Error fetching location details:", error)
      );
  }

  if (
    $(".page-prequotequestions.page-number-3").length > 0 &&
    Instanda.Variables["PackageId"] === 23424
  ) {
    const createdfrom = Instanda.Variables.CreatedFrom;
    if (createdfrom !== "MTA") {
      if (
        $("#CO_primary_AddressLine1_TXT").val() === null ||
        $("#CO_primary_AddressLine1_TXT").val() === ""
      ) {
        getlocationDetails();
      }
    }
  }

