  function mandatoryfieldcheck(event) {
    let errorMessages = [];

    $('.questionItem[data-is-optional="False"]:visible').each(function () {
      let $input = $(this)
        .find("input:visible, select:visible, textarea:visible")
        .first();
      let label = $(this)
        .find("label.control-label")
        .text()
        .replace("*", "")
        .trim();

      if ($input.is(":radio") || $input.is(":checkbox")) {
        if ($(this).find("input:checked").length === 0) {
          errorMessages.push(label + " is a required field");
          $input.addClass("missing-required");
        } else {
          $input.removeClass("missing-required");
        }
      } else {
        if (!$input.val() || $input.val().trim() === "") {
          errorMessages.push(label + " is a required field");
          $input.addClass("missing-required");
        } else {
          $input.removeClass("missing-required");
        }
      }
    });

    if (errorMessages.length > 0) {
      displayApiErrorMessage(errorMessages.join("<br>"));
      if (event) event.preventDefault();
      return false;
    }
    return true;
  }

  async function createCustomer(event, retryCount = 0) {
    event.preventDefault();

    const customerIDField = $("#CustomerID_TXT");
    const accountIDField = $("#AccountID_TXT");
    const sourcesys = "Instanda";
    const sfdccustid = $("#sfdccustomerId_TXT");
    const sfdcaccid = $("#sfdcAccountId_TXT");

    if (isReadOnlyView()) {
      console.log("Read-only view");
      return true;
    }
    showSpinner();

    // Only proceed if both CustomerID and AccountID are blank
    if (customerIDField.val() || accountIDField.val()) {
      hideSpinner();
      console.log("Customer ID or Account ID exists. Aborting function.");
      return true;
    }

    // Get high profile value from checked radio button
    const highProfile =
      $("input[name='HighProfileCustomer_YN']:checked").val() ||
      $(".highprofile .instanda-selected input").val();

    const nameType1 = $("#Name_Type_CHOICEP").val();
    const todaysDate = formatDate(new Date());
    const userid = Instanda.Variables.SalespersonEmail;

    const spchandling = highProfile === "Yes" ? "High Priority" : " ";
    const confindcat = highProfile === "Yes" ? "Yes" : "No";
    const occupation1 = $("#Occupation_CHOICEP").val();
    const occupation =
      occupation1 === "Other-High Profile" ?
        $("#OccupationOtherHigh_TXT").val() :
        occupation1 === "Other-Low Profile" ?
          $("#OccupationOtherLow_TXT").val() :
          occupation1;
    const occupationOther =
      occupation1 === "Other-High Profile" ?
        $("#OccupationOtherHigh_TXT").val() :
        occupation1 === "Other-Low Profile" ?
          $("#OccupationOtherLow_TXT").val() :
          "";
    const insadd1 =
      $("#CO_RiskAddressLine1RO_TXT").val() ||
      $("#RiskAddressLine1RO_TXT").val() ||
      $("#MA_AddressLine1_TXT").val();
    const inscity =
      $("#CO_RiskCityRO_TXT").val() ||
      $("#RiskCityRO_TXT").val() ||
      $("#MA_City_TXT").val();
    const insstate =
      $("#CO_RiskStateRO_TXT").val() ||
      $("#RiskStateRO_TXT").val() ||
      $("#MA_State_CHOICE").val();
    const inszip =
      $("input[name='CO_RiskPostCodeRO_TXT']").val() ||
      $("input[name='RiskPostCodeRO_TXT']").val() ||
      $("input[name='MA_Zip_NUM']").val();
    const inscountry =
      $("select[name='CO_RiskCountryRO_TXT']").val() ||
      $("select[name='RiskCountryRO_TXT']").val() ||
      $("select[name='MA_Country_CHOICE']").val();
    const insCounty =
      $("#CO_RiskAddress_County_TXT").val() ||
      $("#County1_TXT").val() ||
      $("#MA_County1_TXT").val();
    const dobInput = $("#DOB_DATE").val();
    const dobdate = dobInput ? formatDate(dobInput) : formatDate(new Date());
    const nonIndividualType = nameType1 === "Individual" ? "No" : "Yes";
    const indnametxt = $("#NamedInsured_TXT").val();

    const firstName = $("#FirstName_TXT").val() || indnametxt;
    const lastName = $("#LastName_TXT").val() || indnametxt;

    const body = {
      account: {
        specialHandling: spchandling,
        accountSinceDate: todaysDate,
        confidentialIndicator: confindcat,
        platinumAccountIn: confindcat,
        platinumAccountDirectorName: indnametxt,
        RecordTypeId: "012DT000003zilsYAA",
        accountName: indnametxt,
      },
      contact: {
        cityName: inscity,
        addressLine1: insadd1,
        clientAssistInIndicator: "Yes",
        effectiveDate: todaysDate,
        countryName: inscountry,
        zipCode: inszip,
        firstName: firstName,
        stateCode: insstate,
        updateTs: todaysDate,
        birthDate: dobdate,
        occupation: occupation1,
        occupationOther: occupationOther,
        sourceSystemName: sourcesys,
        accountType: nameType1,
        businessEmailId: $("#Email_TXT").val(),
        businessPhoneExtNo: "",
        customerSinceDate: todaysDate,
        gender: "",
        homePhoneNo: $("#Phone_PHONE").val(),
        mobilePhoneNo: $("#Phone_PHONE").val(),
        maritalStatus: "",
        middleName: $("#MiddleName_TXT").val(),
        personalEmailId: $("#Email_TXT").val(),
        lastName: lastName,
        nonIndividualType: nonIndividualType,
        employerName: indnametxt,
        title: $("#Prefix_TXT").val(),
        suffix: $("#Suffix_CHOICE").val(),
        highProfileIndicator: highProfile,
        preferredName: indnametxt,
        accountHolderName: indnametxt,
        insuredName: indnametxt,
        insuredAddress1: insadd1,
        insuredCity: inscity,
        insuredState: insstate,
        insuredZip: inszip,
        insuredCountry: inscountry,
        insuredCounty: insCounty,
        userId: userid,
      },
    };

    if (customerIDField.val() || accountIDField.val()) {
      body.customerDetails = {
        customerId: customerIDField.val(),
        accountId: accountIDField.val(),
      };
    }

    console.log("Request Body:", body);

    const {
      apiBaseUrl,
      subscriptionKey
    } = getApiEndpoint("createcustomer");
    const siteCssLink = document.querySelector('link[href*="SiteCustomCss"]');
    let siteId = null;
    if (siteCssLink) {
      const match = siteCssLink.href.match(/siteId=(\d+)/);
      if (match) {
        siteId = match[1];
      }
    }

    let apiEndpoint;
    if (siteId === "2913") {
      apiEndpoint = `${apiBaseUrl}/salesforce/v1.2/createCustomer`;
    } else {
      apiEndpoint = `${apiBaseUrl}/salesforce/v1/createCustomer`;
    }

    try {
      const response = await fetch(apiEndpoint, {
        method: "POST",
        headers: generateHeaders(subscriptionKey),
        body: JSON.stringify(body),
      });

      hideSpinner();

      if (!response.ok) {
        await response.json(); // Optionally log error details
        throw new Error(
          `Customer information could not be created, please contact Customer Care Center 866-856-6858.`
        );
      }

      const data = await response.json();
      console.log("Response Data:", data);

      customerIDField.val(data.customerId);
      accountIDField.val(data.accountId);
      sfdccustid.val(data.sfdcCustomerId);
      sfdcaccid.val(data.sfdcAccountId);

      // Retry logic if needed
      if ((!data.customerId || !data.accountId) && retryCount < 1) {
        console.log("Customer ID or Account ID is blank, retrying...");
        return await createCustomer(event, retryCount + 1);
      }

      return true;
    } catch (error) {
      hideSpinner();
      console.error("Error:", error);
      displayApiErrorMessage(error.message);
      return false;
    }
  }

  // Initiate Create Customer api call on click of continue button
  if (
    $(".page-prequotequestions.page-number-1.package-23423").length > 0 ||
    $(".page-prequotequestions.page-number-1.package-23424").length > 0
  ) {
    loadingBtnClick(); // No event parameter needed
  }

