  // Address Validation Precisely and Geo Code Function handling
  function handleValidation(event, type) {
    event.preventDefault();

    if (isReadOnlyView()) {
      console.log("Read-only view in handleValidation");
      return;
    }
    // Overlay animation starts
    showSpinner();

    const button = $(event.target);
    const uniqueClass = button.data("unique-class");
    const container = $(`.${uniqueClass}`);

    const addressDetails = getAddressDetails(container);
    if (!validateMandatoryFields(addressDetails)) {
      alert("One or more mandatory fields are missing.");
      // Overlay animation stops
      hideSpinner();
      return;
    }

    const requestBody = constructRequestBody(addressDetails);
    const {
      apiBaseUrl,
      subscriptionKey
    } = getApiEndpoint(type);
    const apiEndpoint = `${apiBaseUrl}/${type === "coreLogic"
      ? "corelogic/v1/getGeoCoding"
      : "precisely/v1/validateAddress"
      }`;

    sendApiRequest(apiEndpoint, requestBody, subscriptionKey, type, container);
  }

  function getAddressDetails(container) {
    return {
      addressLine1: container.find(".instanda-address-line-1 input").val(),
      addressLine2: container.find(".instanda-address-line-2 input").val(),
      city: container.find(".instanda-address-city input").val(),
      state: container.find(".instanda-address-state select").val(),
      zip: container.find(".instanda-address-postcode input").val(),
      county: container.find(".county input").val(),
      country: getCountry(container),
    };
  }

  function validateMandatoryFields({
    addressLine1,
    zip,
    city,
    country
  }) {
    if ($(".page-prequotequestions.page-number-4.package-23423").length > 0) {
      // For package-23423 on page 4 of prequote questions, addressLine1 is not mandatory
      return zip && city && country;
    } else {
      return addressLine1 && zip && city && country;
    }
  }

  function constructRequestBody({
    addressLine1,
    addressLine2,
    city,
    state,
    zip,
    country,
  }) {
    return {
      addressLine1,
      addressLine2,
      postalCode: zip,
      city,
      country,
      stateProvince: state,
    };
  }

  function getCountry(container) {
    // Check for the fixed US country element
    if (
      $(".page-prequotequestions.page-number-1 .add-fixed-country-us").length >
      0
    ) {
      return "US";
    }

    // Get the selected value from the dropdown
    var country = container.find(".instanda-address-country select").val();

    // If country is undefined, null, or empty, default to 'US'
    return country == undefined ||
      country == null ||
      country == "" ||
      country == "USA" ?
      "US" :
      country;
  }

  function sendApiRequest(
    apiEndpoint,
    requestBody,
    subscriptionKey,
    type,
    container
  ) {
    console.log(`Sending ${type} request to ${apiEndpoint}`);
    console.log("Request body:", requestBody);

    fetch(apiEndpoint, {
      method: "POST",
      headers: generateHeaders(subscriptionKey),
      body: JSON.stringify(requestBody),
    })
      .then((response) => {
        if (!response.ok) {
          return response.json().then((err) => {
            throw new Error(err.message);
          });
        }
        return response.json();
      })
      .then((data) => {
        console.log(`${type} response data:`, data);
        processApiResponse(data, type, container);
        // Overlay animation stops
        hideSpinner();
      })
      .catch((error) => {
        console.error(`Error fetching data for ${type}:`, error);
        // Overlay animation stops
        hideSpinner();
        if (type === "coreLogic") {
          alert(
            "Latitude and longitude could not be found. Please verify address information has been entered correctly and try again later or manually override."
          );
        } else if (type === "precisely") {
          alert(
            "Address could not be validated, please ensure correct address has been entered or manually enter the zip code."
          );
        }
      });
  }

  function processApiResponse(data, type, container) {
    switch (type) {
      case "coreLogic":
        processCoreLogicResponse(data, container);
        break;
      case "precisely":
        processPreciselyResponse(data, container);
        break;
      default:
        console.error("Unknown type:", type);
    }
  }

  function processCoreLogicResponse(data, container) {
    const goodCandidate = data.output[0].goodCandidate;

    if (goodCandidate) {
      container.find(".latitude input").val(data.output[0].latitude);
      container.find(".longitude input").val(data.output[0].longitude);
      container.find(".geoResult input").val(data.output[0].geoResult);

      setTimeout(() => {
        if (
          !container.find(".latitude input").val() ||
          !container.find(".longitude input").val()
        ) {
          alert(
            "Latitude and longitude could not be found. Please verify address information has been entered correctly and try again later or manually override."
          );
        } else {
          // Append the custom success message
          $(".parent-section").append(`
                    <div class="warningMessage alert container" id="custom-success-response">
                        <img src="/ImageUpload/DownloadImageVersion?uploadedImageVersionId=YWtWd04zSkVRM05OYVhsb2IyaFVOM29zZVRKd1VWOWYsQUVTMjU2X0NCQ19TVEFOREFSRCxKYlJjUW1lQWVEa2lqUHdyLDEwMDAsQTczaGxudnh0YUU4OU9LOSxENWErYmpqSjh4V2tXaHBYNFMzTVUxOFFRS3FkU0s2QzArdTd3eEx1MG9mQjdWTm4zOGxrNkRzRkdVNzdRUENVOHkzeitUd1NVNXZaSjZBRWNYdFhlUT09" />
                        <span>Latitude and Longitudes have been successfully retrieved. Proceed with further details!.</span>
                        <button type="button" class="close" data-dismiss="alert" aria-label="Close">
                            <span aria-hidden="true">×</span>
                        </button>
                    </div>
                `);

          // Remove the custom success message after 1 seconds
          setTimeout(function () {
            $("#custom-success-response").remove();
          }, 1000);
        }
      }, 500);
    }
  }

  function processPreciselyResponse(data, container) {
    const confidence = parseInt(data.output[0].confidence, 10);

    if (confidence >= 50) {
      $(".parent-section").append(
        '<div class="warningMessage alert container" id="custom-success-response"><img src="/ImageUpload/DownloadImageVersion?uploadedImageVersionId=YWtWd04zSkVRM05OYVhsb2IyaFVOM29zZVRKd1VWOWYsQUVTMjU2X0NCQ19TVEFOREFSRCxKYlJjUW1lQWVEa2lqUHdyLDEwMDAsQTczaGxudnh0YUU4OU9LOSxENWErYmpqSjh4V2tXaHBYNFMzTVUxOFFRS3FkU0s2QzArdTd3eEx1MG9mQjdWTm4zOGxrNkRzRkdVNzdRUENVOHkzeitUd1NVNXZaSjZBRWNYdFhlUT09" /><span>Address has been successfully verified and validated. Proceed with further details!.</span><button type="button" class="close" data-dismiss="alert" aria-label="Close"><span aria-hidden="true">×</span></button></div>'
      );
      setTimeout(function () {
        $("#custom-success-response").remove();
      }, 1000);
    } else if (Instanda.Variables.PackageId === 23423) {
      // Do nothing for package ID 23423
    } else {
      $(".parent-section").append(
        '<div class="warningMessage alert container" id="custom-failure-response"><img src="/ImageUpload/DownloadImageVersion?uploadedImageVersionId=YkRKeFNsUlZSbko1WTJOVVlXbzVPR2NzYkRJeFVWOWYsQUVTMjU2X0NCQ19TVEFOREFSRCxjdXJ4N0kxbzJFeWdpeEhNLDEwMDAseHVqVTRXVk1GQ3Uhak1XMyxJa3Y3Nlk5WVhhWHpJREt5eTJaMmRxOHphUlRkWEdWM2dDQ3VVdDQ3QXZyTEZEbTNzVmNUVTY2NmI3c3JZdHhIL2tlZncvYktrcHZFTGNrSmhleEVLdz09" /><span>Address could not be validated, please ensure correct address has been entered or manually enter the zip code.</span><button type="button" class="close" data-dismiss="alert" aria-label="Close"><span aria-hidden="true">×</span></button></div>'
      );
    }

    if (confidence >= 50 || Instanda.Variables.PackageId === 23423) {
      container
        .find(".instanda-address-line-1 input")
        .val(data.output[0].addressLine1);
      container
        .find(".instanda-address-line-2 input")
        .val(data.output[0].addressLine2);
      container.find(".instanda-address-city input").val(data.output[0].city);
      container
        .find(".instanda-address-state select")
        .val(data.output[0].stateProvince);
      container
        .find(".instanda-address-postcode input")
        .val(data.output[0].postalCode);
      container.find(".county input").val(data.output[0].county);
    }
  }

