  // Toggle Ban Latest code BH-15491 - Rehan
  // BH-23143 start: show buttons by overriding CSS
  function showActionBtns() {
    document.querySelectorAll(".BancreateBtn, .UpdateBanBtn").forEach((btn) => {
      btn.style.setProperty("display", "inline-block", "important");
      btn.style.setProperty("visibility", "visible", "important");
      btn.style.setProperty("opacity", "1", "important");
    });
  }

  // setting enabled/disabled states after ensuring visibility
  function setBanButtonsState({
    createEnabled,
    updateEnabled
  }) {
    showActionBtns();
    if (typeof createEnabled === "boolean") {
      $(".BancreateBtn").prop("disabled", !createEnabled);
    }
    if (typeof updateEnabled === "boolean") {
      $(".UpdateBanBtn").prop("disabled", !updateEnabled);
    }
  }

  function toggleBanBtn() {
    setTimeout(function () {
      //as part of BH-26953
      // Exception IDs for radio buttons, names for other fields
      const banExceptionIds = ["BillingAccount_YNYes", "BillingAccount_YNNo"];
      const banExceptionNames = ["ExistingBillingAcc_CHOICE"];

      console.log("toggleBanbtn banExceptionIds initialize no change");
      console.log("BAN toggled");

      const hasBAN = !!$("#BillingAccountNumber_NUM").val();

      // BH-23143: MTA + Reissue + PackageId 23423/23424 + BAN present
      if (
        (Instanda.Variables.PackageId === 23423 ||
          Instanda.Variables.PackageId === 23424) &&
        Instanda.Variables.ChangeReason_Choice === "Reissue" &&
        Instanda.Variables.CreatedFrom === "MTA" &&
        hasBAN
      ) {
        // Lock all billing inputs/selects except explicit exceptions
        document
          .querySelectorAll(
            ".instanda-question-input input, .instanda-question-input select"
          )
          .forEach(function (element) {
            if (
              element.type === "radio" &&
              banExceptionIds.includes(element.id)
            ) {
              return;
            }
            if (element.type === "radio") {
              const closestLabel = element.closest("label");
              if (closestLabel) closestLabel.style.pointerEvents = "none";
              element.style.pointerEvents = "none";
              element.style.opacity = 0.4;
            } else {
              element.readOnly = true;
            }
            if (element.tagName.toLowerCase() === "select") {
              element.style.pointerEvents = "none";
              element.style.backgroundColor = "#eee";
            }
          });
        // Create visible but disabled; Update visible and enabled
        setBanButtonsState({
          createEnabled: false,
          updateEnabled: true,
        });
        $(".address-valid-text").hide();
        return;
      }

      // Always unlock if ChangeReason_Choice is 'Reissue'
      if (Instanda.Variables.ChangeReason_Choice === "Reissue") {
        document
          .querySelectorAll(
            ".instanda-question-input input, .instanda-question-input select"
          )
          .forEach(function (element) {
            if (
              element.type === "radio" &&
              banExceptionIds.includes(element.id)
            ) {
              return;
            }
            // Unlock radios
            if (element.type === "radio") {
              const closestLabel = element.closest("label");
              if (closestLabel) {
                closestLabel.style.pointerEvents = "";
              }
              element.style.pointerEvents = "";
              element.style.opacity = 1;
            } else {
              element.readOnly = false;
            }
            if (element.tagName.toLowerCase() === "select") {
              element.style.pointerEvents = "";
              element.style.backgroundColor = "";
            }
          });
        $(".address-valid-text").show();
        $(".BancreateBtn").removeAttr("disabled");
        $(".UpdateBanBtn").removeAttr("disabled");
        return;
      }

      // Retain old logic for other change reasons
      if (
        $("#BillingAccountNumber_NUM").val() &&
        Instanda.Variables.ChangeReason_Choice !== "Reissue"
      ) {
        $("#BillingAccount_YNNo").click();
        console.log("toggleBanbtn clicking BANAcc to NO");
        $("#ExistingBillingAcc_CHOICE").val("No");
        $(".BancreateBtn").attr("disabled", true);

        document
          .querySelectorAll(
            ".instanda-question-input input, .instanda-question-input select"
          )
          .forEach(function (element) {
            if (
              (element.type === "radio" &&
                banExceptionIds.includes(element.id)) ||
              banExceptionNames.includes(element.name)
            ) {
              return;
            }
            if (
              element.classList.contains("alwayseditable") ||
              element.closest(".alwayseditable")
            ) {
              return; // Do not touch this element
            }
            //BH-27592 - Mortgagee Details editable for UW and Ops
            if (
              (element.classList.contains("mortgageedetails") ||
                element.closest(".mortgageedetails")) &&
              Instanda.Variables.SalespersonReferralLevel > 3
            ) {
              return; // Do not touch this element
            }
            if (element.type === "radio") {
              const closestLabel = element.closest("label");
              if (closestLabel) {
                closestLabel.style.pointerEvents = "none";
              }
              element.style.pointerEvents = "none";
              element.style.opacity = 0.4;
            } else {
              element.readOnly = true;
            }
            if (element.tagName.toLowerCase() === "select") {
              element.style.pointerEvents = "none";
              element.style.backgroundColor = "#eee";
            }
          });

        $(".address-valid-text").hide();
        $(".UpdateBanBtn").removeAttr("disabled");
      } else {
        $(".BancreateBtn").removeAttr("disabled");
        $(".UpdateBanBtn").attr("disabled", true);
      }
    }, 500);
  }

  function toggleUpdateBanBtn() {
    const disableExceptions = [
      "RecurringPayments_YNYes",
      "RecurringPayments_YNNo",
      "SupressPrint_YNNo",
      "SupressPrint_YNYes",
      "BillingAccount_YNNo",
      "BillingAccount_YNYes",
      // "ExistingBillingAcc_CHOICE" // BH-23143 - Uncommented for Prod deployement
    ];

    const allowedClear = [
      "BillingContactName_TXT",
      "BillingContactFirstName_TXT",
      "BillingContactMiddleName_TXT",
      "BillingContactLastName_TXT",
      "BillingAccPrefix_TXT",
      "BillingPhoneNumber_PHONE",
      "BillingEmail_EMAIL",
      "BillingConfirmEmail_EMAIL",
      "BillingAddressUnit_NUM",
      "BillingAddressLine1_TXT",
      "BillingAddressLine2_TXT",
      "BillingAddressCity_TXT",
      "BillingAddressState_CHOICE",
      "BillingAddressStateNonUS_TXT",
      "BillingAddressZip_NUM",
      "BillingAccountNumber_NUM",
      "BillingAddressCountry_CHOICE",
    ];

    console.log("update ban toggled");

    // Modified toggleUpdateBanBtn to implement "click Update => unlock all, clear BAN, enable/disable buttons" as part of BH-23143
    const hasBAN = !!$("#BillingAccountNumber_NUM").val();
    const isSpecialMtaReissue =
      Instanda.Variables.CreatedFrom === "MTA" &&
      Instanda.Variables.ChangeReason_Choice === "Reissue" &&
      (Instanda.Variables.PackageId === 23423 ||
        Instanda.Variables.PackageId === 23424);

    if (hasBAN && isSpecialMtaReissue) {
      document
        .querySelectorAll(
          ".instanda-question-input input, .instanda-question-input select"
        )
        .forEach(function (element) {
          if (
            disableExceptions.includes(element.id) ||
            disableExceptions.includes(element.name)
          )
            return;
          if (element.type === "radio") {
            const closestLabel = element.closest("label");
            if (closestLabel) closestLabel.style.pointerEvents = "";
            element.style.pointerEvents = "";
            element.style.opacity = 1;
          } else {
            element.readOnly = false;
          }
          if (element.tagName.toLowerCase() === "select") {
            element.style.pointerEvents = "";
            element.style.backgroundColor = "";
          }
        });
      // Clear BAN and make fields editable
      $("#BillingAccountNumber_NUM").val("").prop("readonly", false);
      // Reflect editing state
      $("#ExistingBillingAcc_CHOICE").val("No").trigger("change");
      $(".address-valid-text").show();
      // Buttons flip: Create enabled, Update disabled
      setBanButtonsState({
        createEnabled: true,
        updateEnabled: false,
      });
      return;
    }
    // BH-23143 ends here
    if (Instanda.Variables.ChangeReason_Choice === "Reissue") {
      // Edit all fields regardless of BAN, skip exceptions
      document.querySelectorAll("input, select").forEach(function (element) {
        if (
          disableExceptions.includes(element.id) ||
          disableExceptions.includes(element.name)
        )
          return;

        // Unlock radios specially
        if (element.type === "radio") {
          const closestDiv = element.closest("div");
          if (closestDiv) {
            closestDiv.querySelectorAll("*").forEach(function (a) {
              a.style.pointerEvents = "";
            });
          }
          element.style.opacity = 1;
        } else {
          element.readOnly = false;
        }

        // Selects
        if (element.tagName.toLowerCase() === "select") {
          element.style.pointerEvents = "";
          element.style.backgroundColor = "";
        }
      });
      // If special package, re-toggle BAN
      if (
        Instanda.Variables.PackageId == 23424 ||
        Instanda.Variables.PackageId == 23423
      ) {
        toggleBanBtn();
      }
      return;
    }

    // Original logic applies for non-Reissue
    if (
      $("#BillingAccountNumber_NUM").val() &&
      Instanda.Variables.ChangeReason_Choice !== "Reissue"
    ) {
      console.log("I have a BAN NUMBER so dont do anything");
      document.querySelectorAll("input, select").forEach(function (element) {
        if (
          disableExceptions.includes(element.id) ||
          disableExceptions.includes(element.name)
        )
          return;

        //BH-27592 - Mortgagee Details editable for UW and Ops
        if (
          (element.classList.contains("mortgageedetails") ||
            element.closest(".mortgageedetails")) &&
          Instanda.Variables.SalespersonReferralLevel >= 3
        ) {
          return; // Do not touch this element
        }

        let isAllowed =
          allowedClear.includes(element.name) ||
          allowedClear.some((al) => element.id && element.id.startsWith(al)); // handles dynamic IDs

        // Unlock radios
        if (element.type === "radio") {
          const closestDiv = element.closest("div");
          if (closestDiv) {
            closestDiv.querySelectorAll("*").forEach(function (a) {
              a.style.pointerEvents = "";
            });
          }
          element.style.opacity = 1;
        } else {
          element.readOnly = false;
        }

        if (isAllowed) {
          if (element.tagName.toLowerCase() === "select") {
            element.selectedIndex = 0;
          } else {
            element.value = "";
            element.readOnly = false; // Ensure it's editable
          }
        }

        if (element.tagName.toLowerCase() === "select") {
          element.style.pointerEvents = "";
          element.style.backgroundColor = "";
        }
      });

      if (
        Instanda.Variables.PackageId == 23424 ||
        Instanda.Variables.PackageId == 23423
      ) {
        toggleBanBtn();
      }
    }
  }

