  //////////////////////////////////////////////////////////////////// Bancreate Functionality /////////////////////////////////////////////////////////////

  function handleBancreate(event) {
    return new Promise((resolve, reject) => {
      event.preventDefault();

      if (isReadOnlyView()) {
        console.log("Read-only view");
        resolve("Read-only view");
        return;
      }

      showSpinner();

      // Gather required data
      const custid = Instanda.Variables.CustomerID_TXT;
      const billaccname =
        $("#BillingAccName_TXT").val() || Instanda.Variables.BillingAccName_TXT;
      const billType =
        $('input[name="BillingType_CHOICE"]:checked').val() ||
        $("#BillingType_CHOICE").val() ||
        Instanda.Variables.BillingType_CHOICE;
      const nameType =
        $(".ban-create-name .instanda-selected input").val() ||
        $("#BillingAccNameType_CHOICE").val() ||
        Instanda.Variables.BillingAccNameType_CHOICE;
      const billingAddressLine1 = $("#BillingAddressLine1_TXT").val();
      const billingCity = $("#BillingAddressCity_TXT").val();
      const billingPostalCode = $('input[name="BillingAddressZip_NUM"]').val();
      const billingCountry =
        $("select[name='BillingAddressCountry_CHOICE']").val() ||
        Instanda.Variables.BillingAddressCountry_CHOICE;
      const isUS = String(billingCountry || "").toUpperCase() === "US";
      const billingState = isUS ?
        $("#BillingAddressState_CHOICE").val() ||
        Instanda.Variables.BillingAddressState_CHOICE :
        $("#BillingAddressStateNonUS_TXT").val() ||
        Instanda.Variables.BillingAddressStateNonUS_TXT;
      const paymentPlan = $("#PaymentPlan_CHOICE").val();
      // Add the rest of the required variables
      const OgQuoteref = Instanda.Variables.OriginalQuoteRef;
      const quoterefid = String(Instanda.Variables.QuoteRef);
      const countyBilling = $("#BillingAddressCounty_TXT").val() || "County";
      const brokercodech = Instanda.Variables.SelectedBrokerCode_TXT;
      const contactPrefix = $("#BillingAccPrefix_TXT").val() || "";
      const expdate = formatDate(Instanda.Variables.ExpirationDate_DATE);
      const prdcdchoice = Instanda.Variables.ProductCode_CHOICE;
      const enrollRecurring =
        $('input[name="EnrollRecurring_YN"]:checked').val() ||
        $('input[name="RecurringPayments_YN"]:checked').val() ||
        Instanda.Variables.EnrollRecurring_YN ||
        Instanda.Variables.RecurringPayments_YN;
      const lob = Instanda.Variables.LOBType_Text;

      // Collect fields and labels for validation
      const requiredFields = [{
        value: custid,
        fieldId: "#BillingContactFirstName_TXT",
        displayName: "Customer ID",
      },
      {
        value: billaccname,
        fieldId: "#BillingAccName_TXT",
        displayName: "Billing Account Name",
      },
      {
        value: billType,
        fieldId: "#BillingType_CHOICE",
        displayName: "Billing Type",
      },
      {
        value: nameType,
        fieldId: "#BillingAccNameType_CHOICE",
        displayName: "Account Name Type",
      },
      {
        value: billingAddressLine1,
        fieldId: "#BillingAddressLine1_TXT",
        displayName: "Address Line 1",
      },
      {
        value: billingCity,
        fieldId: "#BillingAddressCity_TXT",
        displayName: "City",
      },
      {
        value: billingPostalCode,
        fieldId: 'input[name="BillingAddressZip_NUM"]',
        displayName: "Postal Code",
      },
      {
        value: billingCountry,
        fieldId: "select[name='BillingAddressCountry_CHOICE']",
        displayName: "Country",
      },

      ...(String(billingCountry).toUpperCase() === "US" ? [{
        value: billingState,
        fieldId: "#BillingAddressState_CHOICE",
        displayName: "State",
      },] : []),

      {
        value: paymentPlan,
        fieldId: "#PaymentPlan_CHOICE",
        displayName: "Payment Plan",
      },
      ];

      let missingFields = [];
      requiredFields.forEach((field) => {
        if (
          field.value == null ||
          field.value === "" ||
          field.value === "Please select"
        ) {
          $(field.fieldId)
            .addClass("input-error")
            .after(
              `<span class='label label-danger' >${field.displayName} is required.</span>`
            );
          missingFields.push(field.displayName);
        } else {
          $(field.fieldId).removeClass("input-error");
          $(field.fieldId).next(".label label-danger").remove();
        }
      });

      if (missingFields.length > 0) {
        hideSpinner();
        displayApiErrorMessage(
          "Please fill all required fields: " + missingFields.join(", ")
        );
        reject("Missing required fields: " + missingFields.join(", "));
        return;
      }

      // Build request body
      const body = {
        policyId: OgQuoteref,
        historyId: quoterefid,
        customerNumber: formatToTenDigits(String(custid)),
        billingAddressLine1: billingAddressLine1,
        billingAddressLine2: $("#BillingAddressLine2_TXT").val(),
        billingCity: billingCity,
        billingPostalCode: billingPostalCode,
        billingState: billingState,
        county: countyBilling,
        billingCountry: billingCountry,
        billingName: billaccname,
        billType: billType,
        brokerCode: formatToSevenDigits(brokercodech),
        contactPrefix: String(contactPrefix),
        email: $("#BillingEmail_EMAIL").val(),
        nameType: nameType,
        firstName: $("#BillingContactFirstName_TXT").val() || billaccname,
        middleName: $("#BillingContactMiddleName_TXT").val(),
        lastName: $("#BillingContactLastName_TXT").val() || billaccname,
        originExpirationDate: expdate,
        originProductCd: String(prdcdchoice),
        otherName: billaccname,
        paymentPlan: paymentPlan,
        phoneNumber: $("#BillingPhoneNumber_PHONE").val(),
        quoteId: quoterefid,
        recurringPayment: enrollRecurring,
        totalPremium: String(Instanda.Variables.TotalTxnBldPremTaxFee_NUM) ||
          String($("#TotalPremium_NUM").val()),
        unitNumber: "Y",
        createBillingAccount: "Yes",
        lob: lob,
      };

      // Determine API endpoint
      const {
        apiBaseUrl,
        subscriptionKey
      } = getApiEndpoint("bancreate");
      const siteCssLink = document.querySelector('link[href*="SiteCustomCss"]');
      let siteId = null;
      if (siteCssLink) {
        const match = siteCssLink.href.match(/siteId=(\d+)/);
        if (match) siteId = match[1];
      }
      let apiEndpoint;
      if (siteId === "2913") {
        apiEndpoint = `${apiBaseUrl}/cgsbilling/v1.2/createBAN`;
      } else {
        apiEndpoint = `${apiBaseUrl}/cgsbilling/v1/createBAN`;
      }

      // Make API call
      fetch(apiEndpoint, {
        method: "POST",
        headers: generateHeaders(subscriptionKey),
        body: JSON.stringify(body),
      })
        .then((response) => {
          if (!response.ok) {
            return response.json().then((err) => {
              hideSpinner();
              if (Instanda.Variables.PCSReferralLevel <= 3) {
                displayApiErrorMessage(
                  "Please contact Customer Care Center 866-856-6858 or reach out to the underwriter."
                );
              } else {
                displayApiErrorMessage(
                  "We were unable to create your billing account at this time. Please try again later. If the issue persists, contact support for further assistance."
                );
              }
              throw new Error(
                "We were unable to create your billing account at this time. Please try again later. If the issue persists, contact support for further assistance."
              );
            });
          }
          return response.json();
        })
        .then((data) => {
          console.log("bancreate response data:", data);
          if (data.status === "Success") {
            $("#BillingAccountNumber_NUM").val(data.billingAccountNumber);
            $("#BillingAccount_YNNo").prop("checked", true).trigger("click");

            // Optionally clear bcaccountid and bctermid
            $("#bcaccountid").val("");
            $("#bctermid").val("");
            $("#PartyRecordIdGeneralBillingInfo_NUM").val("");
            $("#MortgageeRecordID_TXT").val("");

            // Update quote/policy data if function exists
            if (typeof updateQuoteorPolicydata === "function") {
              updateQuoteorPolicydata(null, {
                bcaccountid: "",
                bctermid: "",
                PartyRecordIdGeneralBillingInfo_NUM: "",
              })
                .then(() => {
                  $("#BillingAccNameType_CHOICE")
                    .css({
                      "pointer-events": "none",
                      "background-color": "#eee",
                    })
                    .attr("tabindex", "-1");
                  document.getElementsByName("saveButton")[0].click();
                  if (typeof SaveButtonClickforBilling === "function") {
                    SaveButtonClickforBilling();
                  }
                  hideSpinner();
                  if (
                    Instanda.Variables.PackageId == 23424 ||
                    Instanda.Variables.PackageId == 23423
                  ) {
                    toggleBanBtn();
                  }
                  resolve(data);
                })
                .catch((err) => {
                  hideSpinner();
                  if (Instanda.Variables.PCSReferralLevel <= 3) {
                    displayApiErrorMessage(
                      "Please contact Customer Care Center 866-856-6858 or reach out to the underwriter."
                    );
                  } else {
                    displayApiErrorMessage(
                      "BAN created, but failed to update quote/policy data."
                    );
                  }
                  reject(err);
                });
            } else {
              $("#BillingAccNameType_CHOICE")
                .css({
                  "pointer-events": "none",
                  "background-color": "#eee",
                })
                .attr("tabindex", "-1");
              document.getElementsByName("saveButton")[0].click();
              if (typeof SaveButtonClickforBilling === "function") {
                SaveButtonClickforBilling();
              }
              hideSpinner();
              if (
                Instanda.Variables.PackageId == 23424 ||
                Instanda.Variables.PackageId == 23423
              ) {
                toggleBanBtn();
              }
              resolve(data);
            }
          } else {
            hideSpinner();
            if (Instanda.Variables.PCSReferralLevel <= 3) {
              displayApiErrorMessage(
                "Please contact Customer Care Center 866-856-6858 or reach out to the underwriter."
              );
            } else {
              displayApiErrorMessage(
                "We were unable to create your billing account at this time. Please try again later. If the issue persists, contact support for further assistance."
              );
            }
            reject(
              "We were unable to create your billing account at this time. Please try again later. If the issue persists, contact support for further assistance."
            );
          }
        })
        .catch((error) => {
          hideSpinner();
          console.error(
            "We were unable to create your billing account at this time. Please try again later. If the issue persists, contact support for further assistance.",
            error
          );
          if (Instanda.Variables.PCSReferralLevel <= 3) {
            displayApiErrorMessage(
              "Please contact Customer Care Center 866-856-6858 or reach out to the underwriter."
            );
          } else {
            displayApiErrorMessage(
              "We were unable to create your billing account at this time. Please try again later. If the issue persists, contact support for further assistance."
            );
          }
          reject(error);
        });
    });
  }

