  //////////////////////////////////////////////// Button Validations//////////////////////

  function initializeButtons() {
    $(".geocode-address").each(function (index) {
      const mindex = $(this).data("mindex") || index;
      const uniqueClass = `geocode${mindex}`;
      const container = $(this).addClass(uniqueClass);
      const country = getCountry(container);
      container.append(
        $("<div>", {
          class: "geocode-valid-text",
        }).append(
          $("<label>", {
            text: "Please retrieve geocode before moving forward",
          }),
          $("<br>"),
          $("<button>", {
            text: "Retrieve Geocode",
            class: "GeocodeBtn",
            "data-unique-class": uniqueClass,
          }).on("click", function (event) {
            handleValidation(event, "coreLogic");
          })
        )
      );
      monitorCountryChanges(container);
      const showElements = country === "US";
      container
        .find(".GeocodeBtn, .geocode-valid-text label")
        .toggle(showElements);
    });
    $(".address-question").each(function (index) {
      const mindex = $(this).data("mindex") || index;
      const uniqueClass = `address-question-${mindex}`;
      const container = $(this).addClass(uniqueClass);
      const country = getCountry(container);
      container.append(
        $("<div>", {
          class: "address-valid-text",
        }).append(
          $("<label>", {
            text: "Please validate the address before moving forward",
          }),
          $("<br>"),
          $("<button>", {
            text: "Validate Address",
            class: "AddressValidBtn",
            "data-unique-class": uniqueClass,
          }).on("click", function (event) {
            handleValidation(event, "precisely");
          })
        )
      );

      if ($(this).hasClass("instanda-question-multi-item-question-text")) {
        const multiItemClass = $(this)
          .attr("class")
          .split(" ")
          .find((cls) => cls.startsWith("instanda-multi-item-"));
        if (multiItemClass) {
          const matches = multiItemClass.match(
            /instanda-multi-item-(\w+)(\d+)/
          );
          if (matches) {
            const variable = matches[1];
            const count = matches[2];
            const miUniqueClass = `address-question-mi-${mindex}-${variable}-${count}`;
            $(this).addClass(miUniqueClass);
          }
        }
      }

      monitorCountryChanges(container);
      const showElements = (function () {
        if (country === "US") {
          return true;
        } else {
          return false;
        }
      })();
      container
        .find(".AddressValidBtn, .address-valid-text")
        .toggle(showElements);
    });

    if (
      Instanda.Variables.PackageId == 23424 ||
      Instanda.Variables.PackageId == 23423
    ) {
      $(".ban-create").each(function (index) {
        const uniqueClass = `ban-create-${index}`;
        $(this).addClass(uniqueClass);
        $(this).append(
          $("<button>", {
            text: "Create Billing Account",
            class: "BancreateBtn",
            "data-unique-class": uniqueClass,
            type: "button",
          }).on("click", function (event) {
            handleBancreate(event);
          })
        );

        $(this).append(
          $("<button>", {
            text: "Update Billing Account",
            class: "UpdateBanBtn",
            type: "button",
          }).on("click", function (event) {
            toggleUpdateBanBtn();
          })
        );
      });
    }
  }

  // Monitor Country Changes
  function monitorCountryChanges(container) {
    container
      .find(".instanda-address-country select")
      .on("change", function () {
        const country = $(this).val();
        const showElements = country === "US";
        container
          .find(
            ".GeocodeBtn, .AddressValidBtn, .geocode-valid-text label, .address-valid-text label"
          )
          .toggle(showElements);
      });
  }

  ////////////////////////////////////////////////// Monitor Ban Account Changes//////////////////////////
  function BanAccountChanges() {
    const rewritetype = Instanda.Variables.ChangeReason_Choice;
    const CreatedFrom = Instanda.Variables.CreatedFrom;

    // Check if CreatedFrom is "MTA"
    if (CreatedFrom === "MTA") {
      if (rewritetype === "Reissue") {
        if (Instanda.Variables.SalespersonReferralLevel > 3) {
          $(".BancreateBtn").show();
          $(".UpdateBanBtn").show();
        } else {
          $(".BancreateBtn").hide();
          $(".UpdateBanBtn").hide();
        }
      } else {
        $(".BancreateBtn").hide();
        $(".UpdateBanBtn").hide();
      }
    } else {
      // Attach event listener for input change
      $('input[name="ExistingBillingAcc_CHOICE"]').on("change", function () {
        const existingBillingAcc = $(
          'input[name="ExistingBillingAcc_CHOICE"]:checked'
        ).val();
        let showButtons = false;

        if (existingBillingAcc === "New") {
          showButtons = true;
        } else if (existingBillingAcc === "Old") {
          showButtons = false;
        }

        $(".BancreateBtn").toggle(showButtons);
      });
    }
  }

  // API/modal/BAN/async logic ONLY -- NO event handlers!
  function setupBanCreateConditions(event) {
    return new Promise((resolve) => {
      const v = Instanda.Variables;
      let userBanChoice = null;
      let shouldRunBanCreate = false;
      const pkgId = v.PackageId;
      const Packages =
        ($(".page-postquotequestions.page-number-1").length > 0 &&
          pkgId == 23423) ||
        ($(".page-postquotequestions.page-number-2").length > 0 &&
          pkgId == 23424) ||
        ($(".page-postquotequestions.page-number-1").length > 0 &&
          pkgId == 24338) ||
        ($(".page-postquotequestions.page-number-4").length > 0 &&
          pkgId == 24337) ||
        ($(".page-postquotequestions.page-number-2").length > 0 &&
          pkgId == 24588) ||
        ($(".page-postquotequestions.page-number-2").length > 0 &&
          pkgId == 24518) ||
        ($(".page-postquotequestions.page-number-1").length > 0 &&
          pkgId == 24428);

      function showBanChoiceModal(callback) {
        if ($("#banChoiceModal").length === 0) {
          $("body").append(`
                    <div id="banChoiceModal" style="display:none; position:fixed; top:0; left:0; width:100vw; height:100vh; background:rgba(0,0,0,0.5); z-index:11000;">
                        <div style="background:#fff; padding:24px; max-width:350px; margin:100px auto; border-radius:8px; text-align:center;">
                            <p>Do you want to create a new BAN?</p>
                            <button id="banChoiceYes" style="margin:8px;">Yes, new BAN</button>
                            <button id="banChoiceNo" style="margin:8px;">No, same BAN</button>
                        </div>
                    </div>
                `);
        }
        $("#banChoiceModal").show();
        $("#banChoiceYes")
          .off("click")
          .on("click", function () {
            $("#banChoiceModal").hide();
            callback("newban");
          });
        $("#banChoiceNo")
          .off("click")
          .on("click", function () {
            $("#banChoiceModal").hide();
            callback("sameban");
          });
      }

      // Business logic only
      if (
        v.CreatedFrom === "MTA" &&
        v.ChangeReason_Choice === "Reissue" &&
        v.SalespersonReferralLevel > 3
      ) {
        showBanChoiceModal(function (choice) {
          userBanChoice = choice;
          shouldRunBanCreate = choice === "newban";
          if (shouldRunBanCreate) {
            showSpinner();
            handleBancreate(event)
              .then((data) => {
                hideSpinner();
                resolve(data.status === "Success");
              })
              .catch(() => {
                hideSpinner();
                resolve(false);
              });
          } else {
            resolve(true);
          }
        });
        return;
      }
      if (v.CreatedFrom !== "MTA" && Packages) {
        const $banChoice = $('select[name="ExistingBillingAcc_CHOICE"]');
        const createbillacc = $(
          ".newBillingAccount .instanda-selected input"
        ).val();
        const bannumber = $("#BillingAccountNumber_NUM").val();
        const banChoiceVal = $banChoice.val();
        shouldRunBanCreate =
          (banChoiceVal === "No" && createbillacc === "Yes") ||
          (banChoiceVal === "No" &&
            createbillacc === "No" &&
            bannumber === "") ||
          banChoiceVal === "New";

        if (v.CreatedFrom === "Renewal" && shouldRunBanCreate) {
          showBanChoiceModal(function (choice) {
            userBanChoice = choice;
            shouldRunBanCreate = choice === "newban";
            if (shouldRunBanCreate) {
              showSpinner();
              handleBancreate(event)
                .then((data) => {
                  hideSpinner();
                  resolve(data.status === "Success");
                })
                .catch(() => {
                  hideSpinner();
                  resolve(false);
                });
            } else {
              resolve(true);
            }
          });
          return;
        }
        if (shouldRunBanCreate) {
          showSpinner();
          handleBancreate(event)
            .then((data) => {
              hideSpinner();
              resolve(data.status === "Success");
            })
            .catch(() => {
              hideSpinner();
              resolve(false);
            });
          return;
        }
        resolve(true);
        return;
      }
      resolve(true);
    });
  }

  // Validation function: can be reused anywhere
  function validateFormExcludingBillingAccountNumber($form) {
    // Skip validation if quote is read-only
    if (typeof quoteIsReadOnly !== "undefined" && quoteIsReadOnly === true) {
      return true;
    }
    let isValid = true;
    // Validate BillingAddressZip_NUM specifically
    var $zip = $form.find('input[name="BillingAddressZip_NUM"]');
    var zipValue = $zip.val() ? $zip.val().trim() : "";
    var $zipMsg = $form.find('span[data-valmsg-for="BillingAddressZip_NUM"]');
    $zipMsg
      .text("")
      .removeClass("label-danger")
      .addClass("field-validation-valid");
    if (!zipValue) {
      isValid = false;
      $zipMsg
        .text("Zip/Postal Code is required.")
        .addClass("label-danger")
        .removeClass("field-validation-valid");
      $zip.focus();
    }
    $form.find("input, select, textarea").each(function () {
      const $field = $(this);
      const fieldName = $field.attr("name");
      const $valMsg = $form.find(`span[data-valmsg-for="${fieldName}"]`);
      if (
        fieldName === "BillingAccountNumber_NUM" ||
        $field.closest(".radio-inline").length > 0
      ) {
        $valMsg
          .text("")
          .removeClass("label-danger")
          .addClass("field-validation-valid");
        return;
      }
      if (
        $field.data("val-required") &&
        $field.is(":visible") &&
        !$field.prop("readonly")
      ) {
        if (!$field.val()) {
          isValid = false;
          $valMsg
            .text($field.data("val-required"))
            .addClass("label-danger")
            .removeClass("field-validation-valid");
        } else {
          $valMsg
            .text("")
            .removeClass("label-danger")
            .addClass("field-validation-valid");
        }
      }
    });
    return isValid;
  }

  // Main handler for "Continue" button
  function bancreateloadingBtnClick() {
    if (isReadOnlyView()) {
      return;
    }
    const continueButtons = document.querySelectorAll(
      'button[name="continueButton"]'
    );
    const $form = $('button[name="continueButton"]').closest("form");

    async function handleContinue(event) {
      event.preventDefault();

      continueButtons.forEach((btn) => {
        btn.innerHTML =
          '<span class="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span><span class="visually-hidden">Loading</span>';
        btn.disabled = true;
      });

      // Always validate, and abort logic if invalid!
      if (!validateFormExcludingBillingAccountNumber($form)) {
        continueButtons.forEach((btn) => {
          btn.innerHTML = "Continue";
          btn.disabled = false;
        });
        hideSpinner();
        return false; // Absolutely nothing else runs!
      }

      try {
        let result = await setupBanCreateConditions(event);

        // If result is NOT successful, show error and DO NOT submit form.
        if (!result) {
          displayApiErrorMessage(
            "Billing account could not be created, please contact Customer Care Center 866-856-6858."
          );
          continueButtons.forEach((btn) => {
            btn.innerHTML = "Continue";
            btn.disabled = false;
          });
          hideSpinner();
          return false; // Explicitly exit to prevent submission!
        }

        // Only submit if BAN creation was successful!
        continueButtons.forEach((btn) => {
          if (btn.form) {
            btn.form.action = "PostQuoteQuestionsContinue";
            btn.form.submit();
          }
        });
      } catch (error) {
        continueButtons.forEach((btn) => {
          btn.innerHTML = "Continue";
          btn.disabled = false;
        });
        hideSpinner();
        displayApiErrorMessage(
          "Billing account could not be created, please contact Customer Care Center 866-856-6858."
        );
        // No submission!
      }
    }

    continueButtons.forEach((btn) => {
      btn.removeEventListener("click", handleContinue);
      btn.addEventListener("click", handleContinue);
    });
  }

