  ///////////////////////// Hide/Unhide Fields based on BillingAccNameType_CHOICE (BH-24646)
  $(document).ready(function () {
    let storedBillingInputs = null;

    function hideQuestionByInputId(inputId) {
      const target = document.getElementById(inputId);
      if (target) {
        const parentDiv = target.closest("div.questionItem");
        if (parentDiv) {
          parentDiv.classList.add("hidden");
        }
      }
    }

    function unhideQuestionByInputId(inputId) {
      const target = document.getElementById(inputId);
      if (target) {
        const parentDiv = target.closest("div.questionItem");
        if (parentDiv) {
          parentDiv.classList.remove("hidden");
        }
      }
    }

    function storeBillingInfo() {
      storedBillingInputs = {
        firstName: $("#BillingContactFirstName_TXT").val(),
        middleName: $("#BillingContactMiddleName_TXT").val(),
        lastName: $("#BillingContactLastName_TXT").val(),
        prefix: $("#BillingAccPrefix_TXT").prop("selectedIndex"),
        suffix: $("#BillingAccSuffix_CHOICE").prop("selectedIndex"),
      };
    }

    function restoreBillingInfo() {
      if (storedBillingInputs) {
        $("#BillingContactFirstName_TXT").val(
          storedBillingInputs.firstName || ""
        );
        $("#BillingContactMiddleName_TXT").val(
          storedBillingInputs.middleName || ""
        );
        $("#BillingContactLastName_TXT").val(
          storedBillingInputs.lastName || ""
        );
        $("#BillingAccPrefix_TXT").prop(
          "selectedIndex",
          storedBillingInputs.prefix || 0
        );
        $("#BillingAccSuffix_CHOICE").prop(
          "selectedIndex",
          storedBillingInputs.suffix || 0
        );
      }
    }

    function clearinfo() {
      $("#BillingContactFirstName_TXT").val("");
      $("#BillingContactMiddleName_TXT").val("");
      $("#BillingContactLastName_TXT").val("");
      $("#BillingAccPrefix_TXT").prop("selectedIndex", 0);
      $("#BillingAccSuffix_CHOICE").prop("selectedIndex", 0);
    }

    if (
      $(".page-postquotequestions.page-number-1.package-23423").length > 0 ||
      $(".page-postquotequestions.page-number-2.package-23424").length > 0 ||
      $(".page-postquotequestions.page-number-4.package-24337").length > 0 ||
      $(".page-postquotequestions.page-number-1.package-24428").length > 0 ||
      $(".page-postquotequestions.page-number-2.package-24588").length > 0 ||
      $(".page-postquotequestions.page-number-2.package-24518").length > 0 ||
      $(".page-postquotequestions.page-number-1.package-24338").length > 0
    ) {
      function setNameChoiceOnChange() {
        var billType = $(
          'input[name="BillingAccNameType_CHOICE"]:checked'
        ).val();

        if (billType === "Other") {
          storeBillingInfo();

          $("#BillingAccPrefix_TXT").attr("required", false);
          $("#BillingContactFirstName_TXT").attr("required", false);
          $("#BillingContactMiddleName_TXT").attr("required", false);
          $("#BillingContactLastName_TXT").attr("required", false);
          $("#BillingAccSuffix_CHOICE").attr("required", false);

          clearinfo();

          hideQuestionByInputId("BillingAccPrefix_TXT");
          hideQuestionByInputId("BillingContactFirstName_TXT");
          hideQuestionByInputId("BillingContactMiddleName_TXT");
          hideQuestionByInputId("BillingContactLastName_TXT");
          hideQuestionByInputId("BillingAccSuffix_CHOICE");
        } else if (billType === "Individual") {
          unhideQuestionByInputId("BillingAccPrefix_TXT");
          unhideQuestionByInputId("BillingContactFirstName_TXT");
          unhideQuestionByInputId("BillingContactMiddleName_TXT");
          unhideQuestionByInputId("BillingContactLastName_TXT");
          unhideQuestionByInputId("BillingAccSuffix_CHOICE");

          $("#BillingContactFirstName_TXT").attr("required", true);
          $("#BillingContactLastName_TXT").attr("required", true);

          // Restore only after a store, so prefilled fields remain on page load
          if (storedBillingInputs) restoreBillingInfo();
        }
      }

      setNameChoiceOnChange(); // Run on page load
      $('input[name="BillingAccNameType_CHOICE"]').on(
        "change",
        setNameChoiceOnChange
      );
    }
  });

