  // Function to add red asterisk (*) on all mandatory questions
  function addRedAsteriskToMandatoryQuestions() {
    var elements = document.querySelectorAll(".control-label");
    elements.forEach(function (element) {
      var text = element.innerHTML.trim();
      if (text.endsWith("*")) {
        // Wrap the asterisk in a span tag and apply the style directly
        var newText = text.slice(0, -1).trim();
        newText += ' <span style="color: red; font-size: 16px;">*</span>';
        element.innerHTML = newText;
      }
    });
  }

  // Function to add red asterisk (*) to all address question labels
  function addRedAsteriskToAddressLabels() {
    var addressLabels = document.querySelectorAll(
      ".address-question .instanda-question-inner-label"
    );
    addressLabels.forEach(function (label) {
      if (!label.textContent.trim().endsWith("*")) {
        label.innerHTML +=
          ' <span style="color: red; font-size: 16px;">*</span>';
      }
    });
  }

