  // Spinner animation
  // Inject unified spinner CSS dynamically if not already present
  (function () {
    const css = `
    #unified-spinner-overlay {
      position: fixed;
      top: 0; left: 0; right: 0; bottom: 0;
      background: rgba(255,255,255,0.7);
      z-index: 9999;
      display: flex; align-items: center; justify-content: center;
    }
    .unified-spinner {
      border: 8px solid #f3f3f3;
      border-top: 8px solid #041e42;
      border-radius: 50%;
      width: 60px; height: 60px;
      animation: spin 1s linear infinite;
    }
    @keyframes spin {
      0% { transform: rotate(0deg);}
      100% { transform: rotate(360deg);}
    }
  `;
    if (!document.getElementById("unified-spinner-style")) {
      const style = document.createElement("style");
      style.id = "unified-spinner-style";
      style.type = "text/css";
      style.appendChild(document.createTextNode(css));
      document.head.appendChild(style);
    }
  })();

  // Show the spinner overlay
  function showSpinner() {
    if (!document.getElementById("unified-spinner-overlay")) {
      const overlay = document.createElement("div");
      overlay.id = "unified-spinner-overlay";
      overlay.innerHTML = '<div class="unified-spinner"></div>';
      document.body.appendChild(overlay);
    }
  }

  // Hide the spinner overlay
  function hideSpinner() {
    const overlay = document.getElementById("unified-spinner-overlay");
    if (overlay) overlay.remove();
  }

