  function daysBetween(date1, date2) {
    const oneDay = 24 * 60 * 60 * 1000; // hours * minutes * seconds * milliseconds
    const firstDate = new Date(date1);
    const secondDate = new Date(date2);
    const diffDays = Math.abs((firstDate - secondDate) / oneDay);
    return Math.round(diffDays);
  }

  $(document).ready(function () {
    if ($(".page-prequotequestions.page-number-3.package-23423").length > 0) {
      // Function to update the vessel length based on the selected unit
      function updateVesselLength() {
        // Function to convert inches to feet
        function convertInchesToFeet(inches) {
          return inches / 12;
        }

        // Function to convert inches to meters
        function convertInchesToMeters(inches) {
          return inches * 0.0254;
        }

        var inches = parseFloat($("#YT_LengthofVessel").val());

        if (!isNaN(inches) && inches > 0) {
          var selectedUnit = $(
            'input[name="YT_Vessel_LengthofVesselUnits_CHOICE"]:checked'
          ).val();
          var convertedValue;

          if (selectedUnit === "Feet") {
            convertedValue = convertInchesToFeet(inches);
          } else if (selectedUnit === "Meters") {
            convertedValue = convertInchesToMeters(inches);
          }

          $("#YT_Vessel_LengthofVessel_NUM").val(convertedValue);
        }
      }

      // Update the vessel length when the unit choice changes
      $(
        '#question426584 input[name="YT_Vessel_LengthofVesselUnits_CHOICE"]'
      ).on("change", function () {
        console.log("function called on unit change");
        updateVesselLength();
      });

      // Update the vessel length when the input value changes (change event)
      $("#YT_LengthofVessel").on("change", "input", function () {
        console.log("function called on change");
        updateVesselLength();
      });
    }
  });

  //////////////////////////////////////////////////////////////////////////////making the billing screen read only if its mta and change reason isnt reissue/////////////////////////////
  // hidden the ban create button too see logic for BanAccountChanges and address validation using initializebuttons function's logic

  function billingScreenMTAReadOnly() {
    if (
      Instanda.Variables.PageName === "postquotequestions" &&
      Instanda.Variables.CreatedFrom === "MTA"
    ) {
      if (
        Instanda.Variables.ChangeReason_Choice !== "Reissue" ||
        Instanda.Variables.SalespersonReferralLevel < 3
      ) {
        $("#ExistingBillingAcc_CHOICE_Old").prop("checked", true);

        document
          .querySelectorAll(
            ".instanda-question-input input, .instanda-question-input select"
          )
          .forEach(function (element) {
            // Skip ALL logic if the element or its parent has the class 'alwayseditable'
            if (
              element.classList.contains("alwayseditable") ||
              element.closest(".alwayseditable")
            ) {
              return; // Do not touch this element
            }

            if (element.type === "radio") {
              const closestDiv = element.closest("div");
              if (closestDiv) {
                closestDiv.querySelectorAll("*").forEach(function (a) {
                  a.style.pointerEvents = "none";
                });
                element.style.opacity = 0.4;
              } else {
                element.readOnly = true;
              }
              if (element.tagName.toLowerCase() === "select") {
                element.style.pointerEvents = "none";
                element.style.backgroundColor = "#eee";
              }
            }
          });
      }
    }
  }

