  $(document).ready(function () {
    if (
      $(".page-prequotequestions.page-number-2").length > 0 &&
      Instanda.Variables["PackageId"] === 23424
    ) {
      function handleCheckboxLogic(triggerInput) {
        // Determine the base name (strip _cnf or Blanket_CNF)
        let baseName = triggerInput.name
          .replace("_CNF", "")
          .replace("Blanket", "");

        // Build the full names for both checkboxes
        let cnfName = baseName + "_CNF";
        let blanketName = baseName + "Blanket_CNF";

        // Find both checkboxes
        let cnfInput = document.querySelector(`input[name="${cnfName}"]`);
        let blanketInput = document.querySelector(
          `input[name="${blanketName}"]`
        );

        // Check if both checkboxes exist and are checked
        if (cnfInput && blanketInput) {
          if (cnfInput.checked && blanketInput.checked) {
            // Find the related select
            let selectName = baseName + "BlanketItemLimit_CHOICE";
            let select = document.querySelector(`select[name="${selectName}"]`);

            if (select) {
              if (!select.value) {
                if (Instanda.Variables.CO_RiskRatingState_CHOICE === "NY") {
                  select.value = "$50,000";
                } else {
                  select.value = "$10,000";
                }
                select.dispatchEvent(new Event("change"));
              }
            }
          }
        }
      }

      // Attach event listeners to all _cnf checkboxes
      document
        .querySelectorAll('input[name*="_CNF"]')
        .forEach(function (input) {
          input.addEventListener("click", function () {
            handleCheckboxLogic(input);
          });
        });

      // Attach event listeners to all Blanket_CNF checkboxes
      document
        .querySelectorAll('input[name*="Blanket_CNF"]')
        .forEach(function (input) {
          input.addEventListener("click", function () {
            handleCheckboxLogic(input);
          });
        });
    }
  });

