  //make endorsement screen fields readonly
  $(document).ready(function () {
    if (
      $(".page-prequotequestions.page-number-5").length > 0 &&
      Instanda.Variables["PackageId"] === 23424
    ) {
      function makeCheckboxesReadonly(partialNames) {
        partialNames.forEach(function (partialName) {
          $("input[type='checkbox'][name*='" + partialName + "']").each(
            function () {
              $(this)
                .css({
                  opacity: "0.5",
                  "background-color": "#eee",
                  "pointer-events": "none",
                })
                .on("click keydown", function (e) {
                  e.preventDefault();
                  e.stopImmediatePropagation();
                  return false;
                });
            }
          );
        });
      }

      $(document).ready(function () {
        // Check for CO_AmendBlanketPerItemLimitEndorsement1_CONFIRM
        var amendBox = $("#CO_AmendBlanketPerItemLimitEndorsement1_CONFIRM");
        if (amendBox.length && amendBox.is(":checked")) {
          makeCheckboxesReadonly([
            "CO_AmendBlanketPerItemLimitEndorsement1_CONFIRM",
            "Amend_CONFIRM",
          ]);
        }

        // Check for CO_NoPerItemLimitEndorsement1_CONFIRM
        var noPerItemBox = $("#CO_NoPerItemLimitEndorsement1_CONFIRM");
        if (noPerItemBox.length && noPerItemBox.is(":checked")) {
          makeCheckboxesReadonly([
            "CO_NoPerItemLimitEndorsement1_CONFIRM",
            "NoPerItemLimit1_CONFIRM",
          ]);
        }
      });
    }
  });
