  ///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////
  function toggleCustomerIdVisibility() {
    // question containers
    const YachtCustomerId = document.getElementById("question451285");
    const CollCustomerId = document.getElementById("question439273");

    // input fields
    const YachtCustIdInput = YachtCustomerId ?
      YachtCustomerId.querySelector("input") :
      null;
    const CollectionCustIdInput = CollCustomerId ?
      CollCustomerId.querySelector("input") :
      null;

    document
      .querySelectorAll('input[name="ConvertedPolicy_YN"]')
      .forEach(function (radio) {
        function updateFields(value) {
          if (value === "Yes") {
            if (YachtCustomerId)
              YachtCustomerId.classList.remove("hidden", "readonly");
            if (CollCustomerId)
              CollCustomerId.classList.remove("hidden", "readonly");
            if (YachtCustIdInput) {
              YachtCustIdInput.readOnly = false;
              $("#CustomerID_TXT").attr("required", true);
            }
            if (CollectionCustIdInput) {
              CollectionCustIdInput.readOnly = false;
              $("#CustomerID_TXT").attr("required", true);
            }
          } else if (value === "No") {
            if (YachtCustomerId)
              YachtCustomerId.classList.add("hidden", "readonly");
            if (CollCustomerId)
              CollCustomerId.classList.add("hidden", "readonly");
            if (YachtCustIdInput) {
              YachtCustIdInput.readOnly = true;
              $("#CustomerID_TXT").attr("required", false);
            }
            if (CollectionCustIdInput) {
              CollectionCustIdInput.readOnly = true;
              $("#CustomerID_TXT").attr("required", false);
            }
          }
        }

        radio.addEventListener("change", function () {
          updateFields(this.value);
        });

        // Run on page load if already selected
        if (radio.checked) {
          updateFields(radio.value);
        }
      });
  }

  $(document).ready(function () {
    toggleCustomerIdVisibility();
  });

