  // function to validate zip code and make it 5 digit if country is US.
  function formatZipCode(zip) {
    // If zip is already a string, return as-is
    if (typeof zip === "string") {
      return zip;
    }

    if ($(".package-23423").length > 0) {
      if (Instanda.Variables.MA_Country_CHOICE !== "US") {
        return zip;
      }
    }

    // Always convert to string (only if not already handled above)
    zip = String(zip);

    // Ignore ZIP+4 or any input containing a dash
    if (zip.indexOf("-") !== -1) {
      return zip;
    }

    // Remove non-digits
    var digits = zip.replace(/\D/g, "");

    // Only format if less than 5 digits
    if (digits.length > 0 && digits.length < 5) {
      return digits.padStart(5, "0");
    }

    // Return as string if already 5 or more digits
    return digits.length > 0 ? digits : zip;
  }

  // function to show the alert box when someone tries to close browser at issuance.
  function BrowserCloseMessage() {
    function handler(e) {
      const msg = "Are you sure you want to close the browser?";
      e = e || window.event;
      if (e) e.returnValue = msg; // IE / old Firefox
      return msg; // Chrome / Safari / modern Firefox
    }
    window._issuanceBeforeUnload = handler;
    window.addEventListener("beforeunload", handler);
  }

  // Function to remove alert message.
  function removeBeforeUnload() {
    if (window._issuanceBeforeUnload) {
      window.removeEventListener("beforeunload", window._issuanceBeforeUnload);
      delete window._issuanceBeforeUnload;
    }
  }

  // Code to add message while issuing and cancelling.
  function addSpinnerMessage() {
    // Only proceed if overlay exists and message hasn't been added
    if (
      $("#unified-spinner-overlay").length &&
      !$("#spinnerMessageWrapper").length
    ) {
      var $overlay = $("#unified-spinner-overlay");

      // Ensure overlay is positioned and z-indexed ABOVE other overlays
      $overlay.css({
        position: "fixed",
        top: 0,
        left: 0,
        width: "100vw",
        height: "100vh",
        "z-index": 10999, // Or 11000 to be very safe
        background: "rgba(34, 40, 49, 0.85)", // Optional: ensure opacity
      });

      var $spinner = $overlay.find(".spinner");

      // Create a wrapper div to hold spinner and message vertically
      var $wrapper = $(`
      <div id="spinnerMessageWrapper" style="
        display: flex;
        flex-direction: column;
        align-items: center;
        justify-content: center;
      "></div>
    `);

      // Move the spinner into the wrapper
      $spinner.appendTo($wrapper);

      // Add the beautiful message
      $wrapper.append(`
      <div id="spinnerMessage" style="
        margin-top: 24px;
        color: #fff;
        font-size: 1.2em;
        text-align: center;
        background: rgba(34, 40, 49, 0.85);
        padding: 18px 28px;
        border-radius: 10px;
        box-shadow: 0 4px 16px rgba(0,0,0,0.18);
        max-width: 90vw;
        font-family: 'Segoe UI', Arial, sans-serif;
        letter-spacing: 0.01em;
      ">
        <strong style="font-size:1.3em; display:block; margin-bottom:8px;">
          Processing your request...
        </strong>
        <span style="font-size:1em;">
          Please wait a moment.<br>
          <em>Do not refresh, go back, or close your browser.</em>
        </span>
      </div>
    `);

      // Clear the overlay and add the wrapper
      $overlay.empty().append($wrapper);
    }
  }

