  function getIssuingCompanyCode() {
    const packageid = Instanda.Variables.PackageId;
    let code;
    if (packageid === 23423) {
      const stateVal = Instanda.Variables.MA_State_CHOICE;

      if (stateVal === "HI" || stateVal === "ME") {
        code = "6";
      } else {
        code = "28";
      }

      return code;
    }


    const companyCd =
      $("#UWCompany_CHOICE").val() || Instanda.Variables.UWCompany_CHOICE;

    const company = (companyCd || "").trim();

    if (company === "Illinois National Insurance Company") {
      code = "6";
    } else if (company === "AIG Property Casualty Company") {
      code = "28";
    } else if (company === "Commerce and Industry Insurance Company") {
      code = "13";
    } else if (company === "American Home Assurance Company") {
      code = "11";
    } else if (company === "AIG Specialty Insurance Company") {
      code = "17";
    } else if (company === "Lexington Insurance Company") {
      code = "41";
    } else if (company === "The Insurance Company of the State of Pennsylvania") {
      code = "12";
    } else {
      code = undefined;
    }

    return code;
  }


