  /////////////////Multi Car discount

  if ($(".page-quickquotequestions.page-number-4.package-24338").length > 0) {
    function handleMultiCarRegularLogic(currentID) {
      const getMiNumber = (id) => {
        const m = String(id || "").match(/Vehicle_MI(\d+)_/);
        return m ? Number(m[1]) : null;
      };

      const readValue = (el) => {
        if (!el) return "";
        // inputs/selects
        if ("value" in el && typeof el.value === "string")
          return el.value.trim();
        // summary spans (like your li_... nodes)
        const t = el.getAttribute?.("title");
        if (t && t.trim()) return t.trim();
        return (el.textContent || "").trim();
      };

      // 1) Build MI -> vehicleType from BOTH edit + summary nodes
      const $allVehTypeNodes = $(
        "[id$='VehType_CHOICEP'], span[id*='Vehicle_MI'][id$='_VehType_CHOICEP']"
      );

      const miToType = new Map();
      $allVehTypeNodes.each(function () {
        const mi = getMiNumber(this.id);
        if (mi == null) return;

        const type = readValue(this);
        if (type) miToType.set(mi, type);
      });

      const regularCount = Array.from(miToType.values()).filter(
        (t) => String(t).trim().toLowerCase() === "regular"
      ).length;

      // 2) Apply logic ONLY to editable VehType controls (so we can set the multiCar radios)
      const $editableVehType = $(
        "select[id$='VehType_CHOICEP'], input[id$='VehType_CHOICEP']"
      );

      $editableVehType.each(function () {
        const mi = getMiNumber(this.id);
        const type =
          mi != null ? miToType.get(mi) || $(this).val() : $(this).val();

        const $multiCar = $(this)
          .closest(".questionItem")
          .nextAll(".multiCar")
          .first();

        const isRegular =
          String(type || "")
            .trim()
            .toLowerCase() === "regular";
        const $multicarcreditOverride = $(this)
          .closest(".questionItem")
          .parent()
          .find("input[type='radio'][name^='MultiCarOverride_YN']:checked");
        // const isInDraft = $(`#Vehicle_MI${mi}-draft-chip`).is(":visible");
        // console.log("IS Visible ", mi, " : ", isInDraft);
        const state = Instanda.Variables.PremiumState_CHOICE;
        if ($multicarcreditOverride.val() == "Yes" && state != "California")
          return;

        if (isRegular) {
          const $targetLabel =
            regularCount > 1 ?
              $multiCar.find(".instanda-question-yes-no-yes") :
              $multiCar.find(".instanda-question-yes-no-no");

          $targetLabel.find("input").prop("checked", true).trigger("change");
        } else {
          if (state == "California" && currentID !== `${mi}`) return;
          const $noLabel = $multiCar.find(".instanda-question-yes-no-no");
          $noLabel.find("input").prop("checked", true).trigger("change");
        }
      });

      return regularCount; // optional: helpful for debugging
    }

    // Delegated binding remains unchanged:
    $(document).on("change", "[id$='_VehType_CHOICEP']", function () {
      const currentID = ($(this).attr("id") || "").match(/MI(\d+)/)?.[1];
      handleMultiCarRegularLogic(currentID);
    });

    $("#Vehicle_MIaddButton").on("click", function () {
      setTimeout(function () {
        handleMultiCarRegularLogic(null);
      }, 200);
    });

    // Optionally, run once on page load, if needed:
    handleMultiCarRegularLogic(null);
  }
