  // Setting maxlimit for Couties as 40 characters - BH-24388
  $(document).ready(function () {
    const counties = $("input").filter(function () {
      return this.id && this.id.toLowerCase().includes("county");
    });
    counties.attr(`maxlength`, `40`);
    counties.on(`keypress`, function (e) {
      const char = String.fromCharCode(e.which);
      if (!/^[a-zA-Z\s\.\-]$/.test(char)) {
        e.preventDefault();
      }
    });
    counties.on("input", function () {
      if ($(this).val().length <= 40) return;
      $(this).val($(this).val().slice(0, 40));
    });
  });

