  // Auto
  // Deepanshu - New Requirement Change for Policy Coverage screen
  $(document).ready(function () {
    if ($(".page-quickquotequestions.page-number-6.package-24338").length > 0) {
      if (
        $("#CovTypeValue").val() === "Physical Damage Only" &&
        Instanda.Variables.ChangeReason_Choice === "Reissue"
      ) {
        $(".instanda-quick-quote-questions")
          .css("pointer-events", "auto")
          .css("cursor", "auto");
      }

      const KEEP_VISIBLE_IDS = [
        "question482293",
        "question498751",
        "question498753",
        "question482457",
      ];

      // Enhanced visibility detection
      function isTrulyVisible($el) {
        if (!$el.is(":visible")) return false;
        const style = window.getComputedStyle($el[0]);
        return (
          style.opacity !== "0" &&
          style.visibility !== "hidden" &&
          style.display !== "none" &&
          style.pointerEvents !== "none"
        );
      }

      function restrictCoverages() {
        const isPhysicalDamageOnly =
          $("#CovTypeValue").val() === "Physical Damage Only";
        const $allItems = $(".questionItem");

        // Only add the was-visible class if it doesn't exist yet (ENHANCED)
        if ($allItems.filter(".was-visible").length === 0) {
          $allItems.each(function () {
            const $item = $(this);
            if (isTrulyVisible($item)) $item.addClass("was-visible");
          });
        }

        if (isPhysicalDamageOnly) {
          // Hide all that were visible, then show only those in KEEP_VISIBLE_IDS
          $allItems.filter(".was-visible").each(function () {
            const $item = $(this);
            if (KEEP_VISIBLE_IDS.includes($item.attr("id"))) {
              $item.show();
              $item.find("input, select, textarea").prop("disabled", false);
            } else {
              $item.hide();
              $item.find("input, select, textarea").prop("disabled", true);
            }
          });
        } else {
          // Show and re-enable all that were previously visible
          $allItems.filter(".was-visible").each(function () {
            $(this).show();
            $(this).find("input, select, textarea").prop("disabled", false);
          });
          // CLEANUP: Remsve the special marker ONLY when switching out of Physical Damage mode
          $allItems.removeClass("was-visible");
        }
      }

      setTimeout(restrictCoverages, 600);

      $("#CovTypeValue").on("change", function () {
        setTimeout(restrictCoverages, 600);
      });
    }
  });

