  //BH26138 Homeowners - Policy Coverage Screen - Charge Policy Fee and Charge Inspection Fields Logic.
  $(document).ready(function () {
    if ($(".page-quickquotequestions.page-number-1.package-24337").length > 0) {
      function updateChargeFields() {
        // Get Policy Rewrite value
        var polrwrYes = false;
        var $checkedRadio = $('#question514614 input[type="radio"]:checked');
        if ($checkedRadio.length) {
          var v = String($checkedRadio.val() || "")
            .trim()
            .toLowerCase();
          polrwrYes = ["yes", "y", "1", "true"].includes(v);
        }

        // Get Product Code value (match value OR visible text)
        var $pcSelect = $("#question480748 select");
        var productCodeVal = String($pcSelect.val() || "").trim();
        var productCodeTxt = String(
          $pcSelect.find("option:selected").text() || ""
        ).trim();
        var isNonAdmitted =
          productCodeVal === "Non-Admitted" ||
          productCodeTxt === "Non-Admitted";

        // Get Risk State value (normalize)
        var riskState = String($("#RiskStateRO_TXT").val() || "")
          .trim()
          .toUpperCase();

        var shouldShow =
          polrwrYes &&
          isNonAdmitted && [
            "AK",
            "AL",
            "AR",
            "AZ",
            "CA",
            "CO",
            "CT",
            "DC",
            "DE",
            "FL",
            "GA",
            "HI",
            "IA",
            "ID",
            "IL",
            "IN",
            "KS",
            "KY",
            "LA",
            "MA",
            "MD",
            "ME",
            "MI",
            "MN",
            "MO",
            "MS",
            "MT",
            "NC",
            "ND",
            "NE",
            "NH",
            "NJ",
            "NM",
            "NV",
            "NY",
            "OH",
            "OK",
            "OR",
            "PA",
            "PR",
            "RI",
            "SC",
            "SD",
            "TN",
            "TX",
            "UT",
            "VA",
            "VI",
            "VT",
            "WA",
            "WI",
            "WV",
            "WY",
          ].includes(riskState);

        // Your question IDs + radio group names from the HTML you provided
        var fieldsToControl = [{
          qid: "545119",
          name: "ChargePolicyFeeRW_YN",
        },
        {
          qid: "512956",
          name: "ChargeInspectionFeeRW_YN",
        },
        ];

        fieldsToControl.forEach(function (f) {
          var $qDiv = $("#question" + f.qid);
          if (!$qDiv.length) {
            console.warn("Field not found: #question" + f.qid);
            return;
          }

          var $label = $qDiv
            .find(".instanda-question-label label.control-label")
            .first();
          var $firstRadio = $qDiv
            .find('input[type="radio"][name="' + f.name + '"]')
            .first();

          // marker we can reliably remove
          var requiredSpan =
            ' <span class="sk-required" style="color:red" aria-label="required">*</span>';

          if (shouldShow) {
            // In your HTML these containers start as brokerHidden
            $qDiv.removeClass("brokerHidden").show();

            if ($label.length) {
              $label.removeAttr("data-is-optional").addClass("required");

              // Don’t duplicate required stars
              if ($label.find("span.sk-required").length === 0) {
                if (
                  !/\s*<span[^>]*aria-label="required"[^>]*>\*<\/span>/.test(
                    $label.html()
                  )
                ) {
                  $label.html($.trim($label.html()) + requiredSpan);
                }
              }
            }

            // For radio groups, apply required to the first input
            if ($firstRadio.length)
              $firstRadio.prop("required", true).addClass("required");
          } else {
            $qDiv.addClass("brokerHidden").hide();

            if ($firstRadio.length)
              $firstRadio.prop("required", false).removeClass("required");

            if ($label.length) {
              $label.attr("data-is-optional", "True").removeClass("required");
              var html = $label.html();
              html = html
                .replace(/\s*<span class="sk-required"[^>]*>\*<\/span>/, "")
                .replace(
                  /\s*<span[^>]*aria-label="required"[^>]*>\*<\/span>/,
                  ""
                );
              $label.html($.trim(html));
            }

            // Optional: default to "No" when hidden
            var $no = $("#" + f.name + "No");
            if ($no.length) $no.prop("checked", true).trigger("change");
          }
        });
      }

      // Attach listeners (same as you had)
      $('#question514614 input[type="radio"]').on("change", updateChargeFields);
      $('#question480748 select, #question480748 input[type="radio"]').on(
        "change",
        updateChargeFields
      );
      $("#RiskStateRO_TXT").on("change", updateChargeFields);

      // Run once at the start
      updateChargeFields();
    }
  });

  ///////////Collections Coverage details screen changes - 9536 start//////////////////
  (function ($) {
    $(function () {
      // =========================
      // Config
      // =========================
      var DEBUG = false;

      // Run ONLY when this specific page container exists (prequote page 3, package 23424)
      var PAGE_SELECTOR = ".page-prequotequestions.page-number-3.package-23424";
      var STATE_SELECTOR = "#CO_primary_State_CHOICE";

      // HARD GATE: do absolutely nothing on other packages/pages
      if ($(PAGE_SELECTOR).length === 0) return;

      var ALWAYS_OPTIONAL_FIELDS = [{
        input: 'input[name="CO_BuildingHomeRenovation_YNP"]',
        question: "#question427412",
      },
      {
        input: "#CO_BuildingCodeRenovationYear_NUM",
        question: "#question427413",
      },
      ];

      var RENOVATION_FIELDS = [{
        input: "#CO_Primary_YearofElectricRenovation_NUM",
        question: "#question427401",
      },
      {
        input: "#CO_Primary_YearofPlumbingRenovation_NUM",
        question: "#question427402",
      },
      {
        input: "#CO_Primary_YearofHeatingRenovation_NUM",
        question: "#question427403",
      },
      {
        input: "#CO_Primary_YearofRoofReplacement_NUM",
        question: "#question427404",
      },
      ];

      // Prevent duplicate bindings / observers if script loads multiple times
      // Package-specific key to avoid collisions across packages
      var GLOBAL_KEY =
        "__collectionsRequirementsController__package_23424__page3__";
      if (window[GLOBAL_KEY] && window[GLOBAL_KEY].started) return;

      // =========================
      // Logging helpers
      // =========================
      function log() {
        if (DEBUG && window.console) console.log.apply(console, arguments);
      }

      function warnOnceFactory() {
        var seen = Object.create(null);
        return function (key) {
          if (seen[key]) return;
          seen[key] = true;
          if (window.console) console.warn(key);
        };
      }
      var warnOnce = warnOnceFactory();

      // =========================
      // DOM helpers
      // =========================
      function getAsterisk(questionSelector) {
        return $(
          questionSelector +
          " .instanda-question-label label span[style*='color: red']"
        );
      }

      function getLabel(questionSelector) {
        return $(questionSelector + " .instanda-question-label label");
      }

      function setRequiredState($input, $asterisk, $label, isRequired) {
        var currentlyRequired = !!$input.prop("required");
        var currentlyOptionalAttr =
          ($label.attr("data-is-optional") || "").toLowerCase() === "true";

        if (currentlyRequired === isRequired) {
          if (isRequired) {
            if (currentlyOptionalAttr) $label.attr("data-is-optional", "False");
            if ($asterisk.length) $asterisk.show();
          } else {
            if (!currentlyOptionalAttr) $label.attr("data-is-optional", "True");
            if ($asterisk.length) $asterisk.hide();
            $input.removeAttr("aria-required");
          }
          return;
        }

        if (isRequired) {
          $input.attr("required", "required");
          $input.prop("required", true);
          if ($asterisk.length) $asterisk.show();
          $label.attr("data-is-optional", "False");
        } else {
          $input.removeAttr("required");
          $input.prop("required", false);
          $input.removeAttr("aria-required");
          if ($asterisk.length) $asterisk.hide();
          $label.attr("data-is-optional", "True");
        }
      }

      // =========================
      // Core behavior
      // =========================
      function makeFieldsAlwaysOptional() {
        ALWAYS_OPTIONAL_FIELDS.forEach(function (field) {
          var $input = $(field.input);
          if ($input.length === 0) {
            warnOnce("Always optional field not found: " + field.input);
            return;
          }
          var $asterisk = getAsterisk(field.question);
          var $label = getLabel(field.question);
          setRequiredState($input, $asterisk, $label, false);
        });
      }

      function toggleFieldRequirement(
        inputSelector,
        questionSelector,
        isRequired
      ) {
        var $input = $(inputSelector);
        if ($input.length === 0) {
          warnOnce("Conditional field not found: " + inputSelector);
          return;
        }
        var $asterisk = getAsterisk(questionSelector);
        var $label = getLabel(questionSelector);
        setRequiredState($input, $asterisk, $label, !!isRequired);
      }

      function getInstandaVar(path, fallback) {
        try {
          if (typeof Instanda !== "undefined" && Instanda.Variables) {
            var v = Instanda.Variables[path];
            return v === undefined || v === null ? fallback : v;
          }
        } catch (e) { }
        return fallback;
      }

      function updateAllFieldRequirements() {
        var productCode = getInstandaVar("ProductCode_CHOICE", "") || "";
        var convertedPolicy = getInstandaVar("ConvertedPolicy_YN", "") || "";
        var stateValue = $(STATE_SELECTOR).val() || "";

        var isAdmitted = productCode === "Admitted";
        var isFlorida = stateValue === "FL";
        var isConvertedPolicy = convertedPolicy === "Yes";

        log("Updating requirements", {
          productCode: productCode,
          convertedPolicy: convertedPolicy,
          stateValue: stateValue,
          isAdmitted: isAdmitted,
          isFlorida: isFlorida,
          isConvertedPolicy: isConvertedPolicy,
        });

        if (!isConvertedPolicy) {
          toggleFieldRequirement(
            "#CO_Primary_ConstructionType_CHOICE",
            "#question427373",
            isAdmitted
          );

          toggleFieldRequirement(
            "#CO_Primary_YearBuilt_NUM",
            "#question427379",
            isAdmitted && isFlorida
          );

          toggleFieldRequirement(
            'input[name="CO_Homebeenrenovated_YNP"]',
            "#question427400",
            isAdmitted && isFlorida
          );

          RENOVATION_FIELDS.forEach(function (field) {
            toggleFieldRequirement(
              field.input,
              field.question,
              isAdmitted && isFlorida
            );
          });
        } else {
          log("Converted policy detected - skipping conditional requirements");
        }

        makeFieldsAlwaysOptional();
      }

      // =========================
      // MutationObserver (replaces 100ms interval)
      // =========================
      function getObserverRootNode() {
        var $page = $(PAGE_SELECTOR).first();
        if ($page.length) return $page[0];

        var $form = $("form").first();
        if ($form.length) return $form[0];

        return document.body;
      }

      function startMutationObserver() {
        var controller = window[GLOBAL_KEY];
        if (controller && controller.observer) return;

        var rootNode = getObserverRootNode();
        var scheduled = false;

        function scheduleApply() {
          if (scheduled) return;
          scheduled = true;
          requestAnimationFrame(function () {
            scheduled = false;
            updateAllFieldRequirements();
          });
        }

        var observer = new MutationObserver(function (mutations) {
          for (var i = 0; i < mutations.length; i++) {
            var m = mutations[i];
            if (m.type !== "childList") continue;

            if (
              (m.addedNodes && m.addedNodes.length) ||
              (m.removedNodes && m.removedNodes.length)
            ) {
              scheduleApply();
              break;
            }
          }
        });

        observer.observe(rootNode, {
          childList: true,
          subtree: true,
        });
        window[GLOBAL_KEY].observer = observer;

        updateAllFieldRequirements();
      }

      function stopMutationObserver() {
        var controller = window[GLOBAL_KEY];
        if (controller && controller.observer) {
          controller.observer.disconnect();
          controller.observer = null;
        }
      }

      // =========================
      // Initialization with retry
      // =========================
      function instandaReady() {
        return (
          typeof Instanda !== "undefined" &&
          Instanda.Variables &&
          $(STATE_SELECTOR).length > 0
        );
      }

      function initializeWithRetry(attempts, delay) {
        attempts = attempts || 0;
        delay = delay || 100;

        // Still keep the gate here for safety
        if ($(PAGE_SELECTOR).length === 0) return;

        if (instandaReady()) {
          log("Instanda ready, starting observer + apply");
          startMutationObserver();
          return;
        }

        if (attempts < 20) {
          setTimeout(function () {
            initializeWithRetry(attempts + 1, delay);
          }, delay);
        } else {
          if (window.console) console.error("Instanda failed to initialize");
        }
      }

      // =========================
      // Event bindings (namespaced to avoid duplicates)
      // =========================
      function bindEvents() {
        $(document).off(".collectionsReq");

        $(document).on(
          "change.collectionsReq",
          '[name*="ProductCode_CHOICE"], ' +
          STATE_SELECTOR +
          ', [name*="ConvertedPolicy_YN"]',
          function () {
            if (
              typeof Instanda !== "undefined" &&
              Instanda.Variables &&
              this.name
            ) {
              if (this.name.indexOf("ProductCode") !== -1) {
                Instanda.Variables.ProductCode_CHOICE = $(this).val();
              }
              if (this.name.indexOf("ConvertedPolicy_YN") !== -1) {
                Instanda.Variables.ConvertedPolicy_YN = $(this).val();
              }
            }
            updateAllFieldRequirements();
          }
        );

        $(document).on(
          "change.collectionsReq blur.collectionsReq",
          'input[name="CO_BuildingHomeRenovation_YNP"], #CO_BuildingCodeRenovationYear_NUM',
          function () {
            makeFieldsAlwaysOptional();
          }
        );

        $(document).on("submit.collectionsReq", "form", function () {
          makeFieldsAlwaysOptional();
        });
      }

      // =========================
      // Start
      // =========================
      window[GLOBAL_KEY] = window[GLOBAL_KEY] || {};
      window[GLOBAL_KEY].started = true;
      window[GLOBAL_KEY].stop = stopMutationObserver;

      bindEvents();
      initializeWithRetry(0, 100);

      try {
        if (typeof Instanda !== "undefined" && Instanda.on) {
          Instanda.on("ready", function () {
            if ($(PAGE_SELECTOR).length > 0) startMutationObserver();
          });
        }
      } catch (e) { }

      // Debug helpers
      window.forceOptionalFields = makeFieldsAlwaysOptional;
      window.forceUpdateRequirements = updateAllFieldRequirements;
    });
  })(jQuery);

  ///////////Collections Coverage details screen changes - 9536 end///////////////////

