(() => {
  if (
    $(".page-quickquotequestions.page-number-4.package-24338").length > 0 ||
    $(".page-prequotequestions.page-number-1.package-24338").length > 0
  ) {
    const selector = '[onclick*="saveMultiItemInstance"]'; // any element, not just <button>

    function applyStyling(root = document) {
      const targets = root.querySelectorAll(selector);
      targets.forEach((el) => {
        el.classList.remove("btn-default");
        el.classList.add("instanda-button", "btn", "btn-primary");
        el.dataset._styledSaveMultiItem = "1";
      });
    }

    // 1) Apply immediately (works even if DOMContentLoaded already fired)
    applyStyling();

    // 2) Re-apply when Instanda injects/re-renders content
    const obs = new MutationObserver((muts) => {
      for (const m of muts) {
        for (const n of m.addedNodes) {
          if (n.nodeType !== 1) continue; // element nodes only
          if (n.matches?.(selector)) applyStyling(n.parentNode || document);
          else if (n.querySelector?.(selector)) applyStyling(n);
        }
      }
    });

    obs.observe(document.documentElement, {
      childList: true,
      subtree: true,
    });

    // 3) Safety net: some frameworks rewrite attributes without “addedNodes”
    setInterval(applyStyling, 1000);
  }
})();

