// Mandatory field
(() => {
  const PAGE_SELECTOR = ".page-quickquotequestions.page-number-4.package-24338";
  const onCorrectPage = (() => {
    if (window.jQuery) return window.jQuery(PAGE_SELECTOR).length > 0;
    return document.querySelector(PAGE_SELECTOR) !== null;
  })();
  if (!onCorrectPage) return;

  const CSS_ID = "si-mi-invalid-css";

  // No injected <span>/<li>. Only highlight + displayApiErrorMessage().
  const FIELD_RULES = [{
    key: "PassiveRestraintsValue",
    idSuffix: "_PassiveRestraintsValue",
    message: "Please select a value for Passive Restraints.",
    type: "required",
  },
  {
    key: "AntiTheftValue",
    idSuffix: "_AntiTheftValue",
    message: "Please select a value for Anti-Theft.",
    type: "required",
  },
  {
    key: "AntiLock_CHOICE",
    idSuffix: "_AntiLock_CHOICE",
    message: "Please select a value for Anti-Lock .",
    type: "required",
  },
  {
    key: "AgreedVal_NUM",
    idSuffix: "_AgreedVal_NUM",
    message: "Agreed Value is required as numeric value.",
    type: "numericRequired",
  },
  {
    key: "VehHeight_TXT",
    idSuffix: "_VehHeight_TXT",
    message: "Vehicle Height is required as numeric value.",
    type: "numericRequired",
  },
  {
    key: "EngineSize_NUM",
    idSuffix: "_EngineSize_NUM",
    message: "Engine Size is required as numeric value.",
    type: "numericRequired",
  },
  {
    key: "MaxOperatingSpeed_NUM",
    idSuffix: "_MaxOperatingSpeed_NUM",
    message: "Max Operating Speed is required as numeric value.",
    type: "numericRequired",
  },
  {
    key: "ComprehensiveSym_NUM",
    idSuffix: "_ComprehensiveSym_NUM",
    message: "Comprehensive Symbol is required as numeric value.",
    type: "numericRequired",
  },
  {
    key: "CollisionSym_NUM",
    idSuffix: "_CollisionSym_NUM",
    message: "Collision Symbol is required as numeric value.",
    type: "numericRequired",
  },
  {
    key: "CostNew_NUM",
    idSuffix: "_CostNew_NUMM",
    message: "Cost New is required as numeric value.",
    type: "numericRequired",
  },
  ];

  function ensureCss() {
    if (document.getElementById(CSS_ID)) return;
    const style = document.createElement("style");
    style.id = CSS_ID;
    style.textContent = `
      .si-mi-invalid{
        border-color:#DA291C !important;
        outline:none !important;
        box-shadow: 0 0 0 .15rem rgba(218,41,28,.12) !important;
      }
    `;
    document.head.appendChild(style);
  }

  function isVisible(el) {
    if (!el) return false;
    if (el.hidden) return false;
    if (el.closest('[hidden], [aria-hidden="true"]')) return false;

    const c = el.closest(".collapse");
    if (c && !c.classList.contains("show")) return false;

    const cs = getComputedStyle(el);
    if (
      cs.display === "none" ||
      cs.visibility === "hidden" ||
      Number(cs.opacity) === 0
    )
      return false;
    if (el.offsetParent === null && cs.position !== "fixed") return false;

    return true;
  }

  function getMiMetaFromSaveButton(btn) {
    const miIndex = btn.getAttribute("data-multi-item-index");
    if (miIndex)
      return {
        miIndex: String(miIndex),
      };

    const v = btn.getAttribute("data-multi-item-variable-name") || "";
    const m = /^Vehicle_MI(\d+)$/.exec(v);
    return {
      miIndex: m ? m[1] : null,
    };
  }

  function getFieldElement(miIndex, rule) {
    return document.getElementById(`Vehicle_MI${miIndex}${rule.idSuffix}`);
  }

  function getValidationTarget(el) {
    if (!el) return null;
    if (el.matches?.("select,input,textarea")) return el;
    return el.querySelector?.("select, input, textarea") || el;
  }

  function extractValue(target) {
    if (!target) return "";

    if (target.matches?.("select,input,textarea"))
      return (target.value ?? "").toString();

    const radios = target.querySelectorAll?.('input[type="radio"]');
    if (radios?.length) {
      const chosen = Array.from(radios).find((r) => r.checked);
      return chosen ? chosen.value ?? "on" : "";
    }

    const checks = target.querySelectorAll?.('input[type="checkbox"]');
    if (checks?.length)
      return Array.from(checks).some((c) => c.checked) ? "checked" : "";

    if ("value" in target) return (target.value ?? "").toString();
    return "";
  }

  function isNumeric(val) {
    const s = (val ?? "").toString().trim();
    if (!s) return false;
    const n = Number(s.replace(/,/g, ""));
    return Number.isFinite(n);
  }

  function validateField(rule, target) {
    const v = extractValue(target).trim();

    if (rule.type === "numericRequired") return v.length > 0 && isNumeric(v);
    // default: required
    return v.length > 0;
  }

  function setInvalid(target, invalid) {
    if (!target?.classList) return;
    if (invalid) {
      target.classList.add("si-mi-invalid");
      target.setAttribute?.("aria-invalid", "true");
    } else {
      target.classList.remove("si-mi-invalid");
      target.removeAttribute?.("aria-invalid");
    }
  }

  function callDisplayApiErrorMessage(htmlMessage) {
    if (typeof window.displayApiErrorMessage !== "function") return;
    // Pass one consolidated message (no <li> added here)
    window.displayApiErrorMessage(htmlMessage);

    // Make newlines display as new lines in the rendered error box
    const alertEl =
      document.querySelector(".alert.alert-danger, .alert-danger, .apiErrorMessage, .api-error-message");
    if (alertEl) alertEl.style.whiteSpace = "pre-line";
  }

  // ADDED: Only validate if the field's label ends with '*'
  function labelHasTrailingAsterisk(fieldEl, target) {
    const base = target || fieldEl;

    // Find the question container shown in your screenshot
    const item =
      base?.closest?.(".questionItem") ||
      base?.closest?.(".instanda-question-item") ||
      base?.closest?.(".form-group") ||
      null;

    // Prefer the Instanda label region
    const lbl =
      item?.querySelector?.(".instanda-question-label label") ||
      item?.querySelector?.("label") ||
      null;

    // If we can't locate the label, DO NOT suppress validation
    // (prevents the "no errors at all" regression).
    if (!lbl) return true;

    // 1) Your actual required marker pattern: <label>Text <span>*</span></label>
    const spans = lbl.querySelectorAll?.("span") || [];
    for (const s of spans) {
      if (((s.textContent || "").replace(/\s+/g, " ").trim()) === "*") return true;
    }

    // 2) Fallback: label text ends with '*'
    const text = (lbl.textContent || "").replace(/\s+/g, " ").trim();
    if (/\*\s*$/.test(text)) return true;

    // 3) Fallback: CSS pseudo-element star (if used elsewhere)
    try {
      const after = getComputedStyle(lbl, "::after")?.content || "";
      const before = getComputedStyle(lbl, "::before")?.content || "";
      if (after.includes("*") || before.includes("*")) return true;
    } catch (e) { }

    return false;
  }

  function validateMi(miIndex) {
    ensureCss();

    const errors = [];
    let firstInvalidEl = null;

    for (const rule of FIELD_RULES) {
      const fieldEl = getFieldElement(miIndex, rule);

      if (!fieldEl || !isVisible(fieldEl)) {
        if (fieldEl) setInvalid(getValidationTarget(fieldEl), false);
        continue;
      }

      const target = getValidationTarget(fieldEl);
      const visibleTarget = isVisible(target) ? target : fieldEl;

      // ADDED: skip validation if label is not marked required with '*'
      if (!labelHasTrailingAsterisk(fieldEl, target)) {
        setInvalid(target, false);
        continue;
      }

      const isValid = validateField(rule, visibleTarget);

      if (!isValid) {
        setInvalid(target, true);
        errors.push(rule.message);
        if (!firstInvalidEl) firstInvalidEl = target;
      } else {
        setInvalid(target, false);
      }
    }

    if (errors.length) {
      // Use <br> so it shows as multiple lines without lists
      callDisplayApiErrorMessage(errors.join("\n"));
      firstInvalidEl?.focus?.({
        preventScroll: false,
      });
      return false;
    }

    return true;
  }

  // Block Save if invalid (capture phase beats inline onclick)
  document.addEventListener(
    "click",
    (e) => {
      const btn = e.target.closest('button[onclick*="saveMultiItemInstance"]');
      if (!btn) return;

      const {
        miIndex
      } = getMiMetaFromSaveButton(btn);
      if (!miIndex) return;

      if (!validateMi(miIndex)) {
        e.preventDefault();
        e.stopPropagation();
        e.stopImmediatePropagation();
      }
    },
    true
  );

  // Clear red highlight when corrected
  document.addEventListener("input", (e) => {
    const el = e.target;
    if (!(el instanceof HTMLElement)) return;

    const m = /^Vehicle_MI(\d+)_/.exec(el.id || "");
    if (!m) return;

    const miIndex = m[1];
    const rule = FIELD_RULES.find(
      (r) => `Vehicle_MI${miIndex}${r.idSuffix}` === el.id
    );
    if (!rule) return;

    if (isVisible(el) && validateField(rule, el)) setInvalid(el, false);
  });
})();

