function retentionvalidationauto() {
  if (!window.jQuery) return;
  const $ = window.jQuery;

  // page gate
  if (!$(".page-prequotequestions.page-number-1.package-24338").length) return;

  // prevent double-binding
  if (window.__si_reten_prequote1_pip_init) return;
  window.__si_reten_prequote1_pip_init = true;

  const CSS_ID = "si-reten-invalid-css";
  const INVALID_CLASS = "si-reten-invalid";

  // Retention Code can be PIPRetenCode_CHOICE (your HTML) or other variants
  const RETEN_SELECT =
    'select[id$="PIPRetenCode_CHOICE"], select[id$="RetenCode_CHOICE"], select[id$="RtnCd_CHOICE"]';

  const PREM_FLAT = '[id*="FlatAmnt_CHOICEPNo"], [id*="FlatAmt_CHOICEPNo"]';

  const FACTOR = '[id*="Factor_NUM"], [id*="Factor_Ovrd_NUM"]';

  function ensureCss() {
    if (document.getElementById(CSS_ID)) return;
    const style = document.createElement("style");
    style.id = CSS_ID;
    style.textContent = `
      .${INVALID_CLASS}{
        border-color:#DA291C !important;
        outline:none !important;
        box-shadow: 0 0 0 .15rem rgba(218,41,28,.12) !important;
      }
    `;
    document.head.appendChild(style);
  }

  function setInvalid($el, invalid) {
    if (!$el || !$el.length) return;
    $el.toggleClass(INVALID_CLASS, !!invalid);
    if (invalid) $el.attr("aria-invalid", "true");
    else $el.removeAttr("aria-invalid");
  }

  function showError(htmlMsg) {
    if (typeof window.displayApiErrorMessage === "function") {
      window.displayApiErrorMessage(htmlMsg);
    }
  }

  function getScopeFromSaveBtn(btn) {
    const containerId = btn.getAttribute("data-multi-item-question-container");
    if (containerId && document.getElementById(containerId))
      return $("#" + containerId);

    // fallback: nearest collapse container, else whole doc
    const $c = $(btn).closest(".collapse");
    return $c.length ? $c : $(document);
  }

  function findNextRetenSelect($questionItem) {
    const $nextItem = $questionItem
      .nextAll(".questionItem")
      .filter(function () {
        return $(this).find(RETEN_SELECT).length > 0;
      })
      .first();

    return $nextItem.find(RETEN_SELECT).first();
  }

  // Your original condition, unchanged
  function shouldRequireReten($questionItem) {
    const selectedVal = (
      $questionItem.find(".instanda-selected input").val() ?? ""
    ).toString();

    const factorRawVal = ($questionItem.find(FACTOR).val() ?? "").toString();
    const factorVal = parseFloat(factorRawVal);

    return (
      selectedVal === "Yes" ||
      (selectedVal === "No" &&
        factorRawVal !== "" &&
        Number.isFinite(factorVal) &&
        factorVal !== 1)
    );
  }

  function updateRetenCodeFields($premFlat) {
    const $questionItem = $premFlat.closest(".questionItem");
    const $reten = findNextRetenSelect($questionItem);
    if (!$reten.length) return;

    const requiredNow = shouldRequireReten($questionItem);

    $reten.prop("required", requiredNow).prop("disabled", !requiredNow);

    // show/hide the red * on the Retention Code label
    const $qi = $reten.closest(".questionItem");
    const $star = $qi
      .find('label.control-label > span[style*="color: red"]')
      .first();
    if ($star.length) $star.toggle(requiredNow);

    // if it becomes optional, clear any prior invalid styling
    if (!requiredNow) setInvalid($reten, false);
  }

  // --- Init / live sync ---
  ensureCss();

  // Initial sync
  $(PREM_FLAT).each(function () {
    updateRetenCodeFields($(this));
  });

  // Keep in sync on edits (Factor changes, radio/inputs change)
  $(document).on("change input", FACTOR, function () {
    const $qi = $(this).closest(".questionItem");
    const $premFlat = $qi.find(PREM_FLAT).first();
    if ($premFlat.length) updateRetenCodeFields($premFlat);
  });

  $(document).on("click change", ".questionItem input", function () {
    const $qi = $(this).closest(".questionItem");
    const $premFlat = $qi.find(PREM_FLAT).first();
    if ($premFlat.length) updateRetenCodeFields($premFlat);
  });

  // --- Validate on Save changes (your exact button type) ---
  document.addEventListener(
    "click",
    function (e) {
      const btn = e.target.closest('button[onclick*="saveMultiItemInstance"]');
      if (!btn) return;

      const $scope = getScopeFromSaveBtn(btn);

      // resync within this MI right before validating
      $scope.find(PREM_FLAT).each(function () {
        updateRetenCodeFields($(this));
      });

      // validate required retention selects within this MI
      let $firstInvalid = null;

      $scope.find(RETEN_SELECT).each(function () {
        const $reten = $(this);
        const required = !!$reten.prop("required");
        const disabled = !!$reten.prop("disabled");

        if (!required || disabled) {
          setInvalid($reten, false);
          return;
        }

        const val = ($reten.val() ?? "").toString().trim();
        const ok = val !== "";

        setInvalid($reten, !ok);
        if (!ok && !$firstInvalid) $firstInvalid = $reten;
      });

      if ($firstInvalid && $firstInvalid.length) {
        showError("Please select a Retention Code.");
        try {
          $firstInvalid.trigger("focus");
        } catch (_) { }
        e.preventDefault();
        e.stopPropagation();
        e.stopImmediatePropagation();
      }
    },
    true // capture to beat inline onclick
  );

  // Clear invalid highlight when user fixes it
  $(document).on("change input", RETEN_SELECT, function () {
    setInvalid($(this), false);
  });
}

