$(document).ready(function () {
  if ($(".page-quickquotequestions.page-number-4.package-24338").length > 0) {
    $(document).on(
      "click",
      "button[name='continueButton'][formaction='QuickQuoteQuestionsContinue']",
      function () {
        try {
          const vehiclePDContainer = document.querySelectorAll(
            "[class*='instanda-multi-item-Vehicle_MI']"
          );
          const vehiclePDPrefix = "instanda-multi-item-Vehicle_MI";
          var principalDict = {
            Regular: [],
            Motorcycle: [],
          };
          var principalDrivers = [];

          vehiclePDContainer.forEach((parent) => {
            const miNumber = extractMINumber(parent, vehiclePDPrefix);

            if (
              $(`#Vehicle_MI${miNumber}_VehType_CHOICEP`).val() === "Regular"
            ) {
              principalDict[`Regular`].push(
                $(`#Vehicle_MI${miNumber}_PrincipalDriver_TXT`).val()
              );
            } else if (
              $(`#Vehicle_MI${miNumber}_VehType_CHOICEP`).val() ===
              "Misc. - Motorcycle"
            ) {
              principalDict[`Motorcycle`].push(
                $(`#Vehicle_MI${miNumber}_PrincipalDriver_TXT`).val()
              );
            }
            if (
              !principalDrivers.includes(
                $(`#Vehicle_MI${miNumber}_PrincipalDriver_TXT`).val()
              ) &&
              $(`#Vehicle_MI${miNumber}_PrincipalDriver_TXT`).val() !== ""
            ) {
              principalDrivers.push(
                $(`#Vehicle_MI${miNumber}_PrincipalDriver_TXT`).val()
              );
            }
          });

          const emptyCount = $.grep(
            principalDict[`Regular`],
            (v) => v === ""
          ).length;
          if (
            emptyCount ===
            principalDict[`Regular`].length - principalDrivers.length
          ) {
            if (
              principalDict[`Motorcycle`].every(function (x) {
                return $.inArray(x, principalDict[`Regular`]) !== -1;
              })
            ) {
              $("#motocyclePDFlag").val("false");
            } else {
              $("#motocyclePDFlag").val("true");
            }
          }
          if (
            emptyCount !==
            principalDict[`Regular`].length - principalDrivers.length
          ) {
            if (
              principalDict[`Motorcycle`].every(function (x) {
                return $.inArray(x, principalDict[`Regular`]) !== -1;
              })
            ) {
              $("#motocyclePDFlag").val("false");
            } else {
              $("#motocyclePDFlag").val("true");
            }
          }
          if (
            principalDict[`Regular`].length < principalDrivers.length &&
            emptyCount === 0
          ) {
            $("#motocyclePDFlag").val("false");
          }
          console.log($("#motocyclePDFlag").val(), $("#motorLicPDFlag").val());
        } catch (err) {
          console.warn("Continue click handler ignored error:", err);
          return;
        }
      }
    );
  }
});

