$(document).ready(function () {
  function parseBangList(str) {
    return String(str ?? "")
      .split("!")
      .map((s) => s.trim())
      .filter(Boolean);
  }

  function toBangString(arr) {
    const clean = (arr ?? [])
      .map(String)
      .map((s) => s.trim())
      .filter(Boolean);
    return clean.length ? clean.join("!") + "!" : "";
  }

  function extractDriverIndexFromPDText(pdText) {
    const m = String(pdText ?? "")
      .trim()
      .match(/^(\d+)\s*\./);
    return m ? m[1] : "";
  }

  function getVarValue(inputId, instandaVarName) {
    const fromInput = $(inputId).val();
    if (fromInput != null && String(fromInput).trim() !== "")
      return String(fromInput);
    const fromInstanda = window.Instanda?.Variables?.[instandaVarName];
    return fromInstanda == null ? "" : String(fromInstanda);
  }

  function extractVehicleMiFromId(id) {
    const m = String(id || "").match(/^Vehicle_MI(\d+)_/);
    return m ? m[1] : "";
  }

  // -------------------------
  // Page 2: maintain motorcycleLicPDs (Driver MI indexes where MotorcycleLicInfo = No)
  // -------------------------
  (function setupMotorcycleLicPDsOnPage2() {
    if ($(".page-quickquotequestions.page-number-2.package-24338").length === 0)
      return;

    const driverPrefix = "instanda-multi-item-Driver_MI";

    function recomputeMotorcycleLicPDs() {
      const driverContainers = document.querySelectorAll(
        `[class*='${driverPrefix}']`
      );
      const motorcycleLicPDs = [];

      driverContainers.forEach((parent) => {
        const miNumber = extractMINumber(parent, driverPrefix);
        const noChecked =
          $(`#Driver_MI${miNumber}_MotorcycleLicInfo_YNPNo`).prop("checked") ===
          true;
        if (noChecked) motorcycleLicPDs.push(`${miNumber}!`);
      });

      $("#motorcycleLicPDs").val(motorcycleLicPDs.join(""));
    }

    recomputeMotorcycleLicPDs();

    $(document).on(
      "change",
      "input[id^='Driver_MI'][id$='_MotorcycleLicInfo_YNPYes'], input[id^='Driver_MI'][id$='_MotorcycleLicInfo_YNPNo']",
      recomputeMotorcycleLicPDs
    );
  })();

  // -------------------------
  // Page 4: maintain MotorCycleVehPDList_TXT (current motorcycles only)
  // + warn per-vehicle on save
  // -------------------------
  (function setupMotorcycleVehiclePDListAndWarningOnPage4() {
    if ($(".page-quickquotequestions.page-number-4.package-24338").length === 0)
      return;

    const vehiclePrefix = "instanda-multi-item-Vehicle_MI";

    function recomputeMotorCycleVehPDList(preserveExistingIfEmpty) {
      const existingStr = getVarValue(
        "#MotorCycleVehPDList_TXT",
        "MotorCycleVehPDList_TXT"
      );

      const vehicleContainers = document.querySelectorAll(
        `[class*='${vehiclePrefix}']`
      );
      const computed = [];

      vehicleContainers.forEach((parent) => {
        const miNumber = extractMINumber(parent, vehiclePrefix);

        const vehType = $(`#Vehicle_MI${miNumber}_VehType_CHOICEP`).val();
        if (vehType !== "Misc. - Motorcycle") return;

        const pdText = $(`#Vehicle_MI${miNumber}_PrincipalDriver_TXT`).val();
        const idx = extractDriverIndexFromPDText(pdText);
        if (idx) computed.push(idx);
      });

      // If nothing computed (common during initial load), keep old value BUT sync DOM
      if (preserveExistingIfEmpty === true && computed.length === 0) {
        $("#MotorCycleVehPDList_TXT").val(existingStr);
        return existingStr;
      }

      // Current motorcycles only (no sticky merge), deduped
      const mergedStr = toBangString(Array.from(new Set(computed)));
      $("#MotorCycleVehPDList_TXT").val(mergedStr);
      return mergedStr;
    }

    // Evaluate warning for ONE vehicle MI only
    function evaluateMotorcycleLicWarningForVehicle(miNumber, showWarning) {
      if (!miNumber) return;

      const vehType = $(`#Vehicle_MI${miNumber}_VehType_CHOICEP`).val();
      if (vehType !== "Misc. - Motorcycle") return; // only motorcycles should trigger

      const pdText = $(`#Vehicle_MI${miNumber}_PrincipalDriver_TXT`).val();
      const driverIdx = extractDriverIndexFromPDText(pdText);
      if (!driverIdx) return; // no PD selected => don't warn yet

      const licSet = new Set(
        parseBangList(getVarValue("#motorcycleLicPDs", "motorcycleLicPDs"))
      );
      const hasIssue = licSet.has(driverIdx);

      $("#motorLicPDFlag").val(hasIssue ? "true" : "false");

      if (
        showWarning === true &&
        hasIssue === true &&
        Instanda?.Variables?.ConvertedPolicy_YN === "No"
      ) {
        displayApiWarningMessage(
          "Motorcycle License missing for motorcycle driver"
        );
      }
    }

    // On load: compute list (no global warning spam)
    recomputeMotorCycleVehPDList(true);
    setTimeout(function () {
      recomputeMotorCycleVehPDList(true);
    }, 50);

    // When vehicle type changes, recompute list + (optionally) re-evaluate this vehicle (no popup spam)
    $(document).on(
      "change",
      "select[id^='Vehicle_MI'][id$='_VehType_CHOICEP']",
      function () {
        const miNumber = extractVehicleMiFromId(this.id);
        recomputeMotorCycleVehPDList(false);
        evaluateMotorcycleLicWarningForVehicle(miNumber, false);
      }
    );

    // When PD changes, recompute list + re-evaluate this vehicle (no popup spam)
    $(document).on(
      "change input blur",
      ":input[id^='Vehicle_MI'][id*='_PrincipalDriver_TXT']",
      function () {
        const miNumber = extractVehicleMiFromId(this.id);
        recomputeMotorCycleVehPDList(false);
        evaluateMotorcycleLicWarningForVehicle(miNumber, false);
      }
    );

    // On save click: evaluate ONLY the vehicle being saved (uses data-multi-item-index)
    $(document).on("click", "[onclick*='saveMultiItemInstance']", function () {
      try {
        const miNumber = String($(this).data("multi-item-index") ?? "");
        recomputeMotorCycleVehPDList(false);
        evaluateMotorcycleLicWarningForVehicle(miNumber, true);
      } catch (err) {
        console.warn("saveMultiItemInstance handler ignored error:", err);
      }
    });
    $("button[onclick*='saveMultiItemInstance']").on("click", function () {
      try {
        const miNumber = String($(this).data("multi-item-index") ?? "");
        recomputeMotorCycleVehPDList(false);
        evaluateMotorcycleLicWarningForVehicle(miNumber, true);
      } catch (err) {
        console.warn("saveMultiItemInstance handler ignored error:", err);
      }
    });
  })();
});

