// Auto - Code starts - Display Error Message if assigned drivers are removed/modified
async function validateDriversDropdowns(event) {
  if (isReadOnlyView()) return Promise.resolve("Readonly");

  const showError = (msg) => {
    if (typeof displayApiErrorMessage === "function")
      displayApiErrorMessage(msg);
  };

  try {
    const quoteData = await getQuoteData(event);

    const vehicles = Array.isArray(quoteData?.Vehicle_MI) ?
      quoteData.Vehicle_MI : [];
    const storedRaw = Instanda?.Variables?.StoreDriverVehAssnmt_TXT;

    const storedLines = String(storedRaw ?? "")
      .replace(/\r\n/g, "\n")
      .replace(/\r/g, "\n")
      .split("\n")
      .map((s) => s.trim())
      .filter(Boolean);

    const storedSet = new Set(storedLines);

    // Registered owner / ExistingDrivers_TXT validation (ONLY if .val() is non-null)
    let ownerIssue = false;

    try {
      const $existing =
        typeof $ === "function" ? $("#ExistingDrivers_TXT") : null;

      if ($existing && $existing.length) {
        const rawVal = $existing.val(); // null | string | array

        if (rawVal !== null) {
          let existingDriversVal = "";

          if (Array.isArray(rawVal)) {
            existingDriversVal = (rawVal.find((x) => String(x).trim()) ?? "")
              .toString()
              .trim();
          } else {
            existingDriversVal = (rawVal ?? "").toString().trim();
          }

          // Only validate if there's an actual selected value
          if (existingDriversVal) {
            ownerIssue = !storedSet.has(existingDriversVal);
          }
        }
      }
    } catch (_) {
      ownerIssue = false; // if anything goes wrong, skip owner validation
    }

    // Principal driver per vehicle validation
    const principalIssues = [];
    for (const v of vehicles) {
      const vehicleNo =
        v?.Position != null && String(v.Position).trim() !== "" ?
          String(v.Position).trim() :
          null;

      const vin = (v?.Vin_TXT ?? "").toString().trim();
      const principal = (v?.PrincipalDriver_TXT ?? "").toString().trim();

      if (!principal) continue;

      if (!storedSet.has(principal)) {
        principalIssues.push({
          vehicleNo: vehicleNo ?? "(Vehicle No missing)",
          vin: vin || "(VIN missing)",
          principalDriver: principal,
        });
      }
    }

    if (ownerIssue || principalIssues.length) {
      const messages = [];

      if (ownerIssue) {
        messages.push(
          "Driver details have been updated. The registered owner of the vehicle needs to be updated."
        );
      }

      if (principalIssues.length) {
        const vehicleLines = principalIssues.map(
          (i) => `Vehicle ${i.vehicleNo} (VIN ${i.vin})`
        );
        const vehicleListText =
          principalIssues.length > 2 ?
            vehicleLines.join("\n") :
            vehicleLines.join("; ");

        messages.push(
          "Driver details have been updated. Please review and update the Principal Driver selection for:\n" +
          vehicleListText
        );
      }

      const message = messages.join("\n");
      showError(message);

      const err = new Error(message);
      err.name = "DriverValidationError";
      err.ownerIssue = ownerIssue;
      err.principalIssues = principalIssues;
      return Promise.reject(err);
    }

    return Promise.resolve({
      status: "OK",
    });
  } catch (e) {
    const message =
      e && e.message ? e.message : "Unable to validate driver selections.";
    showError(message);
    return Promise.reject(e);
  }
}

$(document).on(
  "click",
  'button[name="continueButton"][formaction="QuickQuoteQuestionsContinue"]',
  async function (event) {
    // Only run this validation on this specific page/package
    if (
      $(".page-quickquotequestions.page-number-4.package-24338").length === 0
    ) {
      return; // allow normal click/submit behavior
    }

    event.preventDefault();
    event.stopImmediatePropagation();

    const btn = this;

    try {
      await validateDriversDropdowns(event); // shows displayApiErrorMessage on failure

      const form = btn.form;
      if (!form) return;

      // Submit using the clicked button so formaction is honored
      if (typeof form.requestSubmit === "function") {
        form.requestSubmit(btn);
      } else {
        const formaction = btn.getAttribute("formaction");
        if (formaction) form.setAttribute("action", formaction);
        form.submit();
      }
    } catch (_) {
      // Block navigation; error message already shown by validateDriversDropdowns
      return;
    }
  }
);
