$(document).ready(function () {
  // List of states that trigger the condition
  const validStates = [
    'AK', 'AZ', 'AR', 'CT', 'DC', 'DE', 'GA', 'HI', 'ID', 'IN',
    'IA', 'KS', 'KY', 'LA', 'ME', 'MA', 'MD', 'MI', 'MN', 'MO',
    'MT', 'NC', 'NM', 'NJ', 'NV', 'OK', 'OR', 'PA', 'RI', 'SC',
    'TN', 'UT', 'VA', 'VT', 'WA', 'WI', 'WV', 'CA', 'CO', 'FL',
    'IL', 'NY', 'TX'
  ];

  // Function to toggle question549122, question549162, #question549162 (use RiskStateRO_TXT)
  function toggleQuestions549122And549162() {
    const isPolRewrite = $('[name="IsPolRewrite_YNP"]:checked').val() === "Yes";
    const productCode = $('#ProductCode_CHOICE').val() === "Non-Admitted";
    const riskState = $('#RiskStateRO_TXT').val();
    const isValidState = validStates.includes(riskState);

    if (isPolRewrite && productCode && isValidState) {
      $('#question549122, #question549162, #question549162').show();
      $('#question549122, #question549162, #question549162').find('input, select, textarea').prop('required', true);
      $('#question549122, #question549162, #question549162').find('input, select, textarea').attr('aria-required', 'true');

    } else {
      $('#question549122, #question549162, #question549162').hide();
      $('#question549122, #question549162, #question549162').find('input, select, textarea').prop('required', false);
      $('#question549122, #question549162, #question549162').find('input, select, textarea').attr('aria-required', 'false');
      $('#question549122, #question549162, #question549162').find('input, select, textarea').val('');
    }
  }

  // Function to toggle question549195 (use CO_RiskStateRO_TXT)
  function toggleQuestion549195() {
    const isPolRewrite = $('[name="IsPolRewrite_YNP"]:checked').val() === "Yes";
    const productCode = $('#ProductCode_CHOICE').val() === "Non-Admitted";
    const coRiskState = $('#CO_RiskStateRO_TXT').val();
    const isValidState = validStates.includes(coRiskState);

    if (isPolRewrite && productCode && isValidState) {
      $('#question549195').show();
      $('#question549195').find('input, select, textarea').prop('required', true);
      $('#question549195').find('input, select, textarea').attr('aria-required', 'true');
    } else {
      $('#question549195').hide();
      $('#question549195').find('input, select, textarea').prop('required', false);
      $('#question549195').find('input, select, textarea').attr('aria-required', 'false');
      $('#question549195').find('input, select, textarea').val('');
    }
  }

  // Trigger on page load
  toggleQuestions549122And549162();
  toggleQuestion549195();

  // Trigger on change of IsPolRewrite radio buttons
  $('[name="IsPolRewrite_YNP"]').on('change', function () {
    toggleQuestions549122And549162();
    toggleQuestion549195();
  });

  // Trigger on change of ProductCode
  $('#ProductCode_CHOICE').on('change', function () {
    toggleQuestions549122And549162();
    toggleQuestion549195();
  });

  // Trigger on change of RiskStateRO_TXT (for questions 549122 and 549162)
  $('#RiskStateRO_TXT').on('change', function () {
    toggleQuestions549122And549162();
  });

  // Trigger on change of CO_RiskStateRO_TXT (for question 549195)
  $('#CO_RiskStateRO_TXT').on('change', function () {
    toggleQuestion549195();
  });
});

